const QUESTIONS = [
  /* ═══ MCH ═══ */
  { topic:'mch', q:'What is the recommended minimum number of ANC contacts as per WHO 2016 guidelines?', opts:['4 contacts','6 contacts','8 contacts','10 contacts'], ans:2, expl:'WHO 2016 recommends minimum 8 ANC contacts: at <12 weeks, 20, 26, 30, 34, 36, 38, and 40 weeks. India\'s RMNCH+A recommends at least 4 ANCs, but WHO updated to 8 for better outcomes.' },
  { topic:'mch', q:'First ANC visit should ideally be completed within how many weeks of pregnancy?', opts:['First 4 weeks','First 12 weeks','First 16 weeks','First 20 weeks'], ans:1, expl:'First ANC should be within the first trimester (by 12 weeks). This allows early detection of risk factors, registration under JSSK, and timely start of IFA supplementation.' },
  { topic:'mch', q:'IFA tablets in pregnancy primarily prevent:', opts:['Night blindness','Anaemia and neural tube defects','Rickets','Scurvy'], ans:1, expl:'Iron prevents anaemia (most common deficiency in pregnancy). Folic acid prevents Neural Tube Defects (NTDs) like spina bifida and anencephaly.' },
  { topic:'mch', q:'Which injection protects the newborn from neonatal tetanus?', opts:['BCG','TT / Td (Tetanus Toxoid)','OPV','Hepatitis B'], ans:1, expl:'TT/Td is given to pregnant women. Antibodies pass to baby protecting against neonatal tetanus. India now uses Td (Tetanus-Diphtheria). Two doses: TT1 at first contact, TT2 four weeks later.' },
  { topic:'mch', q:'Low Birth Weight (LBW) is defined as birth weight less than:', opts:['2000 g','2500 g','3000 g','1500 g'], ans:1, expl:'LBW = birth weight <2500 g regardless of gestational age. VLBW = <1500 g; ELBW = <1000 g. LBW babies need Kangaroo Mother Care (KMC).' },
  { topic:'mch', q:'Kangaroo Mother Care (KMC) involves:', opts:['Bathing baby immediately after birth','Skin-to-skin contact between mother and LBW/preterm baby','Giving special milk formula','Placing baby in incubator'], ans:1, expl:'KMC = placing LBW/preterm infant in skin-to-skin contact on mother\'s chest. Benefits: maintains temperature, promotes breastfeeding, reduces infections and mortality.' },
  { topic:'mch', q:'Exclusive breastfeeding is recommended for:', opts:['First 3 months','First 6 months','First 9 months','First 12 months'], ans:1, expl:'WHO/UNICEF recommend Exclusive Breastfeeding (EBF) for first 6 months. No water, other liquids or food — only breast milk. Complementary feeding starts at 6 months, breastfeeding continues to 2 years.' },
  { topic:'mch', q:'The first milk after delivery rich in antibodies is called:', opts:['Foremilk','Hindmilk','Colostrum','Transitional milk'], ans:2, expl:'Colostrum = thick yellowish milk in first 2–3 days. Rich in IgA, white blood cells, proteins. Acts as baby\'s first vaccine. Should NEVER be discarded. Breastfeeding should start within 1 hour of birth.' },
  { topic:'mch', q:'APGAR score is assessed at (minutes after birth):', opts:['1 and 5 minutes','2 and 10 minutes','5 and 15 minutes','Immediately at birth'], ans:0, expl:'APGAR at 1 min and 5 min. Parameters: Appearance, Pulse, Grimace, Activity, Respiration. Score 7–10=normal; 4–6=moderate depression; 0–3=severe. Maximum score is 10.' },
  { topic:'mch', q:'PPH (Postpartum Haemorrhage) after vaginal delivery is defined as blood loss exceeding:', opts:['300 mL','500 mL','1000 mL','200 mL'], ans:1, expl:'PPH = blood loss ≥500 mL within 24 hours of vaginal delivery (≥1000 mL after C-section). Most common cause: Uterine Atony (80%). Prevention: Oxytocin 10 IU IM (AMTSL).' },
  { topic:'mch', q:'Vitamin A supplementation to children at 9 months is:', opts:['1,00,000 IU','2,00,000 IU','50,000 IU','3,00,000 IU'], ans:0, expl:'VAS schedule: 1st dose 1,00,000 IU at 9 months with MR vaccine. Then 2,00,000 IU every 6 months from 18 months up to 5 years. VAD causes night blindness and xerophthalmia.' },
  { topic:'mch', q:'Neonatal period is defined as:', opts:['First 7 days of life','First 28 days of life','First 3 months of life','First year of life'], ans:1, expl:'Neonatal period = first 28 days (0–28 days). Early neonatal = 0–7 days; Late neonatal = 7–28 days. Highest mortality risk: sepsis, birth asphyxia, prematurity.' },
  { topic:'mch', q:'JSSK (Janani Shishu Suraksha Karyakram) was launched in:', opts:['2005','2007','2011','2013'], ans:2, expl:'JSSK launched 1 June 2011. Entitles ALL pregnant women at government hospitals to FREE: delivery, drugs, diagnostics, diet (3 days), blood, transport, referral. Sick newborns up to 30 days.' },
  { topic:'mch', q:'The recommended time to initiate breastfeeding after birth is:', opts:['Within 30 minutes','Within 1 hour','Within 6 hours','Within 24 hours'], ans:1, expl:'WHO/UNICEF recommend breastfeeding initiation within 1 hour of birth (golden hour). Early initiation ensures baby gets colostrum and stimulates milk production. It also reduces risk of hypothermia.' },
  { topic:'mch', q:'Danger sign in a pregnant woman requiring immediate referral:', opts:['Mild ankle oedema','Severe headache and blurred vision','Mild nausea in first trimester','Occasional backache'], ans:1, expl:'Severe headache + blurred vision = signs of pre-eclampsia/eclampsia. Other danger signs: vaginal bleeding, fits, reduced fetal movements, high fever, severe abdominal pain. Require immediate referral to FRU/hospital.' },
  { topic:'mch', q:'The PMMVY scheme provides maternity benefit of:', opts:['₹1,000','₹3,000','₹5,000','₹10,000'], ans:2, expl:'PMMVY (Pradhan Mantri Matru Vandana Yojana) provides ₹5,000 in 3 instalments for the first live birth to working women to compensate wage loss and improve health practices.' },
  { topic:'mch', q:'Under RMNCH+A, "A" stands for:', opts:['Anaemia','Adult health','Adolescent health','Ayush'], ans:2, expl:'RMNCH+A = Reproductive, Maternal, Newborn, Child Health, and Adolescent Health. The "A" was added in 2013 to integrate adolescent health under RKSK (Rashtriya Kishor Swasthya Karyakram).' },
  { topic:'mch', q:'PM Surakshit Matritva Abhiyan (PMSMA) provides ANC on which fixed day every month?', opts:['1st','5th','9th','15th'], ans:2, expl:'PMSMA: Every 9th of the month, specialist/medical officer provides free comprehensive ANC to high-risk pregnant women at PHCs/CHCs/DH. Focuses on identifying and managing complicated pregnancies.' },

  /* ═══ FAMILY PLANNING ═══ */
  { topic:'fp', q:'Most effective PERMANENT female family planning method:', opts:['IUCD','Tubectomy','OCP','Condom'], ans:1, expl:'Tubectomy (bilateral tubal ligation) = most effective permanent FP for women. Failure rate <0.5/100 women-years. Order of effectiveness: Tubectomy > Vasectomy > IUCD > Injectables > OCPs > Condoms.' },
  { topic:'fp', q:'Cu-T 380A IUCD is effective for up to:', opts:['3 years','5 years','10 years','15 years'], ans:2, expl:'Cu-T 380A effective for 10 years. "380A" = 380 sq mm copper surface area. Copper ions have spermicidal action and prevent fertilisation. Most widely used IUCD in India.' },
  { topic:'fp', q:'Emergency contraceptive pill should be taken within:', opts:['12 hours','24 hours','72 hours','120 hours'], ans:2, expl:'ECP (levonorgestrel 1.5 mg) most effective within 72 hours. Efficacy: 95% at 24h, 85% at 48h, 58% at 72h. Works mainly by delaying/preventing ovulation.' },
  { topic:'fp', q:'DMPA (Depo-Provera) injectable contraceptive is given every:', opts:['1 month','2 months','3 months','6 months'], ans:2, expl:'DMPA 150 mg deep IM injection every 3 months (12–13 weeks). India introduced it under Antara Programme. Progestin-only, safe for breastfeeding mothers. Main side effect: irregular periods.' },
  { topic:'fp', q:'The Pearl Index measures:', opts:['Side effects of contraceptives','Number of pregnancies per 100 woman-years','Effectiveness of ANC','Number of sterilisations'], ans:1, expl:'Pearl Index = pregnancies per 100 woman-years of use. LOWER Pearl Index = MORE effective method. Tubectomy: 0.5; IUCD: 0.5–1; OCPs: 1–2; Condoms: 3–15 (typical use).' },
  { topic:'fp', q:'Which is the ONLY contraceptive method that also protects against STIs/HIV?', opts:['OCP','IUCD','Male condom','Tubectomy'], ans:2, expl:'Male condom is the only contraceptive that provides dual protection — against pregnancy AND STIs including HIV. Promotes consistent and correct use. Female condom also provides STI protection.' },
  { topic:'fp', q:'PPIUCD stands for:', opts:['Post-Partum Intra-Uterine Contraceptive Device','Pre-Partum Intra-Uterine Contraceptive Device','Post-Primary IUCD','Permanent Protective IUCD'], ans:0, expl:'PPIUCD = Post-Partum IUCD inserted within 10 minutes after delivery of placenta (immediate) or within 48 hours of delivery. Also done at 6 weeks postpartum (interval IUCD). Highly effective.' },
  { topic:'fp', q:'LAM (Lactational Amenorrhoea Method) works when ALL three conditions are met:', opts:['Baby <12 months, mother breastfeeding, periods resumed','Baby <6 months, exclusive breastfeeding, amenorrhoea','Baby <6 months, partial breastfeeding, amenorrhoea','Baby <9 months, EBF, any menstrual status'], ans:1, expl:'LAM conditions: (1) Baby <6 months old, (2) Exclusive breastfeeding (day and night, no supplements), (3) No menstruation (amenorrhoea). All 3 must be present. Failure rate: 0.5–2% if conditions met.' },
  { topic:'fp', q:'Chhaya (Centchroman/Ormeloxifene) is taken:', opts:['Daily','Weekly','Monthly','Every 3 months'], ans:1, expl:'Chhaya (Centchroman/Saheli) is a non-hormonal oral contraceptive pill taken weekly. It is a SERM (Selective Estrogen Receptor Modulator). Twice weekly for first 3 months, then weekly. No serious hormonal side effects.' },
  { topic:'fp', q:'Mission Parivar Vikas targets districts with TFR above:', opts:['2.0','2.1','3.0','4.0'], ans:2, expl:'Mission Parivar Vikas (2016) targets 146 high-fertility districts across 7 states (UP, MP, Rajasthan, Bihar, Jharkhand, Chhattisgarh, Assam) with TFR ≥3. Goal: achieve replacement-level fertility (TFR=2.1).' },

  /* ═══ IMMUNIZATION ═══ */
  { topic:'immunize', q:'BCG vaccine is given by which route?', opts:['Intramuscular (IM)','Subcutaneous (SC)','Intradermal (ID)','Oral'], ans:2, expl:'BCG given by INTRADERMAL injection on left upper arm, 0.1 mL. Correct technique produces 7mm bleb. Protects against TB meningitis and miliary TB in children.' },
  { topic:'immunize', q:'DPT vaccine protects against:', opts:['Diphtheria, Plague, Tetanus','Diphtheria, Pertussis, Tetanus','Dengue, Polio, Typhoid','Diphtheria, Pneumonia, Typhoid'], ans:1, expl:'DPT = Diphtheria + Pertussis (whooping cough) + Tetanus. Given IM. India now uses Pentavalent (DPT + Hib + HepB) at 6, 10, 14 weeks.' },
  { topic:'immunize', q:'OPV is given by which route?', opts:['Injection','Oral (2 drops in mouth)','Nasal drops','Skin patch'], ans:1, expl:'OPV (Oral Polio Vaccine/Sabin vaccine) given as 2 drops orally. India uses bOPV (bivalent types 1&3). India declared POLIO-FREE on 27 March 2014.' },
  { topic:'immunize', q:'Pentavalent vaccine protects against how many diseases?', opts:['3','4','5','6'], ans:2, expl:'Pentavalent = 5-in-1: DPT (Diphtheria + Pertussis + Tetanus) + Hepatitis B + Hib (Haemophilus influenzae type b). Given IM at 6, 10, 14 weeks.' },
  { topic:'immunize', q:'MR vaccine in India protects against:', opts:['Mumps and Rubella','Measles and Rubella','Malaria and Rabies','Meningitis and Rabies'], ans:1, expl:'MR vaccine = Measles + Rubella. Replaced standalone measles vaccine. Given at 9–12 months and 16–24 months. Rubella prevention prevents Congenital Rubella Syndrome (CRS).' },
  { topic:'immunize', q:'Cold chain temperature for storing most vaccines (except OPV) is:', opts:['-20°C to -25°C','+2°C to +8°C','+10°C to +15°C','Room temperature'], ans:1, expl:'+2°C to +8°C = storage temperature for most vaccines in ILR. OPV stored at -15°C to -25°C (deep freezer). Never freeze DPT, HepB, Pentavalent (becomes ineffective — "freeze-sensitive").' },
  { topic:'immunize', q:'VVM (Vaccine Vial Monitor) indicates vaccine is usable when:', opts:['Inner square is DARKER than outer circle','Inner square is LIGHTER than outer circle','Colour change is complete','Monitor turns red'], ans:1, expl:'VVM rule: usable when inner square LIGHTER than outer circle. Discard when inner square is SAME colour or DARKER. Detects cumulative heat exposure — not freeze damage.' },
  { topic:'immunize', q:'Which vaccine is given at birth in India?', opts:['DPT only','BCG + OPV-0 + HepB-0','BCG only','Pentavalent + OPV'], ans:1, expl:'At birth: BCG (intradermal, left arm) + OPV-0 (oral, 2 drops) + Hepatitis B-0 (IM, right thigh). These should be given before discharge from hospital/birth facility.' },
  { topic:'immunize', q:'DPT booster (B1) is given at what age?', opts:['9–12 months','12–16 months','16–24 months','5–6 years'], ans:2, expl:'DPT Booster 1 (B1) = 16–24 months along with OPV booster and MR-2. DPT Booster 2 = 5–6 years. Td (Tetanus-Diphtheria) at 10 years and 16 years.' },
  { topic:'immunize', q:'Rotavirus vaccine was added to UIP in India in:', opts:['2010','2013','2016','2019'], ans:2, expl:'Rotavirus vaccine added to UIP in 2016 in phased rollout. Given orally at 6, 10, 14 weeks. Protects against rotavirus diarrhoea — a major cause of under-5 diarrhoeal deaths.' },
  { topic:'immunize', q:'IPV (Injectable Polio Vaccine) was added to India\'s UIP in:', opts:['2010','2015','2018','2020'], ans:1, expl:'IPV added to UIP in 2015. Given as 0.1 mL fractional dose intradermally (fIPV). Two doses at 6 weeks and 14 weeks. Added to prevent vaccine-derived poliovirus (VDPV) and maintain polio-free status.' },
  { topic:'immunize', q:'Which disease was eradicated globally by vaccination?', opts:['Polio','Measles','Smallpox','Tuberculosis'], ans:2, expl:'Smallpox was the first and only human disease eradicated globally through vaccination. WHO certified global eradication in 1980. The last natural case was in 1977 (Somalia). Achieved through Edward Jenner\'s cowpox vaccine concept.' },

  /* ═══ NUTRITION ═══ */
  { topic:'nutrition', q:'Vitamin A deficiency causes:', opts:['Scurvy','Xerophthalmia and night blindness','Rickets','Beriberi'], ans:1, expl:'VAD → Xerophthalmia: Night blindness (XN) → Conjunctival xerosis (X1A) → Bitot\'s spots (X1B) → Corneal xerosis (X2) → Corneal ulceration (X3A/B) → Keratomalacia. Bitot\'s spots = foamy triangular deposits on conjunctiva.' },
  { topic:'nutrition', q:'Kwashiorkor is characterised by:', opts:['Severe wasting without oedema','Oedema, moon face, flaky paint skin','Only weight loss','High fever and rash'], ans:1, expl:'Kwashiorkor = mainly protein deficiency. Features: Oedema (pitting), moon face, pot belly, flaky paint dermatosis (skin), psychomotor changes, flag sign (hair), fatty liver. Marasmus = calorie-protein deficiency → wasting, NO oedema.' },
  { topic:'nutrition', q:'SAM (Severe Acute Malnutrition) MUAC cutoff in children 6–59 months:', opts:['<11.5 cm','<12.5 cm','<13.5 cm','<14.5 cm'], ans:0, expl:'MUAC: SAM = <11.5 cm (red); MAM = 11.5–12.5 cm (yellow); Normal = ≥12.5 cm (green). SAM children treated at NRCs (Nutrition Rehabilitation Centres) with F-75/F-100 or RUTF.' },
  { topic:'nutrition', q:'Iodine deficiency causes:', opts:['Anaemia','Goitre and cretinism','Night blindness','Rickets'], ans:1, expl:'IDD = Iodine Deficiency Disorders: Goitre, hypothyroidism, cretinism (mental retardation + deaf-mutism + stunting). Prevention: Universal Salt Iodisation (USI) at 30 ppm production level.' },
  { topic:'nutrition', q:'Pellagra (3Ds disease) is caused by deficiency of:', opts:['Vitamin A','Vitamin B1 (Thiamine)','Vitamin B3 (Niacin)','Vitamin C'], ans:2, expl:'Pellagra = Vitamin B3 (Niacin) deficiency. Classic 3Ds: Dermatitis (photosensitive, Casal\'s necklace rash), Diarrhoea, Dementia. Common in populations eating mainly maize. Treatment: Nicotinamide.' },
  { topic:'nutrition', q:'Rickets in children is caused by deficiency of:', opts:['Vitamin A','Vitamin B12','Vitamin C','Vitamin D'], ans:3, expl:'Vitamin D deficiency → Rickets (children) / Osteomalacia (adults). Features: Bowing of legs, rachitic rosary (costochondral beading), Harrison\'s groove, delayed fontanelle closure, dental delay.' },
  { topic:'nutrition', q:'Gomez classification of malnutrition is based on:', opts:['Height for age','Weight for height (WHZ)','Weight for age vs Harvard standard','MUAC'], ans:2, expl:'Gomez classification uses Weight for Age (% of Harvard standard): Grade I = 75–90% (mild); Grade II = 60–74% (moderate); Grade III = <60% (severe). WHO now uses Z-score based classifications.' },
  { topic:'nutrition', q:'ICDS (Integrated Child Development Services) provides how many services through Anganwadi?', opts:['3','4','6','8'], ans:2, expl:'ICDS 6 services: (1) Supplementary nutrition, (2) Immunisation, (3) Health check-up, (4) Referral services, (5) Pre-school non-formal education, (6) Health and nutrition education. The first 3 are called "nutrition-related" services.' },
  { topic:'nutrition', q:'Scurvy is caused by deficiency of:', opts:['Vitamin D','Vitamin A','Vitamin C (Ascorbic acid)','Iron'], ans:2, expl:'Vitamin C deficiency → Scurvy. Features: Bleeding gums, perifollicular haemorrhages (corkscrew hairs), poor wound healing, scorbutic rosary, "woody" leg oedema. Treatment: Vitamin C 100–300 mg/day orally.' },
  { topic:'nutrition', q:'Anaemia Mukt Bharat strategy targets how many beneficiary groups?', opts:['3','4','6','8'], ans:2, expl:'Anaemia Mukt Bharat (2018) = 6×6×6 strategy: 6 beneficiary groups (children 6–59m, 5–9y, adolescent girls 10–19y, adolescent boys 10–19y, pregnant women, non-pregnant women 15–49y), 6 interventions, 6 institutional mechanisms.' },

  /* ═══ COMMUNICABLE DISEASES ═══ */
  { topic:'diseases', q:'Malaria is transmitted by:', opts:['Male Culex mosquito','Female Anopheles mosquito','Aedes aegypti mosquito','Sandfly'], ans:1, expl:'Malaria transmitted by BITE of Female Anopheles mosquito (only females need blood for egg development). P. vivax most common in India; P. falciparum most dangerous. Treatment: CQ for vivax; ACT for falciparum.' },
  { topic:'diseases', q:'Dengue is transmitted by:', opts:['Female Anopheles mosquito','Culex mosquito','Aedes aegypti mosquito (daytime biting)','Tsetse fly'], ans:2, expl:'Aedes aegypti = dengue vector. Breeds in clean stagnant water (flower pots, coolers, tyres). DAYTIME biting. 4 serotypes (DENV 1–4). Severe dengue = DHF/DSS. No specific antiviral — supportive care.' },
  { topic:'diseases', q:'Cholera is caused by:', opts:['Salmonella typhi','Vibrio cholerae','Shigella dysenteriae','E. coli'], ans:1, expl:'Cholera = Vibrio cholerae O1 (El Tor/classical biotype) or O139. Transmission: faecal-oral via contaminated water. Classic: "rice water" stools. Treatment cornerstone = ORS. Prevention: WASH.' },
  { topic:'diseases', q:'HIV is NOT transmitted by:', opts:['Unprotected sex','Sharing IV needles','Mother to child (MTCT)','Mosquito bites'], ans:3, expl:'HIV NOT spread by: mosquito bites, casual contact, handshakes, hugging, sharing food, coughing. Modes of transmission: Sexual (most common), Blood (transfusion/needles), Vertical (MTCT).' },
  { topic:'diseases', q:'Leprosy (Hansen\'s disease) primarily affects:', opts:['Lungs','Skin and peripheral nerves','Liver','Kidneys'], ans:1, expl:'Leprosy caused by Mycobacterium leprae. Affects skin (hypopigmented patches, loss of sensation) and peripheral nerves (thickened — ulnar, radial, peroneal). Treatment: MDT (Rifampicin + Dapsone ± Clofazimine).' },
  { topic:'diseases', q:'The causative agent of Typhoid is:', opts:['Salmonella typhi','Vibrio cholerae','E. coli','Klebsiella'], ans:0, expl:'Typhoid (enteric fever) caused by Salmonella typhi. Incubation 7–14 days. Step-ladder fever, relative bradycardia. Widal test (not gold standard); Blood culture = gold standard. Prevention: Vi typhoid vaccine, safe water.' },
  { topic:'diseases', q:'DOTS in TB treatment stands for:', opts:['Direct Observed Treatment Short-course','Drug Oriented TB Scheme','Daily Oral Treatment Schedule','Direct Oral Therapy Standard'], ans:0, expl:'DOTS = Directly Observed Treatment Short-course. Treatment is taken under direct observation of a health worker to ensure adherence. Key component of NTEP. Treatment for drug-sensitive TB: 2HRZE + 4HR (total 6 months).' },
  { topic:'diseases', q:'Kala-azar (Visceral Leishmaniasis) is transmitted by:', opts:['Anopheles mosquito','Aedes mosquito','Sandfly (Phlebotomus)','Culex mosquito'], ans:2, expl:'Kala-azar transmitted by female Phlebotomus sandfly. Caused by Leishmania donovani. Endemic: Bihar, Jharkhand, UP, West Bengal. Features: prolonged fever, splenomegaly, weight loss. Drug: Miltefosine, Amphotericin B.' },
  { topic:'diseases', q:'Japanese Encephalitis (JE) is transmitted by:', opts:['Aedes mosquito','Culex tritaeniorhynchus mosquito','Anopheles mosquito','Sandfly'], ans:1, expl:'JE transmitted by Culex tritaeniorhynchus mosquito. Breeds in paddy fields. Pigs and wading birds are reservoir hosts. Causes viral encephalitis. JE vaccine given in endemic areas in India at 9–12 months.' },
  { topic:'diseases', q:'Which is the window period for HIV testing?', opts:['1–2 weeks','1–3 months (4th generation tests detect earlier — 2–4 weeks)','6 months','1 year'], ans:1, expl:'Window period = time between HIV infection and positive test. 4th generation tests (ELISA detecting p24 antigen + antibody): window period 2–4 weeks. 3rd generation antibody tests: 3 months. Testing recommended at 3 months after exposure.' },

  /* ═══ NCD ═══ */
  { topic:'ncd', q:'Hypertension is defined as BP ≥ (WHO/JNC-8):', opts:['120/80 mmHg','130/80 mmHg','140/90 mmHg','160/100 mmHg'], ans:2, expl:'WHO/JNC-8 define hypertension as BP ≥140/90 mmHg. Stages: Stage 1: 140–159/90–99; Stage 2: ≥160/≥100. ACC/AHA 2017 uses ≥130/80 but India follows WHO cutoffs.' },
  { topic:'ncd', q:'Fasting plasma glucose ≥ __ mg/dL on two occasions diagnoses Diabetes Mellitus:', opts:['100 mg/dL','110 mg/dL','126 mg/dL','200 mg/dL'], ans:2, expl:'WHO diabetes criteria: FPG ≥126 mg/dL (7.0 mmol/L) on two occasions. OR Random ≥200 with symptoms. OR HbA1c ≥6.5%. OR 2-h OGTT ≥200 mg/dL. Pre-diabetes (IFG): FPG 100–125 mg/dL.' },
  { topic:'ncd', q:'NPCDCS programme targets:', opts:['Communicable diseases only','Cancer, Diabetes, CVD, and Stroke','Mental health only','Nutritional disorders'], ans:1, expl:'NPCDCS = National Programme for Prevention and Control of Cancer, Diabetes, Cardiovascular diseases, and Stroke. NCD clinics at district hospitals/CHCs. Screening at HWCs (Health and Wellness Centres).' },
  { topic:'ncd', q:'Which test is used for cervical cancer screening at HWCs?', opts:['Pap smear','VIA (Visual Inspection with Acetic Acid)','Colposcopy','Biopsy'], ans:1, expl:'VIA (Visual Inspection with Acetic Acid) is primary screening method at HWCs/PHCs. Simple, low-cost, no lab needed. Aceto-white lesions = positive (suspect CIN/cancer). Followed by VILI, colposcopy, biopsy.' },

  /* ═══ NATIONAL PROGRAMS ═══ */
  { topic:'programs', q:'NRHM was launched in:', opts:['1999','2005','2013','2017'], ans:1, expl:'NRHM launched 12 April 2005. Expanded to NHM in 2013 (added NUHM — National Urban Health Mission). Key components: ASHA, RKS, Village Health & Nutrition Days (VHNDs), untied funds.' },
  { topic:'programs', q:'ASHA stands for:', opts:['Accredited Social Health Authority','Accredited Social Health Activist','Approved Social Health Assistant','Affiliated Social Health Agent'], ans:1, expl:'ASHA = Accredited Social Health Activist. One ASHA per 1000 population (or per village in hilly/tribal areas). Link between community and health system. Incentive-based payments.' },
  { topic:'programs', q:'Population norm for a Sub-Centre in plains is:', opts:['3,000','5,000','10,000','30,000'], ans:1, expl:'Sub-Centre: 5,000 (plains) / 3,000 (hilly/tribal). PHC: 30,000 / 20,000. CHC: 1,20,000 / 80,000. Each SC has 1 ANM + 1 MHW. IPHS 2022 revised SC norms to 3,000/1,500.' },
  { topic:'programs', q:'CHC (Community Health Centre) serves a population of:', opts:['30,000 / 20,000','50,000 / 30,000','1,20,000 / 80,000','5,00,000'], ans:2, expl:'CHC: 1,20,000 (plains) / 80,000 (hilly). Has 4 specialists (surgeon, physician, gynaecologist, paediatrician) + 30 beds. Designated FRU (First Referral Unit) for obstetric/newborn emergencies.' },
  { topic:'programs', q:'Janani Suraksha Yojana (JSY) provides cash incentive for:', opts:['Vaccination','Institutional delivery','Family planning','Nutrition'], ans:1, expl:'JSY (under NHM): Cash incentive for institutional delivery. BPL women in rural areas: ₹1,400. Urban: ₹1,000. ASHA gets ₹600 rural / ₹400 urban for facilitating the delivery. Aims to reduce MMR/IMR.' },
  { topic:'programs', q:'India was declared POLIO-FREE by WHO on:', opts:['12 January 2011','27 March 2014','15 August 2015','26 January 2013'], ans:1, expl:'India declared Polio-Free on 27 March 2014 (South-East Asia Region). Last wild poliovirus case in India: 13 January 2011 in Howrah, West Bengal. Achieved through Pulse Polio Immunisation (PPI) campaigns.' },
  { topic:'programs', q:'NIKSHAY portal is used for:', opts:['Malaria case tracking','TB patient tracking under NTEP','HIV patient management','Cancer screening'], ans:1, expl:'NIKSHAY = web-based TB case-based tracking system under NTEP. Every TB case must be notified on NIKSHAY (mandatory notification since 2012). Also manages Nikshay Poshan Yojana (₹500/month to TB patients).' },
  { topic:'programs', q:'RKSK (Rashtriya Kishor Swasthya Karyakram) targets adolescents aged:', opts:['5–14 years','10–19 years','15–25 years','12–18 years'], ans:1, expl:'RKSK targets 10–19 years adolescents. 6 components: Nutrition, Sexual & reproductive health, Non-communicable diseases, Mental health, Injuries & violence, Substance misuse. Delivery through AHD (Adolescent Health Days) and AFHC (Adolescent Friendly Health Clinics).' },
  { topic:'programs', q:'Ayushman Bharat PM-JAY provides health coverage of:', opts:['₹1 lakh/family/year','₹3 lakh/family/year','₹5 lakh/family/year','₹10 lakh/family/year'], ans:2, expl:'PM-JAY (Pradhan Mantri Jan Arogya Yojana) provides ₹5 lakh/family/year for secondary and tertiary hospitalisation. Covers bottom 40% families (10.74 crore families = ~50 crore beneficiaries). Cashless treatment at empanelled hospitals.' },
  { topic:'programs', q:'Health and Wellness Centres (HWCs) are upgraded from:', opts:['CHCs and PHCs only','Sub-Centres and PHCs','District Hospitals','All of the above'], ans:1, expl:'HWCs are upgraded Sub-Centres (SCs) and Primary Health Centres (PHCs) under Ayushman Bharat. They provide comprehensive primary healthcare including: NCD screening, MCH, mental health, oral health, and 12 types of essential services.' },
  { topic:'programs', q:'Village Health Sanitation and Nutrition Committee (VHSNC) meets every:', opts:['Daily','Weekly','Monthly','Quarterly'], ans:2, expl:'VHSNC meets monthly. Chaired by Ward member/Pradhan. Members include ASHA, ANM, AWW, school teacher. Functions: village health planning, monitoring, and overseeing Village Health & Nutrition Day (VHND).' },

  /* ═══ FIRST AID ═══ */
  { topic:'firstaid', q:'Correct compression-to-ventilation ratio in adult CPR (single rescuer) is:', opts:['15:2','30:2','15:1','5:1'], ans:1, expl:'AHA/ERC guidelines: Adult CPR = 30:2. Compress at 100–120/min, depth 5–6 cm, allow full recoil. For infants: 30:2 (single rescuer) or 15:2 (two-rescuer). Hands-only CPR if untrained.' },
  { topic:'firstaid', q:'The first step in managing an unconscious patient:', opts:['Give oxygen','Check breathing','Ensure scene safety and check responsiveness','Start CPR'], ans:2, expl:'DRSABC: Danger (scene safety) → Response (check responsiveness) → Shout for help → Airway (open) → Breathing (check ≤10 sec) → CPR. ALWAYS check safety first.' },
  { topic:'firstaid', q:'For conscious choking adult, first-line intervention is:', opts:['Finger sweep','5 back blows + 5 abdominal thrusts (Heimlich)','Chest compressions','Oxygen'], ans:1, expl:'Severe choking (cannot speak/cough/breathe): 5 firm back blows between shoulder blades, then 5 abdominal thrusts (Heimlich). Alternate until clear or unconscious. Pregnant/obese: chest thrusts.' },
  { topic:'firstaid', q:'For controlling bleeding wound, first step is:', opts:['Apply tourniquet','Apply DIRECT FIRM PRESSURE with clean cloth','Elevate limb','Give aspirin'], ans:1, expl:'Direct firm pressure for 10–15 minutes. Then elevate (if no fracture). Tourniquet only for life-threatening limb haemorrhage when pressure fails. Aspirin is CONTRAINDICATED (thins blood).' },
  { topic:'firstaid', q:'ORS for child with diarrhoea: WHO-ORS sachet is dissolved in:', opts:['200 mL water','500 mL water','1 litre water','2 litres water'], ans:2, expl:'WHO-ORS sachet dissolved in 1 litre clean water. Contains: 2.6g NaCl, 1.5g KCl, 2.9g trisodium citrate, 13.5g glucose. Osmolarity 245 mOsm/L (low-osmolarity ORS). Homemade: 6 tsp sugar + ½ tsp salt in 1 litre.' },
  { topic:'firstaid', q:'In a snakebite victim, correct first aid is:', opts:['Suck out venom with mouth','Apply tourniquet tightly','Immobilise limb, keep below heart level, rush to hospital','Cut and drain the wound'], ans:2, expl:'Snakebite first aid: Immobilise the bitten limb (splint like fracture), keep BELOW heart level to slow venom spread, remove tight clothing/jewellery, calm patient, rush to hospital for antivenom. Do NOT cut, suck, or apply tourniquet.' },
  { topic:'firstaid', q:'Correct position for a pregnant woman in shock:', opts:['Flat supine','Left lateral tilt (15–30°)','Right lateral tilt','Sitting upright'], ans:1, expl:'Pregnant women in shock: left lateral tilt (15–30°) to prevent aorto-caval compression by gravid uterus (supine hypotension syndrome). Also correct position: left lateral for seizures in pregnancy (eclampsia).' },

  /* ═══ ANATOMY ═══ */
  { topic:'anatomy', q:'Normal resting pulse rate in a healthy adult:', opts:['40–60 bpm','60–100 bpm','100–120 bpm','120–160 bpm'], ans:1, expl:'Normal adult resting pulse = 60–100 bpm. Bradycardia: <60 bpm; Tachycardia: >100 bpm. Newborn: 120–160 bpm; Infants: 80–140 bpm; Children 2–10y: 70–120 bpm.' },
  { topic:'anatomy', q:'Normal adult respiratory rate:', opts:['8–10 /min','12–20 /min','25–30 /min','35–40 /min'], ans:1, expl:'Normal adult RR = 12–20/min. Tachypnoea >20/min. Newborn: 40–60/min; Infants: 30–60/min. WHO IMCI: fast breathing in infant ≥60/min is danger sign for pneumonia.' },
  { topic:'anatomy', q:'Normal oral body temperature in adult:', opts:['35.0–36.0°C','36.5–37.5°C','37.5–38.5°C','38–39°C'], ans:1, expl:'Normal oral temperature = 36.5–37.5°C. Fever = >38°C (>100.4°F). Axillary = 0.5°C LOWER; Rectal = 0.5°C HIGHER than oral. Lowest at 4–6 am; Highest at 4–8 pm (diurnal variation).' },
  { topic:'anatomy', q:'The largest organ of the human body is:', opts:['Liver','Skin','Lung','Brain'], ans:1, expl:'Skin = largest organ (~1.5–2 sq m, ~3.5–10 kg). Functions: protection, temperature regulation, sensation, Vitamin D synthesis. Liver = largest INTERNAL organ. Layers: Epidermis, Dermis, Hypodermis.' },
  { topic:'anatomy', q:'Blood pressure is measured using:', opts:['Thermometer','Sphygmomanometer','Stethoscope','Spirometer'], ans:1, expl:'Sphygmomanometer (cuff + manometer) measures BP. Korotkoff sounds via stethoscope: K1=systolic (first sound), K5=diastolic (disappears). Normal adult BP <120/<80 mmHg.' },
  { topic:'anatomy', q:'The human heart has how many chambers?', opts:['2','3','4','6'], ans:2, expl:'4 chambers: 2 atria (RA+LA) + 2 ventricles (RV+LV). Right side: receives deoxygenated blood → lungs. Left side: receives oxygenated blood → body. LV has thickest wall (pumps to systemic circulation).' },
  { topic:'anatomy', q:'Haemoglobin level indicating anaemia in a pregnant woman (WHO):', opts:['<13 g/dL','<12 g/dL','<11 g/dL','<10 g/dL'], ans:2, expl:'WHO: Anaemia in pregnancy = Hb <11 g/dL (1st and 3rd trimester) or <10.5 g/dL (2nd trimester). In non-pregnant women: <12 g/dL; Children <5y: <11 g/dL; Men: <13 g/dL.' },
  { topic:'anatomy', q:'Normal blood pressure in adults:', opts:['<100/<60 mmHg','<120/<80 mmHg','<130/<90 mmHg','<140/<90 mmHg'], ans:1, expl:'Normal BP <120/<80 mmHg. Elevated: 120–129/<80. Stage 1 HTN: 130–139/80–89. Stage 2 HTN: ≥140/≥90. Hypotension: systolic <90 mmHg.' },
  { topic:'anatomy', q:'The universal blood donor group is:', opts:['A positive','B negative','O negative','AB positive'], ans:2, expl:'O negative = Universal DONOR (can donate to all blood groups). AB positive = Universal RECIPIENT (can receive all groups). In emergencies, O-negative packed red cells are given when blood group unknown.' },

  /* ═══ ENVIRONMENT ═══ */
  { topic:'environment', q:'WHO standard for coliforms in drinking water:', opts:['10/100 mL','5/100 mL','Zero (0) per 100 mL','1/100 mL'], ans:2, expl:'WHO: ZERO coliforms per 100 mL in drinking water. Coliforms indicate faecal contamination. Residual chlorine at point of use: 0.2–0.5 mg/L. Chlorination is primary water disinfection method.' },
  { topic:'environment', q:'Biomedical waste: YELLOW bag contains:', opts:['Sharps (needles, blades)','Anatomical waste, soiled items, expired medicines','Glass/broken vials','Recyclable plastics without blood'], ans:1, expl:'BMW (2016 Rules) colour coding: Yellow = anatomical waste, soiled/contaminated waste, expired medicines → Incineration/deep burial. Red = contaminated recyclable (IV sets, syringes without needle). White = sharps. Blue = glass/vials.' },
  { topic:'environment', q:'BMW: How should used needles/sharps be handled?', opts:['Recap and throw in regular bin','Use hub-cutter/needle destroyer at point of use','Bend the needle with fingers','Soak in bleach solution'], ans:1, expl:'NEVER recap used needles. Use hub-cutter or needle destroyer at point of use immediately after use. Prevents needle-stick injuries to health workers. Sharps go in white puncture-proof container.' },
  { topic:'environment', q:'Swachh Bharat Mission was launched on:', opts:['2 October 2014','15 August 2014','26 January 2015','2 January 2015'], ans:0, expl:'SBM launched 2 October 2014 (Gandhi Jayanti, Mahatma Gandhi\'s 145th birth anniversary). Goal: Open Defecation Free (ODF) India. SBM Phase 2: ODF+ and ODF++ (solid/liquid waste management).' },
  { topic:'environment', q:'Fluorosis is caused by excess __ in drinking water:', opts:['Arsenic','Nitrate','Fluoride','Lead'], ans:2, expl:'Excess fluoride (>1.5 mg/L) in drinking water → Fluorosis: Dental fluorosis (mottled teeth), Skeletal fluorosis (bone deformities). Endemic in Rajasthan, Gujarat, Andhra Pradesh, UP. Defluoridation methods: Nalgonda technique, activated alumina.' },

  /* ═══ STATS ═══ */
  { topic:'stats', q:'Infant Mortality Rate (IMR) is:', opts:['Deaths <5y per 1000 live births','Deaths <1y per 1000 live births','Deaths <28 days per 1000 live births','Total deaths per 1000 population'], ans:1, expl:'IMR = deaths <1 year per 1000 live births in same year. India IMR (SRS 2020): 28. NMR (neonatal) = 20. U5MR = 32. MMR = 97 (per 1,00,000 live births, SRS 2018–20).' },
  { topic:'stats', q:'Herd immunity threshold for measles (approx.):', opts:['50%','70%','90–95%','99%'], ans:2, expl:'Measles R0 = 12–18, so herd immunity threshold = 92–95%. When this % is immune, chains of transmission break and unvaccinated people are also protected. This is why high MR vaccine coverage is critical.' },
  { topic:'stats', q:'A cohort study measures:', opts:['Odds Ratio (OR)','Relative Risk (RR)','Prevalence','Positive predictive value'], ans:1, expl:'Cohort study follows exposed vs unexposed groups forward in time → measures Relative Risk (RR). Case-control study → Odds Ratio (OR). Cross-sectional → Prevalence. RCT → NNT, RRR.' },
  { topic:'stats', q:'Sensitivity of a test measures:', opts:['True negative rate','True positive rate (correctly identifies those WITH disease)','Proportion of positives that are true positives','Overall accuracy'], ans:1, expl:'Sensitivity = TP/(TP+FN) = ability to detect DISEASE. High sensitivity → good screening test (SnNOut). Specificity = TN/(TN+FP) = correctly identifies those WITHOUT disease (SpPIn = Specific, Positive result rules IN disease).' },
  { topic:'stats', q:'India\'s Total Fertility Rate (TFR) as per NFHS-5 (2019–21) is approximately:', opts:['1.5','2.0','2.5','3.0'], ans:1, expl:'India\'s TFR = 2.0 (NFHS-5). This is BELOW replacement level (2.1). Shows significant decline from NFHS-4 (2.2). States with highest TFR: Bihar (3.0), Meghalaya (2.9). Lowest: Sikkim, Goa (<1.5).' },

  /* ═══ DRUGS ═══ */
  { topic:'drug', q:'Route of administration for BCG vaccine:', opts:['Intramuscular','Subcutaneous','Intradermal','Oral'], ans:2, expl:'BCG = Intradermal (ID), 0.1 mL, left upper arm. Correct technique produces a raised bleb (wheal). A scar forms in 2–6 weeks indicating successful vaccination.' },
  { topic:'drug', q:'Oxytocin in obstetrics is used for:', opts:['Pain relief','Induction of labour + prevention of PPH (AMTSL)','Prevention of eclampsia','Antibiotic for sepsis'], ans:1, expl:'Oxytocin: Induction/augmentation of labour (IV drip), AMTSL (10 IU IM after baby delivery to prevent PPH). Magnesium sulphate = drug for eclampsia. Misoprostol = alternative when oxytocin unavailable.' },
  { topic:'drug', q:'Magnesium sulphate antidote is:', opts:['Atropine','Calcium gluconate','Naloxone','Adrenaline'], ans:1, expl:'Calcium gluconate = antidote for Magnesium sulphate toxicity. Signs of MgSO4 toxicity: loss of patellar reflexes (first sign), respiratory depression, cardiac arrest. Dose: 10 mL of 10% calcium gluconate IV slowly.' },
  { topic:'drug', q:'Chloroquine is first-line treatment for:', opts:['P. falciparum malaria','P. vivax malaria','Dengue fever','Typhoid'], ans:1, expl:'Chloroquine (CQ) = first-line for P. vivax in India (25 mg/kg over 3 days) + Primaquine for radical cure. For P. falciparum: ACT (Artesunate + SP) + Primaquine. DO NOT use CQ for P. falciparum (resistance).' },
  { topic:'drug', q:'Zinc is given alongside ORS in childhood diarrhoea for how many days?', opts:['5 days','7 days','14 days','21 days'], ans:2, expl:'Zinc 20 mg/day for 14 days (children >6 months) or 10 mg/day (children <6 months). Reduces duration and severity of diarrhoeal episodes and prevents recurrence for 2–3 months.' },
  { topic:'drug', q:'Which drug is CONTRAINDICATED in pregnancy due to risk of teeth discolouration in foetus?', opts:['Amoxicillin','Tetracycline','Metronidazole','Paracetamol'], ans:1, expl:'Tetracycline is contraindicated in pregnancy and children <8 years. It deposits in developing teeth and bones causing yellow-brown discolouration and enamel hypoplasia. Safe alternatives: Amoxicillin, Erythromycin.' },

  /* ═══ MCH — extra ═══ */
  { topic:'mch', q:'Maternal Mortality Ratio (MMR) is expressed per:', opts:['1,000 live births','10,000 live births','1,00,000 live births','1,000 total births'], ans:2, expl:'MMR = maternal deaths per 1,00,000 live births in the same period. India MMR (SRS 2018–20) = 97. SDG target: <70 by 2030. India target: <100 by 2020 (achieved).' },
  { topic:'mch', q:'Which of the following is NOT a direct cause of maternal death?', opts:['Eclampsia','PPH','Anaemia (indirect cause)','Sepsis'], ans:2, expl:'Direct causes: PPH, eclampsia/pre-eclampsia, sepsis, obstructed labour, unsafe abortion. Indirect causes: anaemia, heart disease, hepatitis, malaria. Anaemia is the most common INDIRECT cause of MMR in India.' },
  { topic:'mch', q:'Eclampsia is defined as:', opts:['High BP only in pregnancy','Pre-eclampsia + convulsions','Oedema + proteinuria','BP >130/90 in pregnancy'], ans:1, expl:'Eclampsia = pre-eclampsia (HTN + proteinuria after 20 weeks) PLUS grand mal convulsions not explained by other cause. Life-threatening emergency. Mx: MgSO4 (Pritchard/Zuspan regimen), antihypertensives, urgent delivery.' },
  { topic:'mch', q:'The "golden hour" of the newborn refers to:', opts:['First hour of ANC','First hour after birth for essential newborn care','Hour 0–1 of labour','First 60 min of resuscitation'], ans:1, expl:'Golden hour = first 60 minutes after birth. Key actions: immediate drying, warmth, delayed cord clamping (1–3 min), breastfeeding initiation, skin-to-skin contact. Prevents hypothermia, promotes bonding and lactation.' },
  { topic:'mch', q:'Under JSSK, free diet is provided to the mother for how many days after normal delivery?', opts:['1 day','3 days','7 days','Until discharge'], ans:1, expl:'JSSK entitles free diet for 3 days after normal delivery and 7 days after Caesarean section at government health facilities. Also includes free drugs, diagnostics, blood transfusion, and referral transport.' },
  { topic:'mch', q:'Preterm birth is defined as delivery before:', opts:['34 weeks gestation','37 weeks gestation','36 weeks gestation','38 weeks gestation'], ans:1, expl:'Preterm = birth before 37 completed weeks. Extremely preterm: <28 weeks; Very preterm: 28–32 weeks; Moderate/late preterm: 32–37 weeks. Most common cause of neonatal mortality globally.' },
  { topic:'mch', q:'IFA supplementation during pregnancy is given for a minimum of:', opts:['90 days','120 days','180 days','270 days'], ans:2, expl:'Minimum 180 IFA tablets (1 tablet/day) during pregnancy. Iron 100 mg + Folic acid 0.5 mg. Should start as early as possible, ideally from first ANC. Prevents iron deficiency anaemia and reduces risk of LBW.' },
  { topic:'mch', q:'The most common presentation of foetus at term is:', opts:['Breech','Transverse lie','Vertex (head down)','Face presentation'], ans:2, expl:'Vertex (cephalic/head-down) presentation occurs in ~96% of term pregnancies. Occiput-anterior position is most common. Breech (3–4%) and transverse (<1%) are malpresentations requiring obstetric management.' },
  { topic:'mch', q:'Congenital Rubella Syndrome (CRS) classically causes:', opts:['Cleft palate only','Cataract, deafness, heart defect (PDA/VSD)','Microcephaly only','Spina bifida'], ans:1, expl:'CRS triad: Cataract (eye), sensorineural Deafness (ear), Congenital Heart Defect (PDA, VSD, pulmonary stenosis). Prevention: MR vaccine. Risk highest if rubella infection in 1st trimester (1–12 weeks).' },
  { topic:'mch', q:'Which vitamin supplement is given to the mother within 6 weeks of delivery?', opts:['Vitamin D 60,000 IU','Vitamin A 2,00,000 IU','Vitamin C 500 mg','Vitamin B12 1000 mcg'], ans:1, expl:'Vitamin A 2,00,000 IU given to the mother within 6 weeks of delivery to replenish stores lost in milk production and reduce maternal morbidity. NOT given in pregnancy (teratogenic in high doses).' },
  { topic:'mch', q:'ASHA is eligible for incentive under JSY when she facilitates:', opts:['Any delivery','Institutional delivery of a BPL woman','Home delivery only','Caesarean section only'], ans:1, expl:'ASHA gets ₹600 (rural) / ₹400 (urban) per institutional delivery she facilitates. She must escort the woman, stay during delivery, and assist in registration. BPL/SC/ST women are primary beneficiaries.' },
  { topic:'mch', q:'Active Management of Third Stage of Labour (AMTSL) includes:', opts:['Waiting for placenta to deliver spontaneously','Oxytocin 10 IU IM + controlled cord traction + uterine massage','Only uterine massage','Only controlled cord traction'], ans:1, expl:'AMTSL: (1) Oxytocin 10 IU IM within 1 min of baby delivery, (2) Controlled cord traction (Brandt-Andrews), (3) Uterine massage after placenta delivery. Reduces PPH by 60%. WHO 2012 simplified to oxytocin alone as minimum.' },
  { topic:'mch', q:'Which test detects neural tube defects prenatally?', opts:['Amniocentesis for AFP','Glucose tolerance test','TORCH screen','Thyroid function test'], ans:0, expl:'Alpha-fetoprotein (AFP) in amniotic fluid (amniocentesis) or maternal serum screening. Elevated AFP = open NTD (spina bifida, anencephaly). NTDs prevented by folic acid 400 mcg/day periconceptionally.' },
  { topic:'mch', q:'Symphysio-Fundal Height (SFH) at 28 weeks of pregnancy is approximately:', opts:['20 cm','24 cm','28 cm','32 cm'], ans:2, expl:'SFH in cm ≈ gestational age in weeks (after 20 weeks). At 28 weeks = ~28 cm. Deviation >2 cm above or below expected = needs investigation (IUGR, polyhydramnios, multiple pregnancy). Measured with tape from pubic symphysis.' },
  { topic:'mch', q:'Intrapartum care: foetal heart rate is normally:', opts:['80–100 bpm','100–120 bpm','110–160 bpm','160–200 bpm'], ans:2, expl:'Normal FHR = 110–160 bpm. Bradycardia <110 bpm or tachycardia >160 bpm = foetal distress. Checked every 30 min in active first stage, every 5 min in second stage. Auscultated with Pinard fetoscope or Doppler.' },

  /* ═══ FAMILY PLANNING — extra ═══ */
  { topic:'fp', q:'No-scalpel vasectomy (NSV) differs from conventional vasectomy in that it:', opts:['Uses general anaesthesia','Uses a special puncture technique with no skin incision','Takes longer','Has higher failure rate'], ans:1, expl:'NSV uses a sharp curved clamp to puncture the scrotal skin (no knife/scalpel), grasp vas deferens and occlude it. Benefits: fewer complications (haematoma, infection), faster procedure, quicker recovery. WHO promotes NSV.' },
  { topic:'fp', q:'Interval IUCD insertion is done:', opts:['Immediately after delivery','Within 10 min of placenta delivery','≥6 weeks after delivery (postpartum) or anytime in non-pregnant woman','Only at next menstruation'], ans:2, expl:'Interval IUCD = inserted ≥6 weeks postpartum (after uterus involuted) or at any time in non-pregnant women (if sure not pregnant). PPIUCD = within 10 min of placenta. PAIUCD = within 12 days post-abortion.' },
  { topic:'fp', q:'Failure rate of male condom in "perfect use" is approximately:', opts:['0%','2%','3%','15%'], ans:1, expl:'Male condom perfect use failure rate = 2% (2 pregnancies per 100 women-years). Typical use = 13–15%. Consistent correct use (CCU) is key. Only method that also prevents STI/HIV transmission.' },
  { topic:'fp', q:'OCP (combined oral contraceptive pill) is CONTRAINDICATED in:', opts:['Nulliparous women','Women with history of DVT/stroke/breast cancer','Women >18 years','Non-smokers'], ans:1, expl:'COC absolute contraindications (WHO MEC Cat 4): personal history of DVT/PE, stroke, ischaemic heart disease, breast cancer, liver tumours, migraine with aura, smokers >35 years, uncontrolled hypertension, breastfeeding <6 weeks.' },
  { topic:'fp', q:'Sterilisation (tubectomy) should ideally be performed:', opts:['During menstruation','Immediately postpartum (within 7 days) or interval (after 6 weeks)','Only with husband\'s consent','Only above age 35'], ans:1, expl:'Postpartum tubectomy: within 48 hours (minilaparotomy — easy access to tubes, uterus enlarged) or interval: 6 weeks postpartum or later (laparoscopic/minilaparotomy). Written informed consent of the woman is mandatory (not husband).' },
  { topic:'fp', q:'The contraceptive method with the LOWEST Pearl Index (most effective reversible method) is:', opts:['OCP','Male condom','Copper IUCD','DMPA injectable'], ans:2, expl:'Copper IUCD (Cu-T 380A) has Pearl Index 0.5–0.8 — most effective reversible method. Vasectomy/tubectomy (permanent) have even lower rates. DMPA 0.3; OCP 0.1–1; Condom 2–15.' },
  { topic:'fp', q:'Under the Antara Programme, DMPA injectable is provided at:', opts:['Pharmacies only','Sub-centres and above (given by ANM/MHW)','Private hospitals only','Anganwadi centres only'], ans:1, expl:'Antara Programme (2017) provides DMPA (150 mg/3 months) through public health system at sub-centres, PHCs, CHCs, district hospitals. Administered by trained ANM/MHW as IM injection. Home visits also planned.' },
  { topic:'fp', q:'What is the "basket of contraceptives" approach in India?', opts:['Providing only permanent methods','Offering a wide range of spacing and limiting methods to meet diverse client needs','Using only oral pills','Government procurement of condoms only'], ans:1, expl:'Basket of contraceptives = offering all contraceptive options: condom, OCP, ECP, IUCD, DMPA (Antara), Chhaya (centchroman), PPIUCD, tubectomy, vasectomy. Allows clients to choose based on preference, health status, parity.' },
  { topic:'fp', q:'India\'s Total Fertility Rate (TFR) target to achieve replacement-level fertility is:', opts:['1.5','2.0','2.1','2.5'], ans:2, expl:'Replacement-level fertility = TFR of 2.1 (slightly above 2.0 to account for child mortality). India achieved TFR = 2.0 (NFHS-5), which is BELOW replacement level. SDG target = 2.1 by 2025.' },

  /* ═══ IMMUNIZATION — extra ═══ */
  { topic:'immunize', q:'The vaccine that uses the "fractional dose" (0.1 mL intradermal) in India\'s UIP is:', opts:['OPV','BCG','fIPV (fractional IPV)','PCV'], ans:2, expl:'fIPV = fractional-dose Inactivated Polio Vaccine given as 0.1 mL intradermal (not 0.5 mL IM). Given at 6 and 14 weeks under UIP since 2015-16. Cost-effective and immunogenic. BCG is also ID but full 0.1 mL dose.' },
  { topic:'immunize', q:'Hepatitis B vaccine at birth (HepB-0) should be given within:', opts:['1 hour','6 hours','24 hours','48 hours'], ans:2, expl:'HepB-0 (birth dose) should be given within 24 hours of birth, ideally within 12 hours. Critical to prevent perinatal (mother-to-child) transmission. Efficacy >95% if given within 24 hours + HBIg if mother HBsAg positive.' },
  { topic:'immunize', q:'Which vaccines are "freeze-sensitive" and should NEVER be frozen?', opts:['BCG and OPV','OPV only','DPT, HepB, Pentavalent, TT/Td','BCG only'], ans:2, expl:'Freeze-sensitive vaccines (must be stored at +2°C to +8°C, NEVER below 0°C): DPT, Hepatitis B, Pentavalent, TT/Td, fIPV. Freezing destroys these vaccines. OPV and varicella need to be FROZEN (-15° to -25°C).' },
  { topic:'immunize', q:'Shake test is used to check for:', opts:['Potency of oral vaccines','Freeze damage in freeze-sensitive vaccines','Heat damage in OPV','Bacterial contamination'], ans:1, expl:'Shake test: if a vial has been frozen and thawed, particles settle SLOWLY (clear supernatant = frozen-damaged). Undamaged vials remain uniformly turbid after shaking. Used for DPT, HepB, TT, Pentavalent.' },
  { topic:'immunize', q:'Adverse Event Following Immunisation (AEFI) with BCG vaccine includes:', opts:['Anaphylaxis (common)','Keloid scar at injection site','High fever >40°C','Encephalitis'], ans:1, expl:'Normal AEFI for BCG: redness, papule at 2 weeks → ulcer → scar by 6–12 weeks. Keloid formation (especially in dark-skinned people). Rare severe: BCG osteomyelitis, disseminated BCG (in immunocompromised). Anaphylaxis is rare.' },
  { topic:'immunize', q:'Polio eradication strategy includes all EXCEPT:', opts:['Pulse Polio Immunisation (PPI)','Routine immunisation','Acute Flaccid Paralysis (AFP) surveillance','Treating all AFP cases with vaccines'], ans:3, expl:'Polio eradication components: (1) High routine OPV/IPV coverage, (2) Supplementary Immunisation Activities (SIA/PPI), (3) AFP surveillance + stool specimen collection, (4) Mop-up campaigns. There is no treatment — only prevention.' },
  { topic:'immunize', q:'JE (Japanese Encephalitis) vaccine in India is given in:', opts:['All states at 9 months','Only endemic districts at 9–12 months + 16–24 months','All children at birth','Only during outbreak'], ans:1, expl:'JE vaccine (SA 14-14-2 live attenuated) given in JE-endemic districts only: at 9–12 months and 16–24 months. Endemic states: UP, Bihar, West Bengal, Assam, Karnataka, Tamil Nadu, Kerala, Goa, Maharashtra.' },
  { topic:'immunize', q:'PCV (Pneumococcal Conjugate Vaccine) protects against:', opts:['Pertussis','Streptococcus pneumoniae (pneumococcal disease)','Rotavirus','Meningococcus'], ans:1, expl:'PCV (13-valent) protects against Streptococcus pneumoniae — causes pneumonia (leading killer of children <5), meningitis, septicaemia. Given at 6, 10, 14 weeks + booster at 9 months under UIP in India (phased rollout from 2017).' },
  { topic:'immunize', q:'The "cold chain" in immunisation is maintained to:', opts:['Keep vaccines frozen always','Maintain optimal temperature from manufacture to administration to preserve vaccine potency','Store vaccines at room temperature','Prevent AEFIs'], ans:1, expl:'Cold chain = system of refrigerated storage and transport to maintain vaccines at correct temperatures from manufacturer to point of use. Breaks in cold chain destroy vaccines. Key: ILR (+2°C–+8°C), deep freezer (-15° to -25°C for OPV), vaccine carriers for outreach.' },
  { topic:'immunize', q:'Supplementary Immunisation Activity (SIA) in India targets:', opts:['Only unvaccinated children','All children in target age group regardless of vaccination status','Only adults','Only high-risk groups'], ans:1, expl:'SIA (like Pulse Polio, MR campaigns) targets ALL children in the age group (0–5 years for polio; 9 months–15 years for MR campaign) regardless of prior vaccination status. Aim: achieve very high coverage to interrupt transmission.' },
  { topic:'immunize', q:'MNT (Maternal and Neonatal Tetanus) elimination criteria is:', opts:['Zero NNT cases','<1 NNT case per 1000 live births in every district','<1 NNT case per 100 live births nationally','100% TT coverage'], ans:1, expl:'MNT elimination = <1 case of NNT per 1000 live births at district level. India achieved MNT elimination in 2015. Prevention: 2 doses TT/Td to all pregnant women not previously immunised, clean delivery, cord care.' },

  /* ═══ NUTRITION — extra ═══ */
  { topic:'nutrition', q:'RUTF (Ready-to-Use Therapeutic Food) used in SAM treatment is:', opts:['A liquid formula','A peanut-based paste with milk, sugar, oil, vitamins/minerals (F-100 equivalent)','A vitamin tablet','Normal home food'], ans:1, expl:'RUTF (Plumpy\'nut) = peanut paste + skimmed milk powder + sugar + vegetable oil + vitamins/minerals. Energy 500 kcal/100g. Used for community management of SAM (CMAM). No water added — reduces contamination risk.' },
  { topic:'nutrition', q:'F-75 and F-100 therapeutic milk formulas are used for SAM children:', opts:['F-75 first (stabilisation phase), then F-100 (rehabilitation phase)','F-100 first, then F-75','F-75 only','F-100 throughout'], ans:0, expl:'SAM inpatient management (NRC): Phase 1 (Stabilisation): F-75 (75 kcal/100 mL) — treats hypoglycaemia, hypothermia, infections slowly to avoid refeeding syndrome. Phase 2 (Rehabilitation): F-100 (100 kcal/100 mL) for rapid weight gain.' },
  { topic:'nutrition', q:'Mid-upper arm circumference (MUAC) is measured on which arm?', opts:['Dominant arm (usually right)','Left arm','Either arm','Both arms averaged'], ans:1, expl:'MUAC measured on LEFT upper arm at the midpoint between acromion (shoulder) and olecranon (elbow tip). Measured with non-stretchable MUAC tape (red-yellow-green). Used for children 6–59 months and pregnant women.' },
  { topic:'nutrition', q:'Beriberi is caused by deficiency of:', opts:['Vitamin B2 (Riboflavin)','Vitamin B1 (Thiamine)','Vitamin B6 (Pyridoxine)','Vitamin B12'], ans:1, expl:'Beriberi = Vitamin B1 (Thiamine) deficiency. Wet beriberi = cardiovascular (oedema, cardiomegaly, heart failure). Dry beriberi = peripheral neuropathy. Wernicke\'s encephalopathy = thiamine deficiency in alcoholics.' },
  { topic:'nutrition', q:'Night blindness is the earliest sign of deficiency of:', opts:['Vitamin C','Vitamin D','Vitamin A','Iron'], ans:2, expl:'Night blindness (nyctalopia) = inability to see in dim light = earliest/mildest stage of VAD (Xerophthalmia grade XN). Bitot\'s spots (X1B) = foamy white deposits on conjunctiva = pathognomonic of VAD. Keratomalacia = most severe.' },
  { topic:'nutrition', q:'Iodised salt for consumption should contain iodine at:', opts:['5 ppm','15 ppm at production level','30 ppm at production (≥15 ppm at retail)','50 ppm'], ans:2, expl:'FSSAI (Food Safety & Standards Authority of India) mandates iodine in salt: ≥30 ppm at production level and ≥15 ppm at retail/consumer level (accounting for losses in transit/cooking). Universal Salt Iodisation (USI) policy.' },
  { topic:'nutrition', q:'POSHAN Abhiyaan (National Nutrition Mission) was launched in:', opts:['2013','2016','2018','2020'], ans:2, expl:'POSHAN Abhiyaan launched 8 March 2018 (International Women\'s Day) by PM Modi. Target: reduce stunting, undernutrition, anaemia (children/women) by 2%/year; low birth weight by 2%/year. Uses technology, community mobilisation (Poshan Maah = September).' },
  { topic:'nutrition', q:'The "first 1000 days" concept refers to:', opts:['First 1000 days of life only','Period from conception to the child\'s 2nd birthday','First 1000 days of school','Pregnancy only'], ans:1, expl:'First 1000 days = 270 days of pregnancy + 730 days (2 years) after birth = total ~1000 days. Critical window for brain development, organ formation, immune system, nutrition programming. Interventions here have lifelong impact.' },
  { topic:'nutrition', q:'Vitamin D is synthesised in the body through:', opts:['Dietary intake only','Sunlight (UV-B) exposure on skin converting 7-dehydrocholesterol to Vitamin D3','Exercise','Iron absorption'], ans:1, expl:'Vitamin D3 (cholecalciferol) synthesised in skin by UVB radiation (290–315 nm) converting 7-dehydrocholesterol → pre-Vit D3 → Vit D3. Liver converts to 25-OH-Vit D (storage form); kidneys to 1,25-(OH)2-Vit D (active calcitriol).' },
  { topic:'nutrition', q:'WHO IMCI danger signs for a sick child under 5 include all EXCEPT:', opts:['Cannot drink or breastfeed','Convulsions','Mild diarrhoea for 1 day','Unconscious or lethargic'], ans:2, expl:'IMCI General Danger Signs (classify as EMERGENCY): (1) Cannot drink/breastfeed, (2) Vomits everything, (3) Convulsions now or recently, (4) Lethargy/unconsciousness. Mild diarrhoea for 1 day is NOT a general danger sign (no dehydration).' },
  { topic:'nutrition', q:'The recommended protein intake for a pregnant woman (additional) per day is:', opts:['5 g/day','23 g/day','50 g/day','100 g/day'], ans:1, expl:'ICMR 2020: Additional protein in pregnancy = +23 g/day (2nd trimester: +14g; 3rd trimester: +22.5g; rounded to 23g). Total recommended = 65–75 g/day. Lactating mothers: +18 g/day additional protein.' },

  /* ═══ COMMUNICABLE DISEASES — extra ═══ */
  { topic:'diseases', q:'The causative organism of leprosy (Hansen\'s disease) is:', opts:['Mycobacterium tuberculosis','Mycobacterium leprae','Treponema pallidum','Neisseria gonorrhoeae'], ans:1, expl:'Mycobacterium leprae — acid-fast bacillus, obligate intracellular parasite (grows only in cool body areas: skin, peripheral nerves, anterior eye, upper respiratory tract). Cannot be cultured in vitro. Grows in armadillo footpads.' },
  { topic:'diseases', q:'MDT (Multi-Drug Therapy) for paucibacillary (PB) leprosy consists of:', opts:['Rifampicin + Dapsone for 6 months','Rifampicin + Dapsone + Clofazimine for 12 months','Dapsone alone for 2 years','Rifampicin alone for 1 year'], ans:0, expl:'PB-MDT (1–5 skin patches, no bacilli): Rifampicin 600 mg monthly (supervised) + Dapsone 100 mg daily × 6 months. MB-MDT (>5 patches, bacilli positive): Rifampicin + Dapsone + Clofazimine × 12 months.' },
  { topic:'diseases', q:'The blood film examination for malaria should be taken at:', opts:['Any time','During fever spike (best time)','Only in the morning','Only at night (for W. bancrofti)'], ans:1, expl:'Malaria blood smear: best taken DURING fever spike when parasitaemia is highest. Thick film (more sensitive, detects low parasitaemia); Thin film (species identification). RDT (rapid diagnostic test) available at community level.' },
  { topic:'diseases', q:'ACT (Artemisinin Combination Therapy) is used to treat:', opts:['P. vivax malaria','P. falciparum malaria','Dengue','Kala-azar'], ans:1, expl:'ACT = Artesunate + Sulfadoxine-Pyrimethamine (AS+SP) for uncomplicated P. falciparum. Artemether-Lumefantrine (AL) also used. For severe P. falciparum: IV Artesunate. Primaquine 0.75 mg/kg given on Day 2 to kill gametocytes.' },
  { topic:'diseases', q:'Widal test is used to diagnose:', opts:['Malaria','Typhoid fever (Salmonella typhi)','Dengue','Cholera'], ans:1, expl:'Widal test = agglutination test detecting antibodies against Salmonella typhi O and H antigens. Significant titre: O ≥1:80 or H ≥1:160 (4-fold rise in paired sera). NOT gold standard (false positives common). Gold standard = blood culture.' },
  { topic:'diseases', q:'Incubation period of cholera is:', opts:['1–14 days (usually few hours to 5 days)','14–21 days','1–3 months','6 months'], ans:0, expl:'Cholera incubation = few hours to 5 days (WHO: 1–14 days). Short incubation means outbreaks spread rapidly. V. cholerae produces cholera toxin → massive watery diarrhoea. Case-fatality rate: 25–50% untreated; <1% with ORS.' },
  { topic:'diseases', q:'HIV testing protocol in India uses:', opts:['ELISA alone','3 rapid tests with different antigens (RTK1, RTK2, RTK3)','Western blot only','PCR alone'], ans:1, expl:'India NACO HIV testing: 3 rapid tests on 3 different antigens/principles. If all 3 positive = HIV positive. If 2 positive and 1 negative = inconclusive (repeat in 14 days). ICTC (Integrated Counselling & Testing Centre) provides free testing.' },
  { topic:'diseases', q:'Filariasis (elephantiasis) microfilariae in blood show nocturnal periodicity, meaning peak microfilaraemia is:', opts:['During daytime (6 am–6 pm)','At night (10 pm–4 am)','Throughout the day','Only during fever'], ans:1, expl:'W. bancrofti microfilariae show nocturnal periodicity — peak in peripheral blood at 10 pm–4 am (coinciding with peak biting activity of Culex mosquito). Blood sample for microfilaria MUST be collected at night. Diagnosis: thick blood film, ICT.' },
  { topic:'diseases', q:'DOTS for TB means the patient takes medicines:', opts:['At home alone','Under direct observation of a health worker or treatment supporter','Via injection only','In hospital only'], ans:1, expl:'DOTS = Direct Observation: every dose (or at least first dose of intensive phase) taken under direct observation of provider/treatment supporter. Prevents drug resistance from irregular treatment. 99% of doses observed in intensive phase in NTEP.' },
  { topic:'diseases', q:'Drug Resistant TB (MDR-TB) is defined as resistance to:', opts:['Isoniazid alone','Rifampicin alone','Both Rifampicin AND Isoniazid (two most important first-line drugs)','All first-line drugs'], ans:2, expl:'MDR-TB = resistance to at least Rifampicin + Isoniazid simultaneously. XDR-TB = MDR + resistance to any fluoroquinolone + at least one injectable second-line drug. Pre-XDR = MDR + fluoroquinolone resistance. Diagnosed by CBNAAT/LPA.' },

  /* ═══ NCD — extra ═══ */
  { topic:'ncd', q:'BMI (Body Mass Index) is calculated as:', opts:['Weight (kg) / Height (m)','Weight (kg) / Height² (m²)','Height (m) / Weight (kg)','Weight (kg) × Height (m)'], ans:1, expl:'BMI = Weight (kg) / Height² (m²). Classification (WHO Asian): Underweight <18.5; Normal 18.5–22.9; Overweight 23–24.9; Obese Class I 25–29.9; Obese Class II ≥30. India uses Asian cut-offs (action point at BMI 23).' },
  { topic:'ncd', q:'The leading risk factor for oral cancer in India is:', opts:['Alcohol alone','Tobacco (smoking + smokeless) — responsible for ~90% of oral cancers','Sun exposure','HPV infection'], ans:1, expl:'Tobacco = leading cause of oral cancer in India (90%+). Smokeless tobacco (gutka, khaini, paan masala) is especially common. Other risk factors: alcohol, HPV 16/18, poor oral hygiene, sharp teeth. India has highest oral cancer burden globally.' },
  { topic:'ncd', q:'NPCDCS (National Programme for Prevention and Control of Cancer, Diabetes, CVD and Stroke) provides free screening at:', opts:['District hospitals only','Health and Wellness Centres (HWCs) and above','Private hospitals','ASHA level'], ans:1, expl:'NPCDCS: NCD clinics at CHC and DH level; population-based screening at HWCs (SC and PHC level). Screening for: HTN (BP), DM (blood glucose), oral cancer (oral exam), breast cancer (CBE), cervical cancer (VIA). Population ≥30 years screened.' },
  { topic:'ncd', q:'HPV vaccine for cervical cancer prevention is most effective when given:', opts:['After first sexual intercourse','To girls 9–14 years (before sexual debut)','After cervical cancer diagnosis','To all women ≥35 years'], ans:1, expl:'HPV vaccine most effective BEFORE first sexual exposure (before HPV infection). WHO recommends primary target: girls 9–14 years. India launched Gardasil (4-valent: HPV 6,11,16,18) under Universal Immunisation Programme in 2023. 2-dose schedule.' },
  { topic:'ncd', q:'Blood glucose level for diagnosing hypoglycaemia in a newborn is:', opts:['<4 mmol/L','<2.6 mmol/L (<47 mg/dL)','<6 mmol/L','<1 mmol/L'], ans:1, expl:'Neonatal hypoglycaemia = blood glucose <2.6 mmol/L (47 mg/dL). Risk factors: LBW, prematurity, diabetic mother, birth asphyxia. Clinical: jitteriness, lethargy, apnoea, seizures. Treatment: breastfeeding or IV glucose.' },
  { topic:'ncd', q:'The AUDIT tool is used to screen for:', opts:['Depression','Tobacco dependence','Alcohol use disorders','Drug dependence'], ans:2, expl:'AUDIT (Alcohol Use Disorders Identification Test) = 10-question WHO screening tool for hazardous/harmful alcohol use. Score 8–15: harmful use; 16–19: harmful dependence; ≥20: severe dependence. AUDIT-C is 3-question shortened version.' },
  { topic:'ncd', q:'Which cancer is the most common cancer in Indian women?', opts:['Lung cancer','Ovarian cancer','Breast cancer','Cervical cancer'], ans:2, expl:'Breast cancer = most common cancer in Indian women (replacing cervical cancer now). Cervical cancer = 2nd most common. Screening: CBE (clinical breast examination) at HWC; mammography in urban. BSE (breast self-examination) encouraged monthly.' },

  /* ═══ NATIONAL PROGRAMS — extra ═══ */
  { topic:'programs', q:'VHND (Village Health Nutrition Day) is held at Anganwadi centre every:', opts:['Daily','Weekly','Monthly (every month on a fixed date)','Quarterly'], ans:2, expl:'VHND held monthly at AWC (Anganwadi Centre). Services: immunisation, ANC, weight monitoring, nutrition supplementation, counselling, referral. ASHA mobilises beneficiaries; ANM and AWW conduct the session.' },
  { topic:'programs', q:'Untied funds provided to Sub-Centre under NHM is:', opts:['₹5,000 per year','₹10,000 per year','₹75,000 per year','₹1,00,000 per year'], ans:1, expl:'Untied funds under NHM: Sub-Centre = ₹10,000/year; PHC = ₹25,000/year; CHC = ₹50,000/year; VHSNC = ₹10,000/year. Used for local health priorities, cleaning, minor repairs, community activities. Promotes flexibility at grassroots level.' },
  { topic:'programs', q:'NACP (National AIDS Control Programme) Phase IV ran from:', opts:['2001–2006','2007–2012','2012–2017','2021–2026'], ans:2, expl:'NACP Phase IV: 2012–2017. Focus: consolidating gains, maintaining zero new infections, zero AIDS-related deaths, zero discrimination. India\'s HIV prevalence: 0.22% (adult). NACO manages NACP. Target: 90-90-90 by 2020.' },
  { topic:'programs', q:'RKS (Rogi Kalyan Samiti) is a:', opts:['Government department','Hospital Society/Trust for flexible fund management at facility level','NGO','Insurance scheme'], ans:1, expl:'RKS = Rogi Kalyan Samiti (Patient Welfare Committee) = registered society at PHC/CHC/DH. Can receive and spend funds flexibly for patient welfare. Receives untied funds under NHM. Improves hospital accountability and service quality.' },
  { topic:'programs', q:'HMIS (Health Management Information System) in India collects data on:', opts:['Financial data only','Service delivery data (immunisation, ANC, deliveries, OPD) from all government health facilities monthly','Private sector only','Census data'], ans:1, expl:'HMIS: monthly online reporting of health service data from all government health facilities (SC to DH). Data on: maternal health, child health, immunisation, family planning, disease surveillance, infrastructure. Helps identify gaps for planning.' },
  { topic:'programs', q:'The ANM (Auxiliary Nurse Midwife) is posted at:', opts:['District Hospital','Community Health Centre','Sub-Centre (one ANM per SC)','PHC only'], ans:2, expl:'ANM = primary healthcare provider at Sub-Centre level. 1 ANM per SC (plains: 5000; hilly: 3000 population). Responsible for: MCH, immunisation, FP, basic curative care, health education, VHND. Reports to PHC MO.' },
  { topic:'programs', q:'PMSMA (PM Surakshit Matritva Abhiyan) is implemented on fixed:', opts:['1st of every month','5th of every month','9th of every month','15th of every month'], ans:2, expl:'PMSMA: every 9th of month. Free comprehensive ANC at government facilities (PHC, CHC, DH) by medical officer/specialist. Focuses on high-risk pregnancies. Minimum package: BP, weight, Hb, urine protein, ultrasound, blood group.' },
  { topic:'programs', q:'India\'s Pradhan Mantri Surakshit Matritva Abhiyan targets which group specifically?', opts:['All pregnant women','High-risk pregnant women (anaemia, HTN, diabetes, previous complications)','Only primiparous women','Only tribal women'], ans:1, expl:'PMSMA focuses on identifying and managing high-risk pregnancies. Key conditions: severe anaemia (Hb <7g/dL), hypertension, gestational diabetes, hypothyroidism, previous caesarean/stillbirth/neonatal death. Specialist consultation provided.' },
  { topic:'programs', q:'ASHA Home Visit schedule: new-born home visits are done at:', opts:['Only once at birth','Day 3, Day 7, Day 14, Day 28 (4 home visits in neonatal period)','Weekly for 3 months','Only at immunisation time'], ans:1, expl:'ASHA home visits for newborn: Day 3, Day 7, Day 14, Day 28 (4 visits in neonatal period) under Home Based Newborn Care (HBNC). Checks: breastfeeding, warmth, danger signs, cord care. Additional Day 42 visit for mother.' },
  { topic:'programs', q:'The goal of India\'s National Health Policy 2017 is:', opts:['Universal vaccination','Achieve Universal Health Coverage (UHC) with emphasis on preventive care','Build 1000 new hospitals','Achieve 0% IMR'], ans:1, expl:'NHP 2017 vision: Universal Health Coverage (UHC). Key targets by 2025: IMR ≤28, MMR ≤100, TFR = 2.1, U5MR ≤23, raise health expenditure to 2.5% of GDP. Emphasises preventive, promotive, and primary care; reduce catastrophic health expenditure.' },

  /* ═══ FIRST AID — extra ═══ */
  { topic:'firstaid', q:'In a burn patient, the "Rule of Nines" for an adult assigns what percentage to the head and neck?', opts:['4.5%','9%','18%','1%'], ans:1, expl:'Rule of Nines (adult): Head + neck = 9%; Each arm = 9%; Chest (front) = 9%; Abdomen (front) = 9%; Upper back = 9%; Lower back = 9%; Each thigh = 9%; Each leg below knee = 9%; Genitalia = 1%. Total = 100%. Lund & Browder chart is more accurate for children.' },
  { topic:'firstaid', q:'First aid for a chemical burn to the eye is:', opts:['Apply ointment','Irrigate with copious clean water for 15–20 minutes immediately','Cover with a pad','Apply ice pack'], ans:1, expl:'Chemical eye burn: IMMEDIATE copious irrigation with clean water (or saline) for at least 15–20 minutes. Remove contact lenses if present. Do NOT apply ointment. Seek urgent medical attention after irrigation.' },
  { topic:'firstaid', q:'Position of a patient in anaphylactic shock is:', opts:['Sitting upright','Lying flat with legs elevated (Trendelenburg/supine with legs raised)','Recovery position','Prone'], ans:1, expl:'Anaphylaxis: lay patient FLAT with legs elevated (unless breathing difficulty). Primary treatment: Adrenaline (Epinephrine) 0.5 mg IM (anterolateral thigh) immediately. Then antihistamine + corticosteroids + call emergency services.' },
  { topic:'firstaid', q:'Heat stroke (not heat exhaustion) is characterised by:', opts:['Profuse sweating, normal consciousness','Hot, DRY skin + core temp >40°C + altered mental status/unconsciousness','Mild headache only','Muscle cramps only'], ans:1, expl:'Heat stroke: Hot DRY skin (sweating mechanism failed), core temp >40°C, confusion/unconsciousness. Life-threatening emergency. Mx: rapid cooling (ice packs to neck, axillae, groin; cool water mist; fan). Heat exhaustion: sweating preserved, normal consciousness.' },
  { topic:'firstaid', q:'Heimlich manoeuvre (abdominal thrusts) is NOT recommended for:', opts:['Adults with severe choking','Children >1 year','Infants <1 year (use back blows + chest thrusts)','Obese adults'], ans:2, expl:'Heimlich manoeuvre (abdominal thrusts) = NOT used in infants <1 year (risk of liver injury). For infants: 5 back blows (face-down on forearm) + 5 chest thrusts (2 fingers, lower half sternum). For pregnant/obese adults: chest thrusts.' },
  { topic:'firstaid', q:'For a suspected spinal injury, the neck should be:', opts:['Flexed to check movement','Extended to open airway fully','Immobilised in neutral position (do not move)','Rotated to check sensation'], ans:2, expl:'Suspected cervical spine injury: immobilise neck in neutral position using hands, cervical collar, or rolled towels. Log-roll to turn. Airway: jaw thrust (not head-tilt-chin-lift). Move only with full spinal precautions.' },
  { topic:'firstaid', q:'The recommended dose of ORS for a child with SOME dehydration in 4 hours:', opts:['10–20 mL/kg','50 mL/kg','75 mL/kg over 4 hours','100 mL/kg'], ans:2, expl:'WHO IMCI: Some dehydration = ORS 75 mL/kg over 4 hours at health facility. No dehydration: 10 mL/kg per loose stool at home. Severe dehydration: IV Ringer\'s Lactate 100 mL/kg over 3–6 hours (Plan C).' },

  /* ═══ ANATOMY — extra ═══ */
  { topic:'anatomy', q:'The normal blood pH is:', opts:['7.0–7.2','7.35–7.45','7.5–7.6','6.8–7.0'], ans:1, expl:'Normal arterial blood pH = 7.35–7.45. Acidosis: pH <7.35 (respiratory or metabolic). Alkalosis: pH >7.45. pH <7.2 or >7.6 = life-threatening. Maintained by lungs (CO2), kidneys (HCO3), and buffers.' },
  { topic:'anatomy', q:'Which organ produces insulin?', opts:['Liver','Adrenal gland','Pancreas (beta cells of islets of Langerhans)','Thyroid'], ans:2, expl:'Insulin produced by beta cells of islets of Langerhans (pancreas). Alpha cells → glucagon. Delta cells → somatostatin. Insulin: lowers blood glucose, promotes glycogen synthesis, lipogenesis, protein synthesis. Deficiency → Diabetes Mellitus.' },
  { topic:'anatomy', q:'The menstrual cycle is normally:', opts:['14 days','21–35 days (average 28 days)','35–45 days','7 days'], ans:1, expl:'Normal menstrual cycle = 21–35 days (average 28 days). Day 1 = first day of menstruation. Follicular phase (Day 1–14) → ovulation (Day 14) → luteal phase (Day 14–28). Duration of bleeding = 3–7 days, blood loss <80 mL.' },
  { topic:'anatomy', q:'The hormone responsible for onset of labour is:', opts:['Progesterone','Oestrogen','Oxytocin (from posterior pituitary)','FSH'], ans:2, expl:'Oxytocin (from posterior pituitary) triggers uterine contractions at term. Surge of oxytocin = onset of labour. Prostaglandins also important. Synthetic oxytocin used for induction/augmentation of labour and PPH prevention (AMTSL).' },
  { topic:'anatomy', q:'Haemoglobin carries oxygen by binding to:', opts:['Globin protein chains','Iron (Fe²⁺) in haem groups','Plasma albumin','WBCs'], ans:1, expl:'Each Hb molecule has 4 haem groups, each containing Fe²⁺ that binds one O2 molecule. So 1 Hb molecule = 4 O2. Oxyhaemoglobin (bright red) → deoxyhaemoglobin (dark red/blue). CO binds 250× more avidly than O2 → CO poisoning.' },
  { topic:'anatomy', q:'The function of the placenta includes all EXCEPT:', opts:['Gas exchange (O2/CO2)','Nutrient transfer','Hormone production (hCG, oestrogen, progesterone)','Producing red blood cells for the foetus'], ans:3, expl:'Placenta functions: (1) Gas exchange, (2) Nutrition transfer (glucose, AA), (3) Waste removal (urea, CO2), (4) Hormone production (hCG, oestrogen, progesterone, HPL), (5) Immunity (IgG transfer). Does NOT produce foetal RBCs (that\'s yolk sac, then liver/spleen, then bone marrow).' },
  { topic:'anatomy', q:'Normal urine output in an adult is:', opts:['100–200 mL/day','400–500 mL/day','800–2000 mL/day (avg 1500 mL)','3000–4000 mL/day'], ans:2, expl:'Normal urine output = 0.5–1 mL/kg/hour = ~800–2000 mL/day (average 1500 mL). Oliguria: <400 mL/day (<0.5 mL/kg/h) = kidney concern. Anuria: <100 mL/day. Polyuria: >3000 mL/day (DM, DI, diuretics).' },
  { topic:'anatomy', q:'ABO blood group system: person with blood group AB has:', opts:['Only A antigens on RBCs','Only B antigens on RBCs','Both A and B antigens, NO antibodies in plasma','No antigens, both anti-A and anti-B antibodies'], ans:2, expl:'Blood group AB: A + B antigens on RBCs, NO antibodies (anti-A or anti-B) in plasma. Blood group O: No antigens, anti-A + anti-B antibodies. Universal donor = O negative (no ABO or Rh antigens). Universal recipient = AB positive.' },
  { topic:'anatomy', q:'The normal respiratory rate in a newborn is:', opts:['12–20/min','20–30/min','40–60/min','70–80/min'], ans:2, expl:'Newborn normal RR = 40–60/min. Tachypnoea in newborn: >60/min (WHO IMCI). Grunting, chest indrawing, nasal flaring = signs of respiratory distress. Fast breathing in infants (2–12 months): ≥50/min; Children (1–5 years): ≥40/min.' },

  /* ═══ ENVIRONMENTAL HEALTH — extra ═══ */
  { topic:'environment', q:'Hardness of water is mainly due to:', opts:['Sodium and potassium salts','Calcium and magnesium salts','Iron and manganese','Chloride salts'], ans:1, expl:'Water hardness = dissolved calcium (Ca²⁺) and magnesium (Mg²⁺) salts (bicarbonates, sulphates, chlorides). Temporary hardness (carbonates) removed by boiling. Permanent hardness (sulphates, chlorides) requires chemical treatment (lime-soda, ion exchange).' },
  { topic:'environment', q:'The most effective method of water purification at household level is:', opts:['Settling','Boiling (kills all pathogens)','Adding potassium permanganate','Filtering through cloth'], ans:1, expl:'Boiling = most effective household water treatment. Kills all pathogenic microorganisms (bacteria, viruses, parasites) at 100°C. Boil for at least 1 minute (3 min at high altitude). SODIS (solar disinfection), chlorination, ceramic filters are alternatives.' },
  { topic:'environment', q:'Chlorine dose for emergency water purification is:', opts:['0.1 mg/L','0.5 mg/L','5 mg/L (5 ppm) as initial dose','100 mg/L'], ans:2, expl:'Emergency water treatment: 5 mg/L (5 ppm) free residual chlorine, contact time 30 min. Regular supply: target 0.2–0.5 mg/L residual chlorine at consumer end. Bleaching powder (30–35% available chlorine) used in India.' },
  { topic:'environment', q:'ODF (Open Defecation Free) is the goal of:', opts:['WASH programme only','Swachh Bharat Mission (SBM) and WASH','NRHM','ICDS'], ans:1, expl:'ODF = zero open defecation = key goal of Swachh Bharat Mission (SBM) — launched 2 Oct 2014. India declared ODF in 2019. SBM Phase 2 (2020–25): ODF+ (sanitation + hygiene), ODF++ (solid/liquid waste management), FAL (Faecal Sludge Management).' },
  { topic:'environment', q:'Lead poisoning in children primarily affects:', opts:['Lungs','Kidneys only','Brain (neurotoxicity — IQ reduction, learning disability)','Skin'], ans:2, expl:'Lead (Pb) = potent neurotoxin. No safe blood lead level. Children especially vulnerable: pica (eating paint chips), hand-mouth activity. Effects: intellectual disability, reduced IQ, ADHD, seizures. Sources: old paint, lead pipes, petrol (phased out in India 2000).' },
  { topic:'environment', q:'Waste water treatment: activated sludge process uses:', opts:['Chemicals only','Microorganisms (aerobic bacteria) to break down organic matter','UV light','Sedimentation alone'], ans:1, expl:'Activated sludge process = aerobic biological treatment using aerobic bacteria in aeration tanks. Air pumped in → bacteria break down organic matter → secondary sedimentation. One of the most common urban sewage treatment methods.' },
  { topic:'environment', q:'Methane (CH4) is produced from:', opts:['Nuclear energy','Burning coal','Decomposition of organic waste in landfills and wetlands (biogas)','Solar panels'], ans:2, expl:'Methane = main component of biogas. Produced by anaerobic decomposition of organic matter: landfills, paddy fields, livestock (enteric fermentation), wetlands. Potent greenhouse gas (28× CO2 over 100 years). Also produced intentionally in biogas plants.' },

  /* ═══ HEALTH STATISTICS — extra ═══ */
  { topic:'stats', q:'Crude Birth Rate (CBR) is defined as:', opts:['Live births per 1000 women aged 15–44','Total live births per 1000 mid-year population','Total births including stillbirths per 1000 population','Live births per 100 married women'], ans:1, expl:'CBR = total live births per 1000 mid-year population. India CBR (SRS 2020) ≈ 19.5/1000. General Fertility Rate (GFR) = live births per 1000 women 15–44. TFR = average children per woman over reproductive lifetime.' },
  { topic:'stats', q:'Perinatal mortality rate includes deaths:', opts:['In first 7 days of life only','28 weeks gestation to 7 days after birth (stillbirths + early neonatal deaths)','In first 28 days','All deaths in children <1 year'], ans:1, expl:'Perinatal mortality = stillbirths (≥28 weeks gestation) + early neonatal deaths (0–7 days) per 1000 total births. India PMR ≈ 30/1000 (SRS). Causes: birth asphyxia, prematurity, infection. Reduced by skilled birth attendance, ANC.' },
  { topic:'stats', q:'In a 2×2 table, Positive Predictive Value (PPV) is:', opts:['TP/(TP+FN)','TP/(TP+FP)','TN/(TN+FP)','TN/(TN+FN)'], ans:1, expl:'PPV = TP/(TP+FP) = proportion of positive tests that are truly positive. NPV = TN/(TN+FN). PPV depends on PREVALENCE — high prevalence increases PPV. Sensitivity = TP/(TP+FN). Specificity = TN/(TN+FP).' },
  { topic:'stats', q:'The most important measure of central tendency in a skewed distribution is:', opts:['Mean','Mode','Median','Standard deviation'], ans:2, expl:'In a skewed distribution (income, hospital stay duration), median is preferred over mean as mean is pulled by extreme values. Mean: sensitive to outliers. Median: 50th percentile, unaffected by extremes. Mode: most frequent value.' },
  { topic:'stats', q:'R0 (Basic Reproduction Number) means:', opts:['Recovery rate','Average number of new cases one case generates in a fully susceptible population','Mortality rate','Incubation period'], ans:1, expl:'R0 = basic reproduction number = average secondary cases from one primary case in a fully susceptible population. R0 >1 = epidemic will grow; R0 <1 = epidemic will fade. Measles R0 = 12–18 (highest known). COVID-19 original strain R0 = 2–3.' },
  { topic:'stats', q:'Case Fatality Rate (CFR) differs from Mortality Rate in that CFR is:', opts:['Deaths per 1000 population','Deaths per 1000 live births','Deaths per 100 CASES of a disease','Deaths per year'], ans:2, expl:'CFR = deaths among CASES of the disease / total cases × 100. Measures disease severity. Mortality rate = deaths per 1000 population (measures population impact). Cholera CFR: <1% with treatment; 25–50% untreated. Ebola CFR: 25–90%.' },

  /* ═══ ESSENTIAL MEDICINES — extra ═══ */
  { topic:'drug', q:'WHO-ORS (low-osmolarity) contains:', opts:['Sodium 90 mmol/L, glucose 111 mmol/L, osmolarity 311 mOsm/L','Sodium 75 mmol/L, glucose 75 mmol/L, osmolarity 245 mOsm/L','Sodium 50 mmol/L, glucose 50 mmol/L','Only glucose and sodium'], ans:1, expl:'Low-osmolarity WHO-ORS (2002 revised): Na+ 75 mmol/L, Cl- 65 mmol/L, K+ 20 mmol/L, citrate 10 mmol/L, glucose 75 mmol/L. Total osmolarity 245 mOsm/L. Reduces stool output and vomiting vs. standard (311 mOsm/L). Per sachet in 1 litre.' },
  { topic:'drug', q:'Misoprostol 600 mcg is used at community level for PPH prevention when oxytocin is not available. It is given by which route?', opts:['Intravenous','Oral or sublingual','Intramuscular','Rectal only'], ans:1, expl:'Misoprostol 600 mcg PO (oral) or SL (sublingual) for PPH prevention at community level. Shelf-stable at room temperature — suitable for low-resource settings without cold chain. Oxytocin is preferred (IV/IM) when available.' },
  { topic:'drug', q:'Iron sucrose injection is used in pregnancy for:', opts:['Mild anaemia','Moderate anaemia when oral IFA not tolerated or inadequate response','First trimester supplementation','Prevention of goitre'], ans:1, expl:'IV Iron sucrose (or ferric carboxymaltose) used in 2nd/3rd trimester when: oral iron not tolerated, non-compliance, severe malabsorption, or Hb needs rapid correction (Hb <7 g/dL). Given IV infusion. Faster Hb rise than oral iron.' },
  { topic:'drug', q:'Gentian violet (crystal violet) 0.5% solution is used for:', opts:['Eye infections','Oral thrush in neonates and tropical ulcers','Burns','Diarrhoea'], ans:1, expl:'Gentian violet 0.5%: painted on oral mucosa for oral thrush (neonatal candidiasis); applied to tropical/non-healing ulcers, impetigo. Antifungal and antibacterial. Applied with swab twice daily for oral thrush.' },
  { topic:'drug', q:'The first-line drug for treatment of eclampsia (seizure prevention/control) is:', opts:['Diazepam','Phenytoin','Magnesium sulphate (MgSO4)','Phenobarbitone'], ans:2, expl:'MgSO4 = drug of choice for eclampsia. Pritchard regimen: Loading dose 4g IV (20 mL of 20%) over 20 min + 5g IM each buttock; Maintenance: 5g IM every 4 hours. Reduces recurrence of seizures and maternal mortality.' },
  { topic:'drug', q:'Antidote for organophosphate (pesticide) poisoning is:', opts:['Calcium gluconate','Naloxone','Atropine + Pralidoxime (2-PAM)','Flumazenil'], ans:2, expl:'Organophosphate poisoning (insecticides: malathion, chlorpyrifos): symptoms = SLUDGE (Salivation, Lacrimation, Urination, Defecation, GI cramps, Emesis) + bradycardia, miosis, seizures. Antidotes: Atropine (reverses muscarinic effects) + Pralidoxime (2-PAM, reactivates AChE if given early).' },
  { topic:'drug', q:'Vitamin K injection at birth is given to prevent:', opts:['Neonatal jaundice','Haemorrhagic Disease of Newborn (VKDB — Vitamin K Deficiency Bleeding)','Neonatal sepsis','Hypoglycaemia'], ans:1, expl:'Vitamin K1 (phytomenadione) 1 mg IM at birth prevents VKDB (Vitamin K Deficiency Bleeding / Haemorrhagic Disease of Newborn). Newborns have low Vit K stores (poor placental transfer), low breast milk content, no gut bacteria initially.' },
  { topic:'drug', q:'Paracetamol adult dose and maximum daily dose is:', opts:['250 mg per dose, max 1g/day','500–1000 mg per dose, max 4g/day (3g if chronic alcohol user)','100 mg per dose, max 2g/day','2000 mg per dose, max 8g/day'], ans:1, expl:'Paracetamol (acetaminophen): 500–1000 mg every 4–6 hours; maximum 4g/day (3g/day in liver disease or chronic alcohol use). Overdose → hepatotoxicity. Antidote: N-acetylcysteine (NAC). Safe in pregnancy and breastfeeding (preferred analgesic).' },
  { topic:'drug', q:'Which antibiotic is used for prophylaxis of meningococcal meningitis contacts?', opts:['Amoxicillin','Rifampicin or Ciprofloxacin (single dose)','Metronidazole','Chloramphenicol'], ans:1, expl:'Meningococcal meningitis close contacts: Rifampicin 600 mg twice daily × 2 days (adults) OR Ciprofloxacin 500 mg single dose. Eliminates nasopharyngeal carriage. Index case also receives rifampicin before discharge to eliminate carrier state.' },

  /* ═══ MCH — SET 3 ═══ */
  { topic:'mch', q:'VBSY (Vande Bharat Swasthya Yojana) — under NHM — targets which group?', opts:['Only elderly','Pregnant women, children, and adolescents under RMNCH+A','Only males','Only BPL families'], ans:1, expl:'RMNCH+A (Reproductive, Maternal, Newborn, Child, and Adolescent Health) is India\'s integrated health strategy under NHM targeting women, children, and adolescents. Launched 2013. Includes JSSK, JSY, PMMVY, PMSMA, and adolescent health under RKSK.' },
  { topic:'mch', q:'Foetal movements (quickening) are first felt by the mother at approximately:', opts:['8–10 weeks','12–14 weeks','18–20 weeks (primi), 16–18 weeks (multi)','28–30 weeks'], ans:2, expl:'Quickening = first perception of foetal movements. Primiparous women: 18–20 weeks. Multiparous women: 16–18 weeks (earlier awareness). Foetus actually moves from 8 weeks (ultrasound detectable). Reduced foetal movements = danger sign.' },
  { topic:'mch', q:'The "three delays" model describes barriers to obstetric care. Delay 1 is:', opts:['Delay in reaching facility','Delay in receiving care at facility','Delay in deciding to seek care at home level','Delay in referral from PHC'], ans:2, expl:'Three Delays Model (Thaddeus & Maine 1994): Delay 1 = Decision to seek care (at family/community level — recognition of complications, social/cultural barriers); Delay 2 = Reaching facility (distance, transport, road); Delay 3 = Receiving care at facility (staff, drugs, blood).' },
  { topic:'mch', q:'Normal duration of second stage of labour (expulsive stage) in a primigravida is up to:', opts:['30 minutes','1 hour','2 hours','4 hours'], ans:2, expl:'Second stage: full cervical dilation (10 cm) to delivery of baby. Primigravida: up to 2 hours (without epidural); Multigravida: up to 1 hour. With epidural: add 1 extra hour. Prolonged 2nd stage → foetal distress, obstetric intervention needed.' },
  { topic:'mch', q:'Post-natal visit schedule under NHM requires minimum visits at:', opts:['Only at 6 weeks','24–48 hours, 3–7 days, 4–6 weeks after delivery','Only within 24 hours','Daily for 1 month'], ans:1, expl:'Post-natal check-up schedule (MoHFW): Day 1 (24–48 hrs), Day 3–7, Week 4–6 (6-week postnatal check). At 6 weeks: contraceptive counselling, infant weight, immunisation status, maternal Hb check, family planning advice.' },

  /* ═══ FAMILY PLANNING — SET 3 ═══ */
  { topic:'fp', q:'MTP Act 1971 (amended 2021) allows termination of pregnancy up to:', opts:['12 weeks on request; up to 20 weeks with medical opinion','20 weeks on request; up to 24 weeks for special categories','Any time','Only up to 8 weeks'], ans:1, expl:'MTP Act 2021 amendment: up to 20 weeks = 1 registered medical practitioner opinion; 20–24 weeks (special categories: rape/assault survivors, minor girls, differently abled, humanitarian crisis) = 2 RMP opinions; >24 weeks = Medical Board.' },
  { topic:'fp', q:'The spacing between two births recommended by family planning guidelines is:', opts:['6 months','1 year','At least 2 years (interpregnancy interval ≥24 months)','5 years'], ans:2, expl:'WHO/RMNCH+A recommend interpregnancy interval ≥24 months (2 years) after a live birth before next conception. Short intervals <18 months increase risk of: LBW, preterm birth, maternal anaemia, neonatal death. Promotes optimal child spacing.' },
  { topic:'fp', q:'Which of the following is a progestin-only contraceptive pill (POP)?', opts:['Combined OCP (Mala-N)','Centchroman (Chhaya)','Mini-pill (Norethisterone/Levonorgestrel)','OCP with oestrogen'], ans:2, expl:'Progestin-only pill (POP/mini-pill) contains only progestin (norethisterone, levonorgestrel, desogestrel). No oestrogen. Safe for breastfeeding mothers (unlike COC). Taken continuously without break. Also used in women with oestrogen contraindications.' },

  /* ═══ IMMUNIZATION — SET 3 ═══ */
  { topic:'immunize', q:'Which disease has been ELIMINATED from India (not eradicated globally)?', opts:['Smallpox','Polio','Guinea worm','Maternal and Neonatal Tetanus (MNT)'], ans:3, expl:'India eliminated MNT in 2015 (<1 NNT case/1000 live births in all districts). Polio-free since 2014 (not eliminated globally). Smallpox globally eradicated 1980. Guinea worm close to eradication globally. Yaws eliminated in India 2016.' },
  { topic:'immunize', q:'The site and volume for DPT injection in infants is:', opts:['Upper arm, 0.1 mL','Buttock (gluteal), 0.5 mL','Anterolateral thigh, 0.5 mL IM','Deltoid, 1 mL'], ans:2, expl:'DPT/Pentavalent: 0.5 mL IM into anterolateral thigh (vastus lateralis) in infants. NOT gluteal (risk of sciatic nerve injury in infants). Deltoid preferred in older children/adults. Anterolateral thigh = recommended site in <1 year.' },
  { topic:'immunize', q:'The "open multi-dose vial policy" for vaccines means:', opts:['Opened vials must be discarded within 1 hour','Opened vials of OPV, DPT, TT, Hep-B, and liquid pentavalent can be used up to 28 days if stored correctly','All vaccines must be used in single session','Opened BCG vials last 6 hours only'], ans:1, expl:'India\'s open vial policy (as per WHO guidelines): OPV, DPT, TT, HepB, liquid pentavalent = can be used up to 28 days if: cap not removed (used with syringe), VVM OK, stored at correct temperature, no contamination signs. BCG and measles = use within 4–6 hours of reconstitution.' },
  { topic:'immunize', q:'Which vaccine is given sub-cutaneously (SC)?', opts:['BCG','DPT','MR vaccine','Hepatitis B'], ans:2, expl:'MR (Measles-Rubella) vaccine = 0.5 mL SC in right upper arm. BCG = 0.1 mL ID (intradermal) in left upper arm. DPT/Pentavalent/HepB = 0.5 mL IM (anterolateral thigh in infants). OPV = 2 drops oral.' },

  /* ═══ NUTRITION — SET 3 ═══ */
  { topic:'nutrition', q:'Balanced diet for an adult Indian woman (non-pregnant) should provide approximately:', opts:['1200 kcal/day','1800–2100 kcal/day','3000 kcal/day','500 kcal/day'], ans:1, expl:'ICMR 2020 RDA: Sedentary adult woman = 1900 kcal/day; Moderate activity = 2230 kcal/day. Sedentary adult man = 2320 kcal/day. Pregnancy: +350 kcal (2nd trimester), +450 kcal (3rd trimester). Lactation: +500 kcal/day.' },
  { topic:'nutrition', q:'Breast milk compared to cow\'s milk has:', opts:['More protein and less lactose','Less protein (whey-dominant, easily digestible) and more lactose; ideal fat composition','More iron and vitamin C only','Same composition but warmer'], ans:1, expl:'Breast milk vs. cow\'s milk: Breast milk has LESS total protein but whey-dominant (60:40 whey:casein, easily digestible vs. cow 20:80). More lactose, oligosaccharides (prebiotics), IgA, lysozyme, lactoferrin. Optimal iron bioavailability (50% absorbed vs 10% cow).' },
  { topic:'nutrition', q:'Complementary feeding should be started at:', opts:['3 months','4 months','6 months (along with continued breastfeeding)','12 months'], ans:2, expl:'Complementary feeding (CF) starts at EXACTLY 6 months (180 days). Breast milk alone is sufficient for first 6 months. Starting CF too early (<4 months) increases infection risk; too late (>6 months) causes growth faltering, micronutrient deficiency. CF continues until 2 years.' },
  { topic:'nutrition', q:'Anthropometric indicator used to measure chronic malnutrition (stunting) is:', opts:['Weight for age','Weight for height','Height for age (HAZ score <-2 SD)','MUAC'], ans:2, expl:'Stunting = chronic malnutrition = low Height for Age (HAZ) <-2 SD. India stunting prevalence: 35% (NFHS-5, down from 38% in NFHS-4). Wasting = acute malnutrition = low Weight for Height (WHZ) <-2 SD. Underweight = low Weight for Age (WAZ) <-2 SD.' },

  /* ═══ COMMUNICABLE DISEASES — SET 3 ═══ */
  { topic:'diseases', q:'Swine flu is caused by:', opts:['Influenza A (H1N1) pdm09 virus','Influenza B virus','Parainfluenza virus','RSV'], ans:0, expl:'Swine flu = Influenza A (H1N1) pandemic 2009 strain (pdm09). Transmitted human-to-human by droplets. High-risk groups: pregnant women, children <5y, elderly >65y, immunocompromised, healthcare workers. Treatment: Oseltamivir (Tamiflu). Seasonal flu vaccine provides some cross-protection.' },
  { topic:'diseases', q:'Rabies post-exposure prophylaxis (PEP) includes:', opts:['Wound washing with soap and water + Rabies vaccine (± RIG)','Antibiotics only','Isolation only','Observation of the animal for 10 days — no treatment needed'], ans:0, expl:'Rabies PEP: (1) Immediate wound washing with soap and water for 15 min + iodine; (2) Rabies vaccine (5-dose Essen/4-dose Zagreb schedule); (3) Rabies Immunoglobulin (RIG) for category III bites. Category I (licks on intact skin) = no PEP. 100% fatal once symptoms appear.' },
  { topic:'diseases', q:'ASHA\'s role in malaria control includes:', opts:['Treating all fever cases with antimalarials empirically','Testing with RDT and treating confirmed malaria cases + fever surveillance','Spraying insecticides alone','Only health education'], ans:1, expl:'Under NVBDCP, trained ASHAs can: (1) Test fever cases with malaria RDT, (2) Treat confirmed uncomplicated malaria with ACT/CQ+PQ, (3) Report cases for surveillance, (4) Promote bed nets (LLIN), (5) Refer severe malaria. ASHA as DOTS provider for TB also.' },
  { topic:'diseases', q:'Chickenpox (Varicella) is most infectious:', opts:['After all vesicles have crusted','Before rash appears (1–2 days) until all vesicles are crusted (5–7 days total)','Only during first day of rash','When fever starts'], ans:1, expl:'Chickenpox infectious period: 1–2 days BEFORE rash appears until ALL vesicles have crusted over (5–7 days after rash onset). Varicella-zoster virus. Airborne + droplet + direct contact. Incubation: 10–21 days. Complications: bacterial superinfection, pneumonia, encephalitis.' },
  { topic:'diseases', q:'Incubation period of TB is:', opts:['1–3 days','2–6 weeks (infection to TST/IGRA conversion); years to primary disease','6–12 months','Only 24 hours'], ans:1, expl:'TB: Infection to TST conversion = 2–6 weeks. Infection to primary disease = months to years. Most latent infections (90%) never progress. Risk of progression highest in: infants, immunocompromised (HIV), malnutrition, diabetes. Lifetime risk of reactivation = 10%.' },
  { topic:'diseases', q:'ELISA test for HIV detects:', opts:['HIV virus directly','Antibodies to HIV (and p24 antigen in 4th generation tests)','HIV RNA','CD4 count'], ans:1, expl:'ELISA (Enzyme-Linked Immunosorbent Assay): 3rd generation = antibody detection (IgG/IgM); 4th generation = antibody + p24 antigen (shorter window period 2–4 weeks). Reactive ELISA confirmed by Western blot or second algorithm. Viral load (PCR RNA) used for monitoring treatment.' },

  /* ═══ NCD — SET 3 ═══ */
  { topic:'ncd', q:'Which of the following is a modifiable risk factor for cardiovascular disease?', opts:['Age','Sex','Hypertension, dyslipidaemia, smoking, diabetes (all modifiable)','Family history'], ans:2, expl:'Modifiable CVD risk factors: HTN, DM, dyslipidaemia, smoking, obesity, physical inactivity, unhealthy diet, alcohol. Non-modifiable: age, sex (male risk higher), family history, race/ethnicity. NPCDCS targets modifiable risk factors through screening and lifestyle counselling.' },
  { topic:'ncd', q:'Global target for reduction of premature NCD mortality by 2030 (SDG) is:', opts:['10% reduction','25% reduction (SDG 3.4)','50% reduction','5% reduction'], ans:1, expl:'SDG 3.4: Reduce by one-third premature mortality from NCDs (CVD, cancer, DM, CRD) by 2030 through prevention and treatment. WHO "25×25" target: 25% relative reduction in premature NCD mortality by 2025 (compared to 2010 baseline).' },
  { topic:'ncd', q:'Metabolic syndrome is diagnosed when ≥3 of the following are present. Which is NOT a component?', opts:['Central obesity (waist circumference)','High triglycerides','Low HDL cholesterol','High haemoglobin'], ans:3, expl:'Metabolic syndrome (IDF/AHA criteria) = ≥3 of: (1) Central obesity (WC ≥90 cm men/≥80 cm women Asian), (2) TG ≥150 mg/dL, (3) Low HDL (<40 men/<50 women), (4) BP ≥130/85, (5) Fasting glucose ≥100 mg/dL. High Hb is NOT a component.' },

  /* ═══ NATIONAL PROGRAMS — SET 3 ═══ */
  { topic:'programs', q:'Nikshay Poshan Yojana provides financial support of __ per month to TB patients:', opts:['₹250/month','₹500/month','₹1000/month','₹2000/month'], ans:1, expl:'Nikshay Poshan Yojana (2018): ₹500/month direct benefit transfer (DBT) to all TB patients throughout treatment duration (minimum 6 months for DS-TB; longer for DR-TB). Aims to address nutritional needs and reduce treatment dropout.' },
  { topic:'programs', q:'NVBDCP (National Vector Borne Disease Control Programme) covers which diseases?', opts:['TB and leprosy','Malaria, dengue, kala-azar, filaria, Japanese encephalitis, chikungunya','Only malaria','HIV/AIDS'], ans:1, expl:'NVBDCP covers 6 vector-borne diseases: Malaria, Dengue, Chikungunya, Kala-azar (VL), Lymphatic Filariasis, Japanese Encephalitis. Key strategies: vector control (IRS, LLIN, larval control), case management, IEC/BCC.' },
  { topic:'programs', q:'India\'s Elimination of Lymphatic Filariasis targets which year?', opts:['2020','2023','2027','2030'], ans:2, expl:'India targets elimination of Lymphatic Filariasis (LF) by 2027 (LF global elimination target: 2030). Strategy: MDA (Mass Drug Administration) with DEC + Albendazole annually in endemic districts. Also adding Ivermectin (IDA triple drug). Transmission Assessment Surveys (TAS) verify elimination.' },
  { topic:'programs', q:'ASHA\'s monthly home visits include all EXCEPT:', opts:['Newborn home visit (Day 3, 7, 14, 28)','ANC home visits','Performing surgical procedures','IEC/BCC activities and referral'], ans:2, expl:'ASHA functions include: home visits (newborn, ANC, postnatal), escort to health facilities, immunisation mobilisation, ORS/ORT promotion, DOTS support, distribution of basic medicines, IEC/BCC, registration. ASHA does NOT perform surgical procedures or provide complex medical care.' },
  { topic:'programs', q:'FRU (First Referral Unit) must be able to provide:', opts:['Only OPD services','24/7 emergency obstetric care, blood transfusion, and neonatal care','Only basic immunisation','Tertiary care only'], ans:1, expl:'FRU = First Referral Unit (designated CHC or equivalent). Must provide: 24/7 EmOC (emergency obstetric care), CEmOC (C-section), blood storage, blood transfusion, newborn care (SNCU), PICU. Minimum: surgeon, gynaecologist, anaesthetist, paediatrician. Referral from PHC/SC.' },
  { topic:'programs', q:'India\'s Elimination of Mother-to-Child Transmission (EMTCT) of HIV target requires MTCT rate of <:', opts:['<5% with breastfeeding','<2% (or <50 infections per 100,000 live births)','<20%','<10%'], ans:1, expl:'WHO EMTCT validation criteria: MTCT rate <2% (breastfeeding) or <5% (non-breastfeeding) AND <50 new child HIV infections per 100,000 live births. Under PPTCT programme: all HIV-positive pregnant women get lifelong ART (Option B+) regardless of CD4 count.' },

  /* ═══ FIRST AID — SET 3 ═══ */
  { topic:'firstaid', q:'Recovery position is used for:', opts:['Cardiac arrest','Unconscious patient who is breathing normally (to prevent aspiration)','Conscious patient in shock','Spinal injury'], ans:1, expl:'Recovery position (lateral recumbent) = for unconscious BREATHING patient. Prevents airway obstruction from tongue falling back and aspiration of vomit. NOT for: spinal injury (log roll instead), cardiac arrest (CPR needed), patient with hip/pelvic fracture.' },
  { topic:'firstaid', q:'For an eye injury with a foreign body stuck in the eye, correct first aid is:', opts:['Rub the eye vigorously','Flush with water repeatedly + cover both eyes + seek medical help','Remove with fingers','Apply eye drops without medical consultation'], ans:1, expl:'Embedded foreign body in eye: DO NOT rub or try to remove embedded object. Flush gently with water (not forceful). Cover BOTH eyes with clean cloth/pad (covering both reduces eye movement). Seek urgent ophthalmology care.' },
  { topic:'firstaid', q:'Correct first aid for a severed (amputated) finger is:', opts:['Reattach it yourself','Wrap amputated part in moist cloth → place in sealed bag → put bag on ice (not directly on ice); rush to hospital','Discard the finger','Keep the finger in water alone'], ans:1, expl:'Amputated part: wrap in moist (saline-soaked) sterile gauze → seal in plastic bag → put bag on ice (NOT directly on ice — causes frostbite). Rush to hospital within 6 hours (replantation possible). Keep patient\'s wound clean and elevated.' },

  /* ═══ ANATOMY — SET 3 ═══ */
  { topic:'anatomy', q:'The site of fertilisation in the female reproductive tract is:', opts:['Uterus','Ovary','Outer one-third of fallopian tube (ampullary region)','Cervix'], ans:2, expl:'Fertilisation occurs in the AMPULLA (outer 1/3) of the fallopian tube. Sperm meets ovum within 24 hours of ovulation. Zygote → morula → blastocyst → implants in uterine endometrium at Day 6–10 post-fertilisation.' },
  { topic:'anatomy', q:'Menarche (first menstruation) normally occurs at age:', opts:['8–10 years','11–14 years (average ~13 years in India)','16–18 years','20–22 years'], ans:1, expl:'Menarche normally occurs at 11–14 years (average ~12.5–13 years globally; slightly later in India ~12.5 years). Preceded by thelarche (breast development) and pubarche (pubic hair). Precocious puberty = menarche <8 years; delayed = >16 years.' },
  { topic:'anatomy', q:'Normal foetal heart rate (FHR) at term:', opts:['60–80 bpm','80–100 bpm','110–160 bpm','200–220 bpm'], ans:2, expl:'Normal FHR = 110–160 bpm. Bradycardia <110 bpm = foetal distress (cord compression, placental abruption, maternal hypotension). Tachycardia >160 bpm = foetal distress or maternal fever/infection. FHR monitored by Pinard stethoscope or electronic CTG.' },
  { topic:'anatomy', q:'Functions of the lymphatic system include:', opts:['Red blood cell production','Returning interstitial fluid to blood, fat absorption (lacteals), immune function (lymphocytes)','Hormone production','Oxygen transport'], ans:1, expl:'Lymphatic system: (1) Returns ~3 L/day of interstitial fluid to blood via thoracic duct; (2) Fat absorption via lacteals in small intestine (chylomicrons); (3) Immune function: lymph nodes filter pathogens, lymphocyte production/maturation; (4) Oedema prevention.' },

  /* ═══ ENVIRONMENT — SET 3 ═══ */
  { topic:'environment', q:'DALY (Disability Adjusted Life Year) measures:', opts:['Life expectancy only','Burden of disease = Years of Life Lost (YLL) + Years Lived with Disability (YLD)','Number of hospital admissions','GDP impact of disease'], ans:1, expl:'DALY = YLL (Years of Life Lost due to premature death) + YLD (Years Lived with Disability). 1 DALY = 1 year of healthy life lost. Used to compare burden of different diseases. GBD (Global Burden of Disease) study uses DALYs. India: high DALY burden from NCDs now.' },
  { topic:'environment', q:'Safe disposal of sharps (needles) in healthcare settings uses:', opts:['Yellow bag','Red bag','White translucent puncture-proof container','Open bin'], ans:2, expl:'BMW Management Rules 2016: Sharps (needles, blades, scalpels, broken glass) → White translucent puncture-proof, leak-proof container. Treated by hub-cutter at point of use, then autoclave/microwave/incinerator. Never recap, bend, or break needles by hand.' },
  { topic:'environment', q:'Air pollutant primarily responsible for smog formation in cities is:', opts:['CO2 only','PM2.5, PM10, NO2, SO2, O3 (ground level ozone)','Water vapour','Argon'], ans:1, expl:'Urban smog: Primary pollutants = PM2.5, PM10 (particulate matter), NO2 (nitrogen dioxide), SO2 (sulphur dioxide) from vehicles and industry. Secondary pollutant = ground-level O3 (formed from NOx + VOCs + sunlight). PM2.5 most dangerous (reaches alveoli, causes CVD, lung disease).' },
  { topic:'environment', q:'The term "herd immunity" means:', opts:['Animals are immune to human diseases','When sufficient % of population is immune, even unvaccinated people are protected (chain of transmission breaks)','Individual immunity from vaccination','Immunity in livestock'], ans:1, expl:'Herd immunity = when a critical proportion (herd immunity threshold) of a population is immune (vaccinated or naturally), chains of transmission break and even non-immune individuals are protected indirectly. Threshold = 1 - 1/R0. Measles requires 92–95% immune.' },

  /* ═══ HEALTH STATISTICS — SET 3 ═══ */
  { topic:'stats', q:'In epidemiology, "attack rate" is used during:', opts:['Endemic disease surveillance','Outbreak investigation (proportion of exposed people who develop disease)','Census enumeration','Chronic disease monitoring'], ans:1, expl:'Attack rate = number of people who develop disease / total exposed × 100. Used in OUTBREAK investigation. Secondary attack rate = new cases in household contacts after introduction of index case. Helps identify causative agent and risk factors in outbreaks.' },
  { topic:'stats', q:'Life expectancy at birth in India (2021 estimate) is approximately:', opts:['55 years','62 years','70 years','78 years'], ans:2, expl:'India life expectancy at birth (2019–21 SRS): ~70 years (men: 68.6; women: 71.3). Has increased from 49 years (1970s) to 70 years. SDG target: 75 years by 2030. Kerala has highest (75+); Uttar Pradesh lowest (~64 years).' },
  { topic:'stats', q:'Specificity of a screening test means:', opts:['Ability to detect all diseased persons','Ability to correctly identify those WITHOUT the disease (true negative rate)','Proportion of positives that are truly positive','Overall accuracy'], ans:1, expl:'Specificity = TN/(TN+FP) = correctly identifies TRUE NEGATIVES (non-diseased as negative). High specificity → few false positives → used for confirmatory tests. Mnemonic SpPIn = SPecific Positive rules IN disease. Example: TPHA for syphilis (high specificity).' },
  { topic:'stats', q:'Census in India is conducted every:', opts:['5 years','8 years','10 years','15 years'], ans:2, expl:'India\'s census is conducted every 10 years. Last census: 2011 (2021 census delayed due to COVID). Population 2011: 1.21 billion. Sex ratio: 940 females/1000 males. Literacy: 74%. Conducted by Registrar General and Census Commissioner of India.' },

  /* ═══ DRUG — SET 3 ═══ */
  { topic:'drug', q:'Cotrimoxazole (TMP-SMX) is given to HIV-positive children for prophylaxis against:', opts:['TB only','Pneumocystis jirovecii pneumonia (PCP) and toxoplasmosis','Malaria only','Diarrhoea only'], ans:1, expl:'Cotrimoxazole preventive therapy (CPT) = all HIV-positive children <5 years; HIV-positive adults with CD4 <200 cells/mm³. Prevents PCP (Pneumocystis pneumonia — most common AIDS-defining illness), toxoplasmosis, isosporiasis, bacterial infections.' },
  { topic:'drug', q:'Artemether-Lumefantrine (Coartem) is given for how many days?', opts:['1 day','2 days','3 days','7 days'], ans:2, expl:'AL (Artemether-Lumefantrine/Coartem): 3-day course (6 doses: at 0h, 8h, 24h, 36h, 48h, 60h). For uncomplicated P. falciparum malaria. Must be taken WITH food (fat improves lumefantrine absorption). Highly effective, well-tolerated.' },
  { topic:'drug', q:'The antidote for paracetamol (acetaminophen) overdose is:', opts:['Atropine','Calcium gluconate','N-acetylcysteine (NAC)','Naloxone'], ans:2, expl:'NAC (N-acetylcysteine) = antidote for paracetamol overdose (restores glutathione, prevents hepatotoxicity). Most effective within 8–10 hours of ingestion. IV or oral route. Paracetamol overdose → hepatic necrosis; liver transplant if severe.' },
  { topic:'drug', q:'Co-amoxiclav (Amoxicillin + Clavulanic acid) is more effective than amoxicillin alone because:', opts:['Higher dose','Clavulanic acid inhibits beta-lactamase enzymes produced by resistant bacteria','Better absorption','Less side effects'], ans:1, expl:'Clavulanic acid = beta-lactamase inhibitor. Bacteria resistant to amoxicillin produce beta-lactamase enzyme that destroys the beta-lactam ring. Clavulanic acid inactivates this enzyme, restoring amoxicillin\'s effectiveness against beta-lactamase-producing organisms.' },
  { topic:'drug', q:'Folic acid supplementation for PREVENTION of neural tube defects should be started:', opts:['At first ANC visit (8–12 weeks)','At least 1 month BEFORE conception and continue through 1st trimester','After NTD is diagnosed','Only in 3rd trimester'], ans:1, expl:'Folic acid 400 mcg/day periconceptionally (at least 1 month before conception and first 3 months of pregnancy). NTDs (neural tube defects — spina bifida, anencephaly) form by Day 28 (before most women know they are pregnant). High-risk women: 5 mg/day.' },
  { topic:'drug', q:'Gentamicin in neonates is given cautiously because it can cause:', opts:['Hypoglycaemia','Ototoxicity (hearing loss) and nephrotoxicity','Hyperglycaemia','Skin rash only'], ans:1, expl:'Aminoglycosides (Gentamicin, Amikacin): ototoxic (cochlear and vestibular damage → sensorineural hearing loss) and nephrotoxic. Neonates at higher risk due to immature kidneys. Given once daily (ODD regimen) to maximise efficacy and minimise toxicity. Monitor levels if possible.' },

  /* ═══ MCH — SET 4 ═══ */
  { topic:'mch', q:'Partograph is used to monitor:', opts:['Foetal growth throughout pregnancy','Progress of labour (cervical dilation, foetal descent, maternal condition)','Nutritional status','Antenatal blood tests'], ans:1, expl:'Partograph = graphical record of progress of labour. Monitors: cervical dilation (alert/action lines), foetal head descent, uterine contractions, FHR, maternal vital signs, urine output, medications. Alert line: cervical dilation expected at 1 cm/hr. Action line: 4 hrs right of alert line.' },
  { topic:'mch', q:'SNCU (Sick Newborn Care Unit) is located at:', opts:['Sub-Centre','PHC','District Hospital and above (DH/CHC)','Anganwadi'], ans:2, expl:'SNCU (Sick Newborn Care Unit) established at district hospitals and medical college hospitals under NHM. Provides: incubators, phototherapy, IV fluids, oxygen, infection management. Level 2 care for sick neonates. NBSU (Newborn Stabilisation Unit) at CHC level.' },
  { topic:'mch', q:'Phototherapy is used in neonates for:', opts:['Hypothermia','Jaundice (neonatal hyperbilirubinaemia)','Sepsis','Respiratory distress'], ans:1, expl:'Phototherapy: blue light (wavelength 420–470 nm) converts unconjugated bilirubin in skin to water-soluble isomers excreted in bile and urine. Used for neonatal jaundice. Exchange transfusion if very high levels. Physiological jaundice: Day 2–3 to Day 7–10 in term neonates.' },
  { topic:'mch', q:'Bi-manual compression of the uterus is performed to manage:', opts:['Eclampsia','Atonic PPH when other measures fail','Placenta praevia','Malpresentation'], ans:1, expl:'Bi-manual uterine compression: internal (fist in anterior vaginal fornix) and external (other hand on abdomen) compression of uterus to manage atonic PPH when oxytocin/ergometrine/misoprostol insufficient. Maintains until uterus contracts and bleeding stops.' },
  { topic:'mch', q:'PPIUCD eligibility criteria include:', opts:['Only multiparous women','Any woman delivering vaginally or by C-section who consents and has no contraindications (PID, PROM, chorioamnionitis, PPH, uterine anomaly)','Only >35 years','Only if husband consents'], ans:1, expl:'PPIUCD eligibility: informed consent, no fever/infection, no prolonged ROM >18h, no PPH, no chorioamnionitis, no uterine abnormality, insertion by trained provider. Can be done after vaginal delivery (within 10 min of placenta) or C-section (before uterine closure).' },

  /* ═══ FAMILY PLANNING — SET 4 ═══ */
  { topic:'fp', q:'The "two-child norm" in India means:', opts:['Legal punishment for having >2 children','Government incentive schemes encourage 2-child family; no legal ban nationally','Compulsory sterilisation after 2 children','Denial of all government services after 2 children'], ans:1, expl:'India does NOT have a national two-child law. Government promotes 2-child family through incentives (more for those adopting FP after 1 child). Some states have laws barring persons with >2 children from contesting local body elections. National Population Policy 2000 promotes voluntary small family.' },
  { topic:'fp', q:'Copper IUCD contraindication includes:', opts:['Nulliparous women','Pelvic Inflammatory Disease (PID) or unexplained vaginal bleeding','Women >35 years','Women on OCP previously'], ans:1, expl:'Cu-IUCD contraindications: active PID or cervicitis, unexplained vaginal bleeding, pregnancy, uterine anomaly (fibroids distorting cavity), current STI, puerperium with complications. Relative: Wilson\'s disease, severe dysmenorrhoea, copper allergy.' },

  /* ═══ IMMUNIZATION — SET 4 ═══ */
  { topic:'immunize', q:'Meningococcal vaccine protects against which bacteria?', opts:['Streptococcus pneumoniae','Neisseria meningitidis','Haemophilus influenzae','Mycobacterium meningitis'], ans:1, expl:'Meningococcal vaccine: Neisseria meningitidis (types A, C, W135, Y — quadrivalent MenACWY). Not in India\'s UIP (used in high-risk groups, pilgrims to Mecca/Hajj, outbreak control). Type A most common in India\'s meningitis belt.' },
  { topic:'immunize', q:'India\'s Intensified Mission Indradhanush (IMI) targets:', opts:['Only polio vaccination','Full immunisation coverage for children <2 years and pregnant women in low-coverage areas','Adults above 60','Healthcare workers only'], ans:1, expl:'Mission Indradhanush (2014): Catch-up immunisation for UIP vaccines. IMI 1.0 (2017): focused on 190 high-priority districts. IMI 2.0 (2019), IMI 3.0 (2021), IMI 4.0 (2022). Target: >90% full immunisation coverage. Intensive monthly campaigns.' },
  { topic:'immunize', q:'AEFI reporting in India: a serious AEFI should be reported within:', opts:['7 days','24–48 hours to district/state level','1 month','Only at year end'], ans:1, expl:'Serious AEFI (death, hospitalisation, cluster of AEFIs, anaphylaxis) must be reported within 24–48 hours to district immunisation officer. Level 1: facility/sub-district. Level 2: district. Level 3: state. Level 4: national AEFI committee. Causality assessment done at each level.' },

  /* ═══ NUTRITION — SET 4 ═══ */
  { topic:'nutrition', q:'WHO growth standards for children use which reference population?', opts:['American children','UK children','International sample of healthy breastfed children from 6 countries (MGRS study)','Indian children only'], ans:2, expl:'WHO Multicentre Growth Reference Study (MGRS): collected data from 8440 children in 6 countries (Brazil, Ghana, India, Norway, Oman, USA) raised in optimal conditions (breastfed, non-smokers, adequate nutrition). Released 2006. Used globally including India for Z-score based nutrition assessment.' },
  { topic:'nutrition', q:'Anaemia in a 6-year-old child is defined as Hb <:', opts:['13 g/dL','12 g/dL','11.5 g/dL','10 g/dL'], ans:2, expl:'WHO Hb thresholds for anaemia: Children 5–11 years: <11.5 g/dL. Children 12–14 years: <12 g/dL. Non-pregnant women: <12 g/dL. Pregnant women: <11 g/dL. Men: <13 g/dL. Infants 6–59 months: <11 g/dL.' },
  { topic:'nutrition', q:'Mid-Day Meal (PM POSHAN) is provided under which scheme?', opts:['ICDS','PM POSHAN (formerly MDM scheme — National Programme of Nutritional Support to Primary Education)','JSSK','PMMVY'], ans:1, expl:'PM POSHAN Scheme (2021, formerly Mid-Day Meal): cooked hot meal to children in Classes 1–8 of government and government-aided schools. Calorie: 450 kcal (primary), 700 kcal (upper primary). Protein: 12g/20g. Reduces hunger, improves attendance, nutrition.' },
  { topic:'nutrition', q:'Zinc deficiency in children causes:', opts:['Megaloblastic anaemia','Growth retardation, impaired immunity, diarrhoea, skin lesions (acrodermatitis)','Night blindness only','Rickets'], ans:1, expl:'Zinc deficiency: growth retardation (2nd most important micronutrient for growth after protein), immune impairment (more infections), diarrhoea, poor wound healing, acrodermatitis enteropathica (skin lesions around mouth/eyes/genitalia), hypogonadism, anorexia.' },

  /* ═══ COMMUNICABLE DISEASES — SET 4 ═══ */
  { topic:'diseases', q:'Plague is caused by:', opts:['Yersinia pestis (transmitted by rat flea Xenopsylla cheopis)','Salmonella typhi','Vibrio cholerae','Rickettsia species'], ans:0, expl:'Plague: Yersinia pestis (gram-negative bacillus). Vector: rat flea (Xenopsylla cheopis). Reservoir: rats. Types: Bubonic (most common — enlarged inguinal lymph nodes/buboes), Septicaemic, Pneumonic (most deadly — human-to-human airborne). Treatment: Streptomycin or Doxycycline.' },
  { topic:'diseases', q:'Incubation period of rabies is:', opts:['1–3 days','10–90 days (range: 4 days–years; depends on bite site and viral load)','1–2 years always','24 hours'], ans:1, expl:'Rabies incubation: typically 20–90 days (average 1–3 months). Range: 4 days to years. Shorter if bite on face/neck (closer to CNS). Once symptoms appear (furious or dumb rabies) → 100% fatal. Only preventable by PEP before symptom onset.' },
  { topic:'diseases', q:'The National Tuberculosis Elimination Programme (NTEP) replaced RNTCP and aims to eliminate TB by:', opts:['2025 (5 years before global target of 2030)','2030','2035','2050'], ans:0, expl:'India targets TB elimination (incidence <1/million population) by 2025 — 5 years ahead of global SDG target of 2030. RNTCP → renamed NTEP in 2020. Key: Universal Drug Susceptibility Testing (UDST), private sector engagement (Ni-kshay Mitra), DRTB management.' },
  { topic:'diseases', q:'Scrub typhus is transmitted by:', opts:['Body louse','Trombiculid mites (chiggers — larval stage)','Rat flea','Tick'], ans:1, expl:'Scrub typhus: Orientia tsutsugamushi (intracellular bacterium). Vector: Trombiculid mite larvae (chiggers). Classic triad: fever + eschar at bite site + maculopapular rash. Treatment: Doxycycline. Emerging in J&K, Northeast India, Himalayas. Diagnosis: Weil-Felix, ELISA, PCR.' },
  { topic:'diseases', q:'Universal Precautions in healthcare include:', opts:['Only for HIV-positive patients','Treating ALL patient blood/body fluids as potentially infectious regardless of known diagnosis','Only for TB patients','Only hand washing'], ans:1, expl:'Universal Precautions (now "Standard Precautions"): treat ALL blood and body fluids (except sweat) as infectious regardless of patient HIV/hepatitis status. Measures: gloves, mask, gown, eye protection, safe disposal of sharps, hand hygiene. Introduced by CDC 1987 during HIV epidemic.' },

  /* ═══ NCD — SET 4 ═══ */
  { topic:'ncd', q:'Tobacco use cessation advice — the "5 As" approach stands for:', opts:['Ask, Advise, Assess, Assist, Arrange','Assess, Advise, Act, Assist, Apply','Ask, Alert, Advise, Assist, Apply','Awareness, Action, Advice, Assistance, Arrangement'], ans:0, expl:'5 As for tobacco cessation: (1) Ask: screen all patients for tobacco use; (2) Advise: urge all users to quit; (3) Assess: willingness to quit; (4) Assist: provide counselling/NRT; (5) Arrange: follow-up (1 week, 1 month). WHO recommends this framework for brief advice.' },
  { topic:'ncd', q:'NPCDCS screening for cervical cancer uses VIA. Positive VIA means:', opts:['Positive = definitely cancer','Aceto-white areas visible near transformation zone = suspect CIN/early cancer — needs colposcopy/biopsy','Negative result — no follow-up needed','Yellowish discharge present'], ans:1, expl:'VIA (Visual Inspection with 5% Acetic Acid): Positive = distinct aceto-white areas near squamo-columnar junction. Needs colposcopy → biopsy. VIA sensitivity ~70%, specificity ~85%. VILI uses Lugol\'s iodine. Both are low-tech, low-cost screening tools for low-resource settings.' },

  /* ═══ PROGRAMS — SET 4 ═══ */
  { topic:'programs', q:'IMNCI (Integrated Management of Neonatal and Childhood Illness) classifies sick children into:', opts:['Treatment groups A/B/C','Colour-coded classification: pink (outpatient treatment), yellow (inpatient treatment), green (home care)','Severity grades 1–5','Only vaccinated vs. unvaccinated'], ans:1, expl:'IMNCI classification (adaptation of WHO IMCI + neonatal component): Pink/Red = Severe (urgent referral/hospital); Yellow = Non-severe (specific treatment at facility/home); Green = Well (home care + counselling). Covers: pneumonia, diarrhoea, malaria, measles, malnutrition, ear problems in children <5 years.' },
  { topic:'programs', q:'Which is the nodal ministry for NHM (National Health Mission) in India?', opts:['Ministry of Women and Child Development','Ministry of Health and Family Welfare (MoHFW)','NITI Aayog','Ministry of Finance'], ans:1, expl:'NHM is under Ministry of Health and Family Welfare (MoHFW), Government of India. NHM has 2 sub-missions: NRHM (rural) and NUHM (urban). State Health Societies implement NHM with central/state funding (60:40 general states; 90:10 special category states).' },
  { topic:'programs', q:'ASHA incentive for facilitating male sterilisation (vasectomy) under NHM is:', opts:['₹150','₹250','₹300','₹500'], ans:1, expl:'ASHA incentives for FP (NHM): Vasectomy = ₹250; Tubectomy = ₹150 (beyond 2 children) or ₹200 (<=2 children); PPIUCD = ₹150; Interval IUCD = ₹150; PAIUCD = ₹150; Male condom distribution (per packet) = ₹1. In addition to other incentives.' },
  { topic:'programs', q:'The Pradhan Mantri Jan Arogya Yojana (PM-JAY) under Ayushman Bharat covers how many beneficiary families?', opts:['5 crore families','10.74 crore families (~50 crore beneficiaries)','50 crore families','2 crore families'], ans:1, expl:'PM-JAY: 10.74 crore (107.4 million) poorest families = bottom 40% of Indian population (~50 crore beneficiaries). Coverage: ₹5 lakh/family/year for secondary and tertiary hospitalisation. Cashless treatment at empanelled hospitals. Based on SECC 2011 data. Launched 23 Sep 2018.' },

  /* ═══ FIRST AID — SET 4 ═══ */
  { topic:'firstaid', q:'Defibrillation (electric shock) is indicated for:', opts:['All cardiac arrest','Ventricular fibrillation (VF) and pulseless Ventricular Tachycardia (pVT) only','Asystole','Bradycardia'], ans:1, expl:'AED/defibrillation: shockable rhythms = VF (chaotic electrical activity) and pVT (very rapid, no pulse). Non-shockable = Asystole (flat line) and PEA (pulseless electrical activity) — CPR only. CHAIN OF SURVIVAL: call 108 → CPR → AED → advanced care.' },
  { topic:'firstaid', q:'For a diabetic patient found unconscious, first action is:', opts:['Give insulin immediately','Check blood glucose — if low, give sugar/oral glucose if conscious; if unconscious, IV dextrose 25–50%','Give water','Do CPR immediately'], ans:1, expl:'Unconscious diabetic: assume hypoglycaemia (more common emergency than hyperglycaemia). Check glucose if glucometer available. Conscious: sugar drink/biscuits/glucose gel. Unconscious: IV 25–50% dextrose 25–50 mL OR Glucagon 1 mg IM. Then seek medical care.' },

  /* ═══ ANATOMY — SET 4 ═══ */
  { topic:'anatomy', q:'Apgar score component "Grimace" tests:', opts:['Skin colour','Reflex response to stimulation (nasal catheter/rubbing)','Breathing pattern','Heart rate'], ans:1, expl:'APGAR — Grimace = Reflex Irritability: 0 = No response; 1 = Grimace/frown; 2 = Vigorous cry/cough/sneeze. Tested by passing nasal catheter or rubbing soles. Full APGAR: Appearance + Pulse + Grimace + Activity + Respiration. Max = 10.' },
  { topic:'anatomy', q:'The hormone responsible for milk production (galactopoiesis) is:', opts:['Oxytocin','Progesterone','Prolactin (from anterior pituitary)','Oestrogen'], ans:2, expl:'Prolactin (anterior pituitary) = stimulates milk PRODUCTION. Oxytocin (posterior pituitary) = stimulates milk EJECTION (let-down reflex). Suckling stimulates both. Progesterone and oestrogen INHIBIT milk production during pregnancy despite high prolactin.' },
  { topic:'anatomy', q:'Normal range of haematocrit (PCV) in adult women is:', opts:['25–30%','36–46%','50–60%','20–25%'], ans:1, expl:'Haematocrit (PCV — packed cell volume): Adult women 36–46%; Adult men 40–52%; Newborn 44–64% (higher at birth). PCV <36% in women = anaemia. Elevated PCV = polycythaemia (high altitude, COPD, dehydration). PCV ≈ Hb × 3.' },
  { topic:'anatomy', q:'The Rh (Rhesus) factor: an Rh-negative mother carrying an Rh-positive baby risks:', opts:['No risk in first pregnancy','Haemolytic Disease of the Newborn (HDN) — mainly in subsequent Rh+ pregnancies due to maternal IgG antibodies','Only risk in C-section','Risk only if mother is blood group O'], ans:1, expl:'Rh isoimmunisation: Rh-neg mother + Rh-pos baby → foetal Rh+ RBCs enter mother\'s blood (usually at delivery) → mother makes anti-Rh IgG → crosses placenta in subsequent pregnancies → destroys foetal Rh+ RBCs → HDN (hydrops fetalis, jaundice). Prevention: Anti-D immunoglobulin within 72h of delivery/event.' },

  /* ═══ ENVIRONMENT — SET 4 ═══ */
  { topic:'environment', q:'The Minamata disease was caused by:', opts:['Lead poisoning','Mercury (methyl mercury) contamination in water and fish — Japan 1950s','Arsenic in drinking water','Cadmium poisoning'], ans:1, expl:'Minamata disease (Minimata, Japan): methylmercury poisoning from factory waste in Minamata Bay. Fish bioaccumulated mercury → people eating fish developed neurological disease (sensory disturbances, ataxia, vision/hearing loss, tremors). First environmental disease from industrial pollution.' },
  { topic:'environment', q:'Itai-Itai disease was caused by:', opts:['Mercury','Lead','Cadmium contamination from zinc smelting (Japan 1950s)','Arsenic'], ans:2, expl:'Itai-Itai disease (Japan): cadmium (Cd) poisoning from zinc smelting waste in Jinzu River. Bone softening (osteomalacia), renal tubular dysfunction, painful fractures (Itai-Itai = "ouch ouch" in Japanese). Classic occupational/environmental cadmium toxicity case.' },
  { topic:'environment', q:'WHO definition of health (1948) is:', opts:['Absence of disease','A state of complete physical, mental and social well-being — NOT merely the absence of disease or infirmity','Good physical fitness only','Ability to work productively'], ans:1, expl:'WHO 1948 definition: "Health is a state of complete physical, mental and social well-being and not merely the absence of disease or infirmity." Holistic concept. Spiritual dimension added later. Social determinants of health: education, income, housing, employment, social support.' },
  { topic:'environment', q:'Biomedical waste segregation: liquid waste (blood, body fluids) should be disinfected with:', opts:['Bleaching powder 1% (chlorine 5000 ppm) for 30 min contact time','Boiling only','UV light','Nothing needed'], ans:0, expl:'Liquid biomedical waste (blood, body fluids, secretions): disinfect with 1% bleaching powder (or 5000 ppm sodium hypochlorite) for 30 minutes, then drain into sewer. Sharps: hub-cutter at point of use → white container. Solid contaminated waste → yellow bag → incineration.' },

  /* ═══ STATS — SET 4 ═══ */
  { topic:'stats', q:'The "epidemiological triad" consists of:', opts:['Agent, Host, Vector','Agent, Host, Environment','Incubation, Transmission, Recovery','Infection, Disease, Death'], ans:1, expl:'Epidemiological triad (classic model): Agent (causative organism/factor) + Host (susceptible individual) + Environment (facilitating factors). Disease occurs when balance is disturbed. For NCDs: expanded to web of causation (multiple interacting factors).' },
  { topic:'stats', q:'Surveillance in public health means:', opts:['Watching patients in hospital','Ongoing systematic collection, analysis, and interpretation of health data for planning and action','Investigating outbreaks only','Annual health survey'], ans:1, expl:'Surveillance = "Information for Action." Ongoing, systematic: collection → analysis → interpretation → dissemination → action. Types: passive (routine reporting), active (case-finding), sentinel, syndromic. India: IDSP (Integrated Disease Surveillance Programme) coordinates national surveillance.' },
  { topic:'stats', q:'The Maternal Mortality Ratio (MMR) India target under SDG 3 is:', opts:['<10 per 1,00,000 live births','<70 per 1,00,000 live births by 2030','<200 per 1,00,000','<50 per 1,00,000'], ans:1, expl:'SDG 3.1: Reduce global MMR to <70 per 1,00,000 live births by 2030. India NHP 2017 target: MMR <100 by 2020 (achieved: MMR = 97, SRS 2018–20). India MMR decline: 254 (2004–06) → 97 (2018–20) — significant progress.' },

  /* ═══ DRUG — SET 4 ═══ */
  { topic:'drug', q:'Hepatitis B vaccination schedule in infants (EPI/UIP schedule) is:', opts:['Only 1 dose at birth','0, 1, 6 months (3 doses)','3 doses via Pentavalent at 6, 10, 14 weeks (+ birth dose = 4 doses total)','Annual dose'], ans:2, expl:'India UIP HepB schedule: Dose 0 at birth (within 24h, monovalent HepB) + 3 doses via Pentavalent vaccine at 6, 10, 14 weeks = total 4 doses. Birth dose critical for MTCT prevention. Anti-HBs ≥10 mIU/mL = protective (check in high-risk groups).' },
  { topic:'drug', q:'Digoxin toxicity signs include:', opts:['Hypertension, bradycardia, yellow-green vision (xanthopsia)','Only tachycardia','Only nausea','Hypoglycaemia'], ans:0, expl:'Digoxin toxicity (narrow therapeutic index): GI (nausea, vomiting, anorexia), cardiac (bradycardia, heart block, ventricular arrhythmias), CNS (confusion, fatigue), visual (xanthopsia = yellow-green tinging of vision, halos). Toxicity enhanced by hypokalaemia (diuretics). Antidote: Digoxin-specific Fab antibodies.' },
  { topic:'drug', q:'Which drug is used to treat scabies?', opts:['Permethrin 5% cream (drug of choice) or oral Ivermectin','Gentian violet','Calamine lotion','Clotrimazole cream'], ans:0, expl:'Scabies (Sarcoptes scabiei mite): Permethrin 5% cream applied to whole body (neck to toe) overnight, wash off in morning — first-line. Repeat after 1 week. Oral Ivermectin (200 mcg/kg) = alternative, especially for crusted scabies or large outbreaks. All household contacts treated simultaneously.' },
  { topic:'drug', q:'ORS should NOT be used in which condition?', opts:['Mild diarrhoea','Profuse watery diarrhoea','Paralytic ileus (no bowel sounds, distension) or persistent vomiting preventing oral intake','Moderate dehydration'], ans:2, expl:'ORS contraindications: paralytic ileus (absent bowel sounds, abdominal distension), intractable vomiting (can\'t retain fluid orally), unconsciousness. In these cases: IV Ringer\'s Lactate (Plan C). ORS = first-line for all other dehydration (mild, moderate, severe if can drink).' },
  { topic:'drug', q:'Dose of Vitamin A given to a child aged 12–59 months is:', opts:['50,000 IU','1,00,000 IU','2,00,000 IU','5,00,000 IU'], ans:2, expl:'Vitamin A supplementation (VAS): 9 months: 1,00,000 IU (with MR vaccine); 12 months onwards every 6 months until 5 years: 2,00,000 IU. For VAD treatment: 2,00,000 IU on Day 1, Day 2, and Day 14. SAM children with VAD: same therapeutic dose.' },
  { topic:'drug', q:'Metronidazole (Flagyl) is the drug of choice for:', opts:['Malaria','Amoebiasis, giardiasis, anaerobic infections, trichomoniasis','Tuberculosis','Fungal infections'], ans:1, expl:'Metronidazole: intestinal amoebiasis, amoebic liver abscess, giardiasis, trichomoniasis, anaerobic bacterial infections (BV, C. difficile, dental infections). Mechanism: nitroreduction by anaerobes/parasites → toxic metabolites damage DNA. Avoid alcohol (disulfiram-like reaction). Safe in 2nd/3rd trimester pregnancy.' },

  /* ═══ FINAL BATCH — HIGH-YIELD MIXED ═══ */
  { topic:'mch', q:'Under RMNCH+A strategy, the target for institutional delivery rate is:', opts:['50%','75%','90% and above','100%'], ans:2, expl:'India\'s target under NHM/RMNCH+A: ≥90% institutional deliveries. India achieved ~89% (NFHS-5). Institutional delivery reduces maternal and neonatal mortality by ensuring skilled birth attendance, emergency obstetric care, and immediate newborn care.' },
  { topic:'mch', q:'Symphysiotomy is performed when:', opts:['Normal delivery expected','Obstructed labour due to cephalopelvic disproportion where C-section not feasible','PPH management','Placenta praevia'], ans:1, expl:'Symphysiotomy = surgical division of pubic symphysis to widen pelvis in obstructed labour when C-section not possible (remote area, no anaesthesia). Increases pelvic diameter 1.5–2 cm. Rarely used now. Complications: urinary tract injury, pain, walking difficulty.' },
  { topic:'fp', q:'A woman who has had tubectomy can resume sexual activity after:', opts:['2 days','2 weeks (after wound heals)','3 months','6 months'], ans:1, expl:'After tubectomy: wound healing ~1 week; resume sexual intercourse after ~2 weeks (once wound healed). No effect on libido, hormone levels, or menstruation. Immediate and permanent protection against pregnancy. Failure rate <0.5/100 woman-years.' },
  { topic:'immunize', q:'Number of antigens in Pentavalent vaccine:', opts:['3','4','5','6'], ans:2, expl:'Pentavalent = 5 antigens: Diphtheria toxoid + Pertussis (killed) + Tetanus toxoid + Hepatitis B (HBsAg) + Hib (Haemophilus influenzae type b polysaccharide conjugate). 0.5 mL IM. Replaces DPT + HepB + Hib as separate injections — reduces total injections.' },
  { topic:'nutrition', q:'India\'s National Iodine Deficiency Disorders Control Programme aims for:', opts:['100% iodised salt at 15 ppm','Universal Salt Iodisation (30 ppm at production, 15 ppm at consumer level)','Iodine tablets for all','Iodine injection annually'], ans:1, expl:'NIDDCP (National Iodine Deficiency Disorders Control Programme) = universal salt iodisation (USI). Ban on non-iodised salt. Goal: IDD elimination in all districts. India has made great progress; some pockets in Himalayan states remain deficient.' },
  { topic:'diseases', q:'The causative organism of syphilis is:', opts:['Neisseria gonorrhoeae','Treponema pallidum','Chlamydia trachomatis','Haemophilus ducreyi'], ans:1, expl:'Syphilis: Treponema pallidum (spirochaete). Stages: Primary (painless chancre), Secondary (rash on palms/soles, condylomata lata), Latent, Tertiary (gumma, CVS, neuro). Congenital syphilis. Diagnosis: VDRL (screening); TPHA/FTA-ABS (confirmatory). Treatment: Penicillin G.' },
  { topic:'diseases', q:'Gonorrhoea in pregnancy, if untreated, can cause:', opts:['Congenital rubella syndrome','Ophthalmia neonatorum (gonococcal conjunctivitis) in newborn','Neural tube defects','LBW only'], ans:1, expl:'Gonorrhoea (Neisseria gonorrhoeae): infects newborn eyes during vaginal delivery → gonococcal ophthalmia neonatorum (purulent discharge 2–5 days after birth). Prevention: prophylactic eye drops (1% silver nitrate, or tetracycline/erythromycin eye ointment) at birth. Untreated → blindness.' },
  { topic:'ncd', q:'The NTCP (National Tobacco Control Programme) includes:', opts:['Only smoking cessation clinics','Tobacco taxation, public awareness, smoking bans (COTPA), cessation services, monitoring','Only advertising bans','Only enforcement'], ans:1, expl:'NTCP (2007): Comprehensive tobacco control using MPOWER framework (WHO): Monitor use, Protect from smoke, Offer cessation, Warn about dangers, Enforce bans on advertising, Raise taxes. India\'s COTPA 2003: ban on smoking in public places, no advertising, pictorial health warnings.' },
  { topic:'programs', q:'RBSK (Rashtriya Bal Swasthya Karyakram) provides health screening for children aged:', opts:['0–6 years at AWCs and 6–18 years at schools','Only 6–18 years','Only 0–1 year','Only at birth'], ans:0, expl:'RBSK (2013): health screening and early intervention for children 0–18 years. 0–6 years at AWC/home visits; 6–18 years at government schools. Screens for 4 Ds: Defects at birth, Diseases, Deficiencies, Development delays and Disabilities. Referral to DEIC (District Early Intervention Centre).' },
  { topic:'programs', q:'Under NHM, ASHAs must complete which training?', opts:['No training required','7 modules of training (total ~23 days) with regular refresher training','Only 1-day orientation','Only for family planning topics'], ans:1, expl:'ASHA training: 7 modules (Health communication; MCH; Family planning; Immunisation; Common illness; RMNCH+A; Social mobilisation). Total ~23 days in phased manner. Training conducted by ANM/LHV/PHC MO. ASHA certification exam in some states. Refresher training regularly.' },
  { topic:'firstaid', q:'For a patient with suspected myocardial infarction (heart attack) in the community, first aid includes:', opts:['Give nothing and wait for ambulance','Call emergency services + make patient comfortable (semi-reclined) + aspirin 300 mg if no allergy + early defibrillation if arrested','Give water only','Vigorous exercise to improve circulation'], ans:1, expl:'MI first aid: (1) Call emergency/108; (2) Patient sits or semi-reclines comfortably; (3) Aspirin 300 mg chewed (antiplatelet); (4) Sublingual GTN if available and not hypotensive; (5) CPR + AED if cardiac arrest. Time is muscle — STEMI: PCI within 90 min.' },
  { topic:'firstaid', q:'Correct management of epistaxis (nosebleed) is:', opts:['Tilt head back and pinch nose','Lean forward slightly, pinch soft part of nose for 10–15 minutes, breathe through mouth','Blow nose vigorously','Apply cold compress to back of neck only'], ans:1, expl:'Epistaxis first aid: Sit UPRIGHT and lean FORWARD (prevents blood going to throat → vomiting/aspiration). Pinch soft part of nose (not bony part) continuously for 10–15 minutes. Breathe through mouth. Ice pack on nose bridge. If bleeding >20 min or recurrent → medical attention.' },
  { topic:'anatomy', q:'The pituitary gland ("master gland") is located:', opts:['In the neck','In the sella turcica of the sphenoid bone (base of brain)','In the abdomen','Behind the sternum'], ans:1, expl:'Pituitary gland = "master gland" = in sella turcica (hypophyseal fossa) of sphenoid bone. Anterior pituitary (adenohypophysis): GH, TSH, ACTH, FSH, LH, prolactin. Posterior pituitary (neurohypophysis): oxytocin, ADH (vasopressin) — produced in hypothalamus, stored/released in posterior pituitary.' },
  { topic:'anatomy', q:'The hormone oestrogen is primarily produced by:', opts:['Adrenal gland','Ovarian follicles (theca and granulosa cells)','Thyroid gland','Pituitary gland'], ans:1, expl:'Oestrogen (oestradiol, oestrone, oestriol): primarily produced by granulosa cells of ovarian follicles (under FSH stimulation). Also produced by: placenta (oestriol — pregnancy marker), adrenal cortex, adipose tissue (oestrone). Functions: endometrial proliferation, secondary sexual characteristics, bone protection.' },
  { topic:'environment', q:'The greenhouse gas most responsible for global warming is:', opts:['Oxygen','Carbon Dioxide (CO2) — responsible for ~64% of enhanced greenhouse effect','Nitrogen','Argon'], ans:1, expl:'CO2 = most important greenhouse gas for global warming (64% contribution) due to sheer volume from fossil fuel combustion. Other GHGs: methane (CH4, 17%), nitrous oxide (N2O, 6%), fluorinated gases. Water vapour is most abundant natural GHG but not directly human-caused.' },
  { topic:'stats', q:'Randomised Controlled Trial (RCT) is considered the gold standard for:', opts:['Disease prevalence studies','Evaluating effectiveness of interventions (treatments, vaccines, programmes)','Measuring disease burden','Assessing risk factors retrospectively'], ans:1, expl:'RCT = gold standard for causal inference in intervention studies. Random allocation eliminates selection bias; blinding reduces measurement bias. Measures: RR, ARR, NNT, RRR. Hierarchy of evidence: Meta-analysis/SR > RCT > Cohort > Case-control > Cross-sectional > Case reports.' },
  { topic:'stats', q:'Under-5 Mortality Rate (U5MR) in India as per NFHS-5 (2019-21) is:', opts:['10/1000','32/1000 live births','50/1000','75/1000'], ans:1, expl:'U5MR (NFHS-5, 2019-21) = 32 per 1000 live births. Neonatal (0–28 days) = 24.9; Post-neonatal = 7.1. Rural = 36; Urban = 21. SDG target: U5MR ≤25 by 2030. Main causes: preterm birth, birth asphyxia, pneumonia, diarrhoea, malnutrition.' },
  { topic:'drug', q:'Antenatal corticosteroids (Betamethasone/Dexamethasone) in preterm labour are given to:', opts:['Reduce maternal blood pressure','Accelerate foetal lung maturity (surfactant production) and reduce neonatal RDS in preterm babies','Prevent PPH','Stop uterine contractions'], ans:1, expl:'Antenatal corticosteroids: Betamethasone 12 mg IM × 2 doses 24h apart (or Dexamethasone 6 mg × 4 doses 12h apart). Given at 24–34 weeks when preterm birth expected within 7 days. Reduces: RDS (respiratory distress syndrome), IVH, NEC, neonatal death by 30–50%.' },
  { topic:'drug', q:'Oral Rehydration Therapy (ORT) principle is based on:', opts:['Antibiotics kill the causative organism','Sodium-glucose co-transport in the gut actively absorbs water even during diarrhoea (works even when diarrhoea secretory)','Sugar prevents dehydration','Rice water is sufficient'], ans:1, expl:'ORT principle: sodium-glucose co-transporter (SGLT1) in intestinal epithelium couples Na+ and glucose absorption. This transporter functions EVEN in secretory diarrhoea when other Na+ absorption is impaired. Co-absorption of glucose + Na+ → water follows osmotically → rehydration.' },
  { topic:'mch', q:'WHO\'s "Baby-Friendly Hospital Initiative" (BFHI) promotes:', opts:['Formula feeding','10 steps to successful breastfeeding — exclusive breastfeeding support in hospitals','Mixed feeding','Early introduction of solid foods'], ans:1, expl:'BFHI (WHO/UNICEF 1991): 10 steps including: written breastfeeding policy; staff training; colostrum feeding; rooming-in; breastfeeding on demand; no pacifiers/artificial teats; no free formula samples. Hospitals certified as "Baby-Friendly" if they follow all 10 steps.' },
  { topic:'immunize', q:'The "Universal Immunisation Programme" (UIP) in India was launched in:', opts:['1974','1978','1985','1992'], ans:2, expl:'UIP launched in India 1985 (expanded from EPI of 1978 which itself started in 1974 as pilot). UIP initially covered 6 diseases: TB, diphtheria, pertussis, tetanus, polio, typhoid (typhoid dropped later). Now covers 12 diseases. Goal: full immunisation of every child <1 year.' },
  { topic:'nutrition', q:'Growth monitoring of children is done using:', opts:['Road-to-Health Card (growth chart with weight-for-age)','Blood test only','Urine test','X-ray of bones'], ans:0, expl:'Growth monitoring: weight plotted on Road-to-Health Chart (growth chart). Below reference line = underweight. Flat line = faltering. Done monthly 0–12 months, then 3-monthly. ICDS AWW weighs children at AWC. WHO growth charts used from 2007 (replacing NCHS charts).' },
  { topic:'diseases', q:'Respiratory hygiene/cough etiquette includes:', opts:['Coughing into open air','Cover mouth and nose with tissue/elbow when coughing/sneezing; dispose tissue; hand hygiene','Only wear surgical mask at home','Cough into hands and continue work'], ans:1, expl:'Respiratory hygiene: cover mouth/nose with tissue or inside of elbow (not hands) when coughing/sneezing; dispose used tissue in bin; perform hand hygiene immediately. Reduces spread of respiratory infections (TB, influenza, COVID-19, whooping cough).' },
  { topic:'ncd', q:'Chronic Obstructive Pulmonary Disease (COPD) is primarily caused by:', opts:['Viral infection','Long-term exposure to tobacco smoke and air pollutants (biomass fuel in India)','Genetic causes alone','Bacterial infection'], ans:1, expl:'COPD: irreversible airflow limitation. Main cause in India: tobacco smoking (40%) + biomass fuel combustion (indoor air pollution from cooking — chulha/firewood) especially in rural women. Symptoms: chronic cough, sputum, progressive dyspnoea. Diagnosed by spirometry (FEV1/FVC <0.7).' },
  { topic:'programs', q:'SNEHEE (Sabhi Nasha Harein, Employ & Empower) is related to:', opts:['TB control','School nutrition','Substance abuse de-addiction and rehabilitation','Adolescent health only'], ans:2, expl:'Substance use/addiction control is addressed under NMHP (National Mental Health Programme) and Ministry of Social Justice\'s National Action Plan for Drug Demand Reduction (NAPDDR). Mental health and de-addiction services integrated into HWCs (Health & Wellness Centres) under Ayushman Bharat.' },
  { topic:'firstaid', q:'For a patient with suspected stroke (FAST signs), correct action is:', opts:['Wait to see if symptoms resolve','Call emergency services immediately — "Time is brain" — get to hospital for thrombolysis within 4.5 hours','Give aspirin and observe at home','Make patient exercise'], ans:1, expl:'FAST: Face drooping, Arm weakness, Speech difficulty, Time to call emergency. Ischaemic stroke: IV thrombolysis (tPA) within 4.5 hours of symptom onset. Every 1 minute of stroke = 1.9 million neurons lost. "Time is brain." Do NOT give aspirin without CT scan (may be haemorrhagic).' },
  { topic:'anatomy', q:'Colostrum differs from mature breast milk in that it contains:', opts:['More carbohydrates and less protein','More protein, IgA, white cells; less fat and lactose; yellowish colour','Same composition but less volume','More fat only'], ans:1, expl:'Colostrum (days 1–3): yellowish, thick, small volume (2–20 mL/feed). HIGH protein (especially secretory IgA — passive immunity), lactoferrin, leukocytes, growth factors, Vitamin A. LOW fat and lactose. Transitional milk (day 4–14) → mature milk (Day 14+) has more fat and lactose.' },
  { topic:'environment', q:'The recommended household toilet coverage to achieve ODF (Open Defecation Free) status under SBM is:', opts:['50% households','75% households','100% of households have and USE toilets','Only above poverty line families'], ans:2, expl:'ODF = 100% of population defecating in toilets/latrines — NO open defecation. SBM goal: build toilets + ensure usage behaviour change. India declared ODF in Oct 2019 (self-declared by all states). ODF+ includes hand washing with soap. Community-Led Total Sanitation (CLTS) approach used.' },
  { topic:'stats', q:'Which study design best establishes causality?', opts:['Cross-sectional study','Case-control study','Randomised Controlled Trial (RCT)','Case report'], ans:2, expl:'Hierarchy of evidence for causality: RCT (gold standard) > Cohort study > Case-control > Cross-sectional > Case report/series > Expert opinion. RCT eliminates confounding through randomisation; allows temporal sequence (cause precedes effect); controls bias. Meta-analysis of multiple RCTs = highest level.' },
  { topic:'drug', q:'The correct dose of oral Vitamin A for treatment of measles in a child 12–59 months is:', opts:['50,000 IU','1,00,000 IU','2,00,000 IU × 2 days','2,00,000 IU once only'], ans:2, expl:'WHO recommendation for Vitamin A in measles (all children): 2,00,000 IU/day for 2 days. Reduces measles mortality and complications (corneal ulceration, pneumonia). Give to all measles cases regardless of VAD status. Also given in acute diarrhoea in malnourished children.' },

  /* ═══ NURSING PROCEDURES ═══ */
  { topic:'firstaid', q:'Autoclave sterilisation uses steam under pressure at:', opts:['100°C for 30 min','121°C at 15 psi for 15–20 minutes','150°C for 5 min','80°C for 1 hour'], ans:1, expl:'Autoclave (moist heat sterilisation): 121°C at 15 lbs/sq in (psi) for 15–20 minutes OR 134°C at 30 psi for 3 min. Kills all microorganisms including spores. Used for: surgical instruments, dressings, linens, rubber gloves. GOLD STANDARD of sterilisation.' },
  { topic:'firstaid', q:'The recommended hand-washing duration (WHO/CDC) with soap and water is:', opts:['5 seconds','10 seconds','40–60 seconds','5 minutes'], ans:2, expl:'WHO 6-step hand hygiene technique with soap and water: minimum 40–60 seconds. With alcohol-based hand rub (ABHR): 20–30 seconds. 5 moments of hand hygiene: before patient contact, before aseptic procedure, after body fluid exposure, after patient contact, after touching patient surroundings.' },
  { topic:'firstaid', q:'Intramuscular (IM) injection in adults is given at:', opts:['Inner forearm','Anterolateral thigh or deltoid muscle','Finger tip','Back of hand'], ans:1, expl:'IM injection sites: Deltoid (upper arm — for vaccines, small volumes <2 mL); Vastus lateralis/anterolateral thigh (infants); Ventrogluteal (hip — safest IM site for adults, no major nerves/vessels); Dorsogluteal (buttock — risk of sciatic nerve injury, now less preferred). Needle: 21–23G, 1–1.5 inch.' },
  { topic:'firstaid', q:'Subcutaneous (SC) injection is given at an angle of:', opts:['10–15°','30°','45–90° (depending on tissue and needle length)','180°'], ans:2, expl:'SC injection: 45° angle for thin patients (short needle/limited fat); 90° for obese patients. Sites: abdomen (best absorption), outer upper arm, anterior thigh. Volume ≤1 mL. Examples: insulin, heparin, some vaccines (MR). Aspiration NOT recommended for SC.' },
  { topic:'firstaid', q:'A sterile field during a procedure becomes contaminated when:', opts:['A sterile item touches another sterile item','Sterile gloves touch a non-sterile surface or a non-sterile item is placed in the field','Sterile drapes are placed on the patient','Double gloving is done'], ans:1, expl:'Sterile field principles: contaminated if: sterile touches non-sterile; field becomes wet/moist (capillary action draws bacteria); sterile field left unattended; reaches out of view; expiry date passed; packaging is torn/wet. "When in doubt, throw it out."' },
  { topic:'firstaid', q:'Vital signs monitoring — which should be checked first in an emergency?', opts:['Temperature','Blood pressure','Airway, breathing, and pulse (ABC/CAB — circulation, airway, breathing)','Blood glucose'], ans:2, expl:'Emergency priority: CAB (Circulation-Airway-Breathing) per AHA 2010 guidelines, or ABCDE approach. Airway: patent? Breathing: rate, effort, oxygen saturation. Circulation: pulse, BP, perfusion. Disability: GCS, pupils. Exposure: look for injuries. DRSABC for community BLS.' },
  { topic:'firstaid', q:'Nasogastric (NG) tube insertion — correct position is confirmed by:', opts:['Patient says they can feel it','Auscultating air insufflated through tube over epigastrium (+ pH <5, X-ray)','Colour of tube','Length of tube inserted alone'], ans:1, expl:'NG tube position confirmation: (1) pH of aspirate <5 = gastric; (2) Auscultation of air over epigastrium (less reliable but commonly done); (3) Chest X-ray (gold standard if doubt). NEVER feed through NG without confirming position — misplacement into lung → aspiration pneumonia.' },
  { topic:'firstaid', q:'Sponge bath is given to a febrile patient using water at:', opts:['Ice cold water (0–5°C)','Tepid water (29–32°C / lukewarm)','Hot water (45°C)','Normal tap water at any temperature'], ans:1, expl:'Tepid sponge bath: lukewarm water (29–32°C, slightly below body temp) applied to body. Evaporation cools the patient. Do NOT use ice/cold water (causes vasoconstriction, shivering → raises temperature). Used when fever >38.5°C, especially in children not tolerating antipyretics.' },
  { topic:'firstaid', q:'The correct way to measure a patient\'s weight for clinical purposes:', opts:['With shoes on, heavy clothing','In morning, after urination, light/no clothing, calibrated scale','Any time of day, no preparation','Standing on any surface'], ans:1, expl:'Standardised weight measurement: morning, after voiding urine, before breakfast, in light clothing/underwear only, on calibrated scale on flat floor. Compare at same time of day. Important for: drug dosing, nutritional assessment, monitoring oedema, BMI calculation.' },
  { topic:'firstaid', q:'Catheter care for urinary catheter includes:', opts:['Change catheter daily','Maintain closed drainage, keep bag below bladder, clean meatus daily, change only when blocked/infected/≥4 weeks','Remove after each use and reinsert','Keep drainage bag higher than bladder'], ans:1, expl:'Urinary catheter care: (1) Closed drainage system; (2) Bag BELOW bladder (prevents reflux); (3) Clean urethral meatus with soap/water daily; (4) Adequate hydration; (5) Change if blocked, infected, or per manufacturer (Foley: 4–12 weeks); (6) Remove ASAP to prevent CAUTI (catheter-associated UTI).' },

  /* ═══ MENTAL HEALTH ═══ */
  { topic:'ncd', q:'The most common mental disorder globally is:', opts:['Schizophrenia','Bipolar disorder','Depression (major depressive disorder)','OCD'], ans:2, expl:'Depression = most common mental disorder globally (WHO: 280 million people). Leading cause of disability. Symptoms: persistent sadness, loss of interest/pleasure (anhedonia), fatigue, poor concentration, sleep disturbance, suicidal ideation ≥2 weeks. Treatment: psychotherapy + antidepressants (SSRIs first-line).' },
  { topic:'ncd', q:'Schizophrenia is characterised by:', opts:['Only depression and anxiety','Positive symptoms (hallucinations, delusions, disorganised speech) and negative symptoms (flat affect, alogia, avolition)','Only memory loss','Only suicidal ideation'], ans:1, expl:'Schizophrenia: Positive symptoms (excess/distortion of normal functions): hallucinations (auditory most common), delusions, disorganised thought, catatonia. Negative symptoms (loss of normal functions): flat affect, poverty of speech (alogia), avolition (lack of motivation), anhedonia, social withdrawal. Duration ≥6 months.' },
  { topic:'ncd', q:'NMHP (National Mental Health Programme) was launched in India in:', opts:['1975','1982','1996','2001'], ans:1, expl:'NMHP launched 1982. Objectives: reduce mental illness burden, ensure essential mental healthcare for all. District Mental Health Programme (DMHP) started 1996 (Bellary, Karnataka). Mental Healthcare Act 2017: rights-based approach, decriminalised suicide attempt, free mental health treatment at government hospitals.' },
  { topic:'ncd', q:'The PHQ-9 is a validated tool for screening:', opts:['Anxiety disorders','Depression severity (9 questions from DSM criteria)','Psychosis','Dementia'], ans:1, expl:'PHQ-9 (Patient Health Questionnaire-9): 9 items assessing DSM-5 depression criteria over past 2 weeks. Score 0–27: 1–4 minimal; 5–9 mild; 10–14 moderate; 15–19 moderately severe; 20–27 severe. Used at HWC/primary care level for depression screening. PHQ-2 = ultra-brief 2-question screen.' },
  { topic:'ncd', q:'Suicide prevention includes which key action at community level?', opts:['Ignore people expressing suicidal ideas','Means restriction, gatekeeper training, crisis helplines, follow-up after attempt (iCall, Vandrevala helpline)','Only hospitalisation','Prescribe antidepressants without counselling'], ans:1, expl:'Suicide prevention strategies (WHO LIVE LIFE): restrict access to means (pesticides, drugs); interact with media for responsible reporting; foster life skills in adolescents; identify and manage at-risk persons. India: iCall (9152987821), Vandrevala Foundation (1860-2662-345), NIMHANS SNEHI (080-46110007). Mental Healthcare Act 2017: attempt not a crime.' },
  { topic:'ncd', q:'Alcohol use disorder: the CAGE questionnaire screens with 4 questions. CAGE stands for:', opts:['Cut down, Annoyed, Guilty, Eye-opener (morning drink)','Craving, Anxiety, Guilt, Exhaustion','Consuming, Abstaining, Gaining, Ending','Count, Assess, Grade, Eliminate'], ans:0, expl:'CAGE questionnaire (4 questions): C = Have you ever felt you should Cut down? A = Have people Annoyed you by criticising your drinking? G = Have you ever felt Guilty about drinking? E = Eye-opener: have you ever had a drink first thing in morning? ≥2 "Yes" = significant alcohol problem. Sensitivity 71–93%.' },

  /* ═══ HEALTH EDUCATION & COMMUNICATION ═══ */
  { topic:'programs', q:'IEC stands for:', opts:['Information, Education, Communication','Integrated Environment Control','Immunisation and Epidemic Control','Individual Education Campaign'], ans:0, expl:'IEC = Information, Education, Communication. BCC = Behaviour Change Communication (more action-oriented). IEC/BCC are key NHM components. Methods: interpersonal communication, group education, mass media (radio/TV/posters), social mobilisation, printed materials.' },
  { topic:'programs', q:'The best method of health education for illiterate communities is:', opts:['Printed leaflets','Demonstration, role-play, and folk media (street plays, songs, puppets)','Formal lectures','Written notices'], ans:1, expl:'For illiterate/low-literacy communities: demonstration (seeing and doing), role-play (practice skills), folk media (street theatre/nukkad natak, puppet shows, songs — culturally familiar), flannel graph, flip charts with pictures. Printed text is ineffective. Audio-visual + participatory methods are best.' },
  { topic:'programs', q:'One-to-one counselling in health education is most effective because:', opts:['Cheapest method','Addresses individual concerns, provides personalised advice, ensures two-way communication, highest retention','Quickest to deliver','Requires no skill'], ans:1, expl:'One-to-one (interpersonal) communication: most effective — addresses specific individual needs, allows feedback, clarifies doubts, builds trust. Used for: family planning counselling, HIV testing, chronic disease management, ANC counselling. Requires trained counsellor. Most resource-intensive per person.' },
  { topic:'programs', q:'ASHA\'s primary role as a "link worker" means she:', opts:['Provides medical treatment','Bridges the gap between community and formal health services by mobilising, educating, and facilitating access','Replaces the ANM','Works only in hospitals'], ans:1, expl:'ASHA as link worker/community health activist: (1) Mobilises community for health services; (2) Provides information on health entitlements; (3) Escorts beneficiaries to health facilities; (4) Provides basic preventive/promotive care (ORS, contraceptives, IFA); (5) Feeds back community concerns to health system.' },
  { topic:'programs', q:'The "flip chart" is an audio-visual aid used during health education because:', opts:['It plays recorded audio','Provides sequential visual messages that can be shown one at a time during group education','It is a type of computer software','Used for individual counselling only'], ans:1, expl:'Flip chart: a series of large cards/charts bound at top. Each page = one key message with pictures + text. Turned (flipped) one by one. Benefits: portable, reusable, good for illiterate/semi-literate groups, guides the educator through key messages. Used by ASHA/ANM/AWW during group health education sessions.' },

  /* ═══ DOMICILIARY MIDWIFERY ═══ */
  { topic:'mch', q:'Domiciliary (home) delivery requires MINIMUM essential equipment including:', opts:['Full operation theatre','Clean delivery kit (CDK): blade, cord clamp/tie, plastic sheet, gloves, soap, mucus extractor','Only oxytocin','Ultrasound machine'], ans:1, expl:'Clean Delivery Kit (CDK) for home birth: sterile blade (cord cutting), cord clamp/tie, plastic sheet (clean surface), soap (handwashing), sterile gloves. CDKs distributed under NHM/ASHA kit. Safe home delivery = clean hands, clean surface, clean cord cut, clean cord tie.' },
  { topic:'mch', q:'Under NHM, what happens if delivery happens at home without skilled birth attendant?', opts:['No benefit','ASHA still gets incentive and must provide immediate newborn care; case registered for JSSK if at-risk','Criminal offence','Only doctor visit needed'], ans:1, expl:'Home delivery without SBA: ASHA must be informed, visit within 24 hours, assess mother and newborn, provide essential newborn care, register newborn, begin HBNC (Home Based Newborn Care) visits on Day 3, 7, 14, 28. If complications: refer to hospital. India target: reduce home deliveries below 10%.' },
  { topic:'mch', q:'Signs of placental separation after delivery of baby include all EXCEPT:', opts:['Uterus becomes globular and firm','Lengthening of umbilical cord','Fresh bleeding from vagina','Hardening of cervix (cervical Os closes)'], ans:3, expl:'Signs of placental separation (Brandt-Andrews): (1) Uterus becomes globular/hard (contracts); (2) Cord lengthens at vulva; (3) Gush of fresh blood; (4) Uterus rises in abdomen. Cervical hardening is NOT a sign. Average time: 5–15 min after baby delivery. Placenta retained >30 min = abnormal.' },
  { topic:'mch', q:'Immediate newborn care "IMNCI-ENBC" includes all of the following EXCEPT:', opts:['Immediate drying and warming','Delayed cord clamping 1–3 minutes','Breastfeeding within 1 hour','Routine suctioning of all newborns'], ans:3, expl:'Essential Newborn Care: (1) Dry immediately, replace wet linen; (2) Delayed cord clamping 1–3 min; (3) Skin-to-skin/KMC; (4) Breastfeeding within 1 hour (colostrum); (5) BCG + OPV-0 + HepB-0. Routine suctioning NOT recommended unless meconium-stained liquor with depressed baby. Causes bradycardia, trauma.' },
  { topic:'mch', q:'Cord care in newborn: WHO recommends for term newborns in high-income countries:', opts:['Apply antiseptic (iodine/spirit)','Apply chlorhexidine 7.1% gel','Dry cord care (keep dry, clean, no application)','Apply oil'], ans:2, expl:'WHO 2014: Dry cord care (keep dry, expose to air) recommended for term newborns in settings with low neonatal mortality risk. Chlorhexidine 7.1% gel applied once recommended in settings with high risk of omphalitis (neonatal sepsis through cord). India (high-burden): chlorhexidine recommended at birth and for 3 days.' },
  { topic:'mch', q:'Normal duration of third stage of labour (delivery of placenta) is:', opts:['1–2 minutes','5–30 minutes (up to 30 min = normal)','1–2 hours','More than 2 hours'], ans:1, expl:'Third stage = delivery of placenta + membranes. Normal: 5–30 minutes. Active management (AMTSL with oxytocin) reduces this to ~7 minutes and prevents PPH. Retained placenta = third stage >30 min → manual removal under anaesthesia. Most blood loss occurs in third stage.' },

  /* ═══ ANATOMY — NERVOUS SYSTEM ═══ */
  { topic:'anatomy', q:'The cerebrum is responsible for:', opts:['Breathing control only','Higher functions: consciousness, intelligence, memory, emotion, voluntary movement, sensory interpretation','Heart rate only','Hormone production'], ans:1, expl:'Cerebrum (largest brain part): divided into 4 lobes: Frontal (motor, personality, speech/Broca), Parietal (sensory, spatial), Temporal (hearing, memory, Wernicke), Occipital (vision). Controls voluntary movement (motor cortex), sensation, intelligence, language, memory.' },
  { topic:'anatomy', q:'The spinal cord ends at:', opts:['Sacrum (S3–S4)','L1–L2 vertebral level (conus medullaris)','Thoracic T12','Cervical C7'], ans:1, expl:'Spinal cord ends at L1–L2 (conus medullaris) in adults; L3 in newborns. Below = cauda equina (nerve roots). Lumbar puncture (LP) done at L3–L4 or L4–L5 (below cord end to avoid injury). 31 pairs of spinal nerves: 8 cervical, 12 thoracic, 5 lumbar, 5 sacral, 1 coccygeal.' },
  { topic:'anatomy', q:'The autonomic nervous system\'s "fight or flight" response is mediated by:', opts:['Parasympathetic nervous system','Sympathetic nervous system (adrenaline/noradrenaline)','Somatic nervous system','Cerebellar system'], ans:1, expl:'Sympathetic NS (fight/flight/fright): adrenaline/noradrenaline → increased HR, BP, respiratory rate, dilated pupils, bronchodilation, decreased gut motility, increased blood sugar. Parasympathetic NS (rest/digest): slows HR, increases gut motility, constriction of pupils, bronchoconstriction.' },
  { topic:'anatomy', q:'Cranial nerve responsible for facial expression (smiling, frowning) is:', opts:['Trigeminal (V)','Facial nerve (VII)','Oculomotor (III)','Hypoglossal (XII)'], ans:1, expl:'Facial nerve (CN VII): motor to muscles of facial expression; sensory (taste) to anterior 2/3 tongue; parasympathetic to salivary and lacrimal glands. Bell\'s palsy = LMN facial nerve palsy (entire face affected, including forehead). UMN lesion (stroke): forehead spared (bilateral cortical representation).' },
  { topic:'anatomy', q:'The Glasgow Coma Scale (GCS) assesses:', opts:['Blood pressure and pulse','Eye opening (4), Verbal response (5), Motor response (6) — total 3–15','Blood glucose only','Pupil reaction only'], ans:1, expl:'GCS: Eye opening (E): 4=spontaneous, 3=to voice, 2=to pain, 1=none. Verbal (V): 5=oriented, 4=confused, 3=words, 2=sounds, 1=none. Motor (M): 6=obeys commands, 5=localises, 4=withdraws, 3=flexion, 2=extension, 1=none. GCS 15=fully conscious; <8=coma (intubation threshold); 3=deepest coma.' },
  { topic:'anatomy', q:'Which hormone is released during stress from the adrenal medulla?', opts:['Insulin','Thyroxine','Adrenaline (epinephrine) and noradrenaline (norepinephrine)','Cortisol'], ans:2, expl:'Adrenal medulla (inner layer): releases adrenaline (80%) and noradrenaline (20%) during stress/fear — "fight or flight." Adrenal cortex (outer layer): glucocorticoids (cortisol — stress response, anti-inflammatory), mineralocorticoids (aldosterone — Na+/K+ balance), sex hormones (DHEA).' },

  /* ═══ ANATOMY — MUSCULOSKELETAL ═══ */
  { topic:'anatomy', q:'The largest bone in the human body is:', opts:['Humerus','Radius','Femur (thigh bone)','Tibia'], ans:2, expl:'Femur = largest and strongest bone. Length ~45–50 cm (about 25% body height). Head articulates with acetabulum of pelvis (hip joint). Femur fracture in elderly (especially neck of femur) = common, serious. Smallest bone = stapes (ear ossicle).' },
  { topic:'anatomy', q:'A fracture where the bone breaks into multiple fragments is called:', opts:['Greenstick fracture','Comminuted fracture','Hairline fracture','Stress fracture'], ans:1, expl:'Comminuted fracture: bone shattered into 3+ fragments. High-energy trauma. Greenstick fracture: incomplete fracture in children (bone bends, outer cortex breaks). Hairline/stress fracture: thin crack from repetitive stress. Compound/open fracture: skin broken, bone exposed (high infection risk).' },
  { topic:'anatomy', q:'Osteoporosis is defined as:', opts:['Infection of bone','Decreased bone mineral density (T-score ≤ -2.5) leading to fragile bones and fracture risk','Bone tumour','Inflammation of joints'], ans:1, expl:'Osteoporosis: T-score ≤ -2.5 (DEXA scan). Osteopenia: T-score -1 to -2.5. Risk factors: female, post-menopause, low calcium/Vit D, steroid use, smoking, alcohol, immobility. Prevention: calcium (1000–1200 mg/day), Vit D, weight-bearing exercise. Wrist, hip, vertebral = common fragility fracture sites.' },
  { topic:'anatomy', q:'The diaphragm is the main muscle of:', opts:['Swallowing','Breathing (contraction = inspiration, flattening and descending)','Cardiac pumping','Walking'], ans:1, expl:'Diaphragm = dome-shaped muscle separating thorax from abdomen. Contraction → flattens/descends → increases thoracic volume → air rushes in (inspiration). Relaxation → rises → expiration (passive). Accessory muscles of inspiration: intercostals, scalene, sternocleidomastoid (used in respiratory distress).' },

  /* ═══ MCH EXTRA — Newborn/Child ═══ */
  { topic:'mch', q:'Breastfed baby\'s normal stool in first few weeks is:', opts:['Dark, firm, formed','Soft, yellow/mustard, seedy, frequent (4–8/day) — NOT diarrhoea','Black, tarry','Green, foul-smelling always'], ans:1, expl:'Normal breastfed stool: yellow/golden/mustard colour, seedy/curdy texture, soft, not offensive smell, frequent (up to 10–12/day or may skip 1–2 days in older infants). Formula-fed: pale yellow/brown, firmer, less frequent, more odour. Black tarry stool = meconium (first 2–3 days).' },
  { topic:'mch', q:'Under IMNCI, a child with fever in malaria-endemic area is classified as "Fever — Malaria Unlikely" when:', opts:['Fever for >7 days','Malaria RDT/blood film negative + no stiff neck + no rash + no danger signs','Child looks very ill','Blood in stool'], ans:1, expl:'IMNCI malaria classification: "Malaria" = RDT/smear positive; "Fever — Malaria Unlikely" = negative test + no general danger signs + no stiff neck/petechiae. Treat for local common fever cause (viral illness). Refer if: very ill, stiff neck (meningitis), petechiae (dengue/bleeding disorder).' },
  { topic:'mch', q:'Neonatal sepsis classic signs include all EXCEPT:', opts:['Feeding poorly','Convulsions or unconsciousness','Blue baby (cyanosis)','Normal weight gain'], ans:3, expl:'Neonatal sepsis signs (IMNCI): feeding poorly, lethargy, temperature instability (fever >38°C or hypothermia <35.5°C), fast breathing >60/min, chest indrawing, grunting, bulging fontanelle, pustules >10, umbilical redness spreading, convulsions, cyanosis. Normal weight gain is NOT a sign of sepsis.' },
  { topic:'mch', q:'Weight of a normal newborn at birth and expected weight at 5 months:', opts:['2 kg at birth; 5 kg at 5 months','2.5–3.5 kg at birth (average 3 kg); doubles by 5 months (~6 kg)','4 kg at birth; 8 kg at 5 months','1.5 kg at birth; 3 kg at 5 months'], ans:1, expl:'Normal birth weight: 2.5–3.5 kg (average 3 kg). Weight gain: 25–30 g/day (first 3 months); 20 g/day (3–6 months). Expected milestones: Doubles at 5 months (~6 kg); Triples at 1 year (~9 kg); Quadruples at 2 years (~12 kg). Length: 50 cm at birth; grows 25 cm in year 1.' },
  { topic:'mch', q:'IMNCI classification "POSSIBLE SERIOUS BACTERIAL INFECTION (PSBI)" in young infant includes:', opts:['Normal feeding, no fever','Not feeding well OR fast breathing OR severe chest indrawing OR fever OR hypothermia OR umbilicus red/draining OR 10+ pustules','Mild jaundice only','Only convulsions'], ans:1, expl:'PSBI (Possible Serious Bacterial Infection) in young infant (<2 months): any danger sign = not feeding well, convulsions, fast breathing (≥60/min), severe chest indrawing, fever ≥38°C or hypothermia <35.5°C, umbilical redness extending to skin, 10+ skin pustules. Treat with antibiotics (Gentamicin + Ampicillin) + refer.' },

  /* ═══ COMMUNITY HEALTH ═══ */
  { topic:'programs', q:'PHC (Primary Health Centre) is the FIRST point of contact for:', opts:['Tertiary care','Secondary care for complications','Organised modern medicine for rural population — curative, preventive, promotive, rehabilitative','Surgical emergencies only'], ans:2, expl:'PHC = first contact point between community and organised medical system. Population: 30,000 (plains)/20,000 (hilly). Functions: curative, preventive, promotive and rehabilitative care. Led by Medical Officer. Has 6 beds, laboratory, pharmacy. Manages: OPD, MCH, immunisation, FP, school health, disease surveillance.' },
  { topic:'programs', q:'Epidemiological surveillance in India is managed under:', opts:['NCDC only','IDSP (Integrated Disease Surveillance Programme) at national/state/district levels','Only municipal bodies','WHO directly'], ans:1, expl:'IDSP (Integrated Disease Surveillance Programme, 2004) under NCDC (National Centre for Disease Control), Ministry of Health. Collects S (Syndromic), P (Presumptive), L (Laboratory-confirmed) data weekly from all districts. Detects outbreaks early. Rapid Response Teams (RRTs) deployed for outbreak investigation.' },
  { topic:'programs', q:'Under SHC (Sub-Health Centre), the CHO (Community Health Officer) is posted at:', opts:['District hospital','Health and Wellness Centres (upgraded SHCs)','AIIMS','PHC only'], ans:1, expl:'HWC (Health & Wellness Centre) at SC level: Community Health Officer (CHO) = B.Sc. or GNM nurse trained in 6-month CPHL/Bridge Course. Provides comprehensive primary care including: NCD screening, teleconsultation, mental health, oral health. 1,50,000 HWCs being set up under Ayushman Bharat.' },
  { topic:'programs', q:'Village Health Register maintained by ASHA includes:', opts:['Only immunisation records','Household register: population, births, deaths, eligible couples, children 0–5, pregnant women, immunisation status, migrants','Only BPL households','Only death records'], ans:1, expl:'ASHA\'s Village Health Register: household-wise data — family members, age, sex; eligible couples + FP method; pregnant women (with EDD, ANC status); children 0–5 (immunisation status, weight, growth); births and deaths; migrants. Updated regularly. Basis for planning outreach and prioritising services.' },
  { topic:'programs', q:'Health and Wellness Centres (HWCs) provide how many types of comprehensive primary healthcare services?', opts:['3','6','12 (expanded range including NCD, mental health, palliative, ENT, ophthalmology, oral, geriatric care)','Only MCH'], ans:2, expl:'HWCs provide 12 types of services: MCH + RMNCH+A services, NCD screening (HTN, DM, cancer), oral health, ENT, ophthalmic care, mental health + substance abuse, palliative care, emergency/first aid, geriatric care, trauma care, communicable disease management + immunisation.' },

  /* ═══ IMMUNIZATION EXTRA ═══ */
  { topic:'immunize', q:'The Expanded Programme on Immunisation (EPI) was established by WHO in:', opts:['1966','1974','1985','1992'], ans:1, expl:'WHO EPI established 1974 — initially targeting 6 diseases: TB, diphtheria, pertussis, tetanus, polio, measles. India launched EPI 1978 as pilot in 6 states; expanded to Universal Immunisation Programme (UIP) in 1985. UIP initially covered 6 diseases; now covers 12.' },
  { topic:'immunize', q:'ILR (Ice-Lined Refrigerator) is used at which level of cold chain?', opts:['National level','State level','District/CHC/PHC level','Sub-centre outreach level'], ans:2, expl:'Cold chain equipment by level: National/state = walk-in cooler/freezer; District = deep freezer + ILR; PHC = ILR + deep freezer; Sub-centre = cold box + vaccine carrier; Outreach = vaccine carrier with ice packs. ILR maintains +2°C to +8°C even during power cuts (ice lining).' },
  { topic:'immunize', q:'BCG scar is expected to appear at:', opts:['1–2 days after injection','2–6 weeks after injection (as ulcer that heals to scar)','6 months after','Never (failure of vaccination)'], ans:1, expl:'BCG reaction: local papule at 2 weeks → ulceration/pustule → healing → scar by 6–12 weeks. Absence of scar does NOT always mean failed vaccination (10–20% of successful vaccinations leave no visible scar). DO NOT repeat BCG based on scar absence alone. Scar = useful indicator of coverage in surveys.' },
  { topic:'immunize', q:'Td vaccine (Tetanus-Diphtheria) given at 10 and 16 years replaces:', opts:['DPT','DT (Diphtheria-Tetanus without pertussis — used in older children)','TT alone','Pentavalent'], ans:1, expl:'Td (Tetanus-Diphtheria) contains full-dose tetanus toxoid + REDUCED-dose diphtheria toxoid (safe for older children/adults — full-dose diphtheria toxoid causes reactions in older age). Replaces TT (tetanus only) for school-age boosters. Also given in pregnancy (2 doses for primary, 1 booster each pregnancy if previously immunised).' },

  /* ═══ NUTRITION EXTRA ═══ */
  { topic:'nutrition', q:'The Infant and Young Child Feeding (IYCF) practices recommended by WHO are:', opts:['Formula feed from birth','Initiation of breastfeeding within 1 hour; EBF 6 months; timely complementary feeding from 6 months + continued BF to 2 years','Complementary food from 3 months','Cow milk from 1 month'], ans:1, expl:'WHO IYCF recommendations: (1) Breastfeeding within 1 hour of birth; (2) Exclusive breastfeeding for 6 months (NO other food/water); (3) Complementary feeding from 6 months with continued breastfeeding; (4) Breastfeeding continued to 2 years or beyond. India IYCF policy aligns with WHO.' },
  { topic:'nutrition', q:'The recommended caloric density of complementary food for a 6–8 month infant is:', opts:['50 kcal/100g','70 kcal/100g or more (energy-dense food needed as stomach is small)','30 kcal/100g','Same as adult food'], ans:1, expl:'Complementary food for 6–8 months: minimum energy density ≥70–100 kcal/100g (compared to breast milk at 65–70 kcal/100g). Thick porridge/khichdi/mashed food. Frequency: 2–3 times/day at 6–8 months; 3–4 times/day at 9–24 months. Diversified — all food groups. Avoid salt, sugar, honey (<1 year).' },
  { topic:'nutrition', q:'Marasmus (severe acute malnutrition without oedema) is characterised by:', opts:['Massive oedema, normal weight','Severe muscle wasting, "old man face", weight <60% expected, no oedema — skin and bones','Only anaemia','Only micronutrient deficiency'], ans:1, expl:'Marasmus = calorie + protein deficiency. Features: severe muscle/fat wasting, "wizened/old man face," prominent ribs/spine, baggy pants appearance, loose skin folds, weight <60% of expected (Wellcome classification Grade III), NO oedema (unlike kwashiorkor). Very hungry, alert. Grade III PEM.' },
  { topic:'nutrition', q:'Therapeutic zinc supplementation dose for children 6 months–5 years with acute diarrhoea:', opts:['5 mg/day for 5 days','10 mg/day for 7 days','20 mg/day for 14 days','50 mg/day for 7 days'], ans:2, expl:'WHO zinc supplementation in diarrhoea: Children >6 months: 20 mg/day for 14 days (dispersible tablet). Children <6 months: 10 mg/day for 14 days. Reduces duration/severity of current episode AND prevents recurrence for 2–3 months. Use alongside ORS (not as replacement).' },

  /* ═══ ENVIRONMENT EXTRA ═══ */
  { topic:'environment', q:'Indoor Air Pollution (IAP) from biomass fuel combustion primarily affects:', opts:['Outdoor workers only','Rural women and children (who spend most time indoors near chulha/cook stove)','Only smokers','Urban populations only'], ans:1, expl:'IAP from burning wood, dung, coal, crop residue in chulha (traditional cook stove): rural women and children most exposed (5–6 hours/day near fire). Causes: COPD, lung cancer, pneumonia, LBW, cataract. 4+ lakh premature deaths/year in India from IAP. Ujjwala Yojana: LPG to BPL households.' },
  { topic:'environment', q:'The "One Health" concept recognises that:', opts:['Human health is independent of animal and environmental health','Human, animal, and environmental health are interconnected and must be addressed together','Only veterinary medicine is important','Environment has no impact on health'], ans:1, expl:'One Health: optimal health achieved by integrating human medicine, veterinary medicine, and environmental science. 75% of emerging infectious diseases are zoonotic (animal to human): COVID-19, Ebola, SARS, Nipah, avian influenza, rabies, brucellosis. Requires collaboration across sectors.' },
  { topic:'environment', q:'Safe distance between a soak pit/septic tank and a drinking water well should be at minimum:', opts:['5 metres','15 metres (minimum 30 metres recommended)','50 metres','100 metres'], ans:1, expl:'WHO/BIS: minimum 15–30 metres between sanitary facility (latrine, septic tank, soak pit) and drinking water well. Faecal coliform bacteria can travel through soil and contaminate groundwater. Latrine should be downhill/downwind from well. Open defecation contaminates water table.' },

  /* ═══ FAMILY PLANNING EXTRA ═══ */
  { topic:'fp', q:'Condom failure most commonly occurs due to:', opts:['Manufacturing defect','User errors: inconsistent use, wrong technique, breakage, storage in wallet/heat','Allergy only','Size mismatch only'], ans:1, expl:'Condom "typical use" failure (13–15%) vs "perfect use" (2%) — difference = USER ERROR. Common errors: not using every time (inconsistent use), wrong technique (no space at tip, wrong size, wrong side), using after expiry, storing in heat/wallet (degrades latex), using oil-based lubricants with latex.' },
  { topic:'fp', q:'Vasectomy (male sterilisation) — which is correct?', opts:['Immediately effective (from day 1)','Takes ~3 months/20 ejaculations to clear existing sperm; use backup contraception until confirmed by semen analysis','Affects testosterone and sexual function','Reversible in most cases'], ans:1, expl:'Vasectomy: vas deferens cut/tied/cauterised. NOT immediately effective — sperm stored in distal vas must be cleared (~3 months/20 ejaculations). Must confirm success by semen analysis (azoospermia). Does NOT affect testosterone, libido, or sexual function. Reversal (vasovasostomy) possible but success varies.' },

  /* ═══ STATS EXTRA ═══ */
  { topic:'stats', q:'Prevalence vs. incidence: which is correct?', opts:['Prevalence measures new cases; incidence measures existing cases','Incidence = new cases in a time period; Prevalence = all existing cases at a point in time','Both are the same','Prevalence is always higher for acute diseases'], ans:1, expl:'Incidence = new cases per population per time period (measures risk of getting disease). Prevalence = all cases (new + existing) at a point in time (measures disease burden). Prevalence ≈ Incidence × Duration. High prevalence: chronic diseases (DM, HTN). High incidence relative to prevalence: acute diseases (diarrhoea, malaria).' },
  { topic:'stats', q:'A p-value of <0.05 in statistical analysis means:', opts:['The treatment works 95% of the time','There is a 95% probability that the null hypothesis is correct','The observed result would occur by chance less than 5% of the time (statistically significant)','The sample size was adequate'], ans:2, expl:'p-value: probability of obtaining observed results (or more extreme) if null hypothesis is TRUE. p<0.05 = statistically significant (result unlikely due to chance alone). p<0.01 = highly significant. p<0.001 = very highly significant. Statistical significance ≠ clinical significance (large samples can give tiny but meaningless differences).' },
  { topic:'stats', q:'Natural History of Disease describes:', opts:['History of medicine','Course of disease from exposure/onset to recovery/death without medical intervention','History of a country\'s health system','History of drugs'], ans:1, expl:'Natural History of Disease: (1) Susceptibility stage; (2) Pre-pathogenesis (subclinical, after exposure); (3) Pathogenesis (clinical disease); (4) Outcome (recovery, disability, death). Levels of prevention: Primordial (risk factors), Primary (pre-disease), Secondary (early disease), Tertiary (rehabilitation).' },

  /* ═══ DRUGS EXTRA ═══ */
  { topic:'drug', q:'Drug interactions: which combination is DANGEROUS and should be avoided?', opts:['Paracetamol + ORS','Warfarin + Aspirin (both anti-clotting — major bleeding risk)','ORS + Zinc','Amoxicillin + ORS'], ans:1, expl:'Warfarin + Aspirin = major interaction: Aspirin inhibits platelet function + Warfarin inhibits clotting factors → severe bleeding risk (GI bleed, intracranial haemorrhage). Also dangerous: Methotrexate + NSAIDs; Digoxin + Amiodarone; MAOIs + SSRIs (serotonin syndrome); Simvastatin + Clarithromycin (rhabdomyolysis).' },
  { topic:'drug', q:'Antipyretics: the mechanism of paracetamol differs from NSAIDs in that paracetamol:', opts:['Is a stronger anti-inflammatory','Acts centrally in CNS to reduce temperature; weak peripheral anti-inflammatory effect','Has more side effects','Causes more GI bleeding'], ans:1, expl:'Paracetamol: primarily CENTRAL action (hypothalamus — COX-3 inhibition, endocannabinoid pathway). Weak peripheral anti-inflammatory. Fewer GI side effects than NSAIDs. NSAIDs (ibuprofen, aspirin, diclofenac): peripheral COX-1/COX-2 inhibition, strong anti-inflammatory + antipyretic + analgesic, GI irritation, platelet effects.' },
  { topic:'drug', q:'Oral contraceptive pills should be taken:', opts:['Only when having intercourse','Same time every day to maintain hormone levels (missed pill reduces effectiveness)','Only during menstruation','Every other day'], ans:1, expl:'OCPs must be taken at the SAME TIME every day for consistent hormone levels. Missing a pill (especially combined pill) can result in ovulation and pregnancy. Missed 1 pill: take ASAP, continue pack. Missed 2+ pills in week 1 or 2: take 2 pills/day for 2 days, use backup contraception for 7 days.' },
  { topic:'drug', q:'Vitamin B12 deficiency causes:', opts:['Iron deficiency anaemia','Megaloblastic anaemia (large RBCs) + subacute combined degeneration of spinal cord (neurological)','Sickle cell anaemia','Aplastic anaemia'], ans:1, expl:'Vitamin B12 (cobalamin) deficiency: megaloblastic anaemia (large, immature RBCs — due to impaired DNA synthesis); subacute combined degeneration of spinal cord (SACD — posterior and lateral columns — paraesthesia, ataxia, weakness). Causes: pernicious anaemia (lack of intrinsic factor), strict veganism, malabsorption. Treatment: B12 injection.' },
  { topic:'drug', q:'Injection Gentamicin given to young infant with PSBI (under ASHA/ANM simplified treatment protocol) dose is:', opts:['2 mg/kg','7.5 mg/kg once daily IM','50 mg fixed dose','1 mg/kg twice daily'], ans:1, expl:'WHO/MoHFW simplified treatment for PSBI in young infants when referral not possible: Amoxicillin oral + Gentamicin IM 7.5 mg/kg once daily for 7 days. Given by trained ANM at SC or ASHA with training. If condition deteriorates, refer immediately. Oral Amoxicillin 50 mg/kg/day.' },

  /* ═══ BATCH B — ANATOMY & PHYSIOLOGY ═══ */
  { topic:'anatomy', q:'The normal adult respiratory rate is:', opts:['8–10 breaths/min','12–20 breaths/min','25–30 breaths/min','35–40 breaths/min'], ans:1, expl:'Normal adult respiratory rate: 12–20 breaths/min. Tachypnea >20/min. Bradypnea <12/min. Neonates: 30–60/min. Infants: 24–40/min. Assess for one full minute in resting state.' },
  { topic:'anatomy', q:'The normal adult pulse rate is:', opts:['40–60 bpm','60–100 bpm','100–120 bpm','120–140 bpm'], ans:1, expl:'Normal adult pulse: 60–100 bpm. Bradycardia <60 bpm. Tachycardia >100 bpm. Neonates: 120–160 bpm. Infants: 80–140 bpm. Well-trained athletes may have resting HR 40–60 bpm (normal for them).' },
  { topic:'anatomy', q:'Normal adult blood pressure is:', opts:['90/60 mmHg','120/80 mmHg','140/90 mmHg','160/100 mmHg'], ans:1, expl:'Normal BP: 120/80 mmHg (systolic 120, diastolic 80). Prehypertension: 120-139/80-89. Stage 1 HTN: 140-159/90-99. Stage 2 HTN: 160+/100+. Hypotension: systolic <90 mmHg.' },
  { topic:'anatomy', q:'The largest organ of the human body is:', opts:['Liver','Skin','Small intestine','Lungs'], ans:1, expl:'Skin is the largest organ: covers 1.5-2 m, weighs 3-4 kg. Protects against pathogens, regulates temperature, provides sensation, synthesises Vitamin D. Liver is the largest internal organ.' },
  { topic:'anatomy', q:'Blood flows from the right ventricle to:', opts:['Aorta','Pulmonary artery (deoxygenated blood to lungs)','Pulmonary veins','Superior vena cava'], ans:1, expl:'Right ventricle to Pulmonary artery to Lungs (oxygenation) to Pulmonary veins to Left atrium to Left ventricle to Aorta to Body. Right side carries deoxygenated blood; left side carries oxygenated blood.' },
  { topic:'anatomy', q:'The functional unit of the kidney is:', opts:['Glomerulus','Nephron','Loop of Henle','Collecting duct'], ans:1, expl:'Nephron is the functional unit of the kidney. Each kidney has about 1 million nephrons. Nephron components: glomerulus (filtration), proximal tubule, Loop of Henle (concentration), distal tubule, collecting duct. Produces urine through filtration, reabsorption, secretion.' },
  { topic:'anatomy', q:'Normal urine output in adults is approximately:', opts:['200-400 mL/day','800-1000 mL/day','1000-1500 mL/day','2000-3000 mL/day'], ans:2, expl:'Normal urine output: 1000-1500 mL/day (about 0.5-1 mL/kg/hour). Oliguria: <400 mL/day. Anuria: <100 mL/day. Polyuria: >2500 mL/day. Nocturia: excessive urination at night. Adequate output indicates good renal perfusion.' },
  { topic:'anatomy', q:'The pacemaker of the heart is:', opts:['AV node','Bundle of His','SA node (sino-atrial node)','Purkinje fibres'], ans:2, expl:'SA node is the natural pacemaker, located in right atrium near SVC opening. Fires 60-100 impulses/min. Impulse travels: SA node → AV node → Bundle of His → bundle branches → Purkinje fibres → ventricular myocardium.' },
  { topic:'anatomy', q:'The hormone secreted by the beta cells of pancreatic islets of Langerhans is:', opts:['Glucagon','Insulin','Somatostatin','Pancreatic polypeptide'], ans:1, expl:'Beta cells produce Insulin (lowers blood glucose). Alpha cells produce Glucagon (raises blood glucose). Delta cells produce Somatostatin. Diabetes mellitus: deficiency/resistance to insulin.' },
  { topic:'anatomy', q:'The total number of bones in the adult human body is:', opts:['186','196','206','216'], ans:2, expl:'Adult human skeleton: 206 bones. Newborn has 270-300 bones (many fuse). Axial skeleton: 80 bones. Appendicular skeleton: 126 bones.' },
  { topic:'anatomy', q:'The vitamin responsible for blood clotting is:', opts:['Vitamin A','Vitamin C','Vitamin D','Vitamin K'], ans:3, expl:'Vitamin K is essential for synthesis of clotting factors II, VII, IX, X. Deficiency leads to bleeding tendency. Warfarin works by antagonising Vitamin K. Newborns get Vitamin K injection at birth to prevent haemorrhagic disease of newborn.' },
  { topic:'anatomy', q:'Normal haemoglobin level in adult males is:', opts:['10-12 g/dL','12-14 g/dL','13-17 g/dL','18-22 g/dL'], ans:2, expl:'Normal Hb: Males 13-17 g/dL; Females 12-16 g/dL; Pregnant women at least 11 g/dL (WHO). Neonates: 14-20 g/dL. Anaemia in males: Hb <13 g/dL; females <12 g/dL; pregnant <11 g/dL.' },
  { topic:'anatomy', q:'The Glasgow Coma Scale (GCS) maximum score is:', opts:['12','15','18','21'], ans:1, expl:'GCS maximum = 15 (fully conscious); minimum = 3 (deep coma). Components: Eye opening (E): 4; Verbal response (V): 5; Motor response (M): 6. GCS 8 or less = severe head injury. GCS 9-12 = moderate; 13-15 = mild.' },
  { topic:'anatomy', q:'Which structure separates the thoracic and abdominal cavities?', opts:['Peritoneum','Pleura','Diaphragm','Pericardium'], ans:2, expl:'Diaphragm: dome-shaped musculo-tendinous structure separating thorax from abdomen. Primary muscle of respiration - contracts and flattens during inspiration. Openings for oesophagus (T10), aorta (T12), IVC (T8). Hiatus hernia: stomach herniates through oesophageal opening.' },
  { topic:'anatomy', q:'Normal fasting blood glucose level is:', opts:['Less than 70 mg/dL','70-100 mg/dL','110-125 mg/dL','126 mg/dL or more'], ans:1, expl:'Normal fasting glucose: 70-100 mg/dL. Impaired fasting glucose (pre-diabetes): 100-125 mg/dL. Diabetes mellitus: fasting 126+ mg/dL on two occasions, or random 200+ mg/dL with symptoms, or HbA1c 6.5%+. Hypoglycaemia: <70 mg/dL.' },
  { topic:'anatomy', q:'The liver produces which plasma protein essential for maintaining osmotic pressure?', opts:['Globulin','Albumin','Fibrinogen','Prothrombin'], ans:1, expl:'Albumin (major plasma protein, 3.5-5.5 g/dL) is produced exclusively by the liver. It maintains oncotic pressure. Low albumin (hypoalbuminaemia) leads to oedema and ascites. Liver also produces clotting factors, globulins, fibrinogen.' },
  { topic:'anatomy', q:'The normal platelet count is:', opts:['10,000-50,000/mm3','50,000-100,000/mm3','1,50,000-4,00,000/mm3','5,00,000-10,00,000/mm3'], ans:2, expl:'Normal platelets: 1.5-4.0 lakh/mm3 (150,000-400,000/mm3). Thrombocytopenia: <1,50,000/mm3. Dengue: platelet fall is characteristic feature. Thrombocytosis: >4,00,000/mm3.' },
  { topic:'anatomy', q:'The appendix is located at the junction of:', opts:['Ascending colon and transverse colon','Ileum and caecum (ileocaecal junction)','Transverse and descending colon','Sigmoid and rectum'], ans:1, expl:'Appendix is a vestigial structure at the caecum, near ileocaecal junction, in Right Iliac Fossa (RIF). Appendicitis presents with periumbilical pain migrating to RIF (McBurney\'s point). Treatment: appendicectomy.' },
  { topic:'anatomy', q:'Which cranial nerve controls tongue movements?', opts:['CN IX (Glossopharyngeal)','CN X (Vagus)','CN XI (Accessory)','CN XII (Hypoglossal)'], ans:3, expl:'CN XII (Hypoglossal nerve): motor nerve controlling all intrinsic and most extrinsic muscles of the tongue. Damage leads to tongue deviating toward the side of the lesion, dysarthria, dysphagia.' },
  { topic:'anatomy', q:'The knee-jerk (patellar) reflex tests which spinal level?', opts:['C5-C6','L2-L4','S1-S2','T10-T12'], ans:1, expl:'Patellar (knee-jerk) reflex: L2, L3, L4 spinal segments via femoral nerve. Absent reflex suggests lower motor neuron lesion. Exaggerated reflex suggests upper motor neuron lesion. Ankle jerk reflex: S1-S2.' },
  { topic:'anatomy', q:'Normal intraocular pressure (IOP) is:', opts:['5-8 mmHg','10-21 mmHg','25-30 mmHg','35-40 mmHg'], ans:1, expl:'Normal IOP: 10-21 mmHg (maintained by aqueous humour production and drainage). Glaucoma: IOP >21 mmHg causing optic nerve damage and visual field loss. Open-angle glaucoma is most common type (silent, painless).' },

  /* ═══ BATCH B — MCH ═══ */
  { topic:'mch', q:'WHO recommends exclusive breastfeeding for how long?', opts:['3 months','4 months','6 months','12 months'], ans:2, expl:'WHO/UNICEF/MoHFW: Exclusive breastfeeding (EBF) for the first 6 months. No water, juice, or other food. Followed by complementary feeding from 6 months plus continued breastfeeding up to 2 years or beyond. EBF reduces infections, malnutrition, SIDS, and mother\'s breast cancer risk.' },
  { topic:'mch', q:'APGAR score is assessed at:', opts:['1 minute only','1 and 5 minutes after birth','5 and 10 minutes','Immediately and at 30 minutes'], ans:1, expl:'APGAR score: assessed at 1 min and 5 min after birth. Components: Appearance (skin colour), Pulse (heart rate), Grimace (reflex irritability), Activity (muscle tone), Respiration. Each scored 0-2, total 10. Score 7-10 = good; 4-6 = moderate depression; 0-3 = severe depression (resuscitate).' },
  { topic:'mch', q:'Pre-eclampsia is defined as hypertension after 20 weeks gestation with:', opts:['Presence of oedema only','Proteinuria (300 mg/24 hours or +1 on dipstick)','Hyperemesis gravidarum','Anaemia'], ans:1, expl:'Pre-eclampsia: HTN 140/90+ mmHg after 20 weeks + proteinuria 300 mg/24h+. Eclampsia: convulsions occur. Severe features: BP 160/110+, platelet <1 lakh, creatinine elevated. Treatment: MgSO4 for seizure prevention, antihypertensives.' },
  { topic:'mch', q:'The fundal height at 36 weeks of pregnancy reaches:', opts:['Umbilicus','4 cm above umbilicus','Xiphisternum (xiphoid process)','Symphysis pubis'], ans:2, expl:'Fundal height milestones: 12 weeks = symphysis pubis; 20 weeks = umbilicus; 28 weeks = 3-4 cm above umbilicus; 36 weeks = xiphisternum. After 36 weeks: lightening occurs (head engages), fundus drops slightly.' },
  { topic:'mch', q:'Kangaroo Mother Care (KMC) is recommended for:', opts:['Term babies over 3 kg','Low birth weight (LBW) and preterm babies less than 2000 g','Babies with jaundice','Post-term babies over 42 weeks'], ans:1, expl:'KMC = skin-to-skin contact between mother and LBW/preterm infant. Benefits: stabilises temperature, promotes breastfeeding, reduces infection risk, shortens hospital stay, reduces mortality in preterm babies. WHO recommends KMC for all LBW babies <2000 g as soon as stable.' },
  { topic:'mch', q:'Postpartum haemorrhage (PPH) is defined as blood loss of more than:', opts:['250 mL after vaginal delivery','500 mL after vaginal delivery or 1000 mL after C-section','750 mL after any delivery','1500 mL after any delivery'], ans:1, expl:'PPH: blood loss >500 mL within 24 hours of vaginal delivery, or >1000 mL after C-section. Primary PPH: within 24 hours, most common cause is atonic uterus (4 Ts: Tone, Trauma, Tissue, Thrombin). Treatment: uterine massage, oxytocin, misoprostol, bimanual compression.' },
  { topic:'mch', q:'Placenta praevia presents with:', opts:['Painful vaginal bleeding in late pregnancy','Painless bright-red vaginal bleeding in third trimester','Green-stained liquor','Severe abdominal rigidity'], ans:1, expl:'Placenta praevia: placenta implants over/near internal cervical os. Hallmark: PAINLESS bright red antepartum haemorrhage in third trimester. No abdominal tenderness (unlike abruption). Confirmed by USG. Management: bed rest, delivery by C-section. Placental abruption: painful.' },
  { topic:'mch', q:'Iron supplementation dose in pregnancy (IFA) as per NHM India is:', opts:['30 mg elemental iron + 250 mcg folic acid','60 mg elemental iron + 500 mcg folic acid','100 mg + 1 mg folic acid','45 mg + 400 mcg folic acid'], ans:1, expl:'NHM IFA supplementation: 60 mg elemental iron + 500 mcg folic acid daily for at least 180 days during pregnancy. Start after 1st trimester (12 weeks). Severe anaemia (Hb <7 g/dL): refer + IV iron/blood transfusion.' },
  { topic:'mch', q:'Normal birth weight is:', opts:['Less than 2000 g','2000-2499 g','2500 g or more','3000-4000 g only'], ans:2, expl:'Normal birth weight: 2500 g (2.5 kg) or more. Low birth weight (LBW): <2500 g. Very LBW: <1500 g. Extremely LBW: <1000 g. Macrosomia: >4000 g (risk of shoulder dystocia). India LBW rate about 28% - one of highest in world.' },
  { topic:'mch', q:'Rhesus (Rh) incompatibility causes haemolytic disease of the newborn when:', opts:['Mother is Rh+ and baby is Rh-','Mother is Rh- and baby is Rh+ (antibodies cross placenta in subsequent pregnancies)','Both parents are Rh-','Mother is blood group O and baby is A'], ans:1, expl:'Rh incompatibility: Rh-negative mother sensitised produces anti-D IgG antibodies. In subsequent Rh+ pregnancies, antibodies cross placenta and destroy fetal RBCs causing haemolytic disease of newborn. Prevention: Anti-D immunoglobulin (RhoGAM) within 72 hours of delivery/abortion.' },
  { topic:'mch', q:'The first milk produced after delivery (colostrum) is rich in:', opts:['Fat and carbohydrates','Immunoglobulins (IgA), protein, and Vitamin A','Iron and zinc only','Lactose'], ans:1, expl:'Colostrum (first 3-5 days): thick yellow fluid. Rich in IgA (passive immunity), protein, Vitamin A, lactoferrin, growth factors. Low in fat and lactose. Provides passive immunity against diarrhoea and respiratory infections. Called "liquid gold" and "first vaccine." Never discard colostrum.' },
  { topic:'mch', q:'Meconium-stained amniotic fluid indicates:', opts:['Normal fetal maturity','Post-term normal finding','Fetal distress (hypoxia causes relaxation of anal sphincter)','Maternal infection'], ans:2, expl:'Meconium-stained liquor (MSL): meconium in amniotic fluid = sign of fetal distress. Grade: thin (yellow-green), moderate, thick (pea soup). If baby aspirates thick meconium it causes Meconium Aspiration Syndrome (MAS). Immediate resuscitation team needed.' },
  { topic:'mch', q:'Measles vaccine (first dose) is given at:', opts:['6 weeks','9 months','12 months','15 months'], ans:1, expl:'Measles-Rubella (MR) vaccine: First dose at 9 months; Second dose at 16-24 months (along with DPT booster). MMR in private sector: 12-15 months first dose. Measles incubation: 10-14 days. Koplik spots (pathognomonic), rash starts on face.' },
  { topic:'mch', q:'Under immunisation schedule, OPV booster doses are given at:', opts:['9 months and 2 years','16-24 months and 5 years','2 years and 3 years','1 year only'], ans:1, expl:'OPV schedule: Birth (OPV 0), 6 weeks, 10 weeks, 14 weeks (primary series). Booster: 16-24 months and 5 years. IPV given at 6 and 14 weeks for stronger immunity. Pulse Polio: national immunisation days to eradicate polio.' },
  { topic:'mch', q:'Under NHM, Janani Suraksha Yojana (JSY) cash incentive for BPL institutional delivery in rural area is:', opts:['500 rupees','700 rupees','1400 rupees','1800 rupees'], ans:2, expl:'JSY cash incentive for BPL mother: Rural 1400 rupees; Urban 1000 rupees (in high-performing states like J&K). In low-performing states: Rural 700 rupees; Urban 600 rupees. ASHA incentive: 600 rupees rural, 400 rupees urban. JSY links ANC + institutional delivery + postnatal care.' },
  { topic:'mch', q:'The recommended site for BCG vaccination in infants is:', opts:['Anterolateral thigh','Deltoid region of right arm','Left deltoid / upper outer arm (intradermal)','Buttock'], ans:2, expl:'BCG: given intradermally (ID) on the left upper arm (deltoid region) in most states. Dose: 0.1 mL for neonates. Produces a raised wheal, heals in 6-8 weeks leaving a scar. Protects against miliary TB and TB meningitis in children.' },

  /* ═══ BATCH B — COMMUNITY HEALTH ═══ */
  { topic:'community', q:'Primary Health Centre (PHC) serves a population of:', opts:['5,000-10,000','10,000-20,000','20,000-30,000 in plains / 3,000-5,000 in hilly areas','50,000-1,00,000'], ans:2, expl:'PHC population norm: 30,000 in plains; 20,000 in hilly/tribal areas. First contact point between community and medical officer. Has 1 MO, 14 paramedics, 4 nurses. Sub-centre under PHC: 5,000 (plain), 3,000 (hilly). Community Health Centre: 1,00,000 population, 30 beds, 4 specialists.' },
  { topic:'community', q:'The objective of ICDS (Integrated Child Development Services) is:', opts:['Only to provide nutrition to children','Holistic development of children under 6 years and pregnant/lactating mothers through 6 services','Medical treatment of sick children only','Family planning services only'], ans:1, expl:'ICDS (launched 1975) provides 6 services through Anganwadi Centre: Supplementary nutrition, Immunisation, Health check-up, Referral services, Pre-school education, Nutrition and health education. Beneficiaries: children <6 years, pregnant women, lactating mothers.' },
  { topic:'community', q:'For measles, herd immunity threshold is approximately:', opts:['50%','70%','85%','92-95%'], ans:3, expl:'Measles herd immunity threshold: 92-95% vaccination coverage needed because measles is highly contagious (R0 = 12-18). Polio: about 80-85%. Once threshold is reached, unvaccinated individuals are protected as transmission chains are broken.' },
  { topic:'community', q:'The causative agent of cholera is:', opts:['Salmonella typhi','Vibrio cholerae (O1 or O139)','Entamoeba histolytica','Shigella dysenteriae'], ans:1, expl:'Cholera: caused by Vibrio cholerae. Presents as rice-water stools, profuse watery diarrhoea, vomiting, rapid dehydration. Can kill within hours. Treatment: ORS (main), IV fluids for severe cases, Doxycycline for adults. Prevention: safe water, sanitation.' },
  { topic:'community', q:'The incubation period of typhoid fever is:', opts:['1-3 days','3-7 days','7-21 days (average 10-14 days)','28-42 days'], ans:2, expl:'Typhoid (enteric fever, Salmonella typhi): incubation 7-21 days (average 10-14 days). Features: stepladder fever, rose spots on trunk, splenomegaly, relative bradycardia. Widal test (rising titre >1:160). Treatment: Ceftriaxone, Azithromycin, Ciprofloxacin.' },
  { topic:'community', q:'Leprosy is caused by:', opts:['Mycobacterium tuberculosis','Mycobacterium leprae (Hansen\'s bacillus)','Treponema pallidum','Clostridium perfringens'], ans:1, expl:'Leprosy (Hansen\'s disease): caused by Mycobacterium leprae. Types: Paucibacillary (PB, 1-5 patches) and Multibacillary (MB, >5 patches). Treatment: MDT (WHO regimen): PB - 6 months; MB - 12 months. India achieved elimination (<1/10,000) in 2005.' },
  { topic:'community', q:'The "3 delays" model in maternal mortality refers to:', opts:['Delays in ANC booking, delivery, and postnatal care','Delay in deciding to seek care, reaching facility, and receiving care at facility','Delays in diagnosis, treatment, and follow-up','Delays due to distance, cost, and education'], ans:1, expl:'3-Delays Model (Thaddeus & Maine, 1994): Phase 1 - Delay in deciding to seek care. Phase 2 - Delay in reaching facility (distance, transport). Phase 3 - Delay in receiving adequate care (staffing, supplies). Most maternal deaths preventable by addressing these 3 delays.' },
  { topic:'community', q:'ASHA\'s primary role is:', opts:['To perform deliveries at home','To serve as a link between community and health system (link worker)','To administer vaccines','To conduct surgery'], ans:1, expl:'ASHA (Accredited Social Health Activist): community health volunteer, 1 per 1000 population (rural). Primarily a LINK WORKER between community and government health services. Key roles: mobilising for institutional delivery (JSY), immunisation, ANC registration, TB DOTS support, family planning, HBNC (home-based newborn care).' },
  { topic:'community', q:'Scabies is caused by:', opts:['Phthirus pubis','Pediculus humanus','Sarcoptes scabiei (a mite)','Tinea corporis'], ans:2, expl:'Scabies: caused by Sarcoptes scabiei. Transmitted by prolonged skin-to-skin contact. Features: intense nocturnal itching, burrows between fingers, wrist, genitals. Treatment: Permethrin 5% cream (applied overnight, all family members). Benzyl benzoate 25% (alternative).' },
  { topic:'community', q:'National Vector Borne Disease Control Programme (NVBDCP) covers:', opts:['TB and Leprosy','Malaria, Dengue, Filariasis, Kala-azar, Japanese Encephalitis, Chikungunya','HIV/AIDS and STIs','Blindness and deafness'], ans:1, expl:'NVBDCP covers all vector-borne diseases: Malaria, Dengue, Filariasis (lymphatic), Kala-azar (visceral leishmaniasis), Japanese Encephalitis, Chikungunya. Strategies: vector control (IRS, bed nets, larval source reduction), early diagnosis, prompt treatment.' },
  { topic:'community', q:'Safe drinking water (BIS standards) should have turbidity of not more than:', opts:['1 NTU','5 NTU','10 NTU','25 NTU'], ans:1, expl:'BIS IS:10500 drinking water: Turbidity 5 NTU or less. pH: 6.5-8.5. TDS: 500 mg/L or less. Fluoride: 1 mg/L (desirable), 1.5 mg/L max. Arsenic: 0.01 mg/L or less. Coliform organisms: absent in 100 mL.' },
  { topic:'community', q:'Sentinel surveillance means:', opts:['Passive reporting from all facilities','Data collected from selected representative sites to detect trends (cost-effective for HIV, influenza, birth defects)','Active case finding by health workers','Mandatory reporting of all diseases'], ans:1, expl:'Sentinel surveillance: data from selected sentinel sites representative of larger population. Used for diseases where comprehensive surveillance is impractical. Cost-effective. Active surveillance: health workers actively seek cases. Passive surveillance: facilities report spontaneously.' },
  { topic:'community', q:'The most common vector of malaria in India is:', opts:['Aedes aegypti','Culex quinquefasciatus','Anopheles culicifacies','Mansonia mosquito'], ans:2, expl:'Anopheles culicifacies: most prevalent malaria vector in India (rural, plains). An. stephensi: urban malaria. Aedes = Dengue/Zika/Chikungunya. Culex = JE/Filariasis. An. fluviatilis: important in forested hilly areas. An. minimus: North-East India.' },

  /* ═══ BATCH B — NUTRITION ═══ */
  { topic:'nutrition', q:'The deficiency of Vitamin C causes:', opts:['Rickets','Scurvy (bleeding gums, perifollicular haemorrhages, wound healing failure)','Night blindness','Pellagra'], ans:1, expl:'Scurvy: Vitamin C (ascorbic acid) deficiency. Features: bleeding gums, perifollicular haemorrhages, corkscrew hairs, poor wound healing, anaemia. Vitamin C essential for collagen synthesis. Sources: citrus fruits, guava, amla (richest), tomatoes. RDA: 40 mg/day.' },
  { topic:'nutrition', q:'BMI formula is:', opts:['Height (m) / Weight (kg) squared','Weight (kg) / Height (m) squared','Weight (kg) times Height (m)','Weight (kg) / Height (cm)'], ans:1, expl:'BMI = Weight (kg) / Height squared (m squared). Classification: less than 18.5 = Underweight; 18.5-22.9 = Normal (Asian); 23-24.9 = Overweight; 25+ = Obese (Asian cut-off). WHO: normal 18.5-24.9; overweight 25-29.9; obese 30+.' },
  { topic:'nutrition', q:'Iodine deficiency disorder (IDD) can be prevented by:', opts:['Vitamin A supplementation','Zinc fortification','Use of iodised salt (universal salt iodisation)','Iron tablets'], ans:2, expl:'Universal Salt Iodisation (USI): mandatory iodisation of all edible salt (15-25 ppm). Prevents goitre, cretinism (congenital hypothyroidism - most serious IDD), mental retardation, stillbirth. India: mandatory under PFA Act. NPCC runs district goitre surveys.' },
  { topic:'nutrition', q:'MUAC of less than 11.5 cm in children 6-59 months indicates:', opts:['Normal nutritional status','Moderate Acute Malnutrition (MAM)','Severe Acute Malnutrition (SAM)','Risk of overnutrition'], ans:2, expl:'MUAC (Mid-Upper Arm Circumference): <11.5 cm = SAM - admit to NRC or give RUTF (Ready-to-Use Therapeutic Food). 11.5-12.4 cm = MAM. 12.5 cm+ = Normal. MUAC tape: red <11.5, yellow 11.5-12.4, green 12.5+. Used by ASHA/AWW for community screening.' },
  { topic:'nutrition', q:'Kwashiorkor is primarily caused by:', opts:['Severe energy deficiency','Severe protein deficiency with adequate calorie intake - leading to oedema','Both protein and energy deficiency','Vitamin A deficiency'], ans:1, expl:'Kwashiorkor: protein deficiency despite some calorie intake. Features: oedema (pitting), moon face, hair changes (flag sign), hepatomegaly, skin changes (flaky paint dermatosis), apathy. Marasmus: severe energy+protein deficiency - wasted, no oedema, old man appearance.' },
  { topic:'nutrition', q:'Vitamin D is essential for absorption of:', opts:['Iron and zinc','Calcium and phosphorus','Vitamin A and E','Iodine and selenium'], ans:1, expl:'Vitamin D (calciferol) promotes absorption of Calcium and Phosphorus in the small intestine and promotes their deposition in bone. Deficiency leads to Rickets (children - soft bones, bow legs) or Osteomalacia (adults). Sources: sunlight, fish liver oil, egg yolk, fortified foods. RDA: 400 IU/day.' },
  { topic:'nutrition', q:'Pellagra is caused by deficiency of:', opts:['Vitamin B1 (thiamine)','Vitamin B2 (riboflavin)','Vitamin B3 (niacin/nicotinic acid)','Vitamin B12'], ans:2, expl:'Pellagra: Niacin (Vitamin B3) deficiency. Classic 4 Ds: Dermatitis (photosensitive, Casal\'s necklace), Diarrhoea, Dementia, Death. Common in communities eating maize as staple. Treatment: Nicotinic acid 300-500 mg/day. Also seen in carcinoid syndrome and isoniazid therapy.' },
  { topic:'nutrition', q:'Which food has the highest bioavailable iron?', opts:['Spinach','Animal liver (haem iron, highly bioavailable)','Milk','Rice'], ans:1, expl:'Animal liver has highest bioavailable iron (haem iron, 6-10 mg/100g, 20-30% absorbed). Spinach has non-haem iron (2.7 mg/100g, only 2-5% absorbed, reduced by phytates). Vitamin C enhances non-haem iron absorption. Milk very low in iron. Iron deficiency: most common nutritional deficiency worldwide.' },
  { topic:'nutrition', q:'POSHAN Abhiyaan (2018) aims to reduce stunting by:', opts:['1% per year','2% per year','5% per year','10% per year'], ans:1, expl:'POSHAN Abhiyaan (Pradhan Mantri Poshan Shakti Nirman, 2018): aims to reduce stunting, wasting, undernutrition, and anaemia by 2% per year. Uses real-time monitoring through ICDS-CAS. Target: reduce stunting from 38.4% (NFHS-4) to less than 25% by 2022.' },
  { topic:'nutrition', q:'RDA of protein for a normal adult Indian male is approximately:', opts:['0.5 g/kg/day','0.8-1.0 g/kg body weight/day','1.5 g/kg/day','2.5 g/kg/day'], ans:1, expl:'ICMR RDA for protein: adult male 0.8-1.0 g/kg/day (approximately 60 g/day for 60 kg adult). Pregnant women: extra 15 g/day. Lactating: extra 25 g/day (first 6 months). Protein quality: biological value of egg = 100 (reference); milk 85; meat 80.' },

  /* ═══ BATCH B — IMMUNIZATION ═══ */
  { topic:'immunization', q:'Cold chain equipment used to store vaccines at Sub-Centre level is:', opts:['Deep freezer','Ice-lined refrigerator (ILR)','Vaccine carrier','Cold box'], ans:2, expl:'Cold chain hierarchy: Regional/State: Cold Room, Deep Freeze; District: ILR + Deep Freezer; PHC/CHC: ILR + Deep Freeze; Sub-centre: Vaccine carrier (1 session). For outreach: foam-pad vaccine carrier. Sub-centre ANM uses vaccine carrier to transport vaccines for immunisation sessions.' },
  { topic:'immunization', q:'BCG vaccine repeat dose:', opts:['BCG is given only once - no repeat dose recommended','4 weeks after missed dose','8 weeks after missed dose','3 months after missed dose'], ans:0, expl:'BCG is given only ONCE - at birth or as early as possible. No repeat dose given even if scar does not develop. Absence of BCG scar does NOT indicate failed vaccination. If missed, give up to 1 year of age. No booster required.' },
  { topic:'immunization', q:'Vitamin A supplementation - first large dose is given at:', opts:['At birth','6 weeks','9 months (along with measles vaccine)','12 months'], ans:2, expl:'Vitamin A supplementation schedule: First dose (1,00,000 IU) at 9 months with MR vaccine. Subsequent doses (2,00,000 IU) every 6 months until 5 years. Total 9 doses. Prevents night blindness, xerophthalmia, reduces child mortality.' },
  { topic:'immunization', q:'Which vaccine is given subcutaneously?', opts:['BCG','OPV','MMR (Measles-Mumps-Rubella vaccine)','DPT'], ans:2, expl:'Routes: BCG - Intradermal (ID); OPV - Oral; DPT/Pentavalent - Intramuscular (IM); Hepatitis B - IM; MMR - Subcutaneous (SC); MR - SC; Typhoid (injectable ViPS) - SC; Varicella - SC. BCG ID and MMR SC are most commonly asked.' },
  { topic:'immunization', q:'Cold chain temperature for storing vaccines (except OPV) at PHC level is:', opts:['0-4 degrees C','2-8 degrees C','-10 to 0 degrees C','-20 to -15 degrees C'], ans:1, expl:'Vaccine storage: Most vaccines: 2-8 degrees C. OPV: -20 degrees C (deep freeze) for long-term storage. Never freeze DPT, Hepatitis B, PCV, Hib - these are freeze-sensitive.' },
  { topic:'immunization', q:'Pentavalent vaccine given in Universal Immunisation Programme covers:', opts:['Diphtheria, Tetanus, Pertussis only','DPT + Hepatitis B + Haemophilus influenzae type b (Hib)','DPT + Polio + Measles','Hepatitis A + B + Tetanus'], ans:1, expl:'Pentavalent vaccine: DPT + Hepatitis B + Hib (prevents meningitis, pneumonia, epiglottitis). Given at 6, 10, 14 weeks (3 doses). Replaced DPT + HepB given separately. Introduced in India\'s UIP from 2011.' },
  { topic:'immunization', q:'Rotavirus vaccine (RVV) prevents:', opts:['Polio','Rotavirus diarrhoea (leading cause of severe childhood diarrhoea and death)','Typhoid fever','Cholera'], ans:1, expl:'Rotavirus vaccine prevents rotavirus gastroenteritis - leading cause of severe diarrhoeal dehydration and death in children under 5 years globally. Given orally at 6, 10, 14 weeks. Introduced in India\'s UIP from 2016. Reduces severe diarrhoea hospitalisation by 50-60%.' },
  { topic:'immunization', q:'TT (Tetanus Toxoid) during pregnancy schedule in India:', opts:['One dose at 28 weeks','Two doses: TT1 at first contact after 12 weeks, TT2 four weeks later','Only if not previously vaccinated','Three doses every trimester'], ans:1, expl:'TT in pregnancy (now Td - Tetanus-diphtheria): TT1 - early in pregnancy after 12 weeks. TT2 - 4 weeks after TT1. Booster if received 2+ doses in previous pregnancy within 3 years (only 1 dose then). Protects newborn from neonatal tetanus. Protection duration: about 3 years.' },
  { topic:'immunization', q:'Japanese Encephalitis (JE) vaccine is given under UIP in endemic areas at:', opts:['9 months','9 months and 16-24 months','6 weeks only','At birth'], ans:1, expl:'JE vaccine: 9 months (1st dose) and 16-24 months (2nd dose) in endemic areas. 113 districts in 15 states endemic for JE. JE transmitted by Culex mosquito (pig to mosquito to human). Encephalitis, fever, altered consciousness. CFR 20-30%, survivors 30-50% have neurological sequelae.' },
  { topic:'immunization', q:'The "cold chain" is essential because:', opts:['Vaccines need to be sterile','Vaccines lose potency if exposed to heat (some also to freezing) - must be maintained at 2-8 degrees C throughout','Vaccines need to be mixed with cold water','Vaccines are stored with antibiotics'], ans:1, expl:'Cold chain: system of storing and transporting vaccines at recommended temperatures from manufacturer to recipient. Most vaccines: 2-8 degrees C. Heat-sensitive = all. Freeze-sensitive: DPT, Hep B, PCV, Hib (freezing destroys aluminium adjuvant causing aggregation, loss of potency). Vaccine vial monitor (VVM) indicates heat exposure.' },

  /* ═══ BATCH B — MENTAL HEALTH ═══ */
  { topic:'mental', q:'Positive symptoms of schizophrenia include:', opts:['Flat affect and social withdrawal','Poverty of speech (alogia) and avolition','Hallucinations and delusions','Memory loss and dementia'], ans:2, expl:'Schizophrenia positive symptoms (excess/distortion of normal function): Hallucinations (auditory most common - hearing voices), Delusions (fixed false beliefs - persecutory, grandiose), Disorganised speech. Negative symptoms: Flat affect, Alogia, Avolition, Anhedonia, Social withdrawal. Treatment: antipsychotics.' },
  { topic:'mental', q:'CAGE questionnaire screens for:', opts:['Depression','Anxiety disorder','Alcohol use disorder','Domestic violence'], ans:2, expl:'CAGE: C (Cut down - felt need to cut down drinking?), A (Annoyed - criticised by others?), G (Guilty - felt guilty about drinking?), E (Eye-opener - needed drink first thing in morning?). Score 2 or more = likely alcohol problem. AUDIT (10 questions) is more comprehensive.' },
  { topic:'mental', q:'National Mental Health Programme (NMHP) was launched in:', opts:['1975','1982','1990','2003'], ans:1, expl:'NMHP launched in 1982. Objectives: ensure minimum mental health care for all, encourage community participation, promote mental health through PHC. District Mental Health Programme (DMHP): 1996 - integrated mental health into general healthcare. Mental Healthcare Act 2017: rights-based approach, decriminalises suicide attempt.' },
  { topic:'mental', q:'ECT (Electroconvulsive Therapy) is most effective for:', opts:['Schizophrenia with positive symptoms','Alcohol dependence','Severe depression with suicidal risk or catatonia','Personality disorders'], ans:2, expl:'ECT: Indications - Severe depression (especially with suicidal risk), Catatonia, Severe mania, Refractory schizophrenia. Modified ECT under GA + muscle relaxant. Side effects: anterograde amnesia (usually temporary). Very effective - fastest onset versus antidepressants.' },
  { topic:'mental', q:'Suicide prevention - when a person expresses suicidal ideation, immediate priority is:', opts:['Ignore if they seem calm','Give antidepressants immediately','Risk assessment and ensuring safety (remove means, do not leave alone, refer to psychiatrist)','Tell them to pray'], ans:2, expl:'Suicide risk management: SLAP assessment (Specificity of plan, Lethality of method, Availability of means, Proximity of help). Immediate action: active listening, non-judgemental approach, assess risk level, remove means (guns, medications), do NOT leave alone, refer to mental health professional. iCall (TISS): 9152987821.' },

  /* ═══ BATCH B — ENVIRONMENT ═══ */
  { topic:'environment', q:'Minamata disease is caused by:', opts:['Lead poisoning','Mercury poisoning (methylmercury from contaminated fish)','Arsenic poisoning','Cadmium poisoning'], ans:1, expl:'Minamata disease (Japan, 1950s): methylmercury poisoning from industrial effluent contaminating fish. Features: sensory disturbances, ataxia, visual/hearing impairment, tremors, birth defects. Itai-Itai disease: Cadmium poisoning. Blue baby syndrome: nitrate poisoning (methaemoglobinaemia). Fluorosis: excess fluoride.' },
  { topic:'environment', q:'Bhopal gas tragedy (1984) involved leakage of:', opts:['Chlorine gas','Methyl Isocyanate (MIC) from Union Carbide plant','Carbon monoxide','Sulphur dioxide'], ans:1, expl:'Bhopal gas disaster (December 2-3, 1984): Methyl Isocyanate (MIC) gas leaked from Union Carbide India Ltd. Worst industrial disaster. Over 3,000 immediate deaths; 15,000+ total deaths; 500,000+ affected. Led to Environmental Protection Act 1986 in India.' },
  { topic:'environment', q:'Noise level harmful to hearing with prolonged exposure is above:', opts:['50 dB','70 dB','85 dB','100 dB'], ans:2, expl:'85 dB (A-weighted) is the threshold for occupational noise-induced hearing loss (NIHL) with prolonged exposure (8 hours/day). WHO: recreational noise exposure limit 70 dB (24-hour average). For each 3 dB increase, safe exposure time halves.' },
  { topic:'environment', q:'Biological Oxygen Demand (BOD) measures:', opts:['Dissolved oxygen in water','Amount of oxygen needed by micro-organisms to decompose organic matter in water (indicator of organic pollution)','Total dissolved solids','pH of water'], ans:1, expl:'BOD: amount of oxygen micro-organisms need to decompose organic matter at 20 degrees C in 5 days. High BOD = high organic pollution. Clean river: BOD <1 mg/L; slightly polluted: 2-5; heavily polluted: >10 mg/L. Used to assess sewage treatment efficiency.' },
  { topic:'environment', q:'Pasteurisation of milk (HTST method) involves heating at:', opts:['63 degrees C for 30 minutes','72 degrees C for 15 seconds (High Temperature Short Time - HTST)','100 degrees C for 5 minutes','121 degrees C for 15 minutes'], ans:1, expl:'Milk pasteurisation methods: HTST: 72 degrees C for 15 seconds - most common commercial method. LTLT (Holder method): 63 degrees C for 30 minutes. UHT: 135-150 degrees C for 2-6 seconds (shelf-stable milk). Kills pathogens (TB, Brucella, Salmonella) without affecting nutritive value.' },

  /* ═══ BATCH B — FIRST AID ═══ */
  { topic:'firstaid', q:'RICE principle for musculoskeletal injuries stands for:', opts:['Rest, Ice, Compression, Exercise','Rest, Ice, Compression, Elevation','Rehab, Ice, Cold, Elevation','Run, Immobilise, Cast, Elevate'], ans:1, expl:'RICE for sprains/strains: Rest (stop activity), Ice (20 min every 2 hours - reduces swelling/pain), Compression (elastic bandage - prevents swelling), Elevation (raise limb above heart level - reduces oedema). Apply within 48 hours of injury.' },
  { topic:'firstaid', q:'Heimlich manoeuvre is performed for:', opts:['Cardiac arrest','Choking (foreign body airway obstruction - FBAO) in conscious adult/child','Drowning','Seizure'], ans:1, expl:'Heimlich manoeuvre: abdominal thrusts for conscious choking adult/child over 1 year. Stand behind, hands clasped below xiphoid process and above navel, thrust inward and upward to dislodge foreign body. Infants under 1 year: 5 back blows + 5 chest thrusts (NOT abdominal thrusts). If unconscious: CPR.' },
  { topic:'firstaid', q:'In case of electrical injury, the first step is:', opts:['Start CPR immediately','Disconnect power source / switch off electricity before touching the victim','Apply cold water to burns','Call ambulance then touch victim'], ans:1, expl:'Electrical injury first step: DISCONNECT POWER SOURCE before touching victim (to prevent rescuer becoming a victim). Switch off mains; use non-conductive material (dry wood, rubber) to push away wire if cannot switch off. Then assess and start CPR if needed.' },
  { topic:'firstaid', q:'The correct position for an unconscious but breathing patient is:', opts:['Supine (flat on back)','Prone (face down)','Recovery position (lateral recumbent - left lateral)','Sitting upright'], ans:2, expl:'Recovery position (left lateral/lateral recumbent): used for unconscious patients who ARE BREATHING. Prevents aspiration of vomit, maintains airway. HAINES position for suspected spinal injury. Supine: for CPR. Pregnant women: left lateral to avoid aorto-caval compression.' },
  { topic:'firstaid', q:'A tourniquet should be applied:', opts:['Directly over a wound','As distally (close to wound) as possible on a limb','Proximally (between wound and heart) as high as possible on limb to control life-threatening bleeding','Over a joint'], ans:2, expl:'Tourniquet: used for life-threatening limb haemorrhage when direct pressure fails. Apply PROXIMALLY (between heart and wound), 5-8 cm above wound, NOT over joint. Note time of application. Tighten until bleeding stops. Do NOT remove in field - removal can cause fatal reperfusion haemorrhage.' },
  { topic:'firstaid', q:'For a suspected spinal injury, the most important immediate action is:', opts:['Sit patient up','Immobilise the cervical spine (do not move the neck) and maintain in neutral position','Apply firm massage to the back','Make patient walk to assess injury'], ans:1, expl:'Suspected spinal injury (trauma, fall from height, diving): DO NOT FLEX/ROTATE NECK. Immobilise in neutral alignment. Apply cervical collar if available. Log-roll technique to move (3-4 persons). Jaw-thrust manoeuvre for airway (avoids neck extension). Call 108.' },

  /* ═══ BATCH B — HEALTH PROGRAMS ═══ */
  { topic:'programs', q:'Ayushman Bharat PM-JAY provides health cover of:', opts:['1 lakh per family per year','2 lakh per family per year','5 lakh per family per year','10 lakh per family per year'], ans:2, expl:'PM-JAY (launched Sept 2018): provides 5 lakh rupees per family per year for secondary and tertiary hospitalisation. Covers bottom 40% of population (about 50 crore beneficiaries). Cashless, paperless at empanelled hospitals.' },
  { topic:'programs', q:'Janani Shishu Suraksha Karyakram (JSSK) entitles pregnant women to:', opts:['Cash incentive for institutional delivery','Free and cashless delivery, C-section, drugs, diagnostics, diet, transport - no out-of-pocket expenditure','Conditional cash transfer','Home delivery kit'], ans:1, expl:'JSSK (2011): entitles ALL pregnant women to FREE services - normal delivery, C-section, drugs, diagnostics, diet (3 meals/day during stay), transport (home to facility and back), blood transfusion. Extends to sick newborns up to 30 days. Zero out-of-pocket expenditure.' },
  { topic:'programs', q:'Rashtriya Bal Swasthya Karyakram (RBSK) focuses on screening children for 4 Ds:', opts:['Defects, Diseases, Disorders, Deficiencies (of development - 0-18 years)','Diarrhoea, Dysentery, Dengue, Diabetes','Disability, Death, Delay, Deficiency','Depression, Defects, Disorders, Diseases'], ans:0, expl:'RBSK (2013): screens ALL children (0-18 years) for 4 Ds - Birth Defects, Diseases, Deficiencies (nutrition, anaemia, vision, hearing), Development Delays/Disabilities. Mobile Health Teams visit schools, anganwadis. Free treatment + referral to DEIC (District Early Intervention Centre).' },
  { topic:'programs', q:'NPCDCS stands for:', opts:['National Programme for Cancer, Diabetes, Cardiovascular and Stroke','National Public Child Disease Control Scheme','National Prevention of Communicable Diseases and Control Strategy','National Programme for Community Development and Child Survival'], ans:0, expl:'NPCDCS: National Programme for Prevention and Control of Cancer, Diabetes, Cardiovascular Diseases and Stroke (launched 2010). Under NHM. Provides screening at 30+ years at Sub-Health Centre level for Hypertension, Diabetes, and 3 cancers (oral, breast, cervical).' },
  { topic:'programs', q:'India declared elimination of leprosy in:', opts:['1995','2000','2005 (prevalence less than 1 per 10,000 population)','2010'], ans:2, expl:'India declared elimination of leprosy (prevalence rate <1 per 10,000 population) in December 2005 at national level. NLEP provides free MDT (Multi-Drug Therapy). Targets: zero disability, zero transmission. Disability grade 0: no disability; Grade 1: loss of sensation; Grade 2: visible deformity.' },
  { topic:'programs', q:'Ayushman Bharat Health and Wellness Centres (HWCs) provide how many types of services?', opts:['5','8','12','15'], ans:2, expl:'Ayushman Bharat HWC (converted from Sub-Health Centres and PHCs): provides 12 services including: comprehensive primary care for NCDs, mental health, oral health, ENT, opthalmology, geriatric care, palliative care, trauma, emergency services, maternal/child health, family planning, immunisation. Run by Community Health Officer (CHO).' },
  { topic:'programs', q:'The Village Health Sanitation and Nutrition Committee (VHSNC) meets:', opts:['Annually','Quarterly','Monthly','Weekly'], ans:2, expl:'VHSNC meets monthly. Composition: Panchayat members, ASHA, AWW, ANM, community representatives. Functions: planning village health activities, monitoring sanitation (ODF status), overseeing VHND (Village Health Nutrition Day), reviewing untied funds (10,000 rupees/year per village).' },

  /* ═══ BATCH B — STATISTICS ═══ */
  { topic:'stats', q:'Sensitivity of a diagnostic test means:', opts:['Ability to correctly identify true negatives (healthy people)','Ability to correctly identify true positives (proportion of sick people who test positive)','Positive predictive value','Specificity'], ans:1, expl:'Sensitivity = TP/(TP+FN) x 100 = True Positive Rate. A sensitive test catches most sick people (few false negatives). Use highly SENSITIVE tests for screening. Specificity = TN/(TN+FP) x 100 = True Negative Rate. Specific tests rule out disease. Mnemonic: SnNOut (sensitive + negative result = rules out).' },
  { topic:'stats', q:'Odds Ratio (OR) is used in:', opts:['Cohort studies','Cross-sectional studies','Case-control studies','Randomised controlled trials'], ans:2, expl:'Case-control studies: cannot calculate incidence so use Odds Ratio (OR). OR = (cases exposed/cases unexposed) / (controls exposed/controls unexposed) = ad/bc in a 2x2 table. OR >1 = increased risk. OR <1 = protective. Cohort/RCT use Relative Risk (RR).' },
  { topic:'stats', q:'Normal distribution - percentage of values within plus or minus 1 standard deviation:', opts:['50%','68.2%','95.4%','99.7%'], ans:1, expl:'Normal distribution: +/- 1 SD = 68.2%; +/- 2 SD = 95.4%; +/- 3 SD = 99.7% (68-95-99.7 rule). Reference ranges in clinical medicine use mean +/- 2 SD (captures 95% of normal population).' },
  { topic:'stats', q:'Crude Death Rate (CDR) is expressed as deaths per:', opts:['100 population','1,000 population per year','10,000 population','1,00,000 population'], ans:1, expl:'CDR = (Total deaths in a year / Mid-year population) x 1000. Unit: per 1000 population per year. India CDR (SRS 2020): about 7.4/1000. IMR: deaths under 1 year per 1000 live births. MMR: maternal deaths per 1,00,000 live births.' },
  { topic:'stats', q:'Maternal Mortality Ratio (MMR) is defined as:', opts:['Maternal deaths per 1000 women aged 15-49','Maternal deaths per 1,00,000 live births (during pregnancy/childbirth/42 days postpartum)','Maternal deaths per 1000 deliveries','Maternal deaths per 10,000 pregnancies'], ans:1, expl:'MMR = (Maternal deaths / Live births) x 1,00,000. Maternal death: death during pregnancy or within 42 days from causes related to pregnancy. India MMR (SRS 2018-20): 97/1,00,000 live births. Target SDG 3.1: <70 by 2030. Leading causes in India: PPH, hypertension, sepsis.' },
  { topic:'stats', q:'Incidence rate measures:', opts:['Total cases in population at a point in time','Number of NEW cases developing in a population at risk over a defined time period','Death rate from a disease','Proportion of exposed individuals who develop disease'], ans:1, expl:'Incidence = New cases / Population at risk x 1000. Measures RATE OF OCCURRENCE of new disease. Used for acute/infectious diseases. Prevalence = All cases (new + old) / Total population. Prevalence = Incidence x Duration. High incidence, short duration (common cold) = low prevalence.' },
  { topic:'stats', q:'Attack rate is used mainly in:', opts:['Chronic disease epidemiology','Outbreak/epidemic investigations for communicable diseases','Calculating age-standardised mortality rates','Long-term cohort studies'], ans:1, expl:'Attack rate (AR) = Number of new cases / Population at risk during epidemic x 100. Used in outbreak investigations (foodborne outbreaks, measles outbreaks). Secondary Attack Rate (SAR) = new cases among household contacts / susceptible household contacts x 100.' },
  { topic:'stats', q:'P-value of 0.03 in a study means:', opts:['There is 3% chance the study hypothesis is correct','There is 3% probability of obtaining the observed result if the null hypothesis is true - statistically significant at p<0.05','There is 97% certainty of association','The effect size is clinically important'], ans:1, expl:'P-value: probability of getting observed results assuming null hypothesis is true. p<0.05 = statistically significant. p=0.03 means 3% probability result is due to chance - statistically significant. Does NOT indicate clinical significance or effect size. Confidence intervals provide more information.' },

  /* ═══ BATCH B — NURSING PROCEDURES ═══ */
  { topic:'nursing', q:'WHO 6-step hand washing time is:', opts:['10-15 seconds','20 seconds','40-60 seconds','90-120 seconds'], ans:2, expl:'WHO 6-step hand hygiene technique takes 40-60 seconds with soap and water; 20-30 seconds with alcohol-based hand rub (ABHR). Steps: palm-to-palm, between fingers, backs of hands, interlacing fingers, rotational rubbing of thumbs, fingertips. Perform before/after patient contact, after removing gloves.' },
  { topic:'nursing', q:'Normal oral body temperature in adults is:', opts:['36.0 degrees C','37.0 degrees C (98.6 F)','37.5 degrees C','38.0 degrees C'], ans:1, expl:'Normal oral temperature: 37.0 degrees C (98.6 degrees F). Rectal temperature: 0.5 degrees C higher. Axillary temperature: 0.5 degrees C lower. Fever: 38 degrees C+ (100.4 F) oral. Hyperthermia: >40 degrees C. Hypothermia: <35 degrees C.' },
  { topic:'nursing', q:'Lumbar puncture is performed in which position?', opts:['Prone position','Supine position','Lateral recumbent (fetal position - knees to chest, chin down) or sitting forward-leaning','Standing position'], ans:2, expl:'Lumbar puncture: lateral recumbent (fetal/curled) position OR sitting leaning forward. Both positions flex the spine maximally to widen intervertebral spaces for needle insertion at L3-L4 or L4-L5. Nurse maintains position, monitors for post-LP headache (most common complication - lie flat after).' },
  { topic:'nursing', q:'Best method to confirm NG tube placement is:', opts:['Listening with stethoscope while injecting air','Checking if patient can speak','X-ray (chest X-ray confirming tube position in stomach)','Aspirating and checking pH >7'], ans:2, expl:'BEST method to confirm NG tube placement: X-ray (radiographic confirmation) - gold standard. Aspirate pH 5.5 or less = gastric (reliable). Air injection + auscultation (whoosh test) is UNRELIABLE - not recommended as sole confirmation. Never feed without confirming placement.' },
  { topic:'nursing', q:'Sterile technique is mandatory for:', opts:['Bathing a patient','Taking oral temperature','Urinary catheter insertion (Foley catheter)','Weighing a patient'], ans:2, expl:'Sterile technique (asepsis) mandatory for: Urinary catheter insertion, wound care (surgical dressings), IV insertion, spinal procedures, surgical operations. Clean technique: NG tube insertion, bed bath, enema. Medical asepsis: handwashing, reduces microbial count.' },
  { topic:'nursing', q:'Pressure ulcers most commonly develop over:', opts:['Deltoid region','Knee joint anteriorly','Bony prominences - sacrum, heels, greater trochanter','Abdomen'], ans:2, expl:'Pressure ulcers (bedsores/decubitus ulcers): tissue damage from sustained pressure reducing blood flow. Most common sites: sacrum (No. 1), heels (No. 2), greater trochanter, ischial tuberosities, ankles, occiput. Prevention: 2-hourly repositioning, pressure-relieving mattress, skin assessment, nutrition optimisation. Braden Scale: risk assessment tool.' },
  { topic:'nursing', q:'When preparing an injection, nurse should check:', opts:['5 rights only','5 rights + expiry date + drug appearance + allergies (extended rights)','Only the drug name','Only the dose'], ans:1, expl:'Rights of medication administration: 5 Rights: Right Patient, Right Drug, Right Dose, Right Route, Right Time. Extended rights also include: Right Documentation, Right Reason, Right Response, Right to Refuse. Also check: expiry date, drug integrity, patient allergies. Check 3 times: when taking from shelf, when drawing up, before administering.' },
  { topic:'nursing', q:'WHO 5 Moments of Hand Hygiene include:', opts:['Before eating, after toilet, before cooking, after coughing, before sleeping','Before patient contact, before aseptic procedure, after body fluid exposure, after patient contact, after contact with patient environment','At start of shift, mid-shift, end of shift, after breaks, before documenting','Before medication, after medication, before meals, after meals, before sleep'], ans:1, expl:'WHO 5 Moments: (1) Before patient contact, (2) Before aseptic procedure, (3) After body fluid exposure/risk, (4) After patient contact, (5) After contact with patient surroundings/environment. Prevent transmission of HAIs (Healthcare-Associated Infections).' },
  { topic:'nursing', q:'Suction pressure for oropharyngeal suctioning in adults is:', opts:['50-80 mmHg','80-120 mmHg','150-200 mmHg','200-250 mmHg'], ans:1, expl:'Suction pressure: Adults 80-120 mmHg; Children 80-100 mmHg; Infants/Neonates 60-80 mmHg. Duration: each suction pass 10-15 seconds maximum for adults, 5 seconds for neonates. Oxygenate before and after suctioning.' },

  /* ═══ BATCH C — DISEASES & EPIDEMIOLOGY ═══ */
  { topic:'community', q:'Dengue fever is transmitted by:', opts:['Anopheles mosquito','Aedes aegypti (bites during day, breeds in clean stagnant water)','Culex mosquito','Sandfly'], ans:1, expl:'Dengue: transmitted by Aedes aegypti (primary vector) and Ae. albopictus (secondary). Day-biting mosquito. Breeds in clean, stagnant water (flower pots, tyres, coolers). Four serotypes (DENV 1-4). Features: sudden high fever, severe headache, retro-orbital pain, myalgia, arthralgia, rash. Warning signs: abdominal pain, persistent vomiting, bleeding.' },
  { topic:'community', q:'Kala-azar (visceral leishmaniasis) is transmitted by:', opts:['Anopheles mosquito','Culex mosquito','Sandfly (Phlebotomus argentipes)','Aedes mosquito'], ans:2, expl:'Kala-azar: caused by Leishmania donovani; transmitted by female Phlebotomus argentipes (sandfly). Features: prolonged irregular fever, progressive splenomegaly (massive), hepatomegaly, anaemia, weight loss, darkening of skin (kala-azar = black fever). Endemic in Bihar, Jharkhand, UP, West Bengal. Treatment: Miltefosine (oral), Liposomal Amphotericin B.' },
  { topic:'community', q:'Filariasis (lymphatic) is caused by:', opts:['Wuchereria bancrofti (transmitted by Culex mosquito)','Plasmodium vivax (transmitted by Anopheles)','Leishmania donovani','Trypanosoma brucei'], ans:0, expl:'Lymphatic filariasis: Wuchereria bancrofti (>90%) transmitted by Culex quinquefasciatus. Features: fever, lymphadenitis, lymphoedema, elephantiasis (chronic), hydrocele. Microfilariae in blood (nocturnal periodicity). Treatment: DEC (Diethylcarbamazine) + Albendazole (MDA - Mass Drug Administration annually). India: highest burden globally.' },
  { topic:'community', q:'Japanese Encephalitis (JE) is transmitted by:', opts:['Aedes aegypti','Anopheles mosquito','Culex tritaeniorhynchus (breeds in rice fields)','Sandfly'], ans:2, expl:'Japanese Encephalitis: Flavivirus transmitted by Culex tritaeniorhynchus and related species. Amplifying hosts: pigs and ardeid birds (herons). Breeding in rice field irrigation. Features: fever, headache, vomiting, altered consciousness, seizures (especially children). CFR 20-30%, severe neurological sequelae in survivors.' },
  { topic:'community', q:'The incubation period of malaria (P. falciparum) is:', opts:['1-3 days','7-14 days (average 9-10 days for P. falciparum)','21-28 days','3-6 months'], ans:1, expl:'Malaria incubation periods: P. falciparum: 7-14 days (average 9-10 days). P. vivax: 10-17 days (can be 6-12 months for relapsing strains). P. malariae: 18-40 days. P. ovale: 10-17 days. P. knowlesi: 9-12 days. P. falciparum most dangerous - can cause cerebral malaria (coma), severe anaemia, multi-organ failure.' },
  { topic:'community', q:'Mode of transmission of HIV/AIDS is:', opts:['Mosquito bites','Handshake or sharing utensils','Unprotected sexual intercourse, contaminated blood/needles, mother to child (MTCT)','Airborne droplets'], ans:2, expl:'HIV transmission: Unprotected sexual intercourse (most common globally), Contaminated blood (transfusions, shared needles - IDU), Mother to child (MTCT: during pregnancy, labour/delivery, breastfeeding). NOT transmitted by: mosquitoes, air, sharing utensils, handshake, hugging, saliva (unless blood-contaminated). Window period: 3-12 weeks.' },
  { topic:'community', q:'CD4 count at which ART (antiretroviral therapy) should be started in HIV:', opts:['CD4 <500 cells/mm3','CD4 <350 cells/mm3','Regardless of CD4 count (treat all)','Only when AIDS-defining illness occurs'], ans:2, expl:'WHO/NACO guidelines: Treat ALL HIV-positive individuals regardless of CD4 count (Test and Treat policy, adopted globally 2015). Previously: CD4 <350, then <500. MTCT prevention: ART to all HIV+ pregnant women from diagnosis through breastfeeding. First-line ART in India: TDF + 3TC/FTC + EFV.' },
  { topic:'community', q:'Rabies is transmitted by:', opts:['Mosquito bite','Bite/scratch of infected animal (dog most common in India) - virus in saliva','Contaminated water','Sexual contact'], ans:1, expl:'Rabies: transmitted by bite or scratch of infected animal (saliva contains virus). Dogs (97% in India), bats, jackals, cats, monkeys. Incubation: 20-60 days (can be weeks to months). Features: hydrophobia (fear of water), aerophobia, agitation, paralysis, coma. Once symptoms appear: almost 100% fatal. PEP: wound washing + anti-rabies vaccine + RIG.' },
  { topic:'community', q:'Tetanus is caused by:', opts:['Clostridium tetani (produces tetanospasmin toxin causing muscle spasms)','Staphylococcus aureus','Streptococcus pyogenes','Bacillus anthracis'], ans:0, expl:'Tetanus (lockjaw): Clostridium tetani (gram-positive anaerobic rod, spore-forming). Wound infection releases tetanospasmin toxin → blocks inhibitory neurotransmitters in spinal cord → sustained muscle spasms (trismus/lockjaw, risus sardonicus, opisthotonus). Treatment: wound debridement, TIG (tetanus immunoglobulin), antibiotics (Metronidazole), muscle relaxants.' },
  { topic:'community', q:'The incubation period of chickenpox (varicella) is:', opts:['2-5 days','10-21 days (average 14-16 days)','21-35 days','2-3 months'], ans:1, expl:'Chickenpox (Varicella-zoster virus): incubation 10-21 days (average 14-16 days). Features: pruritic vesicular rash (all stages simultaneously - papule, vesicle, pustule, crust), fever, malaise. Infectious from 1-2 days before rash until all vesicles crusted (usually 5 days after rash onset). Herpes zoster (shingles): reactivation in dermatomal distribution.' },
  { topic:'community', q:'Whooping cough (pertussis) is caused by:', opts:['Bordetella pertussis (transmitted by respiratory droplets)','Streptococcus pneumoniae','Haemophilus influenzae','Mycobacterium tuberculosis'], ans:0, expl:'Pertussis (whooping cough): Bordetella pertussis. Airborne/droplet transmission. Three stages: Catarrhal (cold-like, 1-2 weeks), Paroxysmal (whooping cough, 1-6 weeks - paroxysms ending in whoop, post-tussive vomiting), Convalescent. Most dangerous in infants under 6 months (apnoea). Prevention: DPT vaccine (Pertussis component).' },
  { topic:'community', q:'Measles (rubeola) - characteristic pathognomonic feature is:', opts:['Cherry-red spot on macula','Koplik spots (white spots on buccal mucosa) - appear before rash','Strawberry tongue','Forchheimer spots'], ans:1, expl:'Measles pathognomonic: Koplik spots (white/blue-grey spots on buccal mucosa opposite molar teeth) - appear 2 days before rash, disappear as rash appears. Measles rash: maculopapular, starts at face/behind ears, spreads downward. Complications: pneumonia (most common cause of death), encephalitis, SSPE (subacute sclerosing panencephalitis). Prevention: MR/MMR vaccine.' },
  { topic:'community', q:'Hepatitis B is transmitted through:', opts:['Faeco-oral route (contaminated food/water)','Blood, sexual contact, mother to child (perinatal) - NOT faeco-oral','Airborne droplets','Mosquito bites'], ans:1, expl:'Hepatitis B (HBV): parenteral/sexual/perinatal transmission. Routes: blood transfusion, contaminated needles (IDU, medical), sexual contact, MTCT (perinatal - most common globally). NOT faeco-oral. Hepatitis A: faeco-oral. HBsAg: surface antigen (marker of infection). Anti-HBs: protective antibody (after vaccination or recovery). HBeAg: infectivity marker.' },
  { topic:'community', q:'Multi-Drug Resistant Tuberculosis (MDR-TB) is defined as resistance to:', opts:['Ethambutol and Pyrazinamide','Streptomycin only','Rifampicin and Isoniazid (at minimum)','All second-line drugs'], ans:2, expl:'MDR-TB: resistant to at least Rifampicin (R) and Isoniazid (H) - the two most important first-line drugs. XDR-TB (Extensively Drug Resistant): MDR-TB + resistance to fluoroquinolones + at least one injectable second-line drug. Pre-XDR-TB (2021 WHO definition): MDR-TB + resistance to any fluoroquinolone.' },
  { topic:'community', q:'Chickenpox is most infectious during:', opts:['After all vesicles crust over','1-2 days before rash until all vesicles have crusted (approximately 5 days after rash onset)','Only when fever is present','During the convalescent phase'], ans:1, expl:'Chickenpox is infectious from 1-2 days before rash until ALL vesicles have crusted (approximately 5 days after rash onset). Transmission: respiratory droplets and direct contact with vesicles. Isolation required during infectious period. VZV-IgG can confirm immunity. Varicella vaccine: 2 doses recommended.' },

  /* ═══ BATCH C — REPRODUCTIVE HEALTH & FP ═══ */
  { topic:'fp', q:'The most effective reversible contraceptive method is:', opts:['Male condom (barrier method)','Combined oral contraceptive pills','Copper-T (Intrauterine Device) - failure rate <1%','Rhythm/calendar method'], ans:2, expl:'Copper-T (IUD) is the most effective reversible contraceptive (failure rate <1%). Mechanism: copper ions are spermicidal + prevents implantation. Duration: 5-10 years. Side effects: increased menstrual flow, dysmenorrhoea. Absolute contraindications: pregnancy, PID, uterine anomaly. Hormonal IUD (Mirena): lighter periods.' },
  { topic:'fp', q:'Emergency contraception (morning-after pill) is effective if taken within:', opts:['6 hours of unprotected intercourse','24 hours only','72 hours (3 days) - ideally as soon as possible','7 days'], ans:2, expl:'Emergency contraception (EC): Levonorgestrel (Plan B) 1.5 mg single dose OR 0.75 mg x 2 doses 12 hours apart. Effective within 72 hours (3 days) of unprotected intercourse - efficacy decreases with time delay. Ella (Ulipristal acetate): up to 5 days. Copper-T IUD: most effective EC, up to 5 days. Does NOT cause abortion - prevents ovulation/fertilisation.' },
  { topic:'fp', q:'Vasectomy (male sterilisation) involves:', opts:['Removal of testes','Cutting and ligating the vas deferens (permanent sterilisation, done under local anaesthesia)','Hormonal injection','Insertion of a device'], ans:1, expl:'Vasectomy: bilateral ligation, excision, or occlusion of vas deferens. Permanent sterilisation (consider irreversible). Done under local anaesthesia in outpatient setting (<30 min). Semen analysis after 12-20 ejaculations to confirm azoospermia. Failure rate: <0.1%. Complications: haematoma, infection, sperm granuloma. NSV (No-Scalpel Vasectomy): preferred technique.' },
  { topic:'fp', q:'Tubectomy (female sterilisation) should ideally be performed:', opts:['During menstruation','Interval tubectomy: 6 weeks after delivery or during menstrual phase; Post-partum: within 7 days of delivery','During pregnancy','Only before first pregnancy'], ans:1, expl:'Tubectomy (tubal ligation/occlusion): Interval: 6+ weeks postpartum (uterus involuted) or during menstrual phase (luteal phase - not pregnant). Post-partum (mini-lap): within 48 hours (easier - fundus still high) or 7 days postpartum. Mini-laparotomy (Pomeroy technique most common) or laparoscopy. DMPA (injectable) given same day.' },
  { topic:'fp', q:'DMPA (Depo-Medroxyprogesterone Acetate) injection interval is:', opts:['Every month','Every 2 months','Every 3 months (12 weeks)','Every 6 months'], ans:2, expl:'DMPA (Depo-Provera): injectable progestogen contraceptive given IM (gluteal or deltoid) every 3 months (12 weeks, allowance +/- 2 weeks). Highly effective (failure rate <1%). Side effects: irregular bleeding (most common), amenorrhoea, weight gain, delayed return of fertility (12-18 months). Does NOT protect against STIs.' },
  { topic:'fp', q:'Natural Family Planning (NFP) - the Billings Ovulation Method (BOM) is based on:', opts:['Basal body temperature','Cervical mucus changes (clear, slippery, stretchy = fertile)','Calendar calculation only','Hormone measurement'], ans:1, expl:'Billings Ovulation Method (Cervical Mucus Method): monitors cervical mucus changes throughout cycle. Before ovulation: mucus becomes clear, slippery, stretchy (like raw egg white) = FERTILE phase. After ovulation: mucus thick, cloudy, sticky = infertile. Day of peak mucus = ovulation. Requires training. Failure rate higher than hormonal methods if used alone.' },
  { topic:'fp', q:'Under Mission Parivar Vikas, the total fertility rate (TFR) target for high-focus districts is:', opts:['Below 3.0','Below 2.5','Below 2.1','Below 1.5'], ans:2, expl:'Mission Parivar Vikas (2016): focused on 146 high-fertility districts in 7 states (UP, Bihar, Rajasthan, MP, Chhattisgarh, Jharkhand, Assam) with TFR >3. Target: bring TFR to below 2.1 (replacement level). Services: contraceptives, spacing methods (PPIUCD, PPL), community mobilisation. Saathiya Salah app: youth counselling.' },
  { topic:'fp', q:'Copper-T is contraindicated in:', opts:['Nulliparous women','Women over 40 years','Active pelvic inflammatory disease (PID) or unexplained vaginal bleeding','Women using antibiotics'], ans:2, expl:'Copper-T absolute contraindications: pregnancy, PID (current or recent), unexplained vaginal bleeding, uterine anomaly (bicornuate, fibroid distorting cavity), Wilson\'s disease (copper). Relative contraindications: nulliparity, heavy periods. WHO MEC 4 (absolute C/I): pregnancy, unexplained AUB, gestational trophoblastic disease.' },

  /* ═══ BATCH C — SCHOOL HEALTH & ADOLESCENT HEALTH ═══ */
  { topic:'community', q:'Rashtriya Kishor Swasthya Karyakram (RKSK) addresses health of adolescents aged:', opts:['5-12 years','10-19 years','15-25 years','18-30 years'], ans:1, expl:'RKSK (Rashtriya Kishor Swasthya Karyakram, 2014): addresses health needs of adolescents aged 10-19 years (WHO definition). Six strategic areas: nutrition, reproductive and sexual health, non-communicable diseases, substance misuse, injuries and violence, mental health. Peer educators (Saathiyas) key component. AFHC (Adolescent-Friendly Health Clinic) at PHC level.' },
  { topic:'community', q:'School health programme includes:', opts:['Vaccination only','Medical examination, vision and hearing screening, dental check, nutrition assessment, mental health, health education','Only nutrition supplementation','Only dental check'], ans:1, expl:'School Health Programme (under NHM, RBSK): health screening by Mobile Health Team: vision screening (colour blindness, refractive errors), hearing, dental (dental caries), nutritional assessment (height, weight, MUAC), developmental assessment, congenital defects, skin conditions. Free spectacles for children with refractive errors. Medical records for each child.' },
  { topic:'community', q:'Menarche (first menstruation) typically occurs at age:', opts:['8-10 years','11-14 years (average 13 years)','15-17 years','18-20 years'], ans:1, expl:'Menarche: average 12-13 years in Indian girls (range 11-14 years). Preceded by: thelarche (breast development, average 10-11 years), pubarche (pubic hair). Menstrual cycle: 21-35 days (average 28 days). Duration: 3-7 days. Blood loss: 30-80 mL. Precocious puberty: before 8 years. Delayed puberty: no signs by 13 years.' },
  { topic:'community', q:'Menstrual Hygiene Day is celebrated on:', opts:['8 March','28 May (for 28-day cycle, 5 days of menstruation - 28/5)','14 November','1 December'], ans:1, expl:'Menstrual Hygiene Day: 28 May (chosen for 28-day average menstrual cycle, 5 days average menstruation). Celebrated since 2014 to break taboos and raise awareness. Government schemes: free sanitary napkins under NHM (Suvidha brand, 6 pads for 6 rupees). Sabla scheme: menstrual hygiene component for girls 11-14 years.' },

  /* ═══ BATCH C — GERIATRIC HEALTH ═══ */
  { topic:'community', q:'National Programme for Health Care of the Elderly (NPHCE) defines elderly as persons aged:', opts:['55 years and above','60 years and above','65 years and above','70 years and above'], ans:1, expl:'NPHCE defines elderly: 60 years and above (follows WHO Asia-Pacific definition). India elderly population (2021): ~138 million (10% of total). Very elderly: 80+ years. NPHCE services: dedicated geriatric OPD, 10-bed wards at district hospitals, regional geriatric centres, physiotherapy, occupational therapy, special clinics at HWC level.' },
  { topic:'community', q:'Most common cause of disability in elderly in India is:', opts:['Visual impairment','Locomotor disability','Hearing impairment','Cognitive impairment'], ans:1, expl:'Locomotor disability (mobility impairment) is most common disability in elderly. Causes: osteoarthritis (most common), osteoporosis, fractures (hip fracture - major cause of morbidity/mortality in elderly), stroke sequelae, Parkinson\'s disease. Falls are a major problem - 30% of elderly fall each year. Fall prevention: exercise, environment modification, vision correction.' },

  /* ═══ BATCH C — OCCUPATIONAL HEALTH ═══ */
  { topic:'environment', q:'Silicosis is caused by inhalation of:', opts:['Asbestos fibres','Coal dust','Crystalline silica/quartz dust (stone quarrying, sandblasting, mining)','Cotton fibre (byssinosis)'], ans:2, expl:'Silicosis: pneumoconiosis from inhalation of crystalline silica (quartz). Occupations at risk: mining, stone quarrying, sandblasting, pottery, glass-making. Radiological: eggshell calcification of hilar nodes, nodular opacities (upper lobes). Progressive massive fibrosis. No cure - preventive (dust control, respirators). Increased risk of TB (silicotuberculosis).' },
  { topic:'environment', q:'Byssinosis is an occupational lung disease caused by:', opts:['Coal dust','Asbestos fibres','Cotton, hemp, or flax dust (textile industry)','Silica dust'], ans:2, expl:'Byssinosis (Brown Lung Disease/Monday Fever): caused by inhalation of organic dust from cotton, flax, hemp. Textile workers. Features: chest tightness, cough, wheeze - worse on Monday after weekend break (Monday morning syndrome). Pathology: bronchoconstriction from endotoxins. Prevention: dust control, rotation, PPE. Treatment: bronchodilators.' },
  { topic:'environment', q:'Occupational Safety and Health (OSH) in India is governed by:', opts:['Environment Protection Act 1986','Factories Act 1948 (safety, health, welfare of workers in factories)','Consumer Protection Act','Food Safety Act'], ans:1, expl:'Factories Act 1948: primary legislation for occupational health and safety in India. Provisions: working hours (48 hours/week), leave, canteen, crèche, safety devices, health provisions (cleanliness, ventilation, temperature, lighting, drinking water), appointment of safety officer in factories with 1000+ workers. Amended 1987 to include hazardous processes.' },
  { topic:'environment', q:'Lead poisoning (plumbism) most commonly affects which system?', opts:['Hepatic system','Central nervous system (especially children) and peripheral nervous system','Renal system only','Endocrine system'], ans:1, expl:'Lead poisoning: CNS (children most vulnerable - learning disability, IQ loss, behavioural problems, encephalopathy), peripheral nervous system (wrist drop, foot drop - motor neuropathy), haematological (anaemia - inhibits haem synthesis, basophilic stippling in RBCs), renal (nephropathy). Blood lead >10 mcg/dL in children = toxicity. Sources: leaded paint, contaminated water, batteries, pottery.' },

  /* ═══ BATCH C — DISASTER MANAGEMENT & TRIAGE ═══ */
  { topic:'firstaid', q:'Triage colour for immediate priority (life-threatening but salvageable) is:', opts:['Green (walking wounded)','Yellow (delayed care)','Red (immediate priority - life-threatening injuries)','Black (deceased/expectant)'], ans:2, expl:'START Triage: Red = Immediate (life-threatening, survivable - breathing restored after repositioning, RR >30, no radial pulse, altered mental status). Yellow = Delayed (serious but stable). Green = Minor (walking wounded). Black = Deceased or Expectant (unsurvivable given resources). Applied in mass casualty incidents (MCI).' },
  { topic:'firstaid', q:'In the START (Simple Triage And Rapid Treatment) system, the first step is:', opts:['Check pupillary response','Direct all walking wounded to a specific location (Green/Minor category)','Start CPR on all non-breathing victims','Administer IV fluids'], ans:1, expl:'START Triage first step: Direct all those who can walk to a designated area (Green/Minor). Then assess remaining non-ambulatory patients: Step 1: Breathing? (Open airway if not - if still not breathing = Black). Step 2: Respiratory rate? (>30 = Red). Step 3: Radial pulse/perfusion? (absent = Red). Step 4: Mental status? (cannot follow commands = Red).' },
  { topic:'firstaid', q:'The disaster management cycle includes:', opts:['Mitigation, Preparedness, Response, Recovery','Planning, Implementation, Monitoring, Evaluation','Awareness, Prevention, Treatment, Rehabilitation','Isolation, Treatment, Observation, Discharge'], ans:0, expl:'Disaster Management Cycle (4 phases): Mitigation (reduce risk - building codes, land use planning), Preparedness (plans, training, early warning systems), Response (search/rescue, emergency relief, triage), Recovery (rebuilding, rehabilitation, mental health support). India: National Disaster Management Authority (NDMA) coordinates under Disaster Management Act 2005.' },

  /* ═══ BATCH C — PHARMACOLOGY ═══ */
  { topic:'drug', q:'Which antibiotic is contraindicated in pregnancy (causes "grey baby syndrome" in neonates)?', opts:['Amoxicillin','Chloramphenicol','Erythromycin','Clindamycin'], ans:1, expl:'Chloramphenicol: contraindicated in neonates and late pregnancy. Causes Grey Baby Syndrome (cardiovascular collapse, cyanosis, grey colour) in neonates - immature liver cannot glucuronidate the drug. Also: aplastic anaemia (idiosyncratic, 1:25,000). Use only when no alternative exists. Safe antibiotic in pregnancy: Amoxicillin, Erythromycin, Cephalosporins.' },
  { topic:'drug', q:'ORS (Oral Rehydration Solution) contains (WHO standard formula):', opts:['Glucose 20 g/L, NaCl 10 g/L, KCl 10 g/L','Glucose 13.5 g/L, NaCl 2.6 g/L, KCl 1.5 g/L, Sodium citrate 2.9 g/L (Reduced osmolarity ORS)','Only glucose and water','Salt and sugar only'], ans:1, expl:'WHO Reduced Osmolarity ORS (2002): Glucose 13.5 g/L, NaCl 2.6 g/L, KCl 1.5 g/L, Sodium citrate 2.9 g/L. Osmolarity: 245 mOsm/L (reduced from original 311). Home-made ORS: 1 litre clean water + 6 teaspoons sugar + half teaspoon salt. Zinc supplementation (20 mg/day x 14 days) alongside ORS in diarrhoea.' },
  { topic:'drug', q:'Oxytocin is used for:', opts:['Tocolysis (stopping premature labour)','Induction of labour, augmentation of labour, and prevention/treatment of PPH','Antiemetic in pregnancy','Cervical ripening only'], ans:1, expl:'Oxytocin: naturally released from posterior pituitary during labour and breastfeeding. Therapeutic uses: (1) Induction of labour (IV infusion), (2) Augmentation of slow labour, (3) Prevention of PPH (Active Management of Third Stage Labour - AMTSL: 10 IU IM within 1 minute of baby birth), (4) Treatment of PPH. Contraindicated: cephalopelvic disproportion, fetal distress without delivery setup.' },
  { topic:'drug', q:'Metronidazole is the drug of choice for:', opts:['Malaria','Tuberculosis','Amoebiasis and anaerobic infections (including trichomoniasis)','Typhoid fever'], ans:2, expl:'Metronidazole (Flagyl): nitroimidazole. Drug of choice for: Amoebiasis (intestinal + hepatic amoebic abscess), Giardiasis, Trichomoniasis (both partners treated), Bacterial vaginosis, Anaerobic infections (Bacteroides, Clostridium). Avoid alcohol (disulfiram-like reaction). Safe in 2nd/3rd trimester of pregnancy (avoid 1st trimester theoretically).' },
  { topic:'drug', q:'Diazepam belongs to which drug class?', opts:['Opioid analgesic','Benzodiazepine (anxiolytic, anticonvulsant, muscle relaxant, sedative)','NSAID','Beta-blocker'], ans:1, expl:'Diazepam: benzodiazepine. Enhances GABA (inhibitory neurotransmitter) effect. Uses: anxiety, alcohol withdrawal, status epilepticus (IV), muscle spasm (tetanus), pre-operative sedation, febrile seizures. Adverse effects: sedation, respiratory depression, dependence, paradoxical excitation (in elderly). Flumazenil: reversal agent (competitive antagonist).' },
  { topic:'drug', q:'Salbutamol (Albuterol) is a:', opts:['Beta-1 adrenergic blocker','Beta-2 adrenergic agonist (bronchodilator - used in asthma/COPD)','Alpha-1 agonist','Anticholinergic agent'], ans:1, expl:'Salbutamol (Ventolin): selective Beta-2 agonist. Causes bronchodilation (used in asthma, COPD, bronchospasm). Onset: 5-15 min (inhaled). Also used as tocolytic (suppresses premature uterine contractions). Side effects: tremor, tachycardia, hypokalaemia. MDI technique: shake, exhale, seal lips, slow deep breath, hold 10 sec, wait 1 min between puffs.' },
  { topic:'drug', q:'Artemisinin-based Combination Therapy (ACT) is used for treatment of:', opts:['Vivax malaria only','Falciparum malaria (and all uncomplicated malaria in India - AL combination)','Multi-drug resistant tuberculosis','Kala-azar'], ans:1, expl:'ACT (Artemisinin Combination Therapy): used for P. falciparum malaria. In India: Artemether-Lumefantrine (AL) 3-day course for uncomplicated falciparum. Severe malaria: Artesunate IV (preferred over Quinine). P. vivax: Chloroquine + Primaquine (14 days) for radical cure. Primaquine: kills hypnozoites (liver stages - prevents relapse). G6PD testing before Primaquine.' },
  { topic:'drug', q:'Which drug is used for deworming (anthelmintic therapy) in children under NHM?', opts:['Metronidazole','Albendazole 400 mg single dose (biannual)','Mebendazole 500 mg','Levamisole'], ans:1, expl:'National Deworming Day (NDD): Albendazole 400 mg single dose given biannually to ALL children 1-19 years. Targets: soil-transmitted helminths (STH) - Ascaris, Trichuris, hookworm. Children 1-2 years: Albendazole 200 mg crushed. Given on 10 February and 10 August. Mop-up day 2 weeks later. Also given through ICDS to children under 5 years. Reduces anaemia, improves nutrition/school performance.' },
  { topic:'drug', q:'Which drug should NOT be given to children under 8 years (causes permanent tooth discolouration)?', opts:['Amoxicillin','Azithromycin','Tetracycline (and Doxycycline)','Cephalexin'], ans:2, expl:'Tetracyclines (tetracycline, doxycycline, minocycline): contraindicated in children under 8 years and in pregnancy. Chelates calcium in developing teeth and bones causing permanent yellow-brown discolouration of teeth and enamel hypoplasia. Also inhibits bone growth. Exception: Doxycycline used for Rocky Mountain Spotted Fever in any age when life-threatening.' },

  /* ═══ BATCH C — ANATOMY CONTINUED ═══ */
  { topic:'anatomy', q:'The hormone responsible for "fight or flight" response is:', opts:['Cortisol','Aldosterone','Adrenaline (epinephrine) from adrenal medulla','Thyroid hormone'], ans:2, expl:'Fight or flight response: Adrenaline (epinephrine) from adrenal medulla (chromaffin cells). Effects: increased HR, BP, blood glucose, bronchodilation, pupil dilation, reduced GI motility, sweating. Released during stress, fear, exercise. Noradrenaline: also released (more vasoconstrictive). Cortisol: sustained stress response from adrenal cortex.' },
  { topic:'anatomy', q:'Which part of the brain is responsible for balance and coordination?', opts:['Cerebrum','Cerebellum','Brainstem (medulla oblongata)','Hypothalamus'], ans:1, expl:'Cerebellum (Latin = little brain): posterior cranial fossa. Functions: coordination of voluntary movements, balance, posture, muscle tone, fine motor skills. Damage (cerebellar lesion): ataxia (unsteady gait), dysmetria (past-pointing), dysdiadochokinesia (inability to do rapid alternating movements), intention tremor, nystagmus. FAST mnemonic: Face-Arms-Speech-Time (stroke identification).' },
  { topic:'anatomy', q:'The primary hormone regulating blood calcium levels is:', opts:['Calcitonin','Parathyroid hormone (PTH) - raises blood calcium','Aldosterone','Growth hormone'], ans:1, expl:'PTH (Parathyroid Hormone) from parathyroid glands: raises blood calcium by: (1) Bone resorption (osteoclast activation), (2) Renal calcium reabsorption, (3) Intestinal calcium absorption (via Vitamin D activation). Calcitonin (thyroid C-cells): lowers blood calcium. Hypoparathyroidism: hypocalcaemia, tetany, Chvostek sign, Trousseau sign.' },
  { topic:'anatomy', q:'The menstrual cycle is regulated primarily by:', opts:['Prolactin only','FSH and LH from pituitary, oestrogen and progesterone from ovaries','TSH and T4','Oxytocin only'], ans:1, expl:'Menstrual cycle regulation: hypothalamus (GnRH) → anterior pituitary (FSH + LH) → ovary (oestrogen + progesterone). Follicular phase: FSH stimulates follicle growth, oestrogen rises. Ovulation: LH surge (around day 14). Luteal phase: corpus luteum produces progesterone. If no pregnancy: corpus luteum regresses, progesterone falls, menstruation. Cycle: 28 days average.' },
  { topic:'anatomy', q:'Location of the spleen is:', opts:['Right hypochondriac region','Left hypochondriac region (under left ribs, 9-11)','Epigastric region','Umbilical region'], ans:1, expl:'Spleen: Left hypochondriac region, under ribs 9-11 posterolaterally. Functions: filters blood (removes old/damaged RBCs), immune function (lymphocytes, antibodies), reservoir for blood. Splenomegaly: malaria (most common in India), kala-azar (massive), typhoid, cirrhosis. Splenectomy: post-splenectomy vaccinations (pneumococcal, meningococcal, Hib) required.' },
  { topic:'anatomy', q:'The stomach produces which acid responsible for gastric digestion?', opts:['Acetic acid','Hydrochloric acid (HCl) by parietal cells, plus pepsinogen by chief cells','Bile acids','Pancreatic enzymes'], ans:1, expl:'Stomach secretions: HCl (by parietal/oxyntic cells) - acidifies stomach (pH 1.5-2), activates pepsinogen to pepsin, kills bacteria. Pepsinogen (by chief cells) → Pepsin (protein digestion). Intrinsic Factor (by parietal cells) - essential for Vitamin B12 absorption (deficiency = pernicious anaemia). Mucus (by goblet cells) - protects stomach lining.' },
  { topic:'anatomy', q:'Iron is absorbed mainly in:', opts:['Stomach','Duodenum and upper jejunum (proximal small intestine)','Ileum','Large intestine'], ans:1, expl:'Iron absorption: primarily in duodenum and upper jejunum. Ferrous (Fe2+) better absorbed than ferric (Fe3+). Enhanced by: Vitamin C, acidic environment, haem iron. Inhibited by: phytates, oxalates, tannins (tea), calcium, antacids. Total body iron: 3-4 g (70% in haemoglobin). Daily requirement: adult male 1 mg, female 2 mg (menstruating), pregnant 4 mg.' },
  { topic:'anatomy', q:'The thoracic duct drains lymph from:', opts:['Right side of head and neck, right arm, right thorax','All of body except right upper quadrant (drains into left subclavian vein)','Only abdominal organs','Lower limbs only'], ans:1, expl:'Thoracic duct: largest lymphatic vessel. Drains ALL lymph EXCEPT right upper quadrant. Starts at cisterna chyli (L2), ascends through thorax, empties into left subclavian vein at jugulo-subclavian junction. Right lymphatic duct: drains right head/neck, right arm, right thorax → right subclavian vein. Important in chylothorax, lymphoma.' },

  /* ═══ BATCH C — NURSING THEORY & ETHICS ═══ */
  { topic:'nursing', q:'The nursing process has how many steps?', opts:['3','4','5 (Assessment, Diagnosis, Planning, Implementation, Evaluation)','6'], ans:2, expl:'Nursing Process: 5 steps - (1) Assessment (data collection), (2) Nursing Diagnosis (identify problem - NANDA), (3) Planning (set goals, outcomes), (4) Implementation (carry out nursing interventions), (5) Evaluation (did patient achieve goals? revise plan if needed). Mnemonic: ADPIE. Scientific, systematic, person-centred approach.' },
  { topic:'nursing', q:'Florence Nightingale is known for:', opts:['Discovering penicillin','Founding modern nursing, reducing Crimean War mortality through hygiene and sanitation reforms','Developing the nursing process','Writing the first anatomy textbook'], ans:1, expl:'Florence Nightingale (1820-1910): Lady with the Lamp. Pioneered modern nursing during Crimean War (1853-56). Reduced mortality from 42% to 2% through handwashing, sanitation, nutrition. Founded first nursing school (St. Thomas\'s Hospital, London, 1860). Developed statistical graphics (polar area diagram/rose chart). WHO: 12 May (her birthday) = International Nurses Day.' },
  { topic:'nursing', q:'Informed consent in healthcare means:', opts:['Patient signs a form without explanation','Patient receives complete information about procedure, risks, benefits, alternatives, and voluntarily agrees','Doctor decides without consulting patient','Consent from patient\'s family only'], ans:1, expl:'Informed consent: ethical and legal requirement. Elements: (1) Disclosure - adequate information (diagnosis, procedure, risks, benefits, alternatives), (2) Comprehension - patient understands, (3) Voluntariness - free from coercion, (4) Competence - patient able to decide. Not required in emergencies (implied consent). Written for surgery/invasive procedures. Right to refuse treatment (competent adult).' },
  { topic:'nursing', q:'Maslow\'s Hierarchy of Needs - from LOWEST (most basic) to HIGHEST:', opts:['Physiological, Safety, Love/Belonging, Esteem, Self-actualisation','Safety, Physiological, Esteem, Love, Self-actualisation','Love, Safety, Physiological, Esteem, Self-actualisation','Self-actualisation, Esteem, Love, Safety, Physiological'], ans:0, expl:'Maslow\'s Hierarchy (pyramid base to top): (1) Physiological (food, water, air, sleep, sex), (2) Safety (security, order, protection), (3) Love/Belonging (relationships, family, community), (4) Esteem (recognition, achievement, self-respect), (5) Self-actualisation (reaching full potential). Lower needs must be met before higher. Foundation for nursing care prioritisation.' },
  { topic:'nursing', q:'Which nursing theorist developed the Theory of Human Caring?', opts:['Florence Nightingale','Virginia Henderson','Jean Watson','Dorothy Orem'], ans:2, expl:'Jean Watson: Theory of Human Caring (1979). Core concepts: 10 Caritas Processes (previously carative factors). Focus on humanistic, spiritual aspects of nursing care. Virginia Henderson: defined nursing - "assist the individual...in the performance of activities contributing to health or its recovery." Orem: Self-Care Deficit Theory. Roy: Adaptation Model.' },
  { topic:'nursing', q:'The priority nursing intervention for a patient with airway obstruction is:', opts:['Administer oxygen','Establish IV access','Clear the airway (A - Airway is always first priority in ABC)','Document in nursing notes'], ans:2, expl:'ABC priority: Airway ALWAYS first. Clear airway using: head-tilt/chin-lift (no spinal injury), jaw-thrust (suspected spinal), suctioning, positioning (lateral), Heimlich (choking), insertion of OPA/NPA, intubation. Then Breathing (oxygen, ventilation). Then Circulation (IV access, fluids). Then Disability (neuro assessment). Documentation is last priority in emergencies.' },

  /* ═══ BATCH C — JKSSB SPECIFIC - J&K HEALTH ═══ */
  { topic:'programs', q:'Which National Health Mission (NHM) component addresses tribal and difficult areas in J&K?', opts:['NRHM (National Rural Health Mission)','ASHA and mobile health units for hard-to-reach areas under NHM flexible funding','NUHM (National Urban Health Mission) only','NPCD only'], ans:1, expl:'NHM in J&K: flexible pool funding allows mobile health units for remote/hard-to-reach areas. J&K has 2 divisions, 20 districts. Hilly terrain = lower population norms for PHC (3000-5000). ASHA programme active. Special focus on migrant population (Gujjars/Bakarwals). J&K BOSE (Board of School Education) conducts health education. Free drugs under NDHM.' },
  { topic:'programs', q:'Swachh Bharat Mission (Gramin) aims to achieve:', opts:['100% vaccination coverage','Open Defecation Free (ODF) India and solid/liquid waste management in rural areas','Universal health coverage','100% institutional delivery'], ans:1, expl:'Swachh Bharat Mission (SBM) Gramin (launched 2 Oct 2014): aims for ODF (Open Defecation Free) India. Provides subsidy for individual household toilets (IHHL) - Rs 12,000 for BPL/OBC/SC/ST families. ODF status declared when >95% HHs have and use toilets. SBM 2.0 (2020-2025): ODF-Plus - solid/liquid waste management, fecal sludge management.' },
  { topic:'programs', q:'NIKSHAY portal is used for:', opts:['HIV/AIDS patient registration','TB (Tuberculosis) patient notification and tracking system','Immunisation records','NCD patient management'], ans:1, expl:'NIKSHAY: web-based IT system for TB notification and patient management under National TB Programme (NTP/RNTCP). All TB cases must be NOTIFIED to NIKSHAY (mandatory since 2012, private also since 2014). Patient support: NIKSHAY Poshan Yojana (Rs 500/month food support to TB patients). Also available as NIKSHAY mobile app.' },
  { topic:'programs', q:'Under NHM, untied fund given to ASHA is:', opts:['Rs 5,000 per year','Rs 10,000 per year','Rs 10,000 per year (ASHA Drug Kit + untied fund)','Rs 1,000 per year'], ans:1, expl:'ASHA untied fund: Rs 10,000 per year to maintain drug kit, travel expenses for meetings, etc. ASHA Drug Kit: basic medicines (ORS, OCP, Chlorhexidine, Iron + Folic Acid tablets, paracetamol, DDT/Permethrin) replenished free. Sub-centre untied fund: Rs 10,000 per year. VHSNC untied fund: Rs 10,000 per village per year. PHC Rogi Kalyan Samiti: Rs 1 lakh.' },
  { topic:'programs', q:'Health and Wellness Centre (HWC) is being created by upgrading:', opts:['District hospitals','Community Health Centres only','Sub-Health Centres (SHC) and Primary Health Centres (PHC) - target 1.5 lakh HWCs by 2022','Medical colleges'], ans:2, expl:'Ayushman Bharat - Health and Wellness Centres (HWCs): upgrade 1,50,000 SHCs and PHCs to HWCs by 2022. Each HWC staffed by Community Health Officer (CHO) - B.Sc./Diploma holder trained for 6 months in comprehensive primary healthcare. 12 services including NCDs, mental health, oral health, geriatric care at doorstep. Teleconsultation with specialists.' },

  /* ═══ BATCH C — MORE COMMUNITY NURSING ═══ */
  { topic:'community', q:'The triad of epidemiology (epidemiological triangle) consists of:', opts:['Host, Agent, Vector','Host, Agent, Environment (and time as fourth dimension)','Patient, Doctor, Disease','Prevention, Treatment, Rehabilitation'], ans:1, expl:'Epidemiological Triad: Host (human factors - age, sex, immunity, nutrition, behaviour), Agent (biological, chemical, physical, nutritional, social), Environment (physical, biological, social/cultural, economic). Interaction of all three determines disease occurrence. Time: fourth dimension. John Gordon\'s concept. Used to analyse disease causation and control.' },
  { topic:'community', q:'Subclinical infection (inapparent infection) refers to:', opts:['Infection with no symptoms (asymptomatic) but with immune response and ability to transmit','Severe infection needing hospital','Infection requiring antibiotics','Infection in immunocompromised patients only'], ans:0, expl:'Subclinical infection: infection occurs (pathogen enters, immune response happens) but NO clinical symptoms. Individual may still be infectious to others (carrier state). Iceberg phenomenon: majority of infections are subclinical (below waterline). Clinical cases = tip of iceberg. Examples: polio (99% subclinical), hepatitis A (children often asymptomatic), TB.' },
  { topic:'community', q:'Cross-sectional study measures:', opts:['Incidence (new cases over time)','Prevalence (existing cases at a point in time)','Relative risk','Attributable risk'], ans:1, expl:'Cross-sectional study (prevalence study/survey): measures prevalence of disease at a SINGLE POINT IN TIME. Snapshot of population. Cannot determine causality (exposure and outcome measured simultaneously). Used for: burden of disease, health surveys (NFHS), planning health services. Measures: prevalence ratio or odds ratio. Cannot calculate incidence.' },
  { topic:'community', q:'Notifiable diseases in India must be reported to:', opts:['Only the treating physician','Local health authorities (CMO/DVDMS) within prescribed time - 24 hours for priority diseases','Hospital administrator only','WHO only'], ans:1, expl:'Notifiable disease reporting: to local/district health authority (CMO, DVDMS - District Vector Borne Disease Management Society, etc.). Diseases notifiable under various state epidemic acts + IDSP. Category P1 (Priority 1): immediately notifiable within 24 hours - cholera, plague, SARS, AFP, fever with haemorrhage. Category P2: within 1 week - dengue, typhoid, etc. IDSP: Integrated Disease Surveillance Programme.' },
  { topic:'community', q:'Social autopsy in maternal mortality is:', opts:['Performing post-mortem on maternal death','Community-level investigation to understand social/systemic factors contributing to maternal death (beyond medical cause)','Statistical analysis of death certificates','Autopsy performed by community health workers'], ans:1, expl:'Social autopsy: verbal/social autopsy conducted by community/health team for ALL maternal and infant deaths. Identifies social, economic, cultural, health system factors (3 delays model) that contributed to death - beyond the immediate medical cause. Verbal autopsy: questionnaire to family. WHO V2/V3 questionnaire. Purpose: identify preventable factors, improve quality of care.' },
  { topic:'community', q:'The Millennium Development Goals (MDGs) were replaced by Sustainable Development Goals (SDGs) in:', opts:['2010','2013','2015 (SDGs: 17 goals, 169 targets - target year 2030)','2020'], ans:2, expl:'SDGs (Sustainable Development Goals): adopted September 2015 at UN General Assembly. 17 goals, 169 targets, deadline 2030. Replaced MDGs (2000-2015, 8 goals). Key health-related SDGs: SDG 3 (Good Health and Well-being - 13 sub-targets including UHC, MMR <70, end TB/malaria/AIDS, NCD reduction), SDG 2 (Zero Hunger - nutrition), SDG 6 (Clean water/sanitation).' },

  /* ═══ BATCH C — ADDITIONAL MCH ═══ */
  { topic:'mch', q:'IUGR (Intrauterine Growth Restriction) is defined as:', opts:['Birth weight less than 2000 g','Fetal weight below 10th percentile for gestational age on ultrasound','Gestational age less than 37 weeks','Fetal heart rate below 100 bpm'], ans:1, expl:'IUGR: fetal weight below 10th percentile for gestational age (Biometric parameters: BPD, HC, AC, FL on USG). Types: Symmetric (global - chromosomal, infection, early) and Asymmetric (late onset - placental insufficiency, most common - head sparing). Complications: fetal distress, stillbirth, neonatal hypoglycaemia, hypothermia. Assessment: Doppler (umbilical artery flow).' },
  { topic:'mch', q:'The Partograph is a tool used to monitor:', opts:['Fetal heart rate only','Progress of labour (cervical dilation, fetal descent, maternal vitals, contractions) to detect abnormal labour early','Postpartum haemorrhage','Neonatal resuscitation'], ans:1, expl:'Partograph: graphical record of labour progress. Parameters: cervical dilation (plotted on alert line - 1 cm/hour, action line - 4 hours to right), fetal descent, fetal heart rate (every 30 min), uterine contractions (every 30 min), maternal BP, pulse, temperature, urine. Alert line: normal progress. Action line: take action (augment/refer). WHO recommends universal use.' },
  { topic:'mch', q:'Neonatal jaundice (physiological) appears:', opts:['At birth or within 24 hours (pathological - investigate)','Between 2-3 days and resolves by 7-10 days','After 2 weeks','Only in preterm babies'], ans:1, expl:'Physiological jaundice: appears day 2-3, peaks day 4-5, resolves by day 7 (term) or day 14 (preterm). Due to: breakdown of fetal Hb, immature liver conjugation. Pathological jaundice: appears within 24 hours, bilirubin rises >5 mg/dL/day, total >20 mg/dL in term (higher risk in preterm), persists >2 weeks. Causes: ABO/Rh incompatibility, G6PD deficiency, sepsis. Treatment: phototherapy, exchange transfusion.' },
  { topic:'mch', q:'Neonatal Resuscitation - "Golden Minute" refers to:', opts:['First minute of life - complete initial assessment and ventilation if needed','First hour of life after birth','First 60 seconds of CPR','Time to call a paediatrician'], ans:0, expl:'Golden Minute: complete initial steps of resuscitation and begin ventilation (if needed) within the FIRST 60 SECONDS of life. Initial steps: warm, dry, stimulate, clear airway. Assess breathing, HR. If not breathing/HR <100: PPV (Positive Pressure Ventilation) with bag-mask. If HR <60 despite PPV: chest compressions. Medications: Adrenaline. NRP (Neonatal Resuscitation Programme) guidelines.' },
  { topic:'mch', q:'Under JSSK (Janani Shishu Suraksha Karyakram), sick newborns are entitled to free care up to:', opts:['7 days','15 days','30 days after birth','6 months'], ans:2, expl:'JSSK sick newborn entitlements: FREE care up to 30 days after birth at public health facilities. Includes: free drugs, diagnostics, blood, diet for mother (staying with sick newborn), transport (SNCU to higher centre and back). Extends to all sick newborns regardless of BPL/APL status. Special Newborn Care Unit (SNCU) at district hospitals for level 3 care.' },
  { topic:'mch', q:'The definition of stillbirth (WHO) is:', opts:['Fetal death at any gestational age','Baby born dead after 28 weeks gestation (or 1000 g birth weight)','Baby who dies within first hour of birth','Fetal death before 20 weeks (miscarriage)'], ans:1, expl:'Stillbirth (WHO/national definition): baby born dead after 28 completed weeks of gestation (or 1000 g birth weight). Antepartum stillbirth: death before onset of labour. Intrapartum stillbirth: death during labour (preventable - high quality intrapartum care). India stillbirth rate: ~14/1000 births (NFHS-5). SDG target: reduce to 12/1000 by 2030.' },

  /* ═══ BATCH C — ADDITIONAL ANATOMY ═══ */
  { topic:'anatomy', q:'The four chambers of the heart are:', opts:['2 atria and 2 ventricles (right atrium, right ventricle, left atrium, left ventricle)','3 atria and 1 ventricle','1 atrium and 3 ventricles','2 atria only'], ans:0, expl:'Heart has 4 chambers: Right Atrium (receives deoxygenated blood from SVC/IVC), Right Ventricle (pumps to pulmonary artery/lungs), Left Atrium (receives oxygenated blood from pulmonary veins), Left Ventricle (pumps to aorta/body - thickest wall). Valves: Tricuspid (RA-RV), Pulmonary, Mitral/Bicuspid (LA-LV), Aortic.' },
  { topic:'anatomy', q:'Thyroid gland produces which hormones?', opts:['Insulin and Glucagon','T3 (triiodothyronine) and T4 (thyroxine) and Calcitonin','PTH and Calcitonin only','ACTH and TSH'], ans:1, expl:'Thyroid gland: Follicular cells produce T3 (triiodothyronine, biologically active) and T4 (thyroxine, precursor). Parafollicular C-cells produce Calcitonin. T3/T4: regulate BMR, growth, development, mental function. Hypothyroidism: myxoedema (adult), cretinism (infant). Hyperthyroidism: Graves\' disease (autoimmune, TSH-receptor antibodies), exophthalmos.' },
  { topic:'anatomy', q:'Normal CSF (Cerebrospinal Fluid) pressure is:', opts:['50-100 mmH2O','70-180 mmH2O','200-250 mmH2O','300-400 mmH2O'], ans:1, expl:'Normal CSF pressure: 70-180 mmH2O (5-15 mmHg) in lateral decubitus position. CSF: produced by choroid plexus in lateral ventricles (500 mL/day), circulates through ventricular system, subarachnoid space, reabsorbed by arachnoid granulations into venous sinuses. Volume: 150 mL. Normal appearance: crystal clear, colourless. Xanthochromia (yellow): subarachnoid haemorrhage.' },
  { topic:'anatomy', q:'The female reproductive hormone responsible for maintaining pregnancy (corpus luteum phase) is:', opts:['Oestrogen','Progesterone (produced by corpus luteum, then placenta after 10 weeks)','FSH','Oxytocin'], ans:1, expl:'Progesterone: "pro-gestation" hormone. Produced by: corpus luteum (after ovulation, first 10-12 weeks of pregnancy), placenta (from 10-12 weeks = luteo-placental shift). Functions: maintain endometrium, suppress uterine contractions (maintains pregnancy), stimulate breast development (alveoli), raise basal body temperature (after ovulation - 0.5 degrees C rise = marker of ovulation).' },
  { topic:'anatomy', q:'The site of gaseous exchange in the lungs is:', opts:['Bronchi','Bronchioles','Alveoli (surrounded by pulmonary capillaries - alveolocapillary membrane)','Trachea'], ans:2, expl:'Alveoli: tiny air sacs (300 million in adults - surface area ~70 m2). Site of O2 and CO2 exchange. Alveolocapillary (blood-air) membrane: thin (0.5 micrometres). Alveolar cells: Type I (gas exchange) and Type II (surfactant production - prevents collapse). Surfactant: deficient in preterm babies causing Respiratory Distress Syndrome (IRDS).' },
  { topic:'anatomy', q:'The hormone responsible for "let-down" reflex during breastfeeding is:', opts:['Prolactin','Oxytocin (from posterior pituitary - causes myoepithelial cells to contract, ejecting milk)','FSH','Oestrogen'], ans:1, expl:'Oxytocin (from posterior pituitary - neuroendocrine reflex): causes milk ejection (let-down) by contracting myoepithelial cells around alveoli and ducts. Released by suckling stimulus (or emotional cues). Also causes uterine contractions (helps involution postpartum). Prolactin (from anterior pituitary): stimulates MILK PRODUCTION. Suckling → prolactin release (maintains milk supply).' },

  /* ═══ BATCH D — COMPREHENSIVE REVIEW ═══ */
  { topic:'community', q:'The Integrated Disease Surveillance Programme (IDSP) was launched in:', opts:['1990','2004','2010','2015'], ans:1, expl:'IDSP launched 2004 (Phase 1) under World Bank funding. National Centre for Disease Control (NCDC) is nodal agency. Three reporting formats: S (Syndromic - community/school-based, weekly), P (Presumptive - PHC/ASHA level, weekly), L (Laboratory-confirmed, weekly). Rapid Response Teams (RRT) deployed on outbreak alerts.' },
  { topic:'community', q:'Village Health Nutrition Day (VHND) is held:', opts:['Daily','Weekly','Monthly at Anganwadi Centre','Quarterly'], ans:2, expl:'VHND: held monthly at Anganwadi Centre. Services: Immunisation (all age-appropriate vaccines), ANC check-up, maternal and child nutrition assessment, IFA/Vitamin A/deworming distribution, health education. Organised by ANM with support of ASHA and AWW. Convergence platform for NHM, ICDS, and PRIs.' },
  { topic:'community', q:'Oral cholera vaccine (OCV) provides protection for:', opts:['3 months','6 months','2 years (2 doses, 1-6 weeks apart, booster at 2 years)','Lifelong'], ans:2, expl:'Oral Cholera Vaccine (Shanchol, mORCVAX): 2 doses 1-6 weeks apart. Protection: 65-85% for 2 years. Used for outbreak control and high-risk area protection. Not part of routine UIP. WHO recommends in endemic areas. Hand hygiene + safe water + OCV = synergistic prevention.' },
  { topic:'community', q:'The "chain of infection" in epidemiology includes:', opts:['Agent, Host, Environment','Infectious agent, Reservoir, Portal of exit, Mode of transmission, Portal of entry, Susceptible host','Bacteria, Virus, Parasite, Fungi','Source, Contact, Community'], ans:1, expl:'Chain of infection (6 links): (1) Infectious Agent (pathogen), (2) Reservoir (where agent lives - human, animal, environment), (3) Portal of Exit (how agent leaves reservoir - respiratory secretions, faeces, blood), (4) Mode of Transmission (direct/indirect/airborne/vector/vehicle), (5) Portal of Entry (how enters new host), (6) Susceptible Host. Breaking any link = preventing transmission.' },
  { topic:'community', q:'Social determinants of health include:', opts:['Blood pressure and cholesterol levels','Income, education, employment, social support, built environment (where people live, learn, work, play)','Medical treatments and medications','Genetic factors only'], ans:1, expl:'Social Determinants of Health (SDH): non-medical factors shaping health. WHO Commission on SDH (2008): income inequality, education, employment conditions, food insecurity, housing, social support, access to healthcare. Upstream factors cause health inequalities. Addressing SDH more impactful than individual medical interventions for population health.' },
  { topic:'community', q:'Health promotion (Ottawa Charter 1986) primary strategy includes:', opts:['Treating sick patients','Building healthy public policy, creating supportive environments, developing personal skills, strengthening community action, reorienting health services','Screening for diseases','Providing vaccines'], ans:1, expl:'Ottawa Charter for Health Promotion (1986): 5 action areas: (1) Build Healthy Public Policy, (2) Create Supportive Environments, (3) Strengthen Community Action, (4) Develop Personal Skills, (5) Reorient Health Services toward prevention and health promotion. Health promotion = enabling people to increase control over and improve their health. Goes beyond individual behaviour change.' },
  { topic:'community', q:'Primary prevention means:', opts:['Early detection and treatment of disease','Preventing disease BEFORE it occurs (vaccinations, health education, safe water, sanitation)','Rehabilitation of disabled','Screening asymptomatic populations'], ans:1, expl:'Levels of prevention: Primary - before disease occurs (immunisation, health promotion, sanitation, nutrition). Secondary - early detection and treatment (screening, early diagnosis, prompt treatment). Tertiary - reduce disability/complications (rehabilitation, physiotherapy, limiting disability). Some add Primordial (prevent risk factors developing) and Quaternary (avoid unnecessary medical interventions).' },
  { topic:'community', q:'Which disease has been globally eradicated?', opts:['Polio','Malaria','Smallpox (Variola - certified eradicated by WHO in 1980)','Measles'], ans:2, expl:'Smallpox: only human disease globally ERADICATED. Last natural case: Ali Maow Maalin, Somalia, 1977. WHO certified eradication: May 1980. Campaign: mass vaccination + ring vaccination (vaccinating all contacts of cases). Variola virus now only in 2 WHO-approved labs (CDC Atlanta, VECTOR Novosibirsk). Global Polio Eradication Initiative (GPEI): polio eradication ongoing (wild type 2 and 3 eradicated; type 1 remains in Pakistan/Afghanistan).' },
  { topic:'community', q:'The concept of "One Health" recognises:', opts:['Only human health matters','Human health, animal health, and ecosystem health are interconnected and interdependent','Animal health is separate from human health','Environment has no effect on health'], ans:1, expl:'One Health: integrated approach recognising that human health, animal health, and environmental/ecosystem health are interdependent. Zoonotic diseases (COVID-19, Ebola, rabies, brucellosis, influenza) emerge from human-animal-environment interface. Requires collaboration between medical, veterinary, and environmental sectors. FAO-OIE-WHO Tripartite collaboration promotes One Health approach.' },
  { topic:'community', q:'Reproductive and Child Health (RCH) Programme Phase II was integrated into:', opts:['National AIDS Control Programme','National Health Mission (NHM) / National Rural Health Mission (NRHM) in 2005','National Nutrition Mission','National Mental Health Programme'], ans:1, expl:'RCH Programme Phase II (2005-2012) was integrated into NRHM (National Rural Health Mission, 2005-2013). NRHM was launched in 2005 by PM Manmohan Singh. Covered 18 focus states (including J&K, NE states, Bihar, UP, MP, Rajasthan). NHM (National Health Mission): umbrella of NRHM + NUHM (from 2013). Focus: maternal health, child health, adolescent health, family planning.' },
  { topic:'community', q:'Disability Adjusted Life Years (DALYs) = :', opts:['Years of Potential Life Lost only','Years Lived with Disability (YLD) + Years of Life Lost due to premature death (YLL)','Life expectancy at birth','Mortality rate x population'], ans:1, expl:'DALY: composite measure of overall disease burden. DALY = YLL (Years of Life Lost due to premature death) + YLD (Years Lived with Disability). 1 DALY = 1 lost year of "healthy" life. Used by WHO Global Burden of Disease study to compare disease burden across conditions and countries. NCDs now contribute majority of DALYs in India (cardiovascular, mental health, diabetes).' },
  { topic:'nutrition', q:'Therapeutic feeding in Severe Acute Malnutrition (SAM) uses:', opts:['F-75 milk diet only','F-75 (stabilisation phase) followed by F-100 or RUTF (rehabilitation phase)','Regular diet immediately','IV fluids exclusively'], ans:1, expl:'SAM therapeutic feeding protocol (WHO): Phase 1 (Stabilisation, 1-7 days): F-75 (75 kcal/100 mL) - corrects metabolic derangements, treats infections. Phase 2 (Rehabilitation, 2-6 weeks): F-100 (100 kcal/100 mL) or RUTF (Ready-to-Use Therapeutic Food - Plumpy Nut, 500 kcal/92g sachet) for rapid catch-up growth. 10 Steps: treat hypoglycaemia, hypothermia, dehydration, electrolytes, infections, micronutrients, cautious feeding, catch-up growth, sensory stimulation, discharge.' },
  { topic:'nutrition', q:'National Nutritional Anaemia Control Programme (NNACP) targets:', opts:['Only pregnant women','All vulnerable groups - pregnant/lactating women, children 6-59 months, adolescent girls, ICDS beneficiaries','Only children under 2 years','Only adolescents'], ans:1, expl:'NNACP (now part of POSHAN Abhiyaan/NHM): IFA supplementation to: Pregnant women (60 mg iron + 500 mcg FA x 180 days), Children 6-59 months (IFA syrup - 1 mg/kg/day x 100 days biannually), Children 5-10 years (IFA small tablet - 45 mg iron + 400 mcg FA, weekly), Adolescent girls 10-19 years (IFA large tablet - 60 mg + 500 mcg FA, weekly under WIFS).' },
  { topic:'nutrition', q:'Xerophthalmia (Vitamin A deficiency) staging - Bitot spots (X1B) are:', opts:['Corneal ulcers','Triangular foamy/cheesy white spots on bulbar conjunctiva (temporal side) - reversible','Corneal scars','Night blindness'], ans:1, expl:'WHO Xerophthalmia classification: XN = Night blindness; X1A = Conjunctival xerosis; X1B = Bitot spots (triangular, foamy white deposits on temporal bulbar conjunctiva - reversible); X2 = Corneal xerosis; X3A = Corneal ulceration <1/3 cornea; X3B = Corneal ulceration >1/3 cornea (keratomalacia); XS = Corneal scar; XF = Xerophthalmic fundus. Prevalence indicator for population: >0.5% with Bitot spots = public health problem.' },
  { topic:'nutrition', q:'The Recommended Daily Allowance (RDA) of calories for a moderately active adult Indian male is approximately:', opts:['1500 kcal/day','2000 kcal/day','2500-2750 kcal/day','3500 kcal/day'], ans:2, expl:'ICMR RDA (2020): Adult male (sedentary work): 2100 kcal; Moderate work: 2500 kcal; Heavy work: 3000 kcal. Adult female (sedentary): 1660 kcal; Moderate: 1970 kcal. Pregnancy: +350 kcal (2nd trimester), +450 kcal (3rd trimester). Lactation: +500 kcal (first 6 months), +400 kcal (6-12 months). 1 gram fat = 9 kcal; 1 gram protein = 4 kcal; 1 gram carbohydrate = 4 kcal.' },
  { topic:'nutrition', q:'Fluorosis is caused by:', opts:['Deficiency of fluoride','Excess fluoride intake (endemic in districts with >1.5 ppm fluoride in groundwater)','Deficiency of iodine','Excess iron intake'], ans:1, expl:'Fluorosis: chronic excess fluoride. Dental fluorosis: white/brown mottling, pitting of enamel. Skeletal fluorosis: joint pain, osteosclerosis, crippling deformity in severe cases. Endemic in districts with groundwater fluoride >1.5 ppm. Endemic in Rajasthan, UP, Gujarat, Andhra Pradesh, J&K (some areas). Prevention: alternate water source, defluoridation. Optimal fluoride for dental health: 0.7-1.0 ppm.' },
  { topic:'immunization', q:'The Vaccine Vial Monitor (VVM) indicates:', opts:['Expiry date of vaccine','Cumulative heat exposure of vaccine (colour change from white to dark indicates excessive heat damage)','Batch number','Sterility of vaccine'], ans:1, expl:'VVM (Vaccine Vial Monitor): adhesive label on vaccine vial. Inner square is lighter than outer circle initially. As vaccine is exposed to heat over time, inner square darkens. Do NOT use vaccine if: inner square colour matches or is darker than outer circle (VVM3 for OPV, VVM7 for others). VVM reading more important than expiry date - discard if VVM indicates heat damage even within expiry.' },
  { topic:'immunization', q:'Under Universal Immunisation Programme (UIP), which vaccine is given at birth?', opts:['DPT','BCG, OPV (zero dose), and Hepatitis B (birth dose)','Measles only','Vitamin A'], ans:1, expl:'Birth dose under UIP: BCG (intradermal), OPV-0 (oral, zero dose), Hepatitis B birth dose (IM, within 24 hours ideally). At 6 weeks: Pentavalent (DPT+HepB+Hib), OPV-1, IPV-1, PCV-1, RVV-1. At 10 weeks: Pentavalent-2, OPV-2, PCV-2, RVV-2. At 14 weeks: Pentavalent-3, OPV-3, IPV-2, PCV-3, RVV-3. At 9 months: MR-1, Vitamin A-1, JE-1 (endemic areas).' },
  { topic:'immunization', q:'Seroconversion after hepatitis B vaccination is confirmed by:', opts:['HBsAg positive','Anti-HBs antibody titre >10 mIU/mL','HBeAg positive','Anti-HBc positive'], ans:1, expl:'HepB vaccine seroconversion: Anti-HBs (surface antibody) titre >10 mIU/mL = adequate immune response = protected. Check 4-8 weeks after completing 3-dose series for high-risk groups (healthcare workers). Non-responders (Anti-HBs <10 mIU/mL after 3 doses): revaccinate with 3 more doses. About 5-10% of healthy adults are non-responders. Immunocompromised: may need higher doses.' },
  { topic:'immunization', q:'Which of the following is a LIVE attenuated vaccine?', opts:['DPT (whole-cell)','Hepatitis B vaccine','BCG, OPV, MMR, Varicella (live vaccines)','Rabies vaccine (most modern formulations)'], ans:2, expl:'Live attenuated vaccines: BCG, OPV (oral), Rotavirus (Rotarix, RotaTeq), MMR, Varicella, Yellow fever, JE (SA 14-14-2), Typhoid (Ty21a oral). Killed/inactivated vaccines: IPV, Hepatitis A, Rabies (PCECV, PDEV). Toxoids: DT, TT. Subunit: Hepatitis B, Pertussis acellular, PCV, Hib, HPV. Live vaccines: stronger immune response, one or two doses, contraindicated in immunocompromised patients.' },
  { topic:'programs', q:'National AIDS Control Programme (NACP) Phase IV covered:', opts:['2001-2005','2007-2012','2012-2017','2017-2024 (NACP IV)'], ans:3, expl:'NACP phases: Phase I (1992-99): awareness. Phase II (1999-2006): prevention. Phase III (2007-12): halt and reverse. Phase IV (2012-17): accelerate. NACP V (2021-2026): 95-95-95 targets (95% diagnosed, 95% on ART, 95% virally suppressed). NACO: National AIDS Control Organisation. Free ART at 1000+ ART centres. Targeted interventions for high-risk groups (FSW, MSM, IDU). Blood safety: mandatory testing.' },
  { topic:'programs', q:'Pradhan Mantri Surakshit Matritva Abhiyan (PMSMA) provides:', opts:['Cash incentive for delivery','Free ANC check-up on 9th of every month (from 4+ months) by specialist/MO at government facilities','Free C-section','Home delivery kit'], ans:1, expl:'PMSMA (launched 2016): guaranteed, comprehensive, quality ANC check-up on 9th of EVERY MONTH to all pregnant women at government health facilities. Minimum 3 ANC visits. Services: Blood pressure, weight, urine albumin/sugar, Hb, blood group, abdominal examination, USG (if first visit). Conducted by gynaecologists/MOs. Sticker on MCP card indicating risk categorisation.' },
  { topic:'programs', q:'Mission Indradhanush aims to:', opts:['Provide health insurance','Achieve full immunisation of children and pregnant women left out or dropped out from UIP','Build hospitals','Provide free medicines'], ans:1, expl:'Mission Indradhanush (MI) launched December 2014 by PM Modi: immunise all children under 2 years and pregnant women who missed UIP vaccines. 7 colours of rainbow = 7 vaccines initially. Intensified Mission Indradhanush (IMI) 2017: more intensive in low-coverage districts. IMI 2.0 (2019): added PCV, JE, MR. IMI 3.0 (2021): COVID-19 vaccine catch-up. IMI 4.0 (2022-23): 4 rounds targeting districts with >5% zero-dose children.' },
  { topic:'programs', q:'Pradhan Mantri Matru Vandana Yojana (PMMVY) benefit is:', opts:['Rs 1000 for first delivery','Rs 5000 cash transfer (first living child) in 3 instalments for pregnant and lactating women','Rs 10,000 for all deliveries','Rs 2000 for ANC registration only'], ans:1, expl:'PMMVY (2017, replacing IGMSY): Rs 5000 in 3 instalments for FIRST LIVING CHILD: Instalment 1 (Rs 1000): early ANC registration + 1st ANC check-up (within 150 days of LMP). Instalment 2 (Rs 2000): received minimum 1 ante-natal check-up (after 6 months of pregnancy). Instalment 3 (Rs 2000): child birth registered + received first cycle of BCG, OPV, DPT, HepB. JSY top-up: total benefit up to Rs 6000 for institutional delivery.' },
  { topic:'programs', q:'Rajiv Gandhi Grameen Vidyutikaran Yojana (RGGVY) / Saubhagya Scheme relates to:', opts:['Agricultural subsidies','Rural electrification - providing electricity to all households (health impact: cold chain, light in health facilities, home deliveries)','Rural roads','Sanitation'], ans:1, expl:'Saubhagya (Pradhan Mantri Sahaj Bijli Har Ghar Yojana, 2017): provide electricity connection to all remaining unelectrified households. Health impact of electrification: cold chain for vaccine storage, electric light for night deliveries, medical equipment, improved study environment (reduced child labour), economic empowerment. RGGVY preceded Saubhagya for rural electrification.' },
  { topic:'mental', q:'The ICD-11 (International Classification of Diseases, 11th revision) replaced ICD-10 in:', opts:['2010','2015','2018 (adopted at WHA; member states implement from 2022)','2025'], ans:2, expl:'ICD-11: adopted by World Health Assembly in May 2018; member states implement from 1 January 2022. Includes: Gaming Disorder (new), reclassification of Gender Incongruence (moved from mental disorders to sexual health chapter). DSM-5 (Diagnostic and Statistical Manual): American Psychiatric Association, 2013. Both ICD-11 and DSM-5 used for psychiatric diagnoses.' },
  { topic:'mental', q:'Post-Traumatic Stress Disorder (PTSD) features include:', opts:['Only nightmares','Intrusion (flashbacks, nightmares), Avoidance (of trauma reminders), Negative cognitions/mood, Hyperarousal - after traumatic event lasting >1 month','Depression and anxiety only','Schizophrenia-like features'], ans:1, expl:'PTSD (DSM-5): develops after exposure to actual/threatened death, serious injury, or sexual violence. Four symptom clusters: Intrusion (unwanted memories, flashbacks, nightmares), Avoidance (avoid thoughts, reminders), Negative alterations in cognition and mood (guilt, estrangement, anhedonia), Alterations in arousal/reactivity (hypervigilance, exaggerated startle, sleep disturbance). Duration >1 month. Treatment: Trauma-focused CBT, EMDR.' },
  { topic:'mental', q:'Which antidepressant class is FIRST-LINE for depression and anxiety due to favourable safety profile?', opts:['Tricyclic antidepressants (TCAs)','Monoamine oxidase inhibitors (MAOIs)','Selective Serotonin Reuptake Inhibitors (SSRIs - fluoxetine, sertraline, escitalopram)','Benzodiazepines'], ans:2, expl:'SSRIs (Selective Serotonin Reuptake Inhibitors): first-line for depression and anxiety disorders. Mechanism: block serotonin reuptake at synapse. Examples: Fluoxetine (Prozac), Sertraline (Zoloft), Escitalopram, Paroxetine, Fluvoxamine, Citalopram. Advantages: safer in overdose, fewer anticholinergic effects than TCAs. Side effects: GI upset (nausea, diarrhoea), sexual dysfunction, discontinuation syndrome. Onset: 2-4 weeks.' },
  { topic:'mental', q:'Dementia is defined as:', opts:['Normal age-related memory decline','Progressive decline in memory + at least one other cognitive domain (language, executive function, visuospatial) severe enough to impair daily life','Single episode of confusion','Treatable vitamin deficiency'], ans:1, expl:'Dementia (now termed Major Neurocognitive Disorder in DSM-5): progressive, irreversible cognitive decline affecting multiple domains severe enough to interfere with daily function. Alzheimer\'s disease: most common (60-70%) - insidious onset, memory first, Beta-amyloid plaques, neurofibrillary tangles. Vascular dementia (2nd): step-wise progression. Lewy body: visual hallucinations, parkinsonism, REM sleep disorder. Early diagnosis: MMSE, MoCA.' },
  { topic:'environment', q:'The primary source of indoor air pollution in rural India is:', opts:['Industrial emissions','Biomass burning (wood, cow dung, crop residue) for cooking in poorly ventilated kitchens - causing 600,000+ deaths/year in India','Cigarette smoking only','Vehicle exhaust indoors'], ans:1, expl:'Indoor Air Pollution (IAP) from solid fuel combustion (biomass cooking stoves): major health problem in India. Household Air Pollution (HAP): 40% of Indian households cook with biomass. Causes: respiratory diseases (COPD, pneumonia, lung cancer), cardiovascular disease, adverse pregnancy outcomes. Women and children most exposed. Pradhan Mantri Ujjwala Yojana (PMUY): LPG to BPL households - reduces HAP.' },
  { topic:'environment', q:'WHO defines health as:', opts:['Absence of disease only','A state of complete physical, mental, and social well-being and not merely the absence of disease or infirmity (WHO Constitution, 1946)','Being free from all symptoms','Having normal vital signs'], ans:1, expl:'WHO definition of health (1946 Constitution): "Health is a state of complete physical, mental, and social well-being and not merely the absence of disease or infirmity." Criticisms: "complete well-being" is unattainable ideal; ignores spiritual and environmental dimensions; too broad. Expanded definition: also includes spiritual and dynamic nature. Public health focuses on population, not just individual.' },
  { topic:'environment', q:'Biomedical waste is categorised under which rule in India?', opts:['Environment Protection Act 1986','Biomedical Waste (Management and Handling) Rules 2016 (and Amendment 2019)','Factories Act 1948','Municipal Solid Waste Rules 2000'], ans:1, expl:'Biomedical Waste Management Rules 2016 (amended 2019): categorises biomedical waste into 4 categories and 7 colour-coded bags/containers. Yellow bag: human anatomical waste, infectious/animal waste, soiled linen. Red bag: contaminated plastic waste (IV sets, syringes without needle). White/Translucent sharps container: needles, syringes with needle, blades. Blue/White: glassware.' },
  { topic:'environment', q:'Ozone layer protects earth from:', opts:['Infrared radiation','Ultraviolet (UV-B and UV-C) radiation from sun','Gamma radiation','Radio waves'], ans:1, expl:'Ozone layer (stratosphere, 15-35 km altitude): absorbs harmful UV radiation (UV-B 280-315 nm and UV-C <280 nm). UV-B causes: skin cancer, cataracts, immune suppression, crop damage. Ozone depletion: CFCs (chlorofluorocarbons - refrigerants, aerosols), halons, nitrous oxide. Montreal Protocol (1987): phasing out ozone-depleting substances. Ozone hole discovered over Antarctica.' },
  { topic:'environment', q:'The Clean Air Act equivalent in India is:', opts:['Water Prevention and Control of Pollution Act 1974','Air (Prevention and Control of Pollution) Act 1981','Environment Protection Act 1986','Wildlife Protection Act 1972'], ans:1, expl:'Air (Prevention and Control of Pollution) Act 1981: to prevent, control, and abate air pollution. Central Pollution Control Board (CPCB) and State PCBs enforce standards. National Ambient Air Quality Standards (NAAQS) for PM10, PM2.5, SO2, NO2, CO, ozone, lead, benzene, arsenic, nickel. National Clean Air Programme (NCAP, 2019): 20-30% reduction in PM levels by 2024 in 132 non-attainment cities.' },
  { topic:'firstaid', q:'Signs of shock include:', opts:['High blood pressure and slow pulse','Hypotension (<90 mmHg systolic), tachycardia (>100 bpm), cold clammy skin, altered consciousness, oliguria','High fever and bradycardia','Normal BP with confusion only'], ans:1, expl:'Shock: inadequate tissue perfusion. Signs: Hypotension (SBP <90 mmHg), Tachycardia (HR >100 bpm), Cold clammy skin (peripheral vasoconstriction), Pallor, Altered consciousness (restlessness, confusion), Oliguria (<0.5 mL/kg/hr), Increased respiratory rate. Types: Hypovolaemic (blood/fluid loss), Cardiogenic (pump failure), Distributive (septic, anaphylactic, neurogenic), Obstructive (tension pneumothorax, PE).' },
  { topic:'firstaid', q:'Management of anaphylaxis (severe allergic reaction):', opts:['Give antihistamines first then adrenaline','Adrenaline (epinephrine) 0.5 mg IM (1:1000) to lateral thigh - FIRST and most important drug','Give IV corticosteroids immediately','Lay patient flat and give fluids only'], ans:1, expl:'Anaphylaxis management: ADRENALINE (Epinephrine) 1:1000 solution, 0.5 mg (adult) IM into anterolateral thigh - FIRST priority. Position: supine (or recovery if unconscious). Call ambulance. Repeat adrenaline every 5-15 min if needed. THEN: IV access, IV fluids (crystalloid), chlorphenamine (antihistamine), hydrocortisone IV. Oxygen. Adrenaline-Allergen-Antihistamine-Airway-Breathing-Corticosteroid.' },
  { topic:'firstaid', q:'The recovery time recommended after a head injury before resuming sports is:', opts:['Same day if no loss of consciousness','24 hours minimum','Stepwise return-to-play protocol over minimum 1 week (concussion protocol)','No restriction needed'], ans:2, expl:'Concussion management: NO same-day return to play. Stepwise Return-to-Play (RTP) protocol: each step minimum 24 hours: (1) No activity/rest, (2) Light aerobic exercise, (3) Sport-specific exercise, (4) Non-contact training drills, (5) Full-contact practice, (6) Return to competition. Second Impact Syndrome: fatal re-injury before full recovery. If any symptoms worsen: back to previous step.' },
  { topic:'firstaid', q:'Drowning - immediate action after pulling victim from water is:', opts:['Shake and shout to wake them','Clear airway, give 5 rescue breaths, then 30:2 CPR (start ventilations first for drowning)','Check pulse for 10 seconds first','Give warm fluids orally'], ans:1, expl:'Drowning CPR modification (ILCOR/AHA): start with 5 RESCUE BREATHS (not 30 compressions first, unlike standard CPR) because hypoxia is primary problem in drowning. Then 30:2 compressions:ventilations. Clear airway, remove from water safely. Call 108. Remove wet clothing, prevent hypothermia. Do NOT do abdominal thrusts to remove water (dangerous, delays CPR).' },
  { topic:'firstaid', q:'Snake bite first aid - CORRECT action is:', opts:['Suck the venom out with mouth','Apply tourniquet tightly above bite','Immobilise the bitten limb (splint like fracture), keep below heart level, transport urgently to hospital','Make cuts on wound to bleed out venom'], ans:2, expl:'Snake bite correct first aid: Reassure patient (reduce panic/heart rate/venom spread). IMMOBILISE bitten limb (do NOT use - do not suck venom, do NOT cut and suck, do NOT apply tourniquet, do NOT apply ice). Pressure-immobilisation bandage only for neurotoxic snakes (not for cytotoxic/haematotoxic). Remove jewellery. Transport urgently. ASV (Polyvalent Anti-Snake Venom) at hospital.' },
  { topic:'nursing', q:'The correct technique for administering an intramuscular (IM) injection in the deltoid muscle is:', opts:['2.5 cm (1 inch) below acromion process, 90 degree angle, 1-2 mL maximum volume','Anywhere in upper arm','Lower third of deltoid, 45 degree angle','Over acromion process'], ans:0, expl:'Deltoid IM site: 2.5 cm (1 inch) below acromion process, centre of deltoid. Angle: 90 degrees. Maximum volume: 1 mL (some say 2 mL). Needle: 16-25 mm, 22-25 gauge. Uses: vaccines (HepA, rabies, meningococcal), small-volume injections. Do NOT use in infants (underdeveloped). Vastus lateralis (anterolateral thigh): preferred for infants/young children.' },
  { topic:'nursing', q:'Insulin injection - correct technique is:', opts:['Into muscle for faster absorption','Subcutaneous injection (SC) at 45-90 degree angle, rotate sites to prevent lipodystrophy','Always IV for diabetic emergencies','Intradermal injection'], ans:1, expl:'Insulin injection: subcutaneous (SC) injection, 45 degrees (thin patients/shorter needle) or 90 degrees (standard). Sites: abdomen (fastest absorption), thigh (slowest), buttock, upper arm. Rotate sites systematically. Do NOT inject into lipodystrophic areas (altered absorption). Short-acting insulin: before meals. Long-acting: at bedtime. Regular insulin: only type given IV in emergencies (under supervision).' },
  { topic:'nursing', q:'Urinary catheter care - the most important measure to prevent catheter-associated UTI (CAUTI) is:', opts:['Change catheter every 2 days','Maintain closed drainage system, keep bag below bladder level, remove catheter as soon as no longer needed','Apply antibiotics around catheter insertion site daily','Irrigate catheter daily'], ans:1, expl:'CAUTI prevention bundle: (1) Insert only when necessary (clear indication). (2) Maintain CLOSED sterile drainage system. (3) Keep drainage bag BELOW bladder level (gravity drainage, prevent reflux). (4) Remove catheter as soon as clinically possible (each day of catheterisation increases UTI risk 3-7%). (5) Hand hygiene before catheter care. (6) Daily cleansing of perineal area. (7) No routine antibiotic prophylaxis.' },
  { topic:'nursing', q:'Nasogastric (NG) tube feeding - how often should the tube position be verified?', opts:['Once at insertion only','Before each use/intermittent feeding and every 4 hours during continuous feeding','Only when patient is symptomatic','Weekly'], ans:1, expl:'NG tube position verification: before EVERY intermittent feed, before medication administration, and every 4-8 hours during continuous feeding. Methods: aspirate and check pH (pH 5.5 or less = gastric, 7+ = possibly respiratory). X-ray (gold standard for initial confirmation). Never rely solely on auscultation (air bubbling). Mark tube at nostril with pen to detect displacement.' },
  { topic:'nursing', q:'Informed refusal - when a competent patient refuses a recommended treatment, the nurse should:', opts:['Override the patient\'s decision','Accept the patient\'s decision, ensure they understand the consequences, document the refusal, and continue to provide other care','Call police','Sedate the patient to force treatment'], ans:1, expl:'Informed refusal: competent adult has right to refuse any treatment (Right to Autonomy). Nurse\'s responsibility: (1) Ensure patient has been given clear information about risks of refusing, (2) Check patient understanding, (3) Document: decision, information given, patient understanding, time, witnesses, (4) Inform treating physician, (5) Continue to provide care patient accepts. Cannot force treatment on a competent patient.' },
  { topic:'nursing', q:'Normal CVP (Central Venous Pressure) is:', opts:['0-2 mmHg','2-8 mmHg (or 5-12 cmH2O)','15-20 mmHg','25-30 mmHg'], ans:1, expl:'CVP (measured at right atrium via central line - IJV, subclavian, femoral): Normal 2-8 mmHg (or 5-12 cmH2O). High CVP: fluid overload, right heart failure, cardiac tamponade, tension pneumothorax. Low CVP: hypovolaemia, dehydration. Used to guide fluid resuscitation in critically ill patients (though not sole guide - clinical assessment + other monitoring essential).' },
  { topic:'nursing', q:'In which nursing situation is the supine (flat) position CONTRAINDICATED?', opts:['During CPR','For patients with increased intracranial pressure (ICP) or respiratory distress','Post-spinal anaesthesia (must lie flat for 6-8 hours)','For measuring CVP'], ans:1, expl:'Supine position contraindicated in: increased ICP (head of bed 30 degrees elevation), respiratory distress (semi-Fowler\'s 30-45 degrees or high Fowler\'s 90 degrees), GERD/aspiration risk, term pregnancy (causes aorto-caval compression - left lateral instead), ascites. Trendelenburg position (feet up, head down): use cautiously - can increase ICP, worsen respiratory distress.' },
  { topic:'anatomy', q:'Which enzyme converts fibrinogen to fibrin in blood clotting?', opts:['Factor X','Prothrombin','Thrombin (activated from prothrombin by prothrombinase complex)','Fibrin'], ans:2, expl:'Coagulation cascade: Prothrombin (Factor II) → Thrombin (IIa) by prothrombinase complex (Factor Xa + Va + phospholipid + Ca2+). Thrombin converts Fibrinogen (Factor I) → Fibrin. Fibrin stabilised by Factor XIIIa (cross-linking). Intrinsic pathway: HMWK, prekallikrein, XII, XI, IX, VIII. Extrinsic pathway: Tissue factor + VII. Common pathway: X, V, II, I. Warfarin: inhibits vitamin K-dependent factors (II, VII, IX, X, protein C, S).' },
  { topic:'anatomy', q:'The Eustachian tube connects:', opts:['Middle ear with inner ear','Middle ear (tympanic cavity) with nasopharynx (equalises air pressure)','Nasopharynx with oropharynx','Outer ear with middle ear'], ans:1, expl:'Eustachian tube (pharyngotympanic tube/auditory tube): connects middle ear to nasopharynx. Function: equalise air pressure on both sides of tympanic membrane. Opens during swallowing/yawning (tensor veli palatini muscle). Blocked Eustachian tube (URTI, allergies): fluid accumulation in middle ear, hearing loss, barotrauma (flying/diving). Otitis media with effusion: "glue ear" (children - adenoid hypertrophy blocks tube).' },
  { topic:'anatomy', q:'The portal vein drains blood from:', opts:['Brain to heart','Gastrointestinal tract, spleen, and pancreas to the liver (hepatic portal system)','Liver to inferior vena cava','Kidneys to inferior vena cava'], ans:1, expl:'Portal vein: formed by splenic vein + superior mesenteric vein. Drains: GI tract (stomach, intestines), spleen, pancreas → to liver. Portal hypertension (cirrhosis): backup of portal blood → oesophageal varices, caput medusae, haemorrhoids (portal-systemic anastomoses). Liver first-pass metabolism: absorbed drugs/nutrients processed before systemic circulation.' },
  { topic:'anatomy', q:'Normal white blood cell (WBC/leukocyte) count is:', opts:['2,000-4,000/mm3','4,000-11,000/mm3 (4-11 x 10^9/L)','15,000-20,000/mm3','25,000-30,000/mm3'], ans:1, expl:'Normal WBC: 4,000-11,000/mm3. Types: Neutrophils (40-70% - bacterial infections), Lymphocytes (20-40% - viral infections, B and T cells), Monocytes (2-8% - chronic infections, mature to macrophages), Eosinophils (1-4% - parasites, allergies), Basophils (0-1% - allergies, release histamine). Leukocytosis: >11,000 (infection, inflammation). Leukopenia: <4,000 (viral infections, chemotherapy, TB).' },
  { topic:'anatomy', q:'The lymphatic system function includes:', opts:['Gas exchange only','Return excess interstitial fluid to blood, absorb dietary fat (lacteals), immune defence (lymph nodes filter pathogens)','Hormone production only','Direct gas exchange in tissues'], ans:1, expl:'Lymphatic system functions: (1) Return excess tissue fluid to bloodstream (via lymph capillaries → lymph vessels → thoracic duct/right lymphatic duct → venous system), (2) Fat absorption: lacteals in intestinal villi absorb dietary fats (chylomicrons) → chyle → cisterna chyli → thoracic duct, (3) Immune defence: lymph nodes filter lymph and mount immune responses. Oedema: lymphatic obstruction (filariasis, mastectomy).' },
  { topic:'drug', q:'Which painkiller is safest in a patient with peptic ulcer?', opts:['Aspirin','Ibuprofen (NSAID)','Paracetamol (acetaminophen) - does not cause GI bleeding, not an NSAID','Diclofenac'], ans:2, expl:'Paracetamol (acetaminophen): safest analgesic/antipyretic for patients with peptic ulcer. Does NOT inhibit COX-1 in gastric mucosa (minimal GI effects). NSAIDs (aspirin, ibuprofen, diclofenac, naproxen): inhibit COX-1 → reduce prostaglandins → reduced mucus/bicarbonate production → GI erosion, peptic ulcer, GI bleeding. If NSAIDs needed: use with PPI (omeprazole, pantoprazole).' },
  { topic:'drug', q:'The antidote for paracetamol (acetaminophen) overdose is:', opts:['Naloxone','N-acetylcysteine (NAC)','Flumazenil','Atropine'], ans:1, expl:'Paracetamol overdose: toxic metabolite NAPQI (N-acetyl-p-benzoquinone imine) depletes glutathione → hepatic necrosis. Antidote: N-Acetylcysteine (NAC) IV or oral - replenishes glutathione. Most effective within 8-10 hours of ingestion (can be given up to 24 hours). Rumack-Matthew nomogram: guides treatment decision based on time post-ingestion and serum paracetamol level. Liver transplant if fulminant hepatic failure.' },
  { topic:'drug', q:'Naloxone is the antidote for:', opts:['Benzodiazepine overdose','Opioid overdose (morphine, heroin, codeine, fentanyl - reverses respiratory depression)','Organophosphate poisoning','Beta-blocker overdose'], ans:1, expl:'Naloxone (Narcan): opioid antagonist. Reverses opioid toxidrome: respiratory depression, miosis, coma. Dose: 0.4-2 mg IV/IM/SC/intranasal (IN). Duration: 30-90 minutes (shorter than many opioids - may need repeated doses or infusion). Also used in neonatal opioid withdrawal (if mother received opioids in labour). Flumazenil: reverses benzodiazepines. Atropine + Pralidoxime: organophosphate poisoning.' },
  { topic:'drug', q:'Atropine is used in treatment of:', opts:['Tachycardia','Organophosphate poisoning (blocks muscarinic effects: bradycardia, bronchoconstriction, secretions, miosis)','Hypertension','Asthma as bronchodilator (primary)'], ans:1, expl:'Atropine: competitive muscarinic antagonist. Uses: (1) Organophosphate/carbamate poisoning (antidote for muscarinic effects - DUMBBELS: Defaecation, Urination, Miosis, Bradycardia, Bronchospasm, Emesis, Lacrimation, Salivation), (2) Symptomatic bradycardia (0.5-1 mg IV), (3) Pre-operative medication (reduces secretions), (4) Antispasmodic (belladonna alkaloid). Pralidoxime (PAM): reactivates acetylcholinesterase (within 24-48 hours).' },
  { topic:'drug', q:'The anti-malarial drug that can cause haemolysis in G6PD deficient patients is:', opts:['Chloroquine','Artesunate','Primaquine','Mefloquine'], ans:2, expl:'Primaquine: 8-aminoquinoline anti-malarial. Causes haemolytic anaemia in G6PD-deficient patients (G6PD deficiency: RBCs vulnerable to oxidative stress). Used for: radical cure of P. vivax and P. ovale (kills hypnozoites - liver stages), gametocytocidal (kills P. falciparum gametocytes). MUST check G6PD status before prescribing. G6PD deficiency: X-linked, common in malaria-endemic regions.' },
  { topic:'drug', q:'Corticosteroids (e.g., prednisolone) are used in:', opts:['Bacterial infections (antibiotic-like)','Allergic conditions, autoimmune disorders, severe asthma, adrenal insufficiency, inflammatory conditions','Reducing blood glucose in diabetes','Treating hypertension'], ans:1, expl:'Corticosteroids (glucocorticoids - hydrocortisone, prednisolone, dexamethasone, betamethasone): suppress inflammation and immune response. Uses: severe asthma (inhaled + oral), allergic reactions, rheumatoid arthritis, SLE, IBD, adrenal insufficiency, organ transplant rejection, cerebral oedema, neonatal respiratory distress (betamethasone to mother pre-term). Side effects: immunosuppression, osteoporosis, Cushingoid features, hyperglycaemia, hypertension (long-term use).' },
  { topic:'drug', q:'Heparin works by:', opts:['Inhibiting vitamin K','Activating antithrombin III (inactivates thrombin + Factor Xa, preventing clot formation)','Dissolving existing clots','Inhibiting platelet aggregation only'], ans:1, expl:'Heparin (unfractionated): indirect anticoagulant - binds antithrombin III → dramatically enhances its ability to inactivate thrombin (IIa) and Factor Xa. Onset: immediate (IV). Uses: DVT/PE treatment and prophylaxis, ACS, during haemodialysis, pregnancy (does NOT cross placenta, unlike warfarin). Antidote: Protamine sulphate. Monitor: APTT (target 1.5-2.5x normal). LMWH (enoxaparin): more predictable, given SC.' },
  { topic:'community', q:'Contact tracing is used in epidemiology to:', opts:['Count deaths in a community','Identify all persons who had contact with an infectious case to prevent further spread','Calculate vaccination rates','Measure disease prevalence'], ans:1, expl:'Contact tracing: identifying and following up all persons who had contact with an infectious case (contacts) to: test them, quarantine if exposed (to prevent unknowing transmission), and treat/vaccinate if infected. Essential for: TB (Systematic Contact Investigation), COVID-19, Ebola, STIs, MPox. Digital contact tracing: Aarogya Setu app (India, COVID-19). Ring vaccination strategy uses contact tracing.' },
  { topic:'community', q:'Perinatal mortality includes:', opts:['Deaths only after 28 days of life','Stillbirths (28 weeks+ gestational age) + early neonatal deaths (first 7 days of life)','Maternal deaths','All deaths under 5 years'], ans:1, expl:'Perinatal mortality: stillbirths (28+ weeks gestation OR 1000g+) + Early Neonatal Deaths (first 7 days of life). Perinatal Mortality Rate = (Stillbirths + Early neonatal deaths) / Total births x 1000. India perinatal mortality rate: ~26/1000 births (SRS). Neonatal mortality: deaths in first 28 days. IMR (Infant Mortality Rate): deaths in first 1 year. Under-5 mortality: deaths before 5 years per 1000 live births.' },
  { topic:'community', q:'The best indicator of overall health status of a country is:', opts:['Crude death rate','Under-5 Mortality Rate (U5MR) or Infant Mortality Rate (IMR)','Maternal mortality ratio','Morbidity rates'], ans:1, expl:'IMR/U5MR: considered best single indicators of overall health and social development of a country. IMR reflects: maternal and child health services, nutrition, sanitation, socioeconomic conditions, literacy. India IMR (SRS 2020): 28/1000 live births. U5MR (NFHS-5): 41.9/1000. MMR: best indicator of maternal health services. Crude Death Rate: overall mortality but affected by age structure.' },
  { topic:'stats', q:'Number Needed to Treat (NNT) is:', opts:['Relative Risk Reduction','Absolute Risk Reduction / 100','1 / Absolute Risk Reduction (ARR) - number of patients needing treatment to prevent 1 bad outcome','Relative risk'], ans:2, expl:'NNT = 1/ARR (Absolute Risk Reduction). ARR = Control event rate - Treatment event rate. NNT = 1 indicates treatment very effective (every patient treated avoids bad outcome). NNT = 100 means need to treat 100 patients to prevent 1 outcome. Used to communicate clinical meaningfulness of therapy. Lower NNT = more effective treatment. NNH (Number Needed to Harm): how many treated before one harmed.' },
  { topic:'stats', q:'The median is:', opts:['Sum of values divided by total number','Middle value when data arranged in ascending order','Most frequently occurring value','Range divided by 2'], ans:1, expl:'Median: middle value when data arranged in ascending order. If even number: average of two middle values. More robust than mean for skewed data. Mean: sum/n (affected by outliers). Median: not affected by extreme values. Mode: most frequent value. In normal distribution: mean = median = mode. Positive skew: mean > median > mode. Negative skew: mean < median < mode.' },
  { topic:'stats', q:'Which test is used to compare means of two independent groups (parametric)?', opts:['Chi-square test','Mann-Whitney U test','Independent samples t-test','ANOVA'], ans:2, expl:'Independent samples t-test: compares means of two independent groups (parametric - data normally distributed). Paired t-test: compares means of same group before/after (paired data). ANOVA: compares means of 3+ groups. Chi-square: compares proportions/frequencies (non-parametric). Mann-Whitney U: non-parametric equivalent of independent t-test (for non-normal data). Wilcoxon: non-parametric equivalent of paired t-test.' },
  { topic:'stats', q:'Randomised Controlled Trial (RCT) is considered the gold standard because:', opts:['It is cheap and easy to conduct','Random allocation minimises selection bias, allowing causal inference between intervention and outcome','It studies large populations','It takes less time than other study designs'], ans:1, expl:'RCT (Randomised Controlled Trial): GOLD STANDARD for assessing effectiveness of interventions. Random allocation (randomisation): ensures known and unknown confounders are evenly distributed between groups, allowing causal inference. Double-blind: neither participants nor assessors know allocation. Highest level of evidence (Level I). Limitations: expensive, time-consuming, ethical constraints, may not reflect real-world practice (external validity).' },
  { topic:'programs', q:'The Leptospirosis is a zoonotic disease endemic in some parts of India, transmitted by:', opts:['Direct contact with infected humans','Contact with urine of infected animals (rats, cattle, dogs) contaminating water/soil - enters through skin/mucosa','Mosquito bite','Airborne transmission'], ans:1, expl:'Leptospirosis: caused by Leptospira interrogans (spirochaete). Transmission: contact with urine of infected animals (rodents primary reservoir) - contaminated water, soil, mud (flooded areas). Enters via skin abrasions, mucous membranes. Features: fever, headache, myalgia (calf muscles), conjunctival suffusion, jaundice (Weil\'s disease - severe form). Treatment: Doxycycline (mild), Penicillin/Ceftriaxone (severe). Post-exposure prophylaxis: Doxycycline 200 mg weekly.' },
  { topic:'community', q:'Zoonotic diseases are those that:', opts:['Affect only animals','Can be transmitted between animals and humans (bidirectional)','Affect only marine animals','Are caused by plants'], ans:1, expl:'Zoonoses: diseases transmitted between animals and humans. More than 60% of human infectious diseases are zoonotic (WHO). Examples: Rabies (dogs/bats), Leptospirosis (rodents), Brucellosis (cattle/goats - unpasteurised milk), Q fever (Coxiella burnetti - livestock), Nipah (bats/pigs), SARS-CoV-2 (bats → humans), Influenza (birds/pigs), Ebola (bats), Kala-azar (no animal reservoir in India). One Health approach addresses zoonoses.' },
  { topic:'mch', q:'The frequency of antenatal check-ups recommended by WHO (2016 guidelines) is:', opts:['At least 3 visits (focused ANC)','At least 4 visits','At least 8 contacts (visits)','Monthly only'], ans:2, expl:'WHO ANC Guidelines 2016: Minimum 8 CONTACTS (not just visits - contacts emphasise interaction quality). Schedule: Contact 1 (up to 12 weeks), Contact 2 (20 weeks), Contact 3 (26 weeks), Contact 4 (30 weeks), Contact 5 (34 weeks), Contact 6 (36 weeks), Contact 7 (38 weeks), Contact 8 (40 weeks). India NHM recommends minimum 4 ANCs (earlier WHO guideline) - practice varies. PMSMA: ensures at least one quality ANC.' },
  { topic:'mch', q:'Hyperemesis gravidarum is:', opts:['Normal nausea in pregnancy','Severe, intractable vomiting of pregnancy requiring hospitalisation (causing dehydration, electrolyte imbalance, weight loss >5%)','Vomiting after delivery','Vomiting caused by food poisoning only in pregnancy'], ans:1, expl:'Hyperemesis Gravidarum (HG): severe, persistent nausea and vomiting in pregnancy (beyond first trimester) causing dehydration, electrolyte imbalance, ketonuria, weight loss (>5% pre-pregnancy weight). Hospitalisation required. Associated with high hCG (multiple pregnancy, molar pregnancy). Treatment: IV fluids, electrolyte correction, antiemetics (ondansetron, promethazine, metoclopramide), thiamine (prevent Wernicke\'s encephalopathy), TPN if severe.' },
  { topic:'mch', q:'Prevention of Mother to Child Transmission (PMTCT) of HIV includes:', opts:['Avoiding pregnancy entirely','ART to HIV+ pregnant woman throughout pregnancy + delivery + breastfeeding; Nevirapine to newborn for 6 weeks','Caesarean section only','Formula feeding only without ART'], ans:1, expl:'PMTCT strategy (Option B+ India, 2014): All HIV-positive pregnant women receive lifelong ART (TDF+3TC/FTC+EFV) regardless of CD4 count. Nevirapine syrup to newborn for 6 weeks (even if breastfeeding). Without intervention: MTCT risk ~25-45%. With complete PMTCT (ART + safe delivery + formula/safe breastfeeding): risk <1-2%. PCR for early infant diagnosis at 6 weeks.' },
  { topic:'programs', q:'National Rural Health Mission (NRHM) was merged with National Urban Health Mission (NUHM) to form NHM in:', opts:['2010','2013','2015','2018'], ans:1, expl:'NRHM launched 2005. NUHM launched 2013. National Health Mission (NHM) 2013: umbrella structure incorporating both NRHM and NUHM. NHM extended to 2020, then 2025. NUHM addresses urban health: UPHCs (Urban Primary Health Centres), UCHCs (Urban Community Health Centres), targeting urban poor (slum dwellers), mobile health units, Mahila Arogya Samiti (urban counterpart of VHSNC). India urbanisation: 35%+ urban population.' },
  { topic:'community', q:'The Health Management Information System (HMIS) in India collects data at:', opts:['National level only','Facility level upwards (Sub-Centre, PHC, CHC, District, State, National) through online portal','Village level only','International level'], ans:1, expl:'HMIS (Health Management Information System): facility-based reporting. Facility level → district → state → national. Data: OPD/IPD attendances, deliveries, immunisations, ANC visits, family planning, disease surveillance. Accessed at: hmis.nhp.gov.in. MCTS (Mother and Child Tracking System): individual tracking. ANMOL (ANM-Online): mobile app for ANM data entry. RCH portal: reproductive and child health data.' },
  { topic:'community', q:'Under NHM, which cadre provides integrated preventive and curative care at the village level?', opts:['Medical Officer','Community Health Officer (CHO) stationed at HWC + ASHA working in community together','Specialist physician','District collector'], ans:1, expl:'At village level: ASHA (volunteer, 1/1000 population) - demand generation, community mobilisation, HBNC. Sub-centre level: ANM + CHO. CHO (Community Health Officer): posted at HWC (upgraded from SHC/PHC), B.Sc/Diploma nurse trained in comprehensive primary healthcare (6 months), provides curative + preventive care, teleconsultation, 12 health services. Together: ASHA + ANM + CHO = continuum of care at grassroots.' },

  /* ═══ BATCH E — FINAL PUSH TO 1000 ═══ */
  { topic:'anatomy', q:'The average adult tidal volume (air breathed in/out per breath) is:', opts:['100 mL','500 mL','1000 mL','2000 mL'], ans:1, expl:'Tidal Volume (TV): 500 mL per breath (average adult at rest). Total Lung Capacity (TLC): ~6000 mL. Vital Capacity (VC): ~4800 mL (air exhaled after maximum inhalation). Residual Volume (RV): ~1200 mL (air remaining after maximum exhalation). IRV (Inspiratory Reserve): ~3000 mL. ERV (Expiratory Reserve): ~1300 mL. Spirometry measures these volumes to assess lung function.' },
  { topic:'anatomy', q:'The "hinge" joint that allows only flexion and extension is the:', opts:['Ball-and-socket joint (hip, shoulder)','Pivot joint (atlanto-axial)','Hinge joint (knee, elbow, ankle, interphalangeal)','Saddle joint (thumb)'], ans:2, expl:'Hinge joint (ginglymus): allows flexion and extension in one plane only. Examples: Knee (tibiofemoral), Elbow (humeroulnar), Ankle (tibiotalar), Interphalangeal joints. Ball-and-socket: multiaxial movement (hip, shoulder). Pivot: rotation only (atlanto-axial, proximal/distal radioulnar). Saddle: biaxial (thumb carpometacarpal). Condyloid: biaxial (wrist, MCP joints).' },
  { topic:'anatomy', q:'The function of red bone marrow is:', opts:['Fat storage','Production of blood cells (haematopoiesis) - RBCs, WBCs, platelets','Immune response only','Bone repair only'], ans:1, expl:'Red bone marrow: site of haematopoiesis (blood cell production). Located in: flat bones (sternum, iliac crest - bone marrow aspiration/biopsy sites), vertebrae, ribs, skull, proximal long bone epiphyses (in adults). Produces: RBCs, WBCs, platelets. Yellow bone marrow: fat storage (in diaphysis of long bones). Can convert to red in stress (haemolysis, blood loss).' },
  { topic:'anatomy', q:'The circle of Willis is located:', opts:['In the spinal cord','At the base of the brain (cerebral arterial circle connecting carotid and vertebrobasilar systems)','In the heart','Around the kidney'], ans:1, expl:'Circle of Willis (circulus arteriosus): anastomotic ring at base of brain. Formed by: bilateral anterior cerebral arteries (ACAs), anterior communicating artery (ACoA), bilateral posterior cerebral arteries (PCAs), bilateral posterior communicating arteries (PCoAs), bilateral internal carotid arteries. Provides collateral circulation - if one vessel occluded, others can maintain perfusion. Aneurysms at branching points (berry aneurysms) - cause SAH if rupture.' },
  { topic:'anatomy', q:'Uterus position - normal uterus is:', opts:['Retroverted and retroflexed in all women','Anteverted and anteflexed (tilted forward toward bladder - most common position)','Always vertical (axial)','Lateral position only'], ans:1, expl:'Normal uterus position: Anteverted (tilts forward from vaginal axis at cervix) + Anteflexed (bends forward at junction of body and cervix). Retroverted: tilts backward (10-15% of women, often normal variant). Retroflexed: bends backward. Retroverted retroflexed uterus: may cause dysmenorrhoea, dyspareunia in some women. Assessed by bimanual examination. Clinical significance: IUD insertion, HSG procedure.' },
  { topic:'anatomy', q:'The inguinal canal is clinically important because:', opts:['Contains the uterus in females','It is the site of inguinal hernia (indirect - through deep inguinal ring; direct - through Hesselbach triangle)','It contains the kidney','It is the pathway of bile'], ans:1, expl:'Inguinal canal: 4 cm long oblique canal in the anterior abdominal wall, above medial half of inguinal ligament. Contains: in males - spermatic cord (vas deferens, testicular vessels, ilioinguinal nerve); in females - round ligament, ilioinguinal nerve. Inguinal hernia: most common hernia. Indirect: through deep inguinal ring (more common, congenital). Direct: through Hesselbach triangle (posterior wall weakness, acquired).' },
  { topic:'anatomy', q:'The normal PR interval on ECG is:', opts:['<0.08 seconds','0.12-0.20 seconds (3-5 small squares)','0.30-0.40 seconds','0.60-0.80 seconds'], ans:1, expl:'Normal ECG values: PR interval (atrial depolarisation to ventricular depolarisation) 0.12-0.20 seconds. QRS complex (ventricular depolarisation) <0.12 seconds. QT interval: <0.44 seconds (corrected for HR). Heart rate from ECG: 300/large squares between R waves. First-degree AV block: PR >0.20 sec. Second-degree block: some P waves not followed by QRS. Third-degree (complete) block: no association between P waves and QRS.' },
  { topic:'nursing', q:'Documentation in nursing (recording in patient records) should be:', opts:['Only done once a day','Subjective with nurse opinions','Factual, accurate, current, organised, confidential (FACCO), legible, and timely','Abbreviated to save time using personal shorthand'], ans:2, expl:'Principles of nursing documentation: Factual (what was seen/measured, not opinions), Accurate (exact values, correct patient, correct time), Current (timeliness - document immediately after care given), Organised (logical sequence, SOAP format), Confidential (access restricted to healthcare team), Legible (clear handwriting), Complete, Dated and Signed. Legal document - inadmissible if not properly documented. Electronic Health Records (EHR) increasingly used.' },
  { topic:'nursing', q:'Safe patient handling - the correct technique for turning a patient in bed (log roll) requires:', opts:['One nurse using their back muscles','Three to four staff members to maintain spinal alignment, using draw sheet','Pulling the patient by arms','Using no equipment - hands only'], ans:1, expl:'Log roll (for spinal injury patients): minimum 3 persons (ideally 4). One person stabilises the head/neck in neutral alignment (leader, gives commands). Others at shoulder/hip, hips/thighs. All turn simultaneously on count to keep spine in neutral alignment. Cannot be done by one person. Use draw/turning sheet to reduce friction. Equipment: turning sheets, slide boards, ceiling hoists, transfer belts for other types of moves.' },
  { topic:'nursing', q:'The purpose of a "crash cart" (resuscitation trolley) in hospital is:', opts:['Storage of ward supplies','Immediate availability of emergency drugs and equipment for cardiac/respiratory arrest resuscitation','IV fluid storage','Medication distribution'], ans:1, expl:'Crash cart (resuscitation trolley): contains all equipment and drugs needed for emergency resuscitation (cardiac/respiratory arrest). Contents: Defibrillator, cardiac monitor, suction device, oxygen source, BVM (bag-valve-mask), endotracheal tubes, laryngoscope, IV access supplies, emergency drugs (Adrenaline, Atropine, Amiodarone, Dextrose, Sodium bicarbonate, Lignocaine, calcium gluconate), documentation forms. Must be checked every shift (sealed and intact).' },
  { topic:'nursing', q:'Universal precautions (Standard Precautions) require:', opts:['Only using gloves with AIDS patients','Treating blood and ALL body fluids from ALL patients as potentially infectious (regardless of diagnosis)','Only for patients with known infections','Gloves only when doing injections'], ans:1, expl:'Universal/Standard Precautions (CDC): treat blood and ALL body fluids from ALL patients as potentially infectious (do not need known diagnosis of infection). Components: Hand hygiene (most important), appropriate PPE (gloves, gown, mask, eye protection based on exposure risk), safe sharps handling (no recapping, sharps container), respiratory hygiene/cough etiquette, safe injection practices, environmental cleaning, linen and waste management.' },
  { topic:'nursing', q:'A nursing care plan includes:', opts:['Physician orders only','Nursing diagnoses, goals/expected outcomes, nursing interventions, and evaluation criteria','Medication schedule only','Laboratory results only'], ans:1, expl:'Nursing Care Plan (NCP): written guide for patient care. Components: (1) Assessment data (subjective and objective), (2) Nursing Diagnosis (NANDA format: Problem + Related to + Evidenced by), (3) Goals/Expected Outcomes (SMART: Specific, Measurable, Achievable, Relevant, Time-bound), (4) Nursing Interventions (with rationale), (5) Evaluation (was goal met? fully/partially/not met? revise plan). Ensures continuity of care.' },
  { topic:'mental', q:'In motivational interviewing (MI), the OARS technique stands for:', opts:['Observe, Assess, Respond, Support','Open questions, Affirmations, Reflective listening, Summaries','Order, Assess, Refer, Supervise','Outcomes, Advice, Risk, Safety'], ans:1, expl:'OARS (Motivational Interviewing core skills by Miller and Rollnick): Open questions (explore ambivalence about change - "What concerns do you have about...?"), Affirmations (acknowledge strengths - "You\'ve shown real determination..."), Reflective listening (reflect back to show understanding), Summaries (consolidate information, link themes). MI used for: substance use, lifestyle changes, medication adherence. Based on Transtheoretical/Stages of Change Model.' },
  { topic:'mental', q:'Delirium is differentiated from dementia by:', opts:['Age of onset','Acute onset, fluctuating course, inattention, and disturbed consciousness (vs. dementia: gradual onset, stable decline, consciousness intact)','Severity of cognitive impairment','Presence of hallucinations'], ans:1, expl:'Delirium vs Dementia: Delirium - Acute/sudden onset (hours-days), Fluctuating course (worse at night - sundowning), Inattention (primary feature), Consciousness disturbed (CONFUSED-fluctuating level). Dementia - Gradual/insidious onset (months-years), Progressive stable decline, Attention relatively preserved early, Consciousness intact until late. Delirium often superimposed on dementia (more vulnerable). Causes of delirium: AEIOU TIPS mnemonic.' },
  { topic:'environment', q:'The half-life of DDT (dichlorodiphenyltrichloroethane) in the environment is approximately:', opts:['1-7 days','2-15 years (persistent organic pollutant - POPs)','1 month','1 hour'], ans:1, expl:'DDT: organochlorine pesticide. Persistent Organic Pollutant (POP) - half-life 2-15 years in environment. Bioaccumulates in food chain (biomagnification - highest concentrations in apex predators). Uses: malaria control (indoor residual spraying still permitted under Stockholm Convention for malaria vector control). Banned for agricultural use in India. POPs: banned under Stockholm Convention 2001 (dirty dozen + more).' },
  { topic:'environment', q:'E-waste (electronic waste) contains hazardous materials including:', opts:['Only plastic','Lead (CRT monitors), mercury (fluorescent lamps), cadmium (batteries), chromium, BFRs (brominated flame retardants) - toxic to health and environment','Only glass','Only copper'], ans:1, expl:'E-waste: fastest growing waste stream. Hazardous materials: Lead (CRT glass, solder), Mercury (batteries, fluorescent lamps, switches), Cadmium (rechargeable batteries, semiconductors), Hexavalent chromium (metal casings), PVC (halogenated plastics), BFRs (brominated flame retardants - in plastic casings). Exposure: informal recycling workers in developing countries at highest risk. E-Waste (Management) Rules 2016 (India): Extended Producer Responsibility (EPR).' },
  { topic:'environment', q:'Thermal inversion (temperature inversion) increases air pollution because:', opts:['Cold air rises, taking pollutants away','Warm air traps cold, polluted air near ground surface preventing its dispersal (creates "lid" effect)','It reduces industrial emissions','It increases wind speed'], ans:1, expl:'Thermal inversion: normally temperature decreases with altitude (warm air rises, takes pollutants upward). During inversion: a warm air layer sits above cooler air near ground (inverted). This acts as a lid - pollutants trapped near ground surface, concentrations build up. Common in valleys, cities in winter mornings, calm weather. Examples: London Smog 1952 (4000 deaths), Donora Pennsylvania 1948.' },
  { topic:'firstaid', q:'Rule of Nines for burns - head and neck is:', opts:['1%','4.5%','9%','18%'], ans:2, expl:'Rule of Nines (Wallace Rule of Nines) - estimating body surface area (BSA) burnt in adults: Head and neck = 9%, Each upper arm = 4.5% (total arm = 9%), Anterior trunk = 18%, Posterior trunk = 18%, Each thigh = 9%, Each leg and foot = 9%, Genitalia/perineum = 1%. Total = 100%. In children: Lund and Browder chart more accurate (head larger relative to body). First aid: cool with running cool (not ice cold) water for 20 minutes.' },
  { topic:'firstaid', q:'Carbon monoxide (CO) poisoning - characteristic cherry-red skin colour is caused by:', opts:['Iron deficiency','Carboxyhaemoglobin (COHb) formation - CO binds Hb with 200x affinity of O2','Methemoglobinaemia','Cyanide poisoning'], ans:1, expl:'CO poisoning: CO binds Hb 200-250x more avidly than O2 → forms COHb (bright cherry-red - distinctive but only visible in 50% of cases, unreliable sign). Symptoms: headache (first), nausea, confusion, syncope, coma. Sources: incomplete combustion (car exhaust, heaters, generators in enclosed spaces). Treatment: 100% oxygen (via non-rebreather mask/hyperbaric O2 for severe cases). Co-oximetry (SpO2 unreliable in CO poisoning).' },
  { topic:'firstaid', q:'In a conscious choking adult, after back blows fail, the next action is:', opts:['Begin CPR','Finger sweep blindly in mouth','Give 5 abdominal thrusts (Heimlich manoeuvre)','Lay patient flat'], ans:2, expl:'Choking management (FBAO) in conscious adult: First 5 back blows (heel of hand between shoulder blades). If fails: 5 abdominal thrusts (Heimlich). Alternate 5+5 until object expelled or patient becomes unconscious. If unconscious: lower carefully, call 112/108, start CPR. Each CPR cycle: look in mouth before ventilating - ONLY remove object if VISIBLE (never blind finger sweep). Infant: 5 back blows + 5 chest thrusts (NOT Heimlich).' },
  { topic:'community', q:'AYUSH systems integrated into NHM include:', opts:['Allopathy and Homeopathy only','Ayurveda, Yoga, Unani, Siddha, Homeopathy (plus Naturopathy and Sowa-Rigpa)','Traditional medicine from China only','Alternative medicine from Europe'], ans:1, expl:'AYUSH: Ayurveda, Yoga and Naturopathy, Unani, Siddha, Homeopathy. Ministry of AYUSH (created 2014). Sowa-Rigpa (traditional Tibetan/Himalayan medicine - included 2020). AYUSH health and wellness centres integrated with NHM in states with AYUSH practitioners. AYUSH practitioners serve as MOICs in areas lacking allopathic doctors. Evidence-based integration being promoted. IMPCL: produces AYUSH drugs.' },
  { topic:'community', q:'Disability - under Persons with Disabilities (Equal Opportunities, Protection of Rights and Full Participation) Act, now replaced by Rights of Persons with Disabilities (RPWD) Act 2016, the number of specified disabilities is:', opts:['7','14','21 (expanded from 7 to 21 categories)','30'], ans:2, expl:'RPWD Act 2016 (replacing PWD Act 1995): expanded disabilities from 7 to 21 categories. Includes: Blindness, low vision, leprosy-cured, hearing impairment, locomotor disability, dwarfism, intellectual disability, mental illness, autism spectrum disorder, cerebral palsy, muscular dystrophy, chronic neurological conditions, specific learning disabilities, multiple sclerosis, speech and language disability, thalassemia, haemophilia, sickle cell disease, acid attack victims, Parkinson\'s, multiple disabilities. Benchmark disability: 40%+ impairment.' },
  { topic:'programs', q:'Pradhan Mantri Swasthya Suraksha Yojana (PMSSY) aims to:', opts:['Provide health insurance','Setting up of AIIMS-like institutes (6 new AIIMS) and upgradation of existing government medical colleges','Provide ambulance services','Provide free medicines'], ans:1, expl:'PMSSY (launched 2003): two-pronged strategy: (1) Establishment of AIIMS-like institutions in underserved states (6 new AIIMS in Phase I, more in subsequent phases - including AIIMS Bhopal, Bhubaneswar, Jodhpur, Patna, Raipur, Rishikesh), (2) Upgradation of 13 existing Government Medical College Institutions (GMCIs) to improve tertiary healthcare. Aim: correct regional imbalances in healthcare.' },
  { topic:'programs', q:'Janani Express / 102 ambulance service is:', opts:['For emergency cardiac cases','Free transport for pregnant women (ANC, delivery, PNC) and sick neonates under NHM','For accident victims only','For elderly patients only'], ans:1, expl:'102 (Janani Express): free, round-the-clock transport for pregnant women (to facility for ANC, delivery, return home) and sick newborns. Managed by states under NHM. 108 (Emergency Response Service): for all medical emergencies - accidents, cardiac events, stroke. Both are NHM-funded. 1800-180-1104: helpline. JSSK entitlement includes free transport - 102 is the vehicle for this entitlement.' },
  { topic:'programs', q:'The National Water Mission (under National Action Plan on Climate Change - NAPCC) aims to:', opts:['Provide bottled water to all','Conserve water, minimize wastage and ensure equitable distribution through integrated water resources management (20% improvement in water use efficiency)','Flood control only','Rainwater harvesting only in cities'], ans:1, expl:'NAPCC 2008: 8 National Missions including National Water Mission. Goals: conserve water, minimize wastage, equitable distribution - target 20% improvement in water use efficiency. Other missions: Solar Energy, Enhanced Energy Efficiency, Sustainable Habitat, Sustaining Himalayan Ecosystems, Green India (afforestation), Sustainable Agriculture, Strategic Knowledge for Climate Change.' },
  { topic:'mch', q:'The Integrated Management of Neonatal and Childhood Illness (IMNCI) approach classifies sick young infants and children for:', opts:['Surgical referral only','Color-coded classification (Pink-Treat at home, Yellow-Treat and advise, Red-Refer urgently) with integrated assessment for multiple conditions','Laboratory diagnosis only','Advanced diagnostics only'], ans:1, expl:'IMNCI: WHO/UNICEF strategy for primary healthcare of children under 5 and young infants 0-2 months. Integrated assessment of: danger signs, main symptoms (cough/breathing, diarrhoea, fever, ear problem, malnutrition, anaemia, HIV). Classification: Severe (red) - urgent referral, Moderate (yellow) - specific treatment, Mild (green/pink) - home treatment and advice. Improves case management at PHC/community level.' },
  { topic:'mch', q:'Home Based Newborn Care (HBNC) visits by ASHA cover newborns for:', opts:['First 3 days only','First 7 days only','First 42 days (6 visits in first 42 days)','First year'], ans:2, expl:'HBNC (Home Based Newborn Care): ASHA visits newborn at home at Days 1, 2, 3, 7, 14, 28 (modified to 6 visits). Checks: temperature, feeding (breastfeeding), weight, cord care, skin colour (jaundice, cyanosis), danger signs (fast breathing, severe chest indrawing, hypothermia, poor feeding, convulsions - PSBI signs). Counsels mother on exclusive breastfeeding, warmth, danger sign recognition. HBYC: Home-based care for Young Child (beyond 42 days).' },
  { topic:'mch', q:'Obstetric fistula (vesico-vaginal fistula - VVF) is caused primarily by:', opts:['Poor nutrition during pregnancy','Prolonged/obstructed labour without adequate obstetric care - ischaemic necrosis of bladder/vagina wall','Genetic factors','Old age'], ans:1, expl:'Vesico-Vaginal Fistula (VVF): abnormal connection between bladder and vagina. Obstetric VVF: caused by prolonged/obstructed labour - fetal head compresses tissues against pelvis for hours → ischaemia → necrosis → fistula formation. Result: continuous involuntary urinary leakage, social stigma, depression. Prevention: skilled birth attendance, timely C-section for obstructed labour. Treatment: surgical repair. Free surgery under Rashtriya Arogya Nidhi.' },
  { topic:'nutrition', q:'Low birthweight (LBW) is primarily prevented by:', opts:['Immunisation of mother only','Adequate maternal nutrition (pre-pregnancy weight + weight gain in pregnancy), ANC, prevention and treatment of anaemia, avoidance of tobacco/alcohol, treatment of infections','Vitamin A supplementation only','Delivery at term hospital only'], ans:1, expl:'LBW prevention: Address causes of IUGR and prematurity. Maternal nutrition: pre-pregnancy BMI 18.5+, adequate weight gain in pregnancy (12-15 kg for normal BMI, 7-11 kg for overweight). IFA supplementation. Treat anaemia, malaria in pregnancy. Calcium supplementation (reduce pre-eclampsia). Avoid tobacco, alcohol. Prevention of infections (UTI, STI, periodontal disease). ANC for monitoring fetal growth. PPIUCD + birth spacing (>2 years between births) reduces LBW.' },
  { topic:'nutrition', q:'Ready-to-Use Therapeutic Food (RUTF) - composition per 100 g is approximately:', opts:['50 kcal, low fat, high water content','500 kcal, 10-12 g protein, high fat, no water (safe without refrigeration, F-100 equivalent in peanut/milk/sugar/oil paste)','100 kcal, low protein','Only carbohydrates and water'], ans:1, expl:'RUTF (Plumpy Nut/Plumpy Sup): approximately 500-550 kcal per 92-100g sachet. High energy density, high fat (50% calories from fat), adequate protein (~10-12 g), micronutrient enriched (WHO recommendations). Water activity very low - no water (safe without refrigeration even in field conditions). Used for SAM community management (CMAM). F-100 liquid equivalent. India: local RUTF production using chickpea/peanut base.' },
  { topic:'nutrition', q:'Dietary fiber (roughage) function is:', opts:['Provides high caloric energy','Prevents constipation (increases stool bulk), reduces cholesterol absorption, lowers colorectal cancer risk, improves glycaemic control','Is digested and absorbed for energy','Has no health benefit'], ans:1, expl:'Dietary fiber: non-digestible carbohydrates (cellulose, hemicellulose, pectin, gums, inulin). Two types: Soluble (oats, legumes, fruits - lowers LDL cholesterol, improves glycaemic control) and Insoluble (wheat bran, vegetables - bulks stool, prevents constipation, reduces colorectal cancer risk). RDA: 25-30 g/day. WHO: at least 25 g/day. Benefits: cardiovascular disease prevention, diabetes management, weight management (satiety), colon health.' },
  { topic:'community', q:'In tuberculosis control, sputum smear microscopy (AFB smear) is used for:', opts:['Diagnosis of MDR-TB','Diagnosing pulmonary TB in symptomatic patients and monitoring response to treatment (sputum conversion)','Blood test for TB','Skin test for TB'], ans:1, expl:'AFB (Acid-Fast Bacilli) smear microscopy: standard diagnostic tool for pulmonary TB at peripheral health facilities. Sensitivity: 50-80% (misses paucibacillary cases). Specificity: 99%. WHO endorsed molecular test: CBNAAT/GeneXpert MTB/RIF - preferred initial diagnostic test in India (NTP). Detects TB and Rifampicin resistance in 2 hours. Line Probe Assay (LPA): detects MDR-TB. Culture: gold standard but takes 4-8 weeks (liquid) or 4-8 weeks (solid).' },
  { topic:'community', q:'Oral Polio Vaccine (OPV) is preferred over Inactivated Polio Vaccine (IPV) in some settings because:', opts:['It is injected and more accurate','It provides intestinal immunity (IgA), is easy to administer orally, cheaper, provides herd immunity, but risk of vaccine-associated paralytic polio (VAPP) in rare cases','It has no side effects','It is newer technology'], ans:1, expl:'OPV (Sabin): live attenuated, oral administration, induces gut immunity (IgA - blocks transmission), induces mucosal immunity in community (herd immunity), cheap, easy to administer without trained personnel. Disadvantage: VAPP (1/2.4 million doses), cVDPV (circulating vaccine-derived poliovirus) in areas with low coverage. IPV (Salk): injectable, inactivated, safer (no VAPP), induces humoral immunity (IgG) but less gut mucosal immunity. India uses OPV + IPV (since 2015).' },
  { topic:'community', q:'The number of sub-centres per PHC (norm in plains) is:', opts:['3','6','9','12'], ans:1, expl:'PHC-Sub-Centre ratio: In plains, 1 PHC covers 30,000 population with 6 sub-centres (each sub-centre covers 5,000). In hilly/tribal areas: 1 PHC covers 20,000 with approximately 5-7 sub-centres (each covering 3,000). Sub-centre staffing: 1 ANM (primary), 1 Male Health Worker (MPW-M), 1 Additional ANM under NHM. ANM: the first contact health worker in rural areas.' },
  { topic:'community', q:'Crude Birth Rate (CBR) in India as per recent data is approximately:', opts:['10/1000 population','19-20/1000 population (SRS 2020)','30/1000 population','40/1000 population'], ans:1, expl:'India Crude Birth Rate (SRS 2020): 19.2/1000 population. Total Fertility Rate (TFR) NFHS-5 (2019-21): 2.0 (below replacement). Crude Death Rate (CDR): 7.4/1000. Natural Growth Rate = CBR - CDR = 19.2 - 7.4 = 11.8/1000 = 1.18%. IMR (SRS 2020): 28/1000 live births. Life expectancy at birth (2015-19): Males 68.2 years, Females 70.7 years.' },
  { topic:'programs', q:'Which scheme provides free generic medicines at government health facilities in India?', opts:['PM-JAY','Jan Aushadhi Scheme (Pradhan Mantri Bhartiya Janaushadhi Pariyojana)','JSSK for pregnant women only','Free Diagnostics Service Initiative (FDSI)'], ans:1, expl:'Pradhan Mantri Bhartiya Janaushadhi Pariyojana (PMBJP): generic medicines at affordable prices (50-90% cheaper) through Jan Aushadhi Kendras (8000+ stores). Free medicines at government facilities: Free Drug Service Initiative under NHM (Essential Medicines List). Free diagnostics: Free Diagnostics Service Initiative (FDSI). Aushadi (generic pharma) at HWCs: 175+ generic medicines available free at HWC.' },
  { topic:'programs', q:'Under National Ambulance Service (NAS), "108" service is:', opts:['Emergency Response Service for medical emergencies - free for all citizens','Ambulance for maternal health only','School health programme','Mental health helpline'], ans:0, expl:'108 Emergency Response Service (ERS): free, 24/7 emergency ambulance service. Handles: medical emergencies (cardiac, stroke, trauma, burns, poisoning), obstetric emergencies, road accidents. Basic Life Support (BLS) and Advanced Life Support (ALS) ambulances. Response time target: 15-20 min (urban), 30 min (rural). Managed by state governments with NHM support. CATS (Centralised Accident and Trauma Services): Delhi.' },
  { topic:'programs', q:'Reproductive, Maternal, Newborn, Child, and Adolescent Health (RMNCAH+N) strategy in India integrates:', opts:['Only maternal health services','Reproductive health, safe motherhood, newborn care, child health, adolescent health, and nutrition together as a continuum of care','Family planning only','Disease control only'], ans:1, expl:'RMNCAH+N (Reproductive, Maternal, Newborn, Child, Adolescent Health + Nutrition): integrated strategy replacing fragmented vertical programmes. Continuum of care: pre-pregnancy → pregnancy → birth → newborn → child → adolescent. Cross-cutting: nutrition at every stage. India\'s RMNCH+A Strategic Approach 2013 (under NHM). Focus districts: 184 high-burden districts for intensified interventions. LaMPS (Labour Room QI).' },
  { topic:'stats', q:'Life expectancy at birth means:', opts:['Maximum lifespan of the longest-lived person','Average number of years a newborn is expected to live if current mortality rates continue throughout life','Life expectancy after reaching 65 years','Median age at death'], ans:1, expl:'Life Expectancy at Birth (LEB): average number of years a newborn is expected to live given current age-specific mortality rates. India LEB (SRS 2015-19): Males 68.2 years, Females 70.7 years. Global LEB (WHO 2019): 73.3 years (females 75.9, males 70.8). Japan highest (~84 years). Higher LEB in females (female advantage) in most countries. SDG 3.4: reduce premature NCD mortality by 1/3 by 2030.' },
  { topic:'stats', q:'Positive Predictive Value (PPV) is:', opts:['Sensitivity of a test','Proportion of positive tests that are truly positive (TP/(TP+FP)) - depends on prevalence','Specificity of a test','Proportion of negative tests truly negative'], ans:1, expl:'PPV = TP/(TP+FP): among all positive test results, proportion that are true positives. Depends heavily on PREVALENCE (pre-test probability). High prevalence → higher PPV. NPV (Negative Predictive Value) = TN/(TN+FN): among all negative results, proportion truly negative. PPV and NPV are practical clinical values (tells you meaning of a test result). Sensitivity and Specificity: fixed properties of the test. Bayes theorem underlies this.' },
  { topic:'anatomy', q:'The pH of normal blood is:', opts:['7.0 (neutral)','7.35-7.45 (slightly alkaline)','7.0-7.10','7.5-7.6'], ans:1, expl:'Normal arterial blood pH: 7.35-7.45 (slightly alkaline). Acidosis: pH <7.35 (Metabolic: HCO3- low; Respiratory: CO2 high). Alkalosis: pH >7.45 (Metabolic: HCO3- high; Respiratory: CO2 low). CO2 + H2O ↔ H2CO3 ↔ H+ + HCO3- (Henderson-Hasselbalch). Compensation: lungs compensate metabolic (fast, minutes-hours); kidneys compensate respiratory (slow, days).' },
  { topic:'anatomy', q:'The adrenal glands are located:', opts:['Below the kidneys','On top of each kidney (suprarenal glands) - right: triangular, left: crescent-shaped','In the pelvis','Near the liver only'], ans:1, expl:'Adrenal glands (suprarenal glands): sit on top of each kidney. Right: triangular. Left: crescent-shaped. Two distinct zones: Cortex (outer, 90%) - produces Glucocorticoids (cortisol - stress), Mineralocorticoids (aldosterone - Na/K), Androgens (DHEA). Medulla (inner, 10%) - produces Catecholamines (Adrenaline 80%, Noradrenaline 20%). Pheochromocytoma: tumour of adrenal medulla (hypertensive crises).' },
  { topic:'anatomy', q:'Which lobe of the brain is primarily responsible for personality and executive function?', opts:['Occipital lobe','Parietal lobe','Temporal lobe','Frontal lobe'], ans:3, expl:'Frontal lobe: largest lobe. Functions: executive function (planning, decision-making, problem-solving), personality and behaviour, voluntary motor control (primary motor cortex, precentral gyrus), Broca\'s area (speech production - dominant hemisphere). Parietal: sensory processing, spatial awareness. Temporal: hearing, memory (hippocampus), language comprehension (Wernicke\'s area). Occipital: vision.' },
  { topic:'anatomy', q:'The "window period" in HIV infection refers to:', opts:['Period when HIV is most infectious','Time between HIV infection and when antibodies become detectable (3-12 weeks for 4th generation tests)','Time from diagnosis to treatment','Period of full AIDS'], ans:1, expl:'Window period: time between HIV infection and when the test can detect the infection. 4th generation tests (HIV p24 Ag + HIV Ab combo assay): window period 18-45 days. Older antibody-only tests: 3-12 weeks. During window period: person is HIV positive and infectious but tests NEGATIVE. NACO recommends repeat testing after 72 days (3 months) for definitive result. NAT (Nucleic Acid Test): detects within 10-33 days.' },
  { topic:'anatomy', q:'The total blood volume in an adult is approximately:', opts:['1-2 litres','5-6 litres (about 70 mL/kg body weight)','8-10 litres','15-20 litres'], ans:1, expl:'Total blood volume: approximately 5-6 litres in adult (70-80 mL/kg body weight). Blood = Plasma (55%) + Formed elements (45%) - RBCs (99% of cells), WBCs, platelets. Haematocrit: volume % of RBCs in blood (male 40-54%, female 37-47%). Haemorrhagic shock: Class I <750 mL loss (15%), Class II 750-1500 mL (30%), Class III 1500-2000 mL (40%), Class IV >2000 mL (>40%).' },
  { topic:'nursing', q:'Isolation precautions - for a patient with active pulmonary tuberculosis, which type of isolation is required?', opts:['Contact precautions only','Droplet precautions','Airborne infection isolation (negative-pressure room, N95 respirator for staff)','Standard precautions only'], ans:2, expl:'TB requires AIRBORNE INFECTION ISOLATION: Negative pressure room (6-12 air exchanges/hour, air exhausted to outside), N95 or higher respirator for staff entering room, patient wears surgical mask when outside room. Airborne pathogens: TB, Measles, Chickenpox (varicella/zoster). Droplet precautions: influenza, pertussis, mumps, meningococcal, SARS/COVID. Contact: MRSA, CDiff, scabies, impetigo.' },
  { topic:'nursing', q:'The most common early sign of hypoxia (oxygen deficiency) is:', opts:['Cyanosis (blue lips)','Anxiety, restlessness, and confusion (agitation before cyanosis appears)','Loss of consciousness','Low blood pressure'], ans:1, expl:'Early hypoxia signs: Anxiety, restlessness, agitation, confusion (cerebral hypoxia = earliest sign). Tachycardia (compensatory). Tachypnoea. LATE signs: Cyanosis (visible when >5 g/dL of deoxyhaemoglobin in blood - SpO2 <85% approximately), bradycardia (ominous), altered consciousness, convulsions. Cyanosis can be absent in anaemic hypoxia (insufficient Hb to turn blue). Pulse oximetry detects hypoxaemia before cyanosis.' },
  { topic:'nursing', q:'Which IV fluid is isotonic (same osmolarity as blood plasma)?', opts:['5% Dextrose (D5W) - becomes hypotonic once metabolised','0.45% NaCl (Half Normal Saline)','0.9% Normal Saline (NS) or Ringer\'s Lactate (RL) - isotonic (308 mOsm/L and 273 mOsm/L)','3% Hypertonic Saline'], ans:2, expl:'Isotonic IV fluids: Normal Saline (0.9% NaCl, 308 mOsm/L), Ringer\'s Lactate (273 mOsm/L - slightly hypotonic but considered isotonic in practice), Plasma-Lyte. Stay in extracellular space - used for volume replacement. Hypotonic: 0.45% NaCl, 5% dextrose (after metabolism) - hydrates cells. Hypertonic: 3% NaCl, 20% mannitol - draws fluid from cells (used for cerebral oedema, hyponatraemia).' },
  { topic:'drug', q:'The WHO Essential Medicines List (EML) is revised every:', opts:['Every year','Every 2 years','Every 5 years','Every 10 years'], ans:1, expl:'WHO Essential Medicines List (EML): first published 1977. Updated every 2 years by WHO Expert Committee. Current edition: 23rd EML (2023). Defines minimum medicines needed for basic healthcare system. Currently ~460 items. India: National List of Essential Medicines (NLEM 2022): 384 medicines across 57 therapeutic categories. State-level formularies based on NLEM. Essential medicines: cost-effective for primary healthcare needs.' },
  { topic:'drug', q:'The antibiotic used for prophylaxis against meningococcal meningitis contacts is:', opts:['Amoxicillin','Rifampicin (600 mg BD x 2 days) or Ciprofloxacin (single dose) for close contacts','Metronidazole','Erythromycin'], ans:1, expl:'Meningococcal meningitis prophylaxis for close contacts: Rifampicin 600 mg BD x 2 days (adult), 10 mg/kg BD x 2 days (children >1 year), 5 mg/kg BD (infants <1 year). Alternatives: Ciprofloxacin 500 mg single dose (adult, not children), Ceftriaxone IM single dose (pregnancy). Start within 24 hours of index case. Close contacts: household members, kissing contacts, daycare children.' },
  { topic:'drug', q:'Which diuretic is used for hypertensive emergencies and cerebral oedema?', opts:['Frusemide (furosemide) only','Mannitol (osmotic diuretic) for cerebral oedema; IV frusemide for hypertensive emergencies','Hydrochlorothiazide (thiazide)','Spironolactone (potassium-sparing)'], ans:1, expl:'Mannitol (20% solution IV): osmotic diuretic - draws fluid from cerebral interstitium into blood → reduces ICP (intracranial pressure). Used for: cerebral oedema, acute angle-closure glaucoma, to promote diuresis in poisoning. Frusemide (furosemide - loop diuretic): acute pulmonary oedema, heart failure, hypertensive emergency (IV). Thiazides: mild-moderate hypertension, heart failure (oral). Spironolactone: heart failure, liver cirrhosis ascites (aldosterone antagonist).' },
  { topic:'community', q:'Under Pradhan Mantri Jan Dhan Yojana (PMJDY) - Jan Dhan Darshak (JDD) app helps:', opts:['Financial inclusion only (bank accounts)','Locate nearest financial service points (banks, ATMs, insurance, pension) and is integrated with Ayushman Bharat PM-JAY for health insurance enrollment','Food supply chain management','Water supply management'], ans:1, expl:'Jan Dhan Darshak: mobile app under PMJDY for locating nearest financial service providers. PMJDY (2014): financial inclusion - zero-balance bank accounts for all, Rupay debit card, Rs 1 lakh accident insurance, Rs 30,000 life insurance. Integration with DBT (Direct Benefit Transfer): welfare benefits directly to bank accounts. Linkage with Aadhaar (JAM trinity: Jan Dhan-Aadhaar-Mobile) enables benefit transfers including PMMVY, JSY cash.' },
  { topic:'community', q:'An endemic disease is one that:', opts:['Occurs globally','Is constantly present at a relatively stable level in a specific geographic area or population','Occurs in epidemics periodically','Is always fatal'], ans:1, expl:'Endemic: disease constantly present at stable/expected level in a specific geographic area or population (e.g., malaria in Assam, kala-azar in Bihar). Epidemic: occurrence clearly in excess of normal expectancy (e.g., dengue outbreak). Pandemic: epidemic across multiple countries/continents (e.g., COVID-19, influenza 2009). Sporadic: irregular, occasional cases without pattern (e.g., cholera cases outside endemic area). Hyperendemic: high endemic level affecting all groups.' },
  { topic:'community', q:'The key indicator used to declare an area "Open Defecation Free (ODF)" under SBM-G is:', opts:['100% households having toilets only','95%+ households have access to and use toilets AND no visible open defecation found in public spaces','Only households above poverty line have toilets','Having one community toilet for every 100 people'], ans:1, expl:'ODF declaration criteria (SBM-G): All households have access to and USE toilets/sanitation facilities; No open defecation visible in public places, fields, railway tracks. Verified by: community surveys, third-party verification. ODF+ (SBM 2.0): ODF maintained + solid/liquid waste management. ODF++: ODF+ + WASH in schools and health facilities. India achieved ODF status October 2019 (self-declared, later verified independently).' },
  { topic:'mch', q:'Placental abruption (abruptio placentae) is:', opts:['Placenta over the cervix','Premature separation of a normally situated placenta - painful dark red vaginal bleeding + uterine tenderness','Retained placenta after delivery','Placenta praevia type 3'], ans:1, expl:'Placental abruption: premature separation of normally situated placenta (before delivery of baby). Features: Sudden severe abdominal pain + dark red vaginal bleeding (may be concealed = no external bleeding but massive retro-placental clot), uterine tenderness, hard "woody" uterus, fetal distress/death. Risk factors: hypertension, trauma, cocaine, smoking, previous abruption. Emergency: coagulopathy (DIC) risk. Management: delivery (C-section if severe).' },
  { topic:'mch', q:'The Normal Duration of Pregnancy (calculated from LMP) is:', opts:['36 weeks','38 weeks','40 weeks (280 days, or Naegele\'s rule: LMP + 9 months + 7 days)','42 weeks'], ans:2, expl:'Normal pregnancy: 40 weeks from LMP (280 days), 38 weeks from conception (266 days). Naegele\'s rule: EDD = LMP + 9 months + 7 days (or LMP + 1 year - 3 months + 7 days). Term: 37-41 6/7 weeks. Preterm: <37 weeks (<34 weeks = moderate preterm, <28 weeks = extreme preterm). Post-term: >42 weeks (increased stillbirth risk - induction recommended at 41-42 weeks). Gestational age by ultrasound most accurate in first trimester.' },
  { topic:'mch', q:'Surfactant is produced by which cells in the fetal lung?', opts:['Type I pneumocytes','Type II pneumocytes (produce surfactant from 24 weeks, mature levels by 34-36 weeks)','Alveolar macrophages','Goblet cells'], ans:1, expl:'Pulmonary surfactant: produced by Type II pneumocytes (Type II alveolar cells/pneumonocytes). Main component: phosphatidylcholine (lecithin). Reduces surface tension in alveoli, prevents alveolar collapse on expiration (atelectasis). Synthesis begins 24 weeks, matures 34-36 weeks. Preterm <32-34 weeks: insufficient surfactant → IRDS (Infant Respiratory Distress Syndrome/Hyaline Membrane Disease). Prevention: antenatal corticosteroids (betamethasone/dexamethasone) to accelerate surfactant maturity. Treatment: exogenous surfactant.' },
  { topic:'community', q:'Tobacco control in India - which act prohibits smoking in public places?', opts:['Food Safety and Standards Act','Cigarettes and Other Tobacco Products Act (COTPA) 2003 - Section 4 bans smoking in public places','Motor Vehicles Act','Consumer Protection Act'], ans:1, expl:'COTPA 2003 (Cigarettes and Other Tobacco Products Act): comprehensive tobacco control legislation. Key provisions: Section 4 - no smoking in public places (punishable with fine). Section 5 - no tobacco advertising, promotion, sponsorship. Section 6 - no sale to/by minors under 18 years; no sale within 100 metres of educational institutions. Section 7 - health warnings on all tobacco products (pictorial, 85% of packet). India: MPOWER framework (WHO).' },
  { topic:'community', q:'National Organ and Tissue Transplant Organisation (NOTTO) coordinates:', opts:['Blood transfusion services','Organ donation and transplantation in India (operates 24/7 hotline for organ availability and allocation)','Medicine distribution','Vaccine distribution'], ans:1, expl:'NOTTO (National Organ and Tissue Transplant Organisation): apex organisation under MoHFW. Functions: facilitate and coordinate organ and tissue procurement and transplantation. 24/7 helpline: 1800-11-4770. Transplantation of Human Organs and Tissues Act (THOA) 1994 (amended 2011): legal framework. Brain death: legal definition for cadaveric donation. SoTTO/RoTTO: State/Regional Transplant Organisations. Pledged donors: millions via online portal.' },
  { topic:'environment', q:'The greenhouse gas contributing most to global warming from human activities is:', opts:['Methane (CH4)','Carbon dioxide (CO2 - 76% of greenhouse gas emissions from fossil fuels, deforestation, industry)','Nitrous oxide (N2O)','Water vapour'], ans:1, expl:'CO2: accounts for ~76% of human-caused greenhouse gas emissions (burning fossil fuels 65%, deforestation 11%). Methane (CH4): 16% (cattle, rice paddies, landfills, natural gas leaks). N2O: 6% (agriculture, fertilisers). F-gases: 2%. CO2 persists in atmosphere 300-1000 years. Paris Agreement (2015): limit global warming to 1.5-2 degrees C above pre-industrial levels. India: committed to Net Zero by 2070.' },
  { topic:'environment', q:'Chlorination of drinking water kills most bacteria at a residual chlorine of:', opts:['0.001 mg/L','0.2-0.5 mg/L free residual chlorine at point of use','5 mg/L','10 mg/L'], ans:1, expl:'Chlorination of water: free residual chlorine 0.2-0.5 mg/L at point of use (consumer tap). WHO guidelines: minimum 0.2 mg/L free residual chlorine at point of delivery. At treatment plant: typically 2-5 mg/L applied (contact time 30 minutes). Bleaching powder (calcium hypochlorite): 1 kg per 1000 litres. High-level disinfection for water: superchlorination (10 mg/L). Chlorine ineffective against: Cryptosporidium, Giardia cysts (require filtration).' },
  { topic:'fp', q:'The lactational amenorrhoea method (LAM) is effective as contraception when:', opts:['Baby is over 6 months','Baby is less than 6 months AND mother is fully breastfeeding (no other food/water) AND mother has not resumed menstruation - all 3 conditions must be met','Mother is breastfeeding only once daily','Baby is given formula with breastfeeding'], ans:1, expl:'LAM (Lactational Amenorrhoea Method): 3 criteria ALL must be present: (1) Baby <6 months, (2) Mother fully/exclusively breastfeeding (day and night, no supplements), (3) Amenorrhoea (no period since delivery). Effectiveness: >98% if all 3 conditions met. Once any condition fails: switch to another method immediately. Mechanism: frequent suckling suppresses GnRH/LH/FSH → prevents ovulation (prolactin effect).' },
  { topic:'fp', q:'Copper-T 380A (Cu-T 380A) duration of effectiveness is:', opts:['1 year','3 years','10 years (most widely studied IUD - up to 12 years in some studies)','Permanent (cannot be removed)'], ans:2, expl:'Copper-T 380A: most widely used IUD globally. Duration: 10-12 years. Failure rate: <1% per year. Mechanism: copper ions toxic to sperm (spermicidal), alters uterine environment, prevents fertilisation primarily. Can also be used as emergency contraception within 5 days of unprotected intercourse. Removed by trained provider. Smaller variants (Cu-T 200B, 375): shorter duration (3-5 years). PPIUCD (post-partum IUD): inserted within 48 hours of delivery.' },
  { topic:'community', q:'The term "Vertical programme" in public health refers to:', opts:['Hierarchical administrative structure','Disease-specific programmes with separate administrative, logistical and funding systems (e.g., separate TB programme, malaria programme, HIV programme)','Community programmes running from bottom to top','Only national-level programmes'], ans:1, expl:'Vertical programme: disease-specific, with own infrastructure, staff, supply chain, reporting systems (e.g., NVBDCP, RNTCP, NACP, UIP). Advantages: focused attention, clear accountability, easier to evaluate. Disadvantages: duplication, fragmentation, strain on health workers (multiple reporting systems), unsustainable. NHM: move toward integration (horizontal approach) - merging vertical programmes into comprehensive primary health care. UHC requires both strong vertical and horizontal systems.' },
  { topic:'community', q:'A cohort study follows:', opts:['Diseased people backward to find exposure','A group of people (exposed and unexposed) forward in time to see who develops disease - measures incidence and relative risk','A random sample for 1 day','Only cases, not controls'], ans:1, expl:'Cohort study (prospective): takes a group with exposure/risk factor and without (cohort), follows them forward over time to compare disease incidence. Measures: Incidence Rate, Relative Risk (RR), Attributable Risk (AR). Gold standard for aetiology after RCT. Advantages: establishes temporal sequence (exposure before disease), can study multiple outcomes. Disadvantages: expensive, long follow-up, loss to follow-up (attrition bias). Framingham Heart Study: famous cohort.' },
  { topic:'nursing', q:'Normal oxygen saturation (SpO2) by pulse oximetry is:', opts:['85-89%','90-94%','95-100%','70-80%'], ans:2, expl:'Normal SpO2 (oxygen saturation by pulse oximetry): 95-100%. Mild hypoxaemia: 91-94% (supplemental O2 recommended). Moderate: 86-90%. Severe: <86% (urgent intervention). Pulse oximetry unreliable in: carbon monoxide poisoning (reads falsely high), severe anaemia, nail polish, poor perfusion (cold, shock), dark skin pigmentation (may read slightly lower). Arterial blood gas (ABG): measures actual PaO2 (normal 80-100 mmHg).' },
  { topic:'nursing', q:'The Trendelenburg position (modified) is used for:', opts:['Head injury with raised ICP','Hypovolaemic shock (legs elevated 15-30 degrees, head flat - increases venous return to heart)','Respiratory distress','Abdominal surgery'], ans:1, expl:'Modified Trendelenburg (passive leg raise): legs raised 15-30 degrees while torso horizontal. Used for: hypovolaemia/shock (increases venous return, cardiac output - temporary measure while establishing IV access). Classic Trendelenburg (whole body tilted head-down): controversial - may worsen respiratory distress, increase ICP. NOT used for hypovolaemic shock anymore. Reverse Trendelenburg (head up): for patients with GERD, respiratory distress, facial/neck surgery.' },
  { topic:'nursing', q:'The correct order of PPE (Personal Protective Equipment) DONNING (putting on) is:', opts:['Mask → Gown → Gloves → Goggles','Gown → Mask/Respirator → Goggles/Face shield → Gloves (most vulnerable parts last)','Gloves → Gown → Mask → Goggles','Goggles → Gloves → Gown → Mask'], ans:1, expl:'PPE Donning sequence (WHO/CDC): (1) Hand hygiene, (2) Gown (protects clothes), (3) Mask or Respirator (N95 - fit check), (4) Goggles or Face Shield, (5) Gloves (go on last - most contamination risk). DOFFING (removing - more critical): (1) Gloves (most contaminated), (2) Goggles/Face shield, (3) Gown, (4) Mask/Respirator, (5) Hand hygiene. Perform hand hygiene between each step during doffing.' },

  /* ═══ BATCH F — FINAL 255+ QUESTIONS ═══ */
  { topic:'anatomy', q:'The carotid arteries supply blood to:', opts:['Lower limbs','Brain and head (common carotid → internal carotid to brain, external carotid to face/neck)','Heart','Kidneys'], ans:1, expl:'Common carotid artery (CCA): bifurcates at C4 level (angle of jaw). Internal carotid artery (ICA): supplies brain (anterior circulation - frontal, parietal lobes, basal ganglia, anterior thalamus). External carotid artery (ECA): supplies face, scalp, neck, external ear. Carotid pulse: palpable at angle of jaw. Carotid endarterectomy: for significant stenosis (>70%) to prevent stroke.' },
  { topic:'anatomy', q:'The sciatic nerve (longest nerve in body) originates from:', opts:['C5-C6','L2-L4','L4-S3 (lumbosacral plexus)','T1-T4'], ans:2, expl:'Sciatic nerve: largest and longest nerve in body. Origin: L4, L5, S1, S2, S3 (lumbosacral plexus). Exits pelvis through greater sciatic foramen. Supplies: posterior thigh muscles (hip extensors, knee flexors), all muscles below knee, skin of leg (except medial strip). Divides at popliteal fossa into: Common Peroneal nerve and Tibial nerve. Sciatica: pain radiating from buttock down leg (L4/L5/S1 disc herniation most common).' },
  { topic:'anatomy', q:'Haemostasis (stopping of bleeding) involves:', opts:['Vasoconstriction only','Vasoconstriction + platelet plug formation + coagulation cascade (clot formation) + fibrinolysis (clot dissolution)','Only coagulation','Only platelet aggregation'], ans:1, expl:'Haemostasis process: (1) Vascular phase: immediate vasoconstriction (reduces blood flow). (2) Primary haemostasis: platelet adhesion (von Willebrand factor bridges collagen to platelets via GPIb), activation, aggregation → platelet plug. (3) Secondary haemostasis: coagulation cascade → fibrin mesh reinforces platelet plug. (4) Fibrinolysis: plasmin dissolves clot (tPA activates plasminogen → plasmin → degrades fibrin). ITP: low platelets. Haemophilia: coagulation factor deficiency.' },
  { topic:'anatomy', q:'The normal range of serum sodium (Na+) is:', opts:['120-130 mEq/L','135-145 mEq/L','150-160 mEq/L','165-175 mEq/L'], ans:1, expl:'Normal serum electrolytes: Sodium (Na+): 135-145 mEq/L. Potassium (K+): 3.5-5.0 mEq/L. Calcium (Ca2+): 8.5-10.5 mg/dL (2.1-2.6 mmol/L). Chloride (Cl-): 95-105 mEq/L. Bicarbonate (HCO3-): 22-26 mEq/L. Hyponatraemia: Na+ <135 (dilutional, SIADH, heart failure, liver cirrhosis). Hypernatraemia: Na+ >145 (dehydration, diabetes insipidus). Hyponatraemia: most common electrolyte disorder in hospital.' },
  { topic:'anatomy', q:'Cerebrospinal fluid (CSF) is produced by:', opts:['Blood-brain barrier','Choroid plexus in the lateral, third, and fourth ventricles','Arachnoid membrane','Cerebral cortex'], ans:1, expl:'CSF production: choroid plexus (mainly lateral ventricles). Volume produced: 500 mL/day. Total volume at any time: 120-150 mL. Circulation: lateral ventricles → foramen of Monro → third ventricle → aqueduct of Sylvius → fourth ventricle → subarachnoid space → arachnoid granulations → superior sagittal sinus. Hydrocephalus: obstruction of CSF flow (non-communicating) or impaired absorption (communicating). Lumbar puncture: accesses subarachnoid space at L3-L4 or L4-L5.' },
  { topic:'nursing', q:'Enema administration - what is the maximum amount of solution used in a cleansing enema for an adult?', opts:['100-200 mL','300-500 mL','500-1000 mL (or up to 1500 mL depending on type)','2000-3000 mL'], ans:2, expl:'Cleansing enema (large volume) for adults: 500-1000 mL (sometimes up to 1500 mL) of solution (normal saline, soapsuds, tap water). Fleet enema (small volume hypertonic phosphate): 118 mL. Oil retention enema: 90-120 mL (retained 30 min-1 hour to soften stool). Temperature of solution: 37-40 degrees C (body temperature). Position: Sims (left lateral) position. Insert rectal tube 7-10 cm (adult). Enema bag: 30-40 cm above rectum.' },
  { topic:'nursing', q:'Tracheostomy care - inner cannula should be cleaned:', opts:['Once per week','Every 8 hours or more frequently if secretions are heavy (every 4-8 hours)','Only when blocked','Once daily only'], ans:1, expl:'Tracheostomy inner cannula care: clean every 4-8 hours (or more frequently with heavy secretions). Remove inner cannula, clean with pipe cleaners/brushes and normal saline or sterile water, rinse thoroughly, reinsert. Have spare clean inner cannula ready. Outer cannula (tracheostomy tube): changed by physician/trained nurse every 5-7 days or as needed. Stoma: clean daily with chlorhexidine or normal saline. Inflate cuff to minimum occluding volume.' },
  { topic:'nursing', q:'When administering a blood transfusion, the nurse should:', opts:['Infuse rapidly over 30 minutes','Infuse over 2-4 hours per unit (maximum 4 hours), observe for transfusion reactions first 15 minutes','Store blood at room temperature for 24 hours before use','Mix blood with normal saline or dextrose'], ans:1, expl:'Blood transfusion administration: each unit infuse over 2-4 hours (maximum 4 hours from start - beyond which bacterial growth risk increases). Stay with patient for first 15 minutes (highest reaction risk). Vital signs: before, 15 min after start, periodically, post-transfusion. Use only 0.9% NS to prime/flush (dextrose causes RBC lysis, RL causes clotting). Never warm blood in microwave. Transfusion reactions: febrile, allergic, haemolytic (most serious - stop immediately).' },
  { topic:'nursing', q:'Which patient is at HIGHEST risk for developing pressure ulcers?', opts:['Active mobile post-operative patient','Elderly unconscious patient on ventilator with faecal incontinence and malnutrition','Ambulatory diabetic patient','Young pregnant woman on bed rest for 1 day'], ans:1, expl:'Highest pressure ulcer risk: immobility (cannot reposition) + moisture (incontinence - skin maceration) + malnutrition (impaired healing) + altered consciousness (cannot feel/report discomfort) + age (skin fragility) + critical illness. Braden Scale scores these factors: Sensory perception, Moisture, Activity, Mobility, Nutrition, Friction/Shear. Score <18 = at risk; <12 = high risk. Priority: 2-hourly turning, pressure-relieving surfaces, moisture barriers, nutrition optimisation.' },
  { topic:'nursing', q:'A patient on continuous oxygen therapy via nasal cannula at 2 L/min has an FiO2 (fraction of inspired oxygen) of approximately:', opts:['21% (room air)','28%','40%','60%'], ans:1, expl:'FiO2 estimation via nasal cannula: FiO2 = 21% + (4% x L/min). At 2 L/min: 21 + (4x2) = 29% ~ 28%. 1 L = 25%, 2 L = 29%, 3 L = 33%, 4 L = 37%, 5 L = 41%, 6 L = 45%. Simple face mask (5-10 L): 35-50%. Non-rebreather mask with reservoir (10-15 L): 60-90%. Venturi mask: precise FiO2 (24%, 28%, 31%, 35%, 40%, 60%). High flow nasal cannula (HFNC): 21-100% at 60 L/min.' },
  { topic:'nursing', q:'The "Glasgow Coma Scale" (GCS) - a score of 8 or below indicates:', opts:['Normal consciousness','Mild confusion','Severe brain injury/coma - patient likely needs airway protection (intubation)','Vegetative state'], ans:2, expl:'GCS scoring: E(4)+V(5)+M(6) = 15 maximum. GCS 13-15 = Mild brain injury (alert/mild confusion). GCS 9-12 = Moderate brain injury. GCS 8 or less = Severe brain injury / coma. "GCS 8 - intubate" is a clinical mnemonic (airway protection - cannot protect own airway). GCS 3 = minimum (deepest coma/death). Assess: if score declining → urgent intervention. Reassess serially.' },
  { topic:'community', q:'The "RMNCH+A" strategy emphasizes a continuum of care. The "+A" refers to:', opts:['Anaemia prevention','Adolescent health (addressing reproductive health, nutrition, mental health, substance misuse in 10-19 year olds)','Agriculture and food','Acute disease management'], ans:1, expl:'RMNCH+A: Reproductive + Maternal + Newborn + Child Health + Adolescent. The "+A" addition (2013) recognises adolescents (10-19 years) as a distinct group needing targeted health services. RKSK (Rashtriya Kishor Swasthya Karyakram): operationalises adolescent health under NHM. AFHC: Adolescent Friendly Health Clinics at PHC/CHC level. Peer educators (Saathiyas) support adolescent health in community.' },
  { topic:'community', q:'National Family Health Survey (NFHS) is conducted by:', opts:['Ministry of Agriculture','International Institute for Population Sciences (IIPS), Mumbai under MoHFW, Government of India','WHO directly','UNICEF alone'], ans:1, expl:'NFHS: International Institute for Population Sciences (IIPS), Mumbai. Funded by: MoHFW + USAID + other donors. NFHS-5 (2019-21): 5th round. Covers: fertility, mortality, maternal and child health, family planning, nutrition, anaemia, malaria, HIV/AIDS, domestic violence, health facilities. District-level data for first time in NFHS-5. Results guide NHM planning and policy. SRS (Sample Registration System): MoRGI for birth/death rates.' },
  { topic:'community', q:'The National Health Mission (NHM) flexible pool funding mechanism is called:', opts:['Block grant','Programme Implementation Plan (PIP) - states prepare and submit annually to centre for approval and funding','Direct transfer','Matching grant only'], ans:1, expl:'NHM funding mechanism: States prepare Annual Programme Implementation Plan (PIP) based on DHAP (District Health Action Plan). PIP submitted to MoHFW for approval and release of funds. Central share: 60% (90% for NE states). State share: 40% (10% NE). State Health Society (SHS) and District Health Society (DHS) manage funds. Quarterly fund release based on utilisation. Untied funds: for flexibility at sub-centre, PHC, CHC, district levels.' },
  { topic:'community', q:'Biofilm formation in healthcare settings is clinically important because:', opts:['Biofilms are harmless','Biofilms (bacteria encased in polysaccharide matrix on surfaces/catheters/implants) are highly resistant to antibiotics and disinfectants - major cause of HAIs','Biofilms are easy to treat','Biofilms only form in laboratories'], ans:1, expl:'Biofilm: structured community of bacteria encased in self-produced polysaccharide matrix, attached to surfaces. Clinical significance: (1) Much more resistant to antibiotics (up to 1000x MIC needed), disinfectants. (2) Major source of HAIs (Healthcare-Associated Infections) - on urinary catheters (CAUTI), CVCs (CLABSI), ventilators (VAP), joint prostheses. (3) Difficult to eradicate without removing device. Prevention: aseptic technique, early device removal.' },
  { topic:'community', q:'The case fatality rate (CFR) is:', opts:['Deaths in total population / Total population x 100','Number of deaths from a disease / Number of cases of that disease x 100','Total deaths / Total births x 100','Deaths per year / Population x 1000'], ans:1, expl:'Case Fatality Rate (CFR) = (Deaths from disease / Cases of that disease) x 100. Measures SEVERITY of disease (risk of dying if you GET the disease). Example: Ebola CFR 25-90%; COVID-19 CFR 0.5-2%; Measles CFR <0.1% (developed countries) to 20%+ (malnourished children). Different from mortality rate (which uses total population denominator). High CFR = virulent disease. CFR falls with better treatment (antivirals, ICU care).' },
  { topic:'nutrition', q:'Which amino acids are considered "essential" (must be obtained from diet)?', opts:['Alanine, glycine, glutamine (non-essential)','Leucine, isoleucine, valine, lysine, methionine, phenylalanine, threonine, tryptophan, histidine (9 essential)','Only lysine','Glutamic acid and aspartic acid'], ans:1, expl:'Essential amino acids (EAA - cannot be synthesised by body, must come from diet): HILLY MTTV - Histidine, Isoleucine, Leucine, Lysine, Methionine, Phenylalanine, Threonine, Tryptophan, Valine. 9 EAAs in adults (children: Arginine also essential). Complete protein (contains all EAA): animal sources (eggs, meat, milk, fish). Incomplete protein: most plant sources (except quinoa, soya). Complementary proteins: combine plant proteins (rice + dal = complete).' },
  { topic:'nutrition', q:'The "traffic light" food labelling system helps consumers identify:', opts:['Country of origin of food','Levels of fat, saturated fat, sugar, and salt - Red (high), Amber (medium), Green (low) per serving','Manufacturing date only','Caloric content only'], ans:1, expl:'Traffic Light Labelling (UK/India FSSAI): colour-coded labels on packaged food. Red = high in fat/sugar/salt (limit). Amber = medium. Green = low (healthier choice). Per 100g AND per serving. FSSAI (Food Safety and Standards Authority of India): proposed front-of-pack nutrition labelling (FoPNL) to address NCDs. Helps consumers make healthier food choices at point of purchase.' },
  { topic:'nutrition', q:'Night blindness (nyctalopia) is the earliest sign of:', opts:['Vitamin C deficiency','Vitamin A deficiency (Xerophthalmia Grade XN - cannot see in dim light)','Vitamin D deficiency','Vitamin K deficiency'], ans:1, expl:'Night blindness (Nyctalopia - Grade XN): earliest sign of Vitamin A deficiency. Vitamin A (retinol) is essential for synthesis of rhodopsin (visual purple) in rod cells - needed for dim light vision. Progression: XN (night blindness) → X1A (conjunctival xerosis) → X1B (Bitot spots) → X2 (corneal xerosis) → X3A/X3B (corneal ulceration) → XS (scar) → irreversible blindness. Prevention: Vitamin A supplementation, diet diversification (green leafy veg, orange fruits, animal liver).' },
  { topic:'immunization', q:'Which vaccine is given at 16-24 months (18 months) in addition to measles booster?', opts:['BCG booster','DPT booster + OPV booster (along with MR-2 at 16-24 months)','Hepatitis B booster','Typhoid vaccine'], ans:1, expl:'16-24 months schedule (UIP): MR-2 (Measles-Rubella 2nd dose), DPT booster-1 (1st DPT booster), OPV booster-1, Vitamin A (2nd dose 2,00,000 IU), JE-2 (in endemic areas). At 5 years: DPT booster-2 (2nd DPT booster), OPV booster-2. At 10 years: TT (tetanus toxoid). At 16 years: TT. IPV and PCV have no boosters in UIP after primary series.' },
  { topic:'immunization', q:'Live vaccines should NOT be given to:', opts:['Healthy adults','Immunocompromised patients (HIV/AIDS CD4 <200, chemotherapy, organ transplant, high-dose steroids, primary immunodeficiency)','Elderly persons over 70','Pregnant women only'], ans:1, expl:'Live vaccine contraindications: severe immunocompromise - HIV/AIDS (CD4 <200 cells/mm3 or <15%), patients on immunosuppressive therapy (high-dose steroids - prednisolone >20 mg/day for >2 weeks, chemotherapy, biological agents), primary immunodeficiency (SCID, WAS), organ transplant recipients. Pregnancy: most live vaccines avoided (theoretical fetal risk). Exceptions: Yellow fever in pregnant women if risk outweighs benefit. HIV with CD4 >200: can receive most live vaccines.' },
  { topic:'immunization', q:'The Immunisation schedule under UIP - which vaccine was most recently added (2021 onwards)?', opts:['Pentavalent','Rotavirus','MR (Measles-Rubella)','Pneumococcal Conjugate Vaccine (PCV-13) - nationwide from 2021'], ans:3, expl:'PCV (Pneumococcal Conjugate Vaccine): introduced in UIP as part of IMI 2.0. Universal rollout across India completed by 2021. PCV-13 (13-valent): protects against 13 serotypes of Streptococcus pneumoniae causing pneumonia, meningitis, bacteraemia. Given at 6, 10, 14 weeks (3 doses). Prevents approximately 200,000 deaths per year. Previously: state pilots in Kerala, Himachal Pradesh, UP, Bihar, Rajasthan, MP. Now universal.' },
  { topic:'programs', q:'Pradhan Mantri Poshan Shakti Nirman (PM POSHAN) - formerly Mid-Day Meal Scheme - provides:', opts:['Cash to school children','Hot cooked meal to government/government-aided school children (Class 1-8) to increase enrolment, retention, attendance, and improve nutritional status','Only dry rations','Only for secondary school students'], ans:1, expl:'PM POSHAN (formerly MDM - Mid-Day Meal Scheme, relaunched 2021): provides hot cooked meals in government and government-aided schools (Grades 1-8). Caloric content: 450 kcal + 12g protein (primary), 700 kcal + 20g protein (upper primary). Micronutrients fortified. Benefits: increases school enrolment, reduces dropout, improves nutrition, reduces classroom hunger. India: largest school feeding programme in world (~12 crore children). Started 1995 nationally.' },
  { topic:'programs', q:'The Anganwadi Centre (AWC) is the delivery platform for ICDS. How many AWCs are there approximately in India?', opts:['50,000','5 lakh','14 lakh (13.9 lakh operational as of 2022)','1 crore'], ans:2, expl:'ICDS (Integrated Child Development Services): approximately 13.9 lakh (1.39 million) Anganwadi Centres (AWCs) operational across India. Each AWC serves approximately 1000 people / 40 children under 6 years. Staffed by Anganwadi Worker (AWW) + Anganwadi Helper (AWH). Mini-AWC: serves smaller population 300-800 people (hilly/tribal areas). POSHAN Abhiyaan: uses ICDS-CAS (digital platform) to monitor AWC performance in real-time.' },
  { topic:'programs', q:'The Accredited Social Health Activist (ASHA) programme was launched under:', opts:['National AIDS Control Programme','National Rural Health Mission (NRHM) 2005','ICDS','National Nutritional Supplementation Programme'], ans:1, expl:'ASHA programme launched under NRHM (National Rural Health Mission) 2005. ASHA: female community health volunteer, selected from the village she serves, 18 years minimum age, Class 8+ education (Class 10 preferred), married/widowed/divorced, with effective communication and leadership skills. Selection: by Gram Sabha. Training: 23 days in phases. Currently: 10.3 lakh (1.03 million) ASHAs across India. Performance-based incentives.' },
  { topic:'programs', q:'The National Health Policy (NHP) 2017 targets health expenditure to reach:', opts:['1% of GDP','2.5% of GDP by 2025 (from current ~1.13% - among lowest globally)','5% of GDP','10% of GDP'], ans:1, expl:'NHP 2017: increase government health expenditure to 2.5% of GDP by 2025. India current health expenditure: total ~3.54% GDP (2017-18), government: ~1.13% GDP (very low compared to WHO recommendation of 5%). NHP 2017 goals: reduce U5MR to 23/1000 by 2025, IMR to 28, MMR to 100, TFR to 2.1, eliminate leprosy by 2018, eliminate kala-azar and filariasis by 2017, reduce TB incidence by 85% by 2030.' },
  { topic:'programs', q:'SUMAN (Surakshit Matritva Aashwasan) initiative guarantees:', opts:['Cash incentive for institutional delivery','Zero preventable maternal and newborn deaths - respectful, dignified care to every pregnant woman and newborn regardless of ability to pay','Free C-sections only','ANC services only'], ans:1, expl:'SUMAN (Surakshit Matritva Aashwasan, 2019): commitment for ZERO preventable maternal and newborn deaths through respectful, dignified, and quality care. Guarantees: minimum 4 ANCs, minimum 6 PNC contacts, JSSK entitlements, Lactation Management support, SNCU care for sick neonates. Includes zero tolerance for denial of care. Every woman receives colour-coded sticker (Green=normal risk, Yellow=moderate risk, Red=high risk) on MCP card for triage.' },
  { topic:'mental', q:'Substance Use Disorders - The ICD-11 criteria for dependence include:', opts:['Occasional use of a substance','Strong internal urge/compulsion to use, difficulties controlling use, withdrawal, tolerance, neglect of other areas of life, continued use despite harm - persisting for 1+ months or repeated episodes','One episode of intoxication','Using a substance once weekly'], ans:1, expl:'Substance dependence (ICD-11): strong urge to use (craving), impaired control over use, physiological withdrawal on cessation, tolerance (need more for same effect), neglect of other activities/responsibilities, persistent use despite harmful consequences. Duration: symptoms present for at least 1 month or repeatedly over 12 months. DAST (Drug Abuse Screening Test), CAGE, AUDIT: screening tools. Motivational Interviewing: evidence-based counselling approach.' },
  { topic:'mental', q:'Beck Depression Inventory (BDI) is a self-report questionnaire with how many items?', opts:['9 items','21 items (rated 0-3, total 0-63)','30 items','50 items'], ans:1, expl:'Beck Depression Inventory (BDI/BDI-II): 21-item self-report questionnaire. Each item rated 0-3. Total score: 0-63. Interpretation: 0-13 = minimal, 14-19 = mild, 20-28 = moderate, 29-63 = severe depression. PHQ-9 (Patient Health Questionnaire-9): 9-item, based on DSM criteria, widely used in primary care. HAM-D (Hamilton Depression Rating Scale): clinician-administered. Both used for screening and severity assessment.' },
  { topic:'mental', q:'The Counselling model used in suicide prevention that involves active listening without judgment is:', opts:['Cognitive Behavioural Therapy (CBT)','Non-directive/Person-Centred Counselling (Carl Rogers)','Psychoanalysis (Freud)','Behaviour Modification'], ans:1, expl:'Person-Centred Counselling (Carl Rogers, 1940s-50s): non-directive approach. Core conditions: Unconditional Positive Regard (accept client without judgment), Empathy (understand client\'s perspective), Congruence (genuineness of counsellor). Effective in suicide prevention: client feels heard and accepted, builds therapeutic alliance, explores ambivalence about living/dying. SAFE messaging guidelines: avoid glorifying suicide, use safe language, provide resources (iCall: 9152987821, Vandrevala Foundation: 1860-2662-345).' },
  { topic:'environment', q:'The Brundtland Commission (World Commission on Environment and Development) 1987 defined sustainable development as:', opts:['Economic growth at any environmental cost','Development that meets the needs of the present without compromising the ability of future generations to meet their own needs','Rapid industrialisation','Development only in developed countries'], ans:1, expl:'Brundtland Commission Report "Our Common Future" (1987): "Sustainable development is development that meets the needs of the present without compromising the ability of future generations to meet their own needs." Three pillars: Economic sustainability + Social sustainability + Environmental sustainability. Led to Earth Summit (Rio de Janeiro 1992), Agenda 21, Rio Declaration, UNFCCC. MDGs (2000), SDGs (2015): follow on from this framework.' },
  { topic:'environment', q:'The Swachh Bharat Mission (SBM) targets which key WASH (Water, Sanitation, Hygiene) indicator?', opts:['Water quality only','Open Defecation Free (ODF) status + handwashing with soap promotion + safe drinking water','Waste management in cities only','Industrial water treatment'], ans:1, expl:'SBM WASH targets: (1) Open Defecation Free (ODF): every household/school/health facility has and uses toilets. (2) Handwashing: handwashing facilities at key times (after defecation, before eating, before feeding children). (3) Safe water: alongside sister programme Jal Jeevan Mission (functional household tap connections - Har Ghar Jal by 2024). WASH in schools (WinS): toilet + handwashing + safe water at every school. Key to reducing diarrhoea, school attendance (especially girls).' },
  { topic:'environment', q:'Industrial/occupational exposure to asbestos causes:', opts:['Silicosis','Mesothelioma (cancer of pleura/peritoneum) and asbestosis (interstitial lung fibrosis) - latency 20-40 years','Byssinosis','COPD only'], ans:1, expl:'Asbestos-related diseases: (1) Asbestosis: diffuse interstitial pulmonary fibrosis (dyspnoea, restrictive lung disease, basal crepitations). (2) Mesothelioma: malignant cancer of pleura or peritoneum (almost exclusively from asbestos; latency 20-40 years; poor prognosis). (3) Pleural plaques (benign). (4) Lung cancer (synergistic with smoking - 55x risk with smoking + asbestos vs 5x with asbestos alone). Asbestos banned in India 2002 (blue/brown) but white asbestos (chrysotile) still used. WHO: all types carcinogenic.' },
  { topic:'firstaid', q:'Blood glucose below which emergency treatment for hypoglycaemia is needed:', opts:['Below 100 mg/dL','Below 70 mg/dL (symptomatic: below 54 mg/dL usually)','Below 140 mg/dL','Below 200 mg/dL'], ans:1, expl:'Hypoglycaemia: blood glucose <70 mg/dL. Symptomatic usually at <54 mg/dL. Symptoms: trembling, sweating, hunger, palpitations, anxiety (sympathetic - adrenergic), confusion, difficulty speaking, blurred vision, seizures (neuroglycopenic). Treatment: if conscious - 15g fast-acting carbohydrate (4 glucose tablets, 150 mL fruit juice, 15 mL honey), recheck in 15 min (15-15 rule). If unconscious: glucagon IM/SC or dextrose IV (25-50 mL of 50% dextrose).' },
  { topic:'firstaid', q:'The correct depth of chest compressions during adult CPR is:', opts:['1-2 cm','2-3 cm','5-6 cm (at least 5 cm, not more than 6 cm)','8-10 cm'], ans:2, expl:'Adult CPR (AHA/ERC 2020 guidelines): Compression depth: 5-6 cm (at least 2 inches). Rate: 100-120 compressions/minute. Allow full chest recoil after each compression. Ratio: 30 compressions : 2 breaths (30:2). Interruptions: minimise (<10 seconds). Change compressor every 2 minutes (fatigue). Hard surface. Heel of hand, two-handed, straight arms. High-quality CPR is key to survival. Infant: 2 fingers or 2 thumbs. Child: 1-2 hands, 1/3 depth of chest.' },
  { topic:'firstaid', q:'Burns - which type of burn is most painful?', opts:['Full-thickness (3rd degree) - nerve endings destroyed','Superficial partial-thickness (2nd degree superficial) - most painful, nerve endings intact and stimulated','Deep partial-thickness (2nd degree deep) - less painful','Electrical burns'], ans:1, expl:'Burn pain: Superficial partial thickness (2nd degree superficial) = MOST painful. Epidermis and superficial dermis destroyed, nerve endings exposed and stimulated. Blisters (moist). First degree (superficial - sunburn): painful, dry. Deep partial thickness: less painful (deeper nerve damage). Full thickness (3rd degree): PAINLESS (nerve endings destroyed - can only feel deep pressure). Electrical burns: entry/exit wounds, internal damage out of proportion to external appearance.' },
  { topic:'firstaid', q:'Correct management of an avulsed (knocked out) permanent tooth is:', opts:['Discard the tooth - cannot be reimplanted','Rinse tooth gently with water, reimplant into socket immediately (or store in milk/saliva/Hanks balanced solution) and see dentist URGENTLY within 30-60 minutes','Store in water','Rub tooth with antiseptic then reimplant'], ans:1, expl:'Avulsed tooth management: (1) Find tooth. (2) Handle by crown (not root) to protect periodontal ligament cells. (3) If dirty: rinse gently with milk or saline (do NOT scrub root). (4) Reimplant immediately if possible - push firmly back into socket. (5) If cannot reimplant: store in milk (best) or the patient\'s saliva (buccal vestibule) or saline. DO NOT store in water (causes cell death). (6) See dentist URGENTLY within 30-60 minutes. Success rate drops rapidly after 60 minutes.' },
  { topic:'drug', q:'Which drug class is used as first-line for management of hypertension in pregnancy?', opts:['ACE inhibitors','Beta-blockers (labetalol) or calcium channel blockers (nifedipine) or methyldopa','Diuretics (thiazides)','ARBs (losartan)'], ans:1, expl:'Hypertension in pregnancy - SAFE drugs: Methyldopa (most studied, central alpha-2 agonist), Labetalol (beta-blocker, IV for acute), Nifedipine (calcium channel blocker, oral for chronic). UNSAFE/CONTRAINDICATED in pregnancy: ACE inhibitors (captopril, enalapril) and ARBs (losartan) - cause fetal renal agenesis, oligohydramnios, IUGR, neonatal renal failure. Thiazides: can cause neonatal thrombocytopenia. For severe acute hypertension: IV labetalol or hydralazine.' },
  { topic:'drug', q:'Digoxin is used for:', opts:['Hypertension','Heart failure and atrial fibrillation (increases myocardial contractility, slows AV conduction)','Asthma','Diabetes'], ans:1, expl:'Digoxin (cardiac glycoside): (1) Heart failure (HF): positive inotrope - increases intracellular Ca2+ (inhibits Na/K ATPase), improves contractility, increases cardiac output. (2) Atrial fibrillation/flutter: slows AV node conduction (ventricular rate control). Narrow therapeutic window (toxic at 2 ng/mL+). Toxicity: nausea/vomiting, xanthopsia (yellow-green vision), bradycardia, AV block, arrhythmias. Hypokalaemia increases toxicity (K competes for Na/K ATPase binding site).' },
  { topic:'drug', q:'Drugs causing nephrotoxicity (kidney damage) include:', opts:['Paracetamol and penicillin only','Aminoglycosides (gentamicin), NSAIDs, ACE inhibitors (in renal artery stenosis), Contrast dye, Amphotericin B','Antihistamines and antacids','Vitamins and minerals'], ans:1, expl:'Nephrotoxic drugs (common causes of AKI - Acute Kidney Injury): Aminoglycosides (gentamicin, tobramycin - tubular necrosis). NSAIDs (reduce prostaglandin-mediated renal blood flow). ACE inhibitors/ARBs (in bilateral renal artery stenosis - reduce GFR critically). IV Contrast dye (Contrast-Induced Nephropathy - CIN). Amphotericin B (antifungal). Cisplatin (chemotherapy). Cyclosporine/Tacrolimus (immunosuppressants). Monitor renal function during use.' },
  { topic:'drug', q:'The Directly Observed Treatment (DOT) provider in DOTS strategy can be:', opts:['Only government health worker','Health worker (ASHA, ANM, nurse), community volunteer, pharmacist, teacher, or any trusted community member - NOT family members (as they may be too lenient)','Only physician','Only pharmacist'], ans:0, expl:'DOT provider: observes patient swallow anti-TB drugs. Can be: health worker (ASHA, ANM, CHO), community volunteers, pharmacists, teachers, employers - any reliable person outside the patient\'s household. WHY not family members: they may give tablets without watching ingestion (too emotionally invested, less strict). Patient-centred: patient chooses convenient DOT provider and location. Video DOT (VDOT): acceptable substitute during COVID-19.' },
  { topic:'community', q:'Risk communication in public health emergencies should be:', opts:['Delayed until all information is confirmed','Early (before all facts known - fill information vacuum), honest (acknowledge uncertainty), consistent, actionable (what people can do), and through multiple channels - Build trust','Secretive to prevent panic','Only through government press releases'], ans:1, expl:'Risk communication principles (WHO 2017 guidelines): EARLY (early warning prevents misinformation vacuum), TRANSPARENT (acknowledge uncertainty, partial information better than silence), CONSISTENT (coordinated single message across agencies), ACTIONABLE (tell people what to do), CREDIBLE (authoritative, trusted sources), EMPATHETIC (acknowledge fears). Social media monitoring for rumours. Two-way communication (listen to community concerns). COVID-19: risk communication challenges (infodemic).' },
  { topic:'community', q:'The Global Burden of Disease (GBD) study categorises causes of death into:', opts:['Infectious diseases only','Category 1: Communicable/reproductive/nutritional; Category 2: Non-communicable; Category 3: Injuries','Acute and chronic conditions only','Only top 10 causes'], ans:1, expl:'GBD disease categories: Category 1 = Communicable, Maternal, Neonatal, Nutritional Diseases (CMNNDs); Category 2 = Non-Communicable Diseases (NCDs - cardiovascular, cancer, diabetes, COPD, mental disorders); Category 3 = Injuries (unintentional: road traffic, falls, burns, drowning; intentional: violence, self-harm). Global trend: Category 1 decreasing, Category 2 increasing (epidemiological transition). India: dual burden (high Category 1 + rising Category 2).' },
  { topic:'community', q:'Epidemiological transition theory (Omran 1971) describes a shift from:', opts:['Urban to rural diseases','Infectious/communicable diseases (high mortality) to chronic non-communicable diseases as countries develop economically','Acute to chronic diseases only in elderly','Tropical to temperate disease patterns'], ans:1, expl:'Epidemiological Transition (Omran 1971): as countries develop economically, disease patterns shift from: Pestilence and Famine (high infectious disease mortality) → Receding Pandemics (improving sanitation, vaccination) → Degenerative and Man-Made Diseases (NCD dominance: CVD, cancer, diabetes). India: in transition - high burden of both infectious diseases AND NCDs ("double burden"). Nutritional transition: from undernutrition to overnutrition/obesity.' },
  { topic:'stats', q:'Confounding bias in epidemiology occurs when:', opts:['The sample size is too small','A third variable is associated with both the exposure and outcome, distorting the true relationship between them','The study group drops out','The researcher is biased in measuring outcomes'], ans:1, expl:'Confounding: a confounder is a variable associated with BOTH the exposure (risk factor) and the outcome (disease) independently. Example: Coffee drinking associated with lung cancer - but smoking is a confounder (smokers drink more coffee and smoking causes lung cancer). Control methods: randomisation (RCT), restriction, matching, stratification, multivariable analysis (logistic regression). Selection bias: systematic error in who is selected into study. Information bias: systematic error in data collection.' },
  { topic:'stats', q:'Which measure of central tendency is most affected by extreme values (outliers)?', opts:['Mode','Median','Mean (arithmetic average - sum of all values / n)','Range'], ans:2, expl:'Mean: most sensitive to outliers (extreme values distort it significantly). Example: 5 incomes: 10,000 + 10,000 + 12,000 + 15,000 + 1,00,000 - mean distorted by 1,00,000 outlier. Median: not affected by outliers (just the middle value). Mode: not affected. For skewed data: median preferred. For normally distributed data: mean, median, mode all equal. When to report which: normally distributed → mean; skewed → median; categorical → mode.' },
  { topic:'stats', q:'Relative Risk (RR) of 1.0 in a cohort study means:', opts:['The exposure doubles the risk of disease','The exposed group has twice the risk of the unexposed','No association between exposure and disease (equal risk in exposed and unexposed)','Exposure is protective'], ans:2, expl:'Relative Risk (RR) = Incidence in exposed / Incidence in unexposed. RR = 1.0: no association (equal risk). RR > 1.0: exposure is a risk factor (increases disease risk). RR < 1.0: exposure is protective (e.g., vaccination). Example: RR = 2.0 means exposed group has TWICE the risk. RR = 0.5 means 50% reduction in risk (vaccine efficacy). Used in cohort studies and RCTs. Odds Ratio (OR) approximates RR when disease is rare (<10% prevalence).' },
  { topic:'anatomy', q:'The organ responsible for the detoxification of most drugs is:', opts:['Kidneys','Liver (hepatic metabolism via cytochrome P450 enzymes - Phase I: oxidation/reduction/hydrolysis; Phase II: conjugation)','Spleen','Lungs'], ans:1, expl:'Liver: primary site of drug metabolism. Phase I reactions: CYP450 enzymes (CYP3A4 most common - 50% of drugs) - oxidation, reduction, hydrolysis (introduce reactive groups). Phase II reactions: conjugation (glucuronidation, sulfation, acetylation) - make metabolite more water-soluble for excretion. First-pass effect (hepatic first-pass metabolism): oral drugs absorbed from gut pass through portal system → liver metabolises before reaching systemic circulation. Liver disease: alter drug dosing.' },
  { topic:'anatomy', q:'The human immunodeficiency virus (HIV) primarily attacks which cells?', opts:['Neutrophils','CD4+ T lymphocytes (helper T cells) - CD4 count reflects immune status','Red blood cells','Platelets'], ans:1, expl:'HIV target: CD4+ T lymphocytes (T-helper cells). HIV gp120 binds CD4 receptor + co-receptor (CCR5 or CXCR4) → enters cell → reverse transcriptase converts RNA to DNA → integrase inserts into host genome (provirus) → new viral particles produced. CD4 count: indicator of immune status. Normal: 500-1200 cells/mm3. AIDS: CD4 <200 cells/mm3 OR AIDS-defining illness. Opportunistic infections (OI) below certain CD4 thresholds: PCP <200, CMV <50, MAC <50.' },
  { topic:'anatomy', q:'The Rh (Rhesus) blood group system - Rh positive means:', opts:['ABO blood type A','Presence of D antigen on red blood cell surface','Having Rh antibodies in serum','Being immune to Rh disease'], ans:1, expl:'Rh blood group: determined by presence/absence of D antigen (Rh factor) on RBC surface. Rh positive (Rh+): D antigen present (~85% of Indians). Rh negative (Rh-): D antigen absent (~15%). Other Rh antigens: C, c, E, e. Rh incompatibility (Rh-negative mother, Rh-positive baby): maternal sensitisation → anti-D IgG antibodies → cross placenta in next Rh+ pregnancy → HDN (Haemolytic Disease of Newborn). Prevention: Anti-D immunoglobulin (Rhogam) within 72 hours.' },
  { topic:'community', q:'MCH (Mother and Child Health) services are delivered through:', opts:['Only hospitals','Continuum of care at various levels: ASHA (community) → ANM/Sub-centre (village) → PHC → CHC → District Hospital → Medical College (referral chain)','Only private sector','Online telemedicine only'], ans:1, expl:'MCH continuum of care framework: community level (ASHA - HBNC, HBYC, ANC registration, JSY), sub-centre/HWC (ANM - ANC, immunisation, delivery if trained), PHC (MO - delivery, ANC, sick child), CHC (specialist - C-section, SNCU), District Hospital (FRU - comprehensive emergency obstetric care, blood bank, NICU), Medical College (tertiary care). Referral system: each level refers to next when beyond capacity. Free transport: 102/108.' },
  { topic:'community', q:'First Referral Unit (FRU) is a facility capable of providing:', opts:['Only ANC services','24/7 Comprehensive Emergency Obstetric Care (CEmOC): C-section, blood transfusion, newborn care - at CHC level or District Hospital','Only normal delivery','Only outpatient services'], ans:1, expl:'FRU (First Referral Unit): facility providing Comprehensive Emergency Obstetric Care (CEmOC) on 24/7 basis. Services: C-section, operative vaginal delivery, manual removal of placenta, management of obstetric complications (eclampsia, PPH, sepsis), blood transfusion, newborn resuscitation and care. Designated at CHC or District Hospital level. Operationalisation: requires obstetrician, anaesthetist, paediatrician, blood storage, OT. LSAS (Life-Saving Anaesthesia Skills): trains MOs for anaesthesia.' },
  { topic:'community', q:'Under NHM, which document serves as a comprehensive record for a pregnant woman?', opts:['Referral slip','Mother and Child Protection (MCP) Card - records ANC visits, immunisation, delivery, postnatal care, child health and immunisation up to 2 years','Death certificate','HMIS report'], ans:1, expl:'Mother and Child Protection (MCP) Card: comprehensive health record for pregnant woman and child. Contains: ANC details (BP, weight, Hb, USG, TT doses), delivery information, postnatal check-ups, newborn details (APGAR, birth weight, initial health status), child immunisation record (up to 2 years), growth chart, key messages/counselling points. Given at first ANC registration. Risk sticker colour-coded: Green/Yellow/Red (SUMAN). PMMVY instalment tracking.' },
  { topic:'programs', q:'WHO HEARTS technical package for cardiovascular disease prevention covers:', opts:['Surgical interventions only','Healthy lifestyle counselling, Evidence-based protocols, Access to essential medicines, Risk-based management, Team-based care, Systems for monitoring (HEARTS)','Cardiac surgery only','Emergency cardiac care only'], ans:1, expl:'WHO HEARTS (2016): 6 modules for CVD prevention in primary healthcare: H - Healthy lifestyle counselling; E - Evidence-based protocols; A - Access to essential medicines and technology; R - Risk-based management; T - Team-based care (multidisciplinary); S - Systems for monitoring (HMIS integration, quality indicators). Adapted as India HEARTS (NPCDCS): for NCDs in HWCs. 30+ mg/dL cholesterol: statin. BP 140/90+: antihypertensive.' },
  { topic:'programs', q:'Social Health Insurance in India - which state was the first to implement it?', opts:['Kerala (Karuna Health Scheme)','Andhra Pradesh (Aarogyasri, 2007 - launched before PM-JAY)','Rajasthan (Bhamashah)','Gujarat (Mukhyamantri Amrutum)'], ans:1, expl:'Andhra Pradesh launched Aarogyasri (2007, CM YS Rajasekhara Reddy): cashless treatment for BPL families for tertiary conditions at empanelled hospitals. First major state health insurance scheme in India. Became model for PM-JAY. Other state schemes: RSBY (Rashtriya Swasthya Bima Yojana, 2008 - central for BPL families). Tamil Nadu (Chief Minister\'s Comprehensive Health Insurance Scheme). PM-JAY (2018): national scheme, subsumed RSBY. J&K: PM-JAY + J&K Sehat card.' },
  { topic:'nursing', q:'The purpose of a risk assessment tool like the "Braden Scale" is to:', opts:['Measure pain levels','Identify patients at risk of developing pressure ulcers (6 subscales: sensory perception, moisture, activity, mobility, nutrition, friction/shear - score range 6-23, lower = higher risk)','Assess fall risk','Measure cognitive function'], ans:1, expl:'Braden Scale: most widely used pressure ulcer risk assessment tool. 6 subscales: (1) Sensory Perception (1-4), (2) Moisture (1-4), (3) Activity (1-4), (4) Mobility (1-4), (5) Nutrition (1-4), (6) Friction and Shear (1-3). Total score: 6-23. Scores: At risk <18; Moderate risk 13-14; High risk 10-12; Very high risk <9. Used on admission and regularly thereafter. Guides prevention: turning frequency, support surface selection, skin care, nutrition.' },
  { topic:'nursing', q:'Assessment of pain in non-verbal patients or infants uses:', opts:['VAS (Visual Analogue Scale)','Numeric Rating Scale (NRS 0-10)','FLACC scale (Face, Legs, Activity, Cry, Consolability) or CRIES for neonates','McGill Pain Questionnaire'], ans:2, expl:'Pain assessment in non-verbal patients/infants: FLACC Scale (Face: 0-2, Legs: 0-2, Activity: 0-2, Cry: 0-2, Consolability: 0-2) = total 0-10. Used for children 2 months-7 years and adults with cognitive impairment. CRIES: Crying, Requires O2, Increased vital signs, Expression, Sleeplessness - for neonates 0-6 months post-operative. NIPS (Neonatal Infant Pain Scale): for preterm/term infants. Numeric Rating Scale (NRS 0-10): for verbal patients. Pain is "fifth vital sign."' },
  { topic:'nursing', q:'Therapeutic communication techniques include:', opts:['Giving advice immediately','Using medical jargon to seem professional','Active listening, reflection, open-ended questions, clarification, silence, empathy, summarising','Changing the subject when patient becomes emotional'], ans:2, expl:'Therapeutic communication (nurse-patient relationship): Active listening (attend fully), Open-ended questions ("Tell me about...", "How do you feel?"), Reflection (mirror feelings back), Clarification ("What do you mean by...?"), Validation/empathy ("That sounds really difficult"), Silence (allows patient to gather thoughts), Summarising (confirm understanding). NON-therapeutic: giving advice, false reassurance ("You\'ll be fine"), minimising ("Others have it worse"), changing subject, using jargon.' },
  { topic:'nursing', q:'The Nursing Diagnosis (NANDA) format is:', opts:['Medical diagnosis + lab results','Problem (Human Response) Related To (Etiology/Contributing Factors) As Evidenced By (Signs and Symptoms/Defining Characteristics)','Only the disease name','A list of medications needed'], ans:1, expl:'NANDA Nursing Diagnosis format (3-part PES): Problem (P - altered human response, e.g., "Ineffective Airway Clearance"), Related To (R/T - etiology, e.g., "related to excessive secretions"), As Evidenced By (AEB - defining characteristics/signs, e.g., "as evidenced by productive cough, abnormal breath sounds, SpO2 88%"). Different from medical diagnosis (identifies pathology). Risk diagnoses: Problem + R/T only (no AEB - hasn\'t happened yet). Wellness diagnoses: positive state to maintain.' },
  { topic:'nursing', q:'Which position is used post-thyroidectomy to reduce oedema and tension on suture line?', opts:['Supine flat','Prone','Semi-Fowler\'s to high Fowler\'s (30-45 degrees head elevation)','Trendelenburg'], ans:2, expl:'Post-thyroidectomy position: Semi-Fowler\'s (30-45 degrees) or high Fowler\'s. Rationale: (1) Reduces venous pressure and oedema at surgical site. (2) Reduces tension on suture line. (3) Facilitates breathing (reduces pressure on trachea). Post-thyroidectomy monitoring: airway patency (haematoma can compress trachea - emergency), calcium levels (hypocalcaemia from parathyroid damage - Chvostek sign, Trousseau sign), voice changes (recurrent laryngeal nerve damage), wound drainage.' },
  { topic:'anatomy', q:'Which structure controls the body\'s "biological clock" (circadian rhythm)?', opts:['Hippocampus','Suprachiasmatic nucleus (SCN) of the hypothalamus','Pineal gland alone','Cerebral cortex'], ans:1, expl:'Suprachiasmatic Nucleus (SCN): located in anterior hypothalamus, above optic chiasm. Acts as master circadian clock (24-hour rhythm). Light input: via retinohypothalamic tract from retinal ganglion cells. Controls: sleep-wake cycles, hormone release (cortisol peaks morning, melatonin peaks at night - via pineal gland), body temperature, metabolism. Jet lag: SCN desynchronised with local time. Shift work: disrupted circadian rhythm → metabolic syndrome, depression, cancer risk.' },
  { topic:'anatomy', q:'The function of the gallbladder is to:', opts:['Produce bile','Concentrate and store bile (produced by liver) until needed for fat digestion in duodenum','Absorb nutrients','Produce digestive enzymes'], ans:1, expl:'Gallbladder: small pear-shaped organ under liver. Function: concentrate (10-fold) and store bile (produced by hepatocytes). Cholecystokinin (CCK) - released by duodenal I-cells in response to fat → contracts gallbladder → releases bile into duodenum via cystic duct → common bile duct → ampulla of Vater. Bile: emulsifies fats, aids digestion and absorption of fat-soluble vitamins (A, D, E, K). Cholelithiasis (gallstones): cholesterol or pigment stones. Cholecystitis: inflammation.' },
  { topic:'anatomy', q:'The normal intraocular pressure (IOP) range is 10-21 mmHg. Glaucoma causes visual loss by:', opts:['Cataract formation','Progressive damage to the optic nerve (due to elevated IOP in most cases) → irreversible peripheral vision loss (tunnel vision)','Macular degeneration','Retinal detachment'], ans:1, expl:'Glaucoma: group of conditions causing optic nerve damage (cupping of optic disc) leading to irreversible visual field loss starting peripherally (tunnel vision - as if looking through a tunnel). Risk factors: elevated IOP (>21 mmHg), family history, age, race (African descent). Types: Primary Open-Angle Glaucoma (POAG - most common, asymptomatic, bilateral); Acute Angle-Closure Glaucoma (sudden painful red eye, headache, halos, nausea - ophthalmic emergency). Treatment: eye drops (latanoprost, timolol), laser, surgery.' },
  { topic:'programs', q:'The NIPUN Bharat Mission (2021) aims to ensure foundational literacy and numeracy by:', opts:['Secondary school (Class 10)','End of Grade 3 (by 2026-27) - children can read, understand, and do basic arithmetic by 8-9 years','Pre-school age (2-3 years)','College education'], ans:1, expl:'NIPUN Bharat (National Initiative for Proficiency in Reading with Understanding and Numeracy): launched July 2021 under NEP 2020. Target: all children achieve basic literacy (read a text of Class 2 level with comprehension) and numeracy (basic arithmetic) by Grade 3 (by age 8-9) by 2026-27. Addresses "learning poverty" (children who cannot read). Foundational Stage: ECCE (3-6 years) + Grades 1-2. Implemented through NIPUN Lakhshya, FLN Mission. Close link with health: school readiness depends on nutrition, health.' },
  { topic:'programs', q:'Pradhan Mantri Kaushal Vikas Yojana (PMKVY) is related to:', opts:['Health insurance','Skill development and vocational training for youth (health sector: CHO training, home health aide training)','Agricultural subsidies','Housing schemes'], ans:1, expl:'PMKVY: Skill India flagship scheme - provides free short-term skill training and recognition of prior learning to youth. Healthcare sector skills: Healthcare Sector Skill Council (HSSC) - courses: General Duty Assistant (GDA), Home Health Aide (HHA), Emergency Medical Technician (EMT), Phlebotomist, Medical Lab Technician. CHO (Community Health Officer) training: 6-month certificate course at Community Health Officer Education Centres (CHOEC). Funded by MSDE (Ministry of Skill Development and Entrepreneurship).' },
  { topic:'community', q:'The "Pradhan Mantri Gram Sadak Yojana" (PMGSY) has a health impact because:', opts:['It is a health scheme itself','Road connectivity to villages reduces the 2nd delay (reaching facility) in maternal mortality - roads enable ambulance access and institutional delivery','It provides health workers for villages','It builds health centres'], ans:1, expl:'PMGSY (rural road connectivity): indirect but significant health impact. Reduces the "second delay" (Phase 2 of 3-delays model) in reaching health facilities, especially for obstetric emergencies. Studies show: villages with better road access have lower MMR, higher institutional delivery rates, lower IMR. Roads also improve cold chain for vaccines (transport), reduce time for ambulance services (102/108). Convergence: PMGSY + NHM + 102 Ambulance + JSY.' },
  { topic:'nursing', q:'Which nursing intervention is most important immediately after a patient returns from surgery (post-anaesthesia)?', opts:['Administer pain medication immediately','Airway assessment and maintenance + monitoring vital signs (consciousness, breathing, circulation) - PACU/recovery room monitoring','Give oral fluids','Encourage ambulation'], ans:1, expl:'Immediate post-operative care (PACU - Post-Anaesthesia Care Unit): (1) AIRWAY: ensure patent airway (position, suction if needed, jaw-thrust if still sedated). (2) Breathing: respiratory rate, SpO2, breath sounds. (3) Circulation: pulse, BP, bleeding from wound/drain. (4) Level of consciousness: Aldrete score (activity, respiration, circulation, consciousness, colour - score of 9-10 = ready for discharge from PACU). (5) Pain assessment. (6) Temperature (hypothermia common post-op). Keep nil by mouth until gag reflex returns.' },
  { topic:'nursing', q:'The therapeutic nurse-patient relationship has how many phases?', opts:['2 phases','3 phases (Pre-interaction/Orientation, Working, Termination)','4 phases','5 phases'], ans:1, expl:'Therapeutic Nurse-Patient Relationship phases (Hildegard Peplau\'s model - 1952): (1) Pre-interaction phase: before first meeting - review records, self-awareness (nurse examines own biases). (2) Orientation phase (Introduction): establish trust, rapport, contract (purpose, goals, confidentiality, boundaries), assess patient needs. (3) Working phase: patient works on identified problems, nurse provides therapeutic interventions, patient achieves goals. (4) Termination phase: end of therapeutic relationship, review goals, plan follow-up, prevent dependency. Prepare from beginning of relationship.' },
  { topic:'community', q:'The "baby-friendly hospital initiative" (BFHI) requires hospitals to follow:', opts:['10 steps to successful breastfeeding (WHO/UNICEF) + International Code on Marketing of Breast Milk Substitutes','5 steps to successful breastfeeding','Only provide lactation rooms','Only give vitamin K to newborns'], ans:0, expl:'BFHI: WHO/UNICEF initiative to support breastfeeding. Ten Steps to Successful Breastfeeding: Written breastfeeding policy; Train all healthcare staff; Inform pregnant women about benefits; Skin-to-skin contact + breastfeeding within 1 hour of birth; Show mothers how to breastfeed; No food/drink other than breast milk (unless medically indicated); Rooming-in (24 hours); Demand feeding; No pacifiers; Foster breastfeeding support groups. International Code on Marketing of Breast Milk Substitutes (WHO, 1981): bans marketing of infant formula to pregnant women and mothers.' },
  { topic:'community', q:'Social marketing in health refers to:', opts:['Selling health products for profit','Applying commercial marketing principles to promote health behaviour changes in the public (e.g., ORS promotion, condom social marketing)','Advertising healthcare facilities','Online health information'], ans:1, expl:'Social marketing: uses commercial marketing principles (4 Ps: Product, Price, Place, Promotion) for social good (voluntary behaviour change for public benefit). Health social marketing examples: condom social marketing (HIV/STI prevention - subsidised, branded), ORS social marketing, handwashing with soap campaigns, tobacco cessation, breast cancer screening promotion. Different from commercial marketing (profit motive). Philip Kotler: pioneer. India: HRIDAY-SHAN social marketing for tobacco.' },
  { topic:'community', q:'Health belief model (HBM) proposes that people take health action based on:', opts:['Only financial incentives','Perceived susceptibility to disease + Perceived severity + Perceived benefits of action - Perceived barriers + Cue to action + Self-efficacy','Social pressure only','Government mandates only'], ans:1, expl:'Health Belief Model (Rosenstock 1966, expanded by Becker): predicts health behaviour. Components: (1) Perceived Susceptibility ("Am I at risk?"), (2) Perceived Severity ("How serious is it?"), (3) Perceived Benefits ("Will the action help?"), (4) Perceived Barriers ("What are the obstacles?"), (5) Cue to action (trigger: media, symptoms, advice), (6) Self-efficacy (Bandura addition - "Can I do it?"). Used to design health education programmes. If barriers > benefits → no action. Reduce barriers, increase benefits.' },
  { topic:'fp', q:'Male condom - effectiveness (typical use) against pregnancy is approximately:', opts:['99.9%','85% (typical use) - 98% with perfect use','50%','70%'], ans:1, expl:'Male condom effectiveness: Typical use (real-world, occasional incorrect/inconsistent use): ~85% (15% pregnancy rate per year). Perfect use (correct every time): ~98%. Main reasons for failure: not using consistently, incorrect use (not leaving space at tip, not using throughout intercourse, wrong size, oil-based lubricants with latex, expired). Additional benefit: protects against STIs including HIV (dual protection). Female condom: 79% typical use, 95% perfect. Combined with another method: highly effective.' },
  { topic:'fp', q:'The sub-dermal implant (Implanon/Nexplanon) for contraception contains:', opts:['Both oestrogen and progestogen','Etonogestrel (single progestogen rod) inserted subdermally in upper inner arm - effective 3 years','Copper','Levonorgestrel only as daily tablet'], ans:1, expl:'Subdermal implant (Implanon NXT/Nexplanon): single rod (4 cm x 2 mm) containing etonogestrel (68 mg progestogen). Inserted subdermally in upper inner arm (non-dominant) under local anaesthesia. Duration: 3 years. Highly effective: <1% failure rate. Mechanism: inhibits ovulation + thickens cervical mucus. Side effects: irregular bleeding (most common - 20% amenorrhoea, 40% infrequent bleeding). Quick return of fertility after removal. Not available in govt. sector India routinely.' },
  { topic:'community', q:'Under India\'s Ayushman Bharat Digital Mission (ABDM), which unique identifier is given to each citizen?', opts:['Aadhaar number only','Ayushman Bharat Health Account (ABHA) number - 14-digit unique health ID','PAN card number','Voter ID number'], ans:1, expl:'ABDM (Ayushman Bharat Digital Mission, formerly NHA/NDHM): ABHA (Ayushman Bharat Health Account) ID - 14-digit unique Health ID linked to health records. Created: via ABDM app using Aadhaar/mobile. Enables: linked health records (lab reports, prescriptions, discharge summaries) accessible to patient and authorised healthcare providers. DigiDoctor: doctor registry. Health Facility Registry (HFR): facility database. ABDM consent manager: patient controls health data sharing. India Health Stack.' },
  { topic:'community', q:'The Pradhan Mantri Ujjwala Yojana (PMUY) provides:', opts:['Free food grains','Free LPG (Liquefied Petroleum Gas) connections to BPL women - reducing indoor air pollution and drudgery','Free electricity','Free drinking water'], ans:1, expl:'PMUY (2016): free LPG connection (deposit-free) to adult women from BPL households. Aim: provide clean cooking fuel, reduce indoor air pollution (HAP) from solid fuel burning (biomass, wood, cow dung). Health benefits: reduced respiratory disease, reduced acute lower respiratory infections in children, reduced maternal mortality (improved birth outcomes), reduced kerosene fire hazard. Phase 2 (2021): Ujjwala 2.0, expanded to migrants. Target: 9.5 crore connections.' },
  { topic:'programs', q:'National Deworming Day (NDD) is observed on:', opts:['2 October and 2 April','10 February and 10 August every year (biannual)','15 August and 26 January','1 January and 1 July'], ans:1, expl:'National Deworming Day (NDD): 10 February and 10 August (biannual). All children 1-19 years given Albendazole (400 mg for children 2+ years; 200 mg for 1-2 years, crushed). Given in government schools, anganwadi centres, private schools. Mop-up day: 2 weeks later for children who missed. Objective: reduce STH (Soil-Transmitted Helminths - Ascaris, Trichuris, hookworm) burden. Benefits: reduces anaemia, improves nutrition, cognitive function, school attendance.' },
  { topic:'programs', q:'Pradhan Mantri TB Mukt Bharat Abhiyan (2022) target is to eliminate TB from India by:', opts:['2025','2030 (SDG target)','2035','2050'], ans:0, expl:'India\'s National Strategic Plan for TB Elimination: target to ELIMINATE TB (incidence <1 per lakh population) by 2025 - 5 years ahead of global SDG target of 2030. Current TB burden: India has highest TB burden (28% of global cases). Strategies: Universal Drug Susceptibility Testing (UDST), NIKSHAY POSHAN nutritional support, digital DOTS, private sector engagement, DPCM (District Programme Coordination and Monitoring), Ni-kshay Mitra (corporate support). Pradhan Mantri TB Mukt Bharat Abhiyan: celebrity adopters to support TB patients.' },
  { topic:'nursing', q:'Which parameter is assessed using the "AVPU" scale in rapid trauma assessment?', opts:['Pain level','Level of consciousness (Alert, responds to Voice, responds to Pain, Unresponsive)','Blood pressure','Respiratory effort'], ans:1, expl:'AVPU Scale (rapid consciousness assessment): A = Alert (fully conscious, responds spontaneously); V = responds to Voice (needs calling to rouse); P = responds to Pain only (sternal rub, nail bed pressure); U = Unresponsive (no response to any stimulus). Used in primary survey (ABCDE - Airway, Breathing, Circulation, Disability/Neurological, Exposure). AVPU P or U → GCS typically <9 (consider airway protection). AVPU quicker than GCS for rapid assessment.' },
  { topic:'nursing', q:'In perioperative nursing, "time out" (surgical safety checklist) is performed:', opts:['At the end of surgery','Before skin incision - team confirms: correct patient, correct procedure, correct site, allergies, antibiotic prophylaxis, blood products availability','At anaesthesia induction','During instrument count only'], ans:1, expl:'WHO Surgical Safety Checklist (SSC): 3 phases. Sign In (before anaesthesia induction): confirm patient identity, procedure, site marking, allergies, anaesthesia safety check, pulse oximetry working. TIME OUT (before skin incision): ALL team members confirm verbally - patient identity, procedure, site, anticipated critical events, antibiotic prophylaxis, imaging. Sign Out (before patient leaves OR): instrument count, specimen labelling, key concerns for recovery. Reduces surgical complications by 30-50%.' },
  { topic:'community', q:'The "One Stop Centre" (Sakhi) under Nirbhaya Fund provides services to:', opts:['Pregnant women only','Women affected by violence (domestic, sexual, acid attack) - police, medical, legal, psychological, shelter under one roof','Elderly citizens','Malnourished children'], ans:1, expl:'Sakhi One Stop Centre (OSC): established under Nirbhaya Fund. Provides integrated support services to women affected by violence (domestic violence, sexual assault, honour crimes, acid attack): (1) Medical assistance (emergency/long-term), (2) Police assistance (filing FIR - CCTV recordings), (3) Legal aid, (4) Psychological counselling, (5) Temporary shelter (up to 5 days). Women helpline: 181 (toll-free). ASHA/ANM: refer violence survivors to OSC. 728 OSCs established across India (2022).' },
  { topic:'community', q:'The concept of "Primary Health Care" was defined at the Alma Ata Declaration in:', opts:['1948 (WHO Constitution)','1978 (Alma Ata, Soviet Kazakhstan - "Health for All by 2000", PHC as key strategy)','1986 (Ottawa Charter)','2000 (MDGs)'], ans:1, expl:'Alma Ata Declaration (1978): International Conference on PHC, Alma-Ata, Soviet Kazakhstan. Declared: "Health for All by the year 2000" (HFA 2000). Defined Primary Health Care: essential healthcare based on practical, scientifically sound, socially acceptable methods. PHC components (at least 8): Health education, Nutrition, Water/sanitation, MCH/FP, Immunisation, Endemic disease control, Essential drugs, Treatment of common diseases. Selective PHC (UNICEF critique): focused on GOBI (Growth monitoring, ORS, Breastfeeding, Immunisation).' },

  /* ═══ BATCH G — FINAL 175 QUESTIONS ═══ */
  { topic:'anatomy', q:'The hormone that stimulates the thyroid gland is secreted by:', opts:['Hypothalamus','Anterior pituitary (TSH - Thyroid Stimulating Hormone)','Posterior pituitary','Adrenal gland'], ans:1, expl:'Hypothalamic-Pituitary-Thyroid Axis: Hypothalamus secretes TRH (Thyrotropin-Releasing Hormone) → Anterior pituitary secretes TSH (Thyroid Stimulating Hormone) → Thyroid gland secretes T3/T4. Negative feedback: T3/T4 suppress TRH and TSH. Hypothyroidism: TSH high (primary), T3/T4 low. Hyperthyroidism: TSH low (suppressed), T3/T4 high. Subclinical hypothyroidism: TSH high, T3/T4 normal. TSH most sensitive test for thyroid function.' },
  { topic:'anatomy', q:'The jugular vein is used clinically to assess:', opts:['Arterial blood pressure','Central venous pressure (CVP) - elevated in right heart failure, cardiac tamponade, SVC obstruction','Blood oxygenation','Kidney function'], ans:1, expl:'Internal Jugular Vein (IJV): reflects right atrial pressure (CVP). Jugular Venous Pressure (JVP): assessed visually at 45 degrees - height of venous pulsation above sternal angle (+ 5 cm = CVP). Elevated JVP (>3 cm above sternal angle): right heart failure (cor pulmonale), cardiac tamponade, SVC obstruction, tricuspid regurgitation, fluid overload. JVP pulsations: a-wave (atrial contraction), x-descent, v-wave (venous filling), y-descent. Cannot be compressed (vs carotid: can be compressed).' },
  { topic:'anatomy', q:'Which part of the ear is responsible for equilibrium (balance)?', opts:['Cochlea','Semicircular canals and otolith organs (utricle and saccule) of the inner ear (vestibular apparatus)','Tympanic membrane','Ossicles (malleus, incus, stapes)'], ans:1, expl:'Vestibular apparatus (inner ear): Semicircular canals (3 canals: anterior, posterior, lateral - detect rotational acceleration). Otolith organs: Utricle (horizontal acceleration, gravity) and Saccule (vertical acceleration). Hair cells: mechanoreceptors. Vestibular nerve (CN VIII - vestibulocochlear): carries signals to cerebellum and brainstem. Cochlea: hearing. Benign Paroxysmal Positional Vertigo (BPPV): most common vestibular disorder (displaced otoliths).' },
  { topic:'anatomy', q:'The normal serum creatinine level in adults is:', opts:['0.1-0.4 mg/dL','0.6-1.2 mg/dL (males); 0.5-1.1 mg/dL (females)','2.0-3.0 mg/dL','5.0-8.0 mg/dL'], ans:1, expl:'Normal serum creatinine: Males 0.6-1.2 mg/dL; Females 0.5-1.1 mg/dL (lower in females - less muscle mass). Creatinine: waste product of creatine phosphate metabolism in muscle (filtered by kidney, not reabsorbed - therefore good marker of GFR). Rises with renal failure. Acute Kidney Injury (AKI): rise >0.3 mg/dL in 48 hours OR >1.5x baseline in 7 days OR urine output <0.5 mL/kg/hr for 6 hours. Creatinine clearance: estimates GFR (normal 90-120 mL/min/1.73 m2).' },
  { topic:'mch', q:'Episiotomy repair layers from inside out are:', opts:['Skin only','Vaginal mucosa, fascial layers/perineal muscles, and perineal skin - repaired in layers','Muscle only','Skin and mucosa only'], ans:1, expl:'Episiotomy repair: absorbable sutures (Vicryl/catgut). Layer-by-layer repair: (1) Vaginal mucosa (start above apex of incision into vaginal wall). (2) Perineal muscles (deep fascia and muscle layer - interrupted sutures). (3) Perineal skin (subcuticular or interrupted). Important: haemostasis, identify apex, no tension, avoid rectal wall suturing. Complications: haematoma, infection, dehiscence, dyspareunia, fistula. Paracervical/pudendal block: local anaesthesia.' },
  { topic:'mch', q:'Low birth weight (LBW) babies are at higher risk of:', opts:['Only obesity in adulthood','Hypothermia (large surface area to body mass ratio), hypoglycaemia, infections, feeding difficulties, respiratory distress, and NCDs in adult life (Barker hypothesis)','Only respiratory infections','Only jaundice'], ans:1, expl:'LBW (<2500 g) complications: Immediate - Hypothermia (poor thermoregulation, large surface:mass ratio), Hypoglycaemia (low glycogen stores), Feeding difficulties, Respiratory Distress Syndrome (preterm - surfactant deficiency), Sepsis (immature immunity), Jaundice, Apnoea. Long-term: Barker hypothesis (DOHaD - Developmental Origins of Health and Disease): LBW babies at higher risk of hypertension, diabetes, CVD, metabolic syndrome in adult life (programming in utero).' },
  { topic:'mch', q:'Duration of exclusive breastfeeding recommended by the National Guidelines on Infant and Young Child Feeding (NGL-IYCF) is:', opts:['3 months','4 months','6 months (align with WHO recommendation)','12 months'], ans:2, expl:'India NGL-IYCF (2004, revised 2017): Exclusive breastfeeding for 6 months. Initiation: within 1 hour of birth (early initiation). Continue breastfeeding: up to 2 years and beyond. Complementary feeding: start at 6 months (400-500 kcal/day at 6-9 months from complementary foods, increasing with age). MAD (Minimum Acceptable Diet): breastfed children achieving minimum dietary diversity + minimum meal frequency. IYCF counselling: key role of ANM, ASHA, AWW.' },
  { topic:'mch', q:'The most common cause of maternal death globally is:', opts:['Anaemia','Postpartum Haemorrhage (PPH) - 27% of all maternal deaths globally (WHO)','Infection (sepsis)','Hypertensive disorders'], ans:1, expl:'Global maternal mortality causes (WHO): PPH 27%, Hypertensive disorders 14%, Sepsis 11%, Unsafe abortion 8%, Embolism 3%, Other direct causes 9%, Indirect causes 28%. In India: PPH is also leading cause (top 3: PPH, hypertensive disorders, sepsis). Active Management of Third Stage of Labour (AMTSL): most effective PPH prevention (oxytocin 10 IU IM + uterine massage + early cord clamping). Misoprostol: community-level PPH prevention by ASHA.' },
  { topic:'mch', q:'Pelvic floor exercises (Kegel exercises) are recommended for:', opts:['Building abdominal muscles','Strengthening pelvic floor muscles - preventing/treating urinary stress incontinence, supporting uterus/bladder/rectum','Reducing back pain','Cardiovascular fitness'], ans:1, expl:'Kegel exercises (pelvic floor exercises): contract pelvic floor muscles (as if stopping urination) for 3-5 seconds, relax, repeat 10-15 times, 3 sets daily. Benefits: prevent urinary stress incontinence (common post-partum and in elderly women), treat mild-moderate stress incontinence, support pelvic organs (prevent pelvic organ prolapse), improve sexual function. Recommended: during and after pregnancy, perimenopause. Physiotherapist: can assess and guide proper technique.' },
  { topic:'nutrition', q:'Therapeutic Zinc supplementation in childhood diarrhoea is given for:', opts:['1 day','5 days','10-14 days (20 mg/day for children over 6 months; 10 mg/day for under 6 months)','30 days'], ans:2, expl:'WHO/UNICEF recommendation for zinc in diarrhoea: 20 mg/day for children over 6 months; 10 mg/day for under 6 months. Duration: 10-14 days (reduces duration of diarrhoea and prevents recurrence for 2-3 months). Mechanism: zinc improves gut immune function, intestinal mucosa integrity, promotes recovery. Alongside ORS (not as substitute). Reduces diarrhoea duration by 25% and severity by 30%. Also reduces subsequent episodes for 2-3 months.' },
  { topic:'nutrition', q:'Complementary feeding should be started at:', opts:['3 months','4 months','6 months (when solid food introduced alongside breast milk)','12 months'], ans:2, expl:'Complementary feeding: introduce at exactly 6 months (not before - gut not mature for solids). Start: mashed/pureed family foods (rice, dal, vegetables). Frequency: 2-3 meals/day at 6-8 months; 3-4 meals at 9-12 months; 3-4 meals + 1-2 snacks at 12-24 months. Energy density: must be high (calorie-dense). Avoid: salt, sugar, honey (botulism risk <1 year), whole nuts (choking), low-iron foods only. Continue breastfeeding alongside. IYCF counselling by ASHA/AWW at VHND.' },
  { topic:'nutrition', q:'Therapeutic diet in acute renal failure (AKI) restricts:', opts:['Carbohydrates','Protein (0.6-0.8 g/kg/day), potassium, sodium, phosphate (to reduce uraemia and metabolic complications)','Vitamin C','Fat only'], ans:1, expl:'AKI diet: Protein restriction (0.6-0.8 g/kg/day in non-dialysed; 1.2-1.5 g/kg/day if on dialysis - loss through dialysis). Potassium restriction (<2 g/day if hyperkalaemia - avoid bananas, oranges, potatoes, tomatoes). Sodium restriction (reduce oedema, hypertension). Phosphate restriction (prevent hyperphosphataemia - avoid dairy, cola). Fluid restriction (=urine output + 500 mL insensible losses). High calorie from carbohydrates and fats (prevent catabolism). Nephrologist + dietitian: plan diet.' },
  { topic:'nutrition', q:'Essential fatty acids (EFAs) that cannot be synthesised by the body include:', opts:['Saturated fatty acids (palmitic, stearic)','Linoleic acid (omega-6) and Alpha-linolenic acid (omega-3) - must come from diet','Oleic acid (omega-9)','Myristic acid'], ans:1, expl:'Essential Fatty Acids (EFAs): cannot be synthesised by humans (lack desaturase enzymes). Linoleic acid (LA, omega-6): found in vegetable oils (sunflower, safflower, corn). Alpha-Linolenic acid (ALA, omega-3): found in flaxseeds, walnuts, canola oil, chia seeds. Derivatives: LA → Arachidonic acid (AA). ALA → EPA and DHA (fish oils). Functions: cell membrane structure, prostaglandins, eicosanoids, brain development (DHA critical for fetal brain). Deficiency: dermatitis, poor growth, impaired immune function.' },
  { topic:'community', q:'The Global WASH (Water, Sanitation, Hygiene) situation - what percentage of world population lacked safely managed drinking water services in 2020?', opts:['Less than 5%','About 26% (2 billion people)','About 50%','About 75%'], ans:1, expl:'WHO/UNICEF JMP 2021: 2.3 billion people (26%) lack safely managed drinking water. 771 million lack at least basic water (surface water). 3.6 billion (46%) lack safely managed sanitation. 2.3 billion lack basic handwashing facilities. Global WASH targets SDG 6: universal access to safe water and sanitation by 2030. India Jal Jeevan Mission (Har Ghar Jal): functional household tap connections to all households by 2024.' },
  { topic:'community', q:'Water-borne diseases are caused by ingestion of contaminated water. Fomite-borne transmission means:', opts:['Transmission via water','Transmission via inanimate objects (fomites) contaminated with infectious material - e.g., towels, doorknobs, toys','Transmission via air','Transmission via blood'], ans:1, expl:'Fomite: any inanimate object that can carry and transmit infectious material. Examples: Contaminated doorknobs (influenza, COVID-19), toys (norovirus), towels (ringworm, scabies), medical equipment (stethoscopes, blood pressure cuffs - MRSA). Control: surface cleaning/disinfection, hand hygiene after touching fomites. Different from: airborne (droplet nuclei), droplet (large droplets, <1 metre), direct contact (person-to-person), vehicle-borne (contaminated food/water), vector-borne (arthropods).' },
  { topic:'community', q:'Population density is:', opts:['Total population only','Number of persons per unit area (persons/km2) - indicates crowding, disease transmission risk','Birth rate minus death rate','Annual population growth rate'], ans:1, expl:'Population density = Population / Area (persons/km2). High density areas: more rapid disease transmission (respiratory, faecal-oral), water contamination risk, slum development, mental health stress. India average density: ~423 persons/km2 (2021). Highest: Bihar (1,106/km2), West Bengal (1,102/km2). Lowest: Arunachal Pradesh (17/km2). J&K: 56/km2. Urban areas much higher density (Mumbai slums: up to 3,00,000/km2). Public health implication: herd immunity harder to achieve, outbreaks more intense.' },
  { topic:'community', q:'Infant Mortality Rate (IMR) in India as per SRS 2020 is:', opts:['10 per 1000 live births','28 per 1000 live births','50 per 1000 live births','75 per 1000 live births'], ans:1, expl:'India IMR (SRS 2020): 28 per 1000 live births. Rural IMR: 31/1000; Urban IMR: 19/1000. Best performing state: Kerala (6/1000), Goa (9/1000). Highest IMR: Madhya Pradesh (43/1000). J&K: approximately 17/1000. Global IMR: 27/1000 (WHO 2019). SDG target: end preventable deaths of under-5s; IMR <12/1000 by 2030 (SDG 3.2). NFHS-5 IMR: 35.2/1000 live births.' },
  { topic:'community', q:'The "Barefoot Doctor" programme originated in:', opts:['India (ASHA programme)','China (1965 Cultural Revolution - village-level healthcare workers without full medical training)','UK','USA'], ans:1, expl:'Barefoot Doctors (China, 1965-1981 Cultural Revolution): peasants with 3-6 months basic medical training, provided basic healthcare in rural villages, worked barefoot in rice fields. Inspired community health worker (CHW) concept globally. India ASHA (2005): influenced by Barefoot Doctor concept. WHO adopted CHW concept for PHC (Alma Ata 1978). Brazil Family Health Strategy, Ethiopia HEWs (Health Extension Workers), Rwanda CHWs: similar concepts worldwide.' },
  { topic:'community', q:'Sterilisation methods - the most reliable method for destroying ALL microorganisms including bacterial spores is:', opts:['Boiling at 100 degrees C','Pasteurisation','Autoclaving (steam under pressure - 121 degrees C at 15 psi for 15 minutes)','70% alcohol'], ans:2, expl:'Autoclaving: most reliable sterilisation method. Steam under pressure at 121 degrees C (15 psi/103 kPa) for 15 minutes kills ALL microorganisms including heat-resistant endospores (Bacillus, Clostridium). Porous loads: 134 degrees C for 3 minutes. Bowie-Dick test (daily): tests steam penetration. Biological indicators (Geobacillus stearothermophilus spores): weekly validation. Hot air oven: 160 degrees C for 1 hour (dry heat, for glassware, oils, powders that cannot be wet). Boiling: kills most but NOT endospores.' },
  { topic:'nursing', q:'A patient on heparin infusion - which laboratory value monitors anticoagulation?', opts:['PT/INR','APTT (Activated Partial Thromboplastin Time) - therapeutic range 1.5-2.5x control (60-100 seconds)','Platelet count','Fibrinogen level'], ans:1, expl:'Heparin monitoring: APTT (Activated Partial Thromboplastin Time). Therapeutic target: 1.5-2.5x control (approximately 60-100 seconds). Normal APTT: 25-35 seconds. Warfarin monitoring: PT/INR (Prothrombin Time/International Normalised Ratio). Therapeutic INR: 2.0-3.0 (most indications); 2.5-3.5 (mechanical heart valves). LMWH (enoxaparin): monitor Anti-Xa levels (for high-risk: renal failure, obesity, pregnancy). Dabigatran, rivaroxaban (NOACs/DOACs): routine monitoring usually not required.' },
  { topic:'nursing', q:'The purpose of nasogastric tube (Ryle\'s tube) insertion includes:', opts:['Measuring blood pressure','Feeding (enteral nutrition), drug administration, gastric decompression (removing gas/contents), gastric lavage, gastric content aspiration for diagnosis','IV fluid administration','Oxygen delivery'], ans:1, expl:'NG tube (Ryle\'s tube) indications: (1) Enteral feeding (when cannot swallow - stroke, unconscious, preterm babies). (2) Drug administration (cannot swallow tablets - crushed). (3) Gastric decompression (post-operative ileus, bowel obstruction - removes gas and secretions). (4) Gastric lavage (poison ingestion - controversial, falling out of use). (5) Gastric content aspiration (diagnose occult GI bleeding). Tube sizes: adult 12-18 French. Nasogastric vs nasojejunal: aspirating risk.' },
  { topic:'nursing', q:'In managing a patient with seizures, immediate nursing actions include:', opts:['Restrain the patient firmly','Position on side (lateral), protect from injury (remove hard objects, cushion head), do not put anything in mouth, time the seizure, call for help, oxygen, anticonvulsant if ordered','Give oral medication immediately','Perform CPR'], ans:1, expl:'Seizure management: (1) Protect: position lateral (recovery position - prevents aspiration), clear area of hard objects, cushion head. (2) Do NOT restrain (increases injury risk). (3) Do NOT put anything in mouth (tongue bite risk is myth; cannot swallow tongue). (4) Time the seizure (>5 minutes = status epilepticus, give benzodiazepine IV - diazepam or lorazepam). (5) Monitor airway/breathing after seizure (postictal phase). (6) O2 by mask. (7) IV access. (8) Document: type, duration, post-ictal state.' },
  { topic:'nursing', q:'The most common healthcare-associated infection (HAI) is:', opts:['MRSA bloodstream infection','Catheter-associated urinary tract infection (CAUTI) - 30-40% of all HAIs','Surgical site infection','Ventilator-associated pneumonia'], ans:1, expl:'CAUTI: most common HAI (30-40% of all HAIs). Risk factor: urinary catheter (Foley). Each day of catheterisation: 3-7% risk of infection. Prevention bundle: Insert only when necessary, maintain closed drainage system, keep bag below bladder, remove ASAP, daily perineal care, aseptic insertion. HAI hierarchy: CAUTI > SSI (Surgical Site Infection) > VAP (Ventilator-Associated Pneumonia) > CLABSI (Central Line-Associated Bloodstream Infection). MRSA: most dangerous but not most common.' },
  { topic:'drug', q:'Drugs used in the management of pre-eclampsia include:', opts:['Aspirin only','MgSO4 (magnesium sulphate for seizure prevention/treatment) + Antihypertensives (labetalol, nifedipine, hydralazine) + Delivery (definitive treatment)','Diazepam and NSAIDs','Steroids and diuretics'], ans:1, expl:'Pre-eclampsia management: (1) MgSO4 (magnesium sulphate): drug of choice for eclampsia prevention and treatment. Regimen: Loading dose 4g IV over 15-20 min + 5g IM each buttock → Maintenance 5g IM every 4 hours (or IV infusion 1-2g/hour). Monitor: respiratory rate (>12/min), knee jerk (present), urine output (>100 mL/4 hours). Antidote: Calcium gluconate 10mL of 10% IV. (2) Antihypertensives for BP >160/110: Labetalol IV, Nifedipine oral. (3) Delivery: definitive cure.' },
  { topic:'drug', q:'The antidote for warfarin overdose is:', opts:['Protamine sulphate','Vitamin K (phytomenadione) + FFP (Fresh Frozen Plasma) for severe/life-threatening bleeding','Naloxone','Flumazenil'], ans:1, expl:'Warfarin reversal: Vitamin K1 (phytomenadione) IV/oral - onset 6-12 hours (reversal not immediate). For severe/life-threatening bleeding: FFP (Fresh Frozen Plasma) - immediate effect, contains all clotting factors. Prothrombin Complex Concentrate (PCC/beriplex): faster and more complete reversal than FFP, preferred now. NOACs: Dabigatran - Idarucizumab (Praxbind); Rivaroxaban/Apixaban - Andexanet alfa. Heparin: Protamine sulphate. ASA/NSAIDs: platelet transfusion.' },
  { topic:'drug', q:'Morphine (opioid analgesic) side effects include:', opts:['Hypertension and tachycardia','Respiratory depression, miosis (pinpoint pupils), constipation, nausea, sedation, urinary retention, hypotension','Increased gut motility','Tachycardia and mydriasis'], ans:1, expl:'Opioid toxidrome (morphine, heroin, codeine, fentanyl, tramadol): Respiratory depression (life-threatening - rate and depth reduced), Miosis (pinpoint pupils - pathognomonic), Sedation/coma, Constipation (reduce gut motility - useful in diarrhoea), Nausea/vomiting, Urinary retention, Hypotension, Bradycardia. Tolerance: develops to most effects (except constipation and miosis). Dependence: physical and psychological. Naloxone: antidote. Titrate opioids carefully in elderly, COPD.' },
  { topic:'drug', q:'Which drug is a proton pump inhibitor (PPI) used for peptic ulcer disease?', opts:['Ranitidine (H2 blocker)','Omeprazole (PPI - irreversibly inhibits H+/K+ ATPase proton pump in gastric parietal cells)','Sucralfate (mucosal protectant)','Antacid (aluminium hydroxide)'], ans:1, expl:'PPIs (omeprazole, pantoprazole, lansoprazole, esomeprazole, rabeprazole): most effective acid-suppressing drugs. Mechanism: irreversibly inhibit H+/K+ ATPase proton pump in gastric parietal cells. Reduce acid production >90%. Uses: peptic ulcer disease, GERD, H. pylori eradication (triple therapy: PPI + clarithromycin + amoxicillin), Zollinger-Ellison syndrome, prevent NSAID-induced gastropathy. Take before meals. H2 blockers (ranitidine, famotidine): less effective. Antacids: immediate but short-lasting neutralisation.' },
  { topic:'community', q:'ASHA is expected to motivate families for which activities? (Multiple correct - select the most complete answer)', opts:['Vaccination only','Family planning only','Institutional delivery and JSY claim only','Antenatal care, institutional delivery (JSY), immunisation, HBNC, family planning, ORS/Zinc for diarrhoea, DOTS for TB, school health - broad range of health promotion activities'], ans:3, expl:'ASHA (Accredited Social Health Activist) responsibilities: ANC registration, motivate institutional delivery (JSY incentive), postnatal follow-up, HBNC (6 home visits), newborn care, immunisation mobilisation, family planning counselling and spacing, ORS/zinc distribution for diarrhoea, DOTS supporter for TB, referral of sick children, VHND support, household survey, community mobilisation. She is a multi-purpose community volunteer, not specialised in one area.' },
  { topic:'community', q:'Vector control method used for malaria - Indoor Residual Spraying (IRS) uses which insecticide?', opts:['DDT (outdated) and now Synthetic pyrethroids (deltamethrin, cyfluthrin) or Bendiocarb','Only DDT','Only natural herbs','Chlorine only'], ans:0, expl:'IRS (Indoor Residual Spraying): insecticide sprayed on inside walls and ceilings of homes. Mosquitoes resting on walls are killed. Previously: DDT (effective, cheap, persistent - but banned for agricultural use, still WHO-permitted for malaria IRS under Stockholm Convention). Current WHO-recommended insecticides: Synthetic pyrethroids (deltamethrin, alpha-cypermethrin), Organophosphates (malathion, pirimiphos-methyl), Carbamates (bendiocarb). Insecticide resistance: major challenge. Rotate insecticide classes.' },
  { topic:'community', q:'The "Miasma theory" of disease (pre-germ era) was replaced by the "Germ Theory" largely due to work of:', opts:['John Snow and Florence Nightingale','Louis Pasteur (microbiology - pasteurisation) and Robert Koch (Koch\'s postulates for microbial causation)','Hippocrates and Galen','William Farr'], ans:1, expl:'Miasma theory: disease caused by bad air (miasma) from rotting matter. Replaced by Germ Theory (19th century): Louis Pasteur - demonstrated microbes cause disease (pasteurisation, vaccines for anthrax, rabies). Robert Koch - isolated M. tuberculosis (1882), V. cholerae (1883); developed Koch\'s postulates (criteria to establish germ-disease causation). John Snow: Broad Street pump - epidemiological method (cholera transmission through water). Florence Nightingale: statistics and sanitation.' },
  { topic:'community', q:'Demographic transition theory describes population change in stages. India is currently in:', opts:['Stage 1 (high birth rate, high death rate)','Stage 2 (high birth rate, falling death rate - high population growth)','Stage 3 (falling birth rate, low death rate - slowing growth)','Stage 4 (low birth rate, low death rate - stable/declining population)'], ans:2, expl:'Demographic Transition Theory (Warren Thompson, 1929): Stage 1: pre-industrial (high CBR, high CDR, low growth). Stage 2: early transition (high CBR, falling CDR due to improved health - rapid growth). Stage 3: late transition (falling CBR, low CDR - slowing growth). Stage 4: post-industrial (low CBR, low CDR - stable). India: Stage 3 (TFR 2.0 - below replacement, CDR declining further). Some southern states (Kerala, Tamil Nadu): approaching Stage 4. Bihar, UP: transitioning from Stage 2 to 3.' },
  { topic:'firstaid', q:'Correct first aid for a chemical (acid/alkali) eye injury is:', opts:['Apply neutralising solution (acid to alkali, alkali to acid)','Immediate copious irrigation with water or normal saline for at least 15-20 minutes (do NOT try to neutralise)','Apply antibiotic ointment immediately','Patch the eye and go to hospital'], ans:1, expl:'Chemical eye injury (chemical burn): ophthalmic emergency. First aid: IMMEDIATE COPIOUS IRRIGATION with clean water or NS for AT LEAST 15-20 minutes. Do NOT attempt to neutralise (adding acid to alkali generates heat - further damage). Remove contact lenses first (if possible without delay). Evert eyelids to remove solid particles. Alkali burns (more dangerous - penetrate deeper than acid - progressive damage). After irrigation: urgent ophthalmology referral. Check pH of tears (target: 7.0-7.4).' },
  { topic:'firstaid', q:'Signs of a tension pneumothorax include:', opts:['Decreased respiratory rate and low blood pressure only','Severe respiratory distress, absent breath sounds on affected side, tracheal deviation AWAY from affected side, hypotension, distended neck veins','Normal chest X-ray','Only shortness of breath without other signs'], ans:1, expl:'Tension pneumothorax: air accumulates under pressure in pleural space → compresses lung and mediastinum → shifts toward opposite side. Classic signs: (1) Severe respiratory distress (hypoxia). (2) Absent breath sounds on affected side. (3) Tracheal deviation AWAY from affected side (late sign). (4) Hypotension (obstructive shock - impaired venous return). (5) Distended neck veins (elevated venous pressure). EMERGENCY: needle decompression (2nd intercostal space, mid-clavicular line) BEFORE chest X-ray. Do NOT wait for imaging.' },
  { topic:'firstaid', q:'A person found unconscious with suspected opioid overdose - what is the correct prehospital action?', opts:['Give oral fluids','Administer Naloxone (intranasal or intramuscular) + call emergency services + recovery position if breathing + CPR if not breathing','Give activated charcoal','Leave them to sleep it off'], ans:1, expl:'Opioid overdose first aid: Signs: unconscious/difficult to wake, slow/shallow breathing, pinpoint pupils, blue lips. Action: (1) Call 112/108. (2) Naloxone: if available - 4 mg intranasal (IN) OR 0.4-2 mg IM. Onset IN: 2-5 min. May repeat after 2-3 min if no response. (3) If breathing: recovery position (lateral). (4) If not breathing: rescue breathing (1 breath every 5 sec) or CPR. Naloxone availability: take-home naloxone programmes (IVDUs). Duration: 30-90 min (shorter than opioid - may need repeat dose).' },
  { topic:'stats', q:'Confidence Interval (CI) in statistics means:', opts:['The exact true value','The range of values within which the true population parameter is estimated to lie with a specified probability (95% CI = 95% confidence the true value lies in this range)','P-value above 0.05','The sample size needed'], ans:1, expl:'Confidence Interval (95% CI): calculated from sample data. If we repeated the study 100 times, 95 of those CIs would contain the true population value. Narrower CI: more precise estimate (larger sample). Wider CI: less precise. If 95% CI for a relative risk does NOT cross 1.0 (or OR, or mean difference does not cross 0): statistically significant at p<0.05. CI provides MORE information than p-value alone (shows effect size + precision). Preferred over reporting p-value only.' },
  { topic:'stats', q:'Sensitivity = 90%, Specificity = 80% for a screening test. If prevalence of disease is 1%, which statement is TRUE?', opts:['PPV will be very high (>90%)','PPV will be low (less than 10%) despite good sensitivity - rare disease has low PPV even with good test','NPV will be low','The test is not useful at all'], ans:1, expl:'Bayes theorem + low prevalence paradox: when disease prevalence is low (1%), even a highly sensitive/specific test has LOW PPV. Example: in 10,000 people with 1% prevalence: 100 true cases. Sensitivity 90% → 90 TP, 10 FN. 9900 non-cases. Specificity 80% → 80% correctly negative: 7920 TN but 1980 FP. PPV = 90/(90+1980) = 4.4%. Very low! Most positives are false positives. This is why population screening for rare diseases must use very specific tests (or two-step testing).' },
  { topic:'stats', q:'The Kappa statistic measures:', opts:['Correlation between two continuous variables','Inter-rater agreement beyond chance agreement (0 = chance agreement; 1 = perfect agreement; 0.61-0.80 = substantial agreement)','Relative risk in case-control studies','Incidence rate ratio'], ans:1, expl:'Cohen\'s Kappa (k): measures agreement between two raters (or a test and reference standard) accounting for chance agreement. Formula: k = (Po - Pe)/(1 - Pe) where Po = observed agreement, Pe = expected by chance. Interpretation: <0 = less than chance; 0-0.20 = slight; 0.21-0.40 = fair; 0.41-0.60 = moderate; 0.61-0.80 = substantial; 0.81-1.0 = almost perfect. Used for: diagnostic concordance, inter-rater reliability in research.' },
  { topic:'environment', q:'The major source of indoor air pollution in urban households in India is:', opts:['Burning biomass exclusively','LPG combustion products + Environmental Tobacco Smoke (ETS/secondhand smoke) + Radon + volatile organic compounds from paint/furniture','Only outdoor air entering homes','Cooking odours only'], ans:1, expl:'Urban indoor air pollutants: LPG combustion products (nitrogen oxides, carbon monoxide), Environmental Tobacco Smoke (ETS/secondhand smoke - 4000+ chemicals, major carcinogen exposure for children and non-smoking adults), Radon (radioactive gas, seeps from soil/building materials - lung cancer risk), VOCs (volatile organic compounds - formaldehyde from new furniture, paint, carpets), PM2.5 from cooking, dust mites, mould. Rural: biomass burning dominates. Both: major contributors to respiratory disease.' },
  { topic:'environment', q:'The Ganga Action Plan (GAP) was launched to:', opts:['Build dams on the Ganga','Clean and rejuvenate the river Ganga through sewage treatment, industrial effluent control, and riverfront development - now Namami Gange Programme','Prevent floods only','Provide drinking water from Ganga'], ans:1, expl:'Ganga Action Plan (GAP I: 1985, GAP II: 1993): reduce pollution load of Ganga. National River Conservation Plan (NRCP, 1995): extended to other rivers. Now: Namami Gange Programme (2015, Rs 20,000 crore): comprehensive approach - sewage treatment plants (STPs), crematoria modernisation, rural sanitation (ODF Ganga villages), industrial effluent standards, riverfront development (ghats), biodiversity conservation (Gangetic dolphin, turtle conservation). Connected to AMRUT (urban infrastructure) and SBM.' },
  { topic:'environment', q:'Climate change impacts on health include:', opts:['Only heat-related deaths','Increased heat stress deaths, expanded range of vector-borne diseases (malaria, dengue moving to higher altitudes), extreme weather events, food/water insecurity, mental health impacts, displacement','Improved agricultural productivity only','Reduced infectious disease through UV irradiation'], ans:1, expl:'Climate change-health linkages: (1) Direct: heat stress deaths (elderly, outdoor workers), extreme weather events (floods, cyclones - drowning, injuries, waterborne diseases). (2) Indirect: expanded vector range (malaria, dengue, JE moving to higher altitudes/latitudes with warming), changes in crop yields (food insecurity), water scarcity, air pollution (ground-level ozone from heat). (3) Mental health: climate anxiety, displacement trauma. WHO: climate change is the biggest health threat of 21st century.' },
  { topic:'programs', q:'National Programme for Prevention and Control of Deafness (NPPCD) in India screens:', opts:['Only school children','All age groups - newborn hearing screening (Universal Newborn Hearing Screening - UNHS) + school children + adults at risk','Only adults with noise exposure','Only elderly for presbycusis'], ans:1, expl:'NPPCD: Universal Newborn Hearing Screening (UNHS) - OAE (Otoacoustic Emissions) test within 48 hours of birth. Congenital hearing loss: 1-3 per 1000 newborns. Early detection: enables fitting hearing aid/cochlear implant by 6 months (critical language development period). School screening: audiometry for detection. Industrial workers: annual audiometry (occupational noise). Elderly: pure tone audiometry. ADIP scheme: assistive devices for persons with disabilities.' },
  { topic:'programs', q:'The Mukhyamantri Sehat Bima Yojana in J&K has been integrated with:', opts:['State Insurance Corporation separately','PM-JAY (Ayushman Bharat - Pradhan Mantri Jan Arogya Yojana) - J&K beneficiaries get "SEHAT Card" for cashless treatment','ESIC only','Private insurance companies only'], ans:1, expl:'J&K SEHAT (Social, Economic and Health Activities for Transformation) Card: integrated with PM-JAY. Launched January 2021. Coverage: Rs 5 lakh per family per year for ALL residents of J&K (not just BPL - unlike other states where PM-JAY covers only bottom 40%). Covers all 20 million residents. Cashless treatment at all empanelled hospitals (government and private) for secondary and tertiary care. Previous Sehat Bima Yojana (for government employees) merged. India\'s most inclusive state scheme.' },
  { topic:'community', q:'The life expectancy at birth in J&K as compared to India average is:', opts:['Lower than India average','Higher than India average (J&K LE: approximately 72-74 years vs India national average ~69.7 years)','Same as India average','Data not available for J&K'], ans:1, expl:'J&K life expectancy at birth: approximately 73-74 years (higher than national average ~69.7 years). Reasons: lower fertility rate, lower infant mortality, better female literacy, relatively better healthcare infrastructure compared to many states. IMR in J&K: approximately 17/1000 (lower than national 28). MMR: lower than national average. However: geographic challenges (difficult terrain, harsh winters) create access barriers, especially in Ladakh and remote hilly areas.' },
  { topic:'community', q:'The number of ASHA workers in Jammu and Kashmir is approximately:', opts:['5,000','18,000-20,000 (one per 1000 rural population)','50,000','1,00,000'], ans:1, expl:'ASHA in J&K: approximately 18,000-20,000 ASHAs (1 per 1000 rural population norm). J&K total rural population: approximately 11-12 million. Given J&K\'s challenging geography (high altitude areas, seasonal inaccessibility), additional provisions for remote areas. ASHA selection: by Gram Panchayat, from the same village. Training: conducted by Block level trainers. Performance-based incentives. ASHA drug kit: refilled quarterly. ASHA annual incentives including HBNC visits.' },
  { topic:'community', q:'In India, the majority of out-of-pocket (OOP) health expenditure by households is on:', opts:['Hospitalisation costs','Medicines and drugs (approximately 50-60% of total OOP health expenditure)','Diagnostic tests','Health insurance premiums'], ans:1, expl:'India health expenditure pattern: OOP expenditure on health: 47.1% of total health expenditure (among highest in world). Of OOP: medicines and drugs = 50-60% of spending (reason: generic drug unavailability, high brand prices, prescription of branded drugs). This is why PMBJP (Jan Aushadhi Kendras) and free drug service under NHM are critical. National Health Accounts (NHA) India: tracks health spending. Financial protection: PM-JAY for hospitalisation, free OPD drugs at HWC reduces OOP.' },
  { topic:'community', q:'Malnutrition affects child development through (the "nutrition-cognition link"):', opts:['Only physical growth','Stunting impairs brain development (fewer synapses, reduced myelination), reduces school readiness, cognitive function, and adult productivity - perpetuating poverty cycle','Only immunological function','Only later-life cardiovascular risk'], ans:1, expl:'Nutrition-cognition link (first 1000 days: conception to 2 years most critical): Stunting (linear growth failure from chronic undernutrition) → impaired brain development, reduced school performance, cognitive deficits, reduced adult earning capacity. Iron deficiency: anaemia reduces attention, learning. Iodine: essential for brain development. Micronutrient deficiency: affects neurotransmitter synthesis. POSHAN Abhiyaan: recognises this - targets first 1000 days (Poshan Maah - September - national nutrition month).' },
  { topic:'anatomy', q:'The "rule of thumb" for estimating percentage of surface area burnt in an INFANT is:', opts:['Same as adult (Rule of Nines)','Modified Lund and Browder chart (head = 18%, each leg = 14% - different proportions from adults due to larger head and smaller legs)','Palmar surface = 9%','Body weight-based formula only'], ans:1, expl:'Burns BSA estimation in children: Lund and Browder Chart: more accurate than Rule of Nines for children because body proportions change with age. In infants: head = 18% (vs adult 9%), each thigh = 3.25% (smaller). Rule of Nines in adults: head = 9%, each thigh = 9%. Palmar method: patient\'s palm (including fingers) = approximately 1% BSA - useful for small or irregular burns in any age.' },
  { topic:'anatomy', q:'Which type of blood vessel has valves to prevent backflow?', opts:['Arteries','Veins (especially in lower limbs - venous valves prevent blood pooling against gravity)','Capillaries','Arterioles'], ans:1, expl:'Veins: have valves (bicuspid semilunar valves - especially prominent in limbs). Valves prevent retrograde blood flow (backflow against gravity in lower limbs). Varicose veins: incompetent valves → blood pools → vein dilation, tortuosity. Deep Vein Thrombosis (DVT): thrombus in deep veins (usually calf → popliteal → femoral), can embolise to lungs (PE). Virchow\'s triad: stasis + endothelial injury + hypercoagulability → DVT. Arteries: no valves (pressure maintains flow direction). Exception: semilunar valves of aorta and pulmonary artery.' },
  { topic:'anatomy', q:'Lymph nodes - which regional lymph node group drains the breast?', opts:['Inguinal lymph nodes','Axillary lymph nodes (primarily - especially lateral group) - important in breast cancer staging','Cervical lymph nodes','Iliac lymph nodes'], ans:1, expl:'Breast lymphatic drainage: 75% → Axillary nodes (5 groups: anterior/pectoral, posterior/subscapular, lateral, central, apical/infraclavicular). 25% → Internal mammary (parasternal) nodes. Sentinel lymph node biopsy (SLNB): first lymph node to drain a tumour - if negative, less likely to have spread. Axillary node status: most important prognostic factor in breast cancer. Lymphoedema of arm: after axillary node dissection/radiotherapy in breast cancer surgery.' },
  { topic:'nursing', q:'Which nursing action prevents venous thromboembolism (VTE) in post-operative patients?', opts:['Bed rest for first 5 days','Early ambulation (within 24 hours when possible) + elastic stockings + sequential compression devices + LMWH prophylaxis if high risk','Only IV fluids','Elevation of head only'], ans:1, expl:'VTE prevention bundle (post-operative): (1) Early ambulation (mobilisation within 24 hours when medically possible - most effective). (2) Elastic compression stockings (TED stockings). (3) Intermittent pneumatic compression devices (SCDs - sequential compression devices). (4) LMWH (Low Molecular Weight Heparin) pharmacological prophylaxis: enoxaparin 40 mg SC once daily (high-risk patients). Caprini score: VTE risk stratification. Virchow\'s triad: immobility, surgery = risk factors. DVT: swelling, warmth, redness of calf (Homan\'s sign unreliable).' },
  { topic:'nursing', q:'A patient with congestive heart failure (CHF) should be positioned in:', opts:['Flat supine to reduce preload','High Fowler\'s position (60-90 degrees) to reduce dyspnoea by decreasing venous return to heart (preload) and improving lung expansion','Prone position','Trendelenburg (legs up)'], ans:1, expl:'CHF positioning: HIGH FOWLER\'S (60-90 degrees) or sitting upright. Rationale: gravity reduces venous return (preload) to already overloaded heart, reduces pulmonary congestion (fluid settles to lung bases with improved upper zone expansion). Also relieves dyspnoea (orthopnoea - difficulty breathing when lying flat). "Orthopnea: how many pillows?" (1 pillow = mild, 3 pillows = severe CHF). Acute pulmonary oedema: dangling legs over bedside further reduces venous return.' },
  { topic:'nursing', q:'Wound healing by primary intention (primary closure) means:', opts:['Wound heals by scar tissue formation from inside out (large wounds)','Wound edges are brought together (sutured/stapled/glued) - heals with minimal scarring and reduced infection risk (clean surgical wounds)','Wound is left open to heal','Wound heals after skin grafting'], ans:1, expl:'Wound healing types: Primary intention (first intention): edges approximated (sutured/stapled/taped/glued), wound closed - heals fastest with minimal scarring. Example: clean surgical incisions. Secondary intention: wound left open (infected/contaminated/large wounds) - granulation tissue fills from inside out (long, scarred). Tertiary intention (delayed primary closure): initially left open (contaminated), closed after 4-5 days when infection controlled. Factors impairing healing: diabetes, malnutrition, steroids, infection, poor blood supply.' },
  { topic:'programs', q:'The Integrated Action Plan (IAP) for districts with high burden of TB, HIV, malaria and other diseases includes:', opts:['Separate vertical plans for each disease','District Health Action Plan (DHAP) - integrated planning across all programmes under NHM for the district','National-level planning only','State-level planning only'], ans:1, expl:'DHAP (District Health Action Plan): bottom-up planning process. Prepared by District Health Society (DHS) based on: local epidemiology, health indicators, facility assessment, community needs. Includes: all NHM components (RMNCH+A, immunisation, disease control, HWC development, HR, infrastructure). Rolled up to State PIP → National NHM plan. Ideally: DHAP should drive spending (decentralisation) rather than top-down mandates. District Collector chairs DHS; CMO is CEO.' },
  { topic:'programs', q:'National Nutrition Month (Rashtriya Poshan Maah) is observed in:', opts:['January','March','September (entire month - 2018 onwards)','December'], ans:2, expl:'Rashtriya Poshan Maah (National Nutrition Month): September every year (since 2018 under POSHAN Abhiyaan). Activities: village-level Poshan melas, distribution of micronutrients, growth monitoring camps, IEC on first 1000 days nutrition, complementary feeding demonstrations, cultivation of kitchen gardens, WIFS (weekly iron/folic acid supplementation) for adolescent girls. Anganwadi worker - central to activities. Poshan Pakhwada: second fortnight of March.' },
  { topic:'community', q:'Effective communication in health education includes:', opts:['Only written pamphlets','Using appropriate language (local language, no jargon), multiple methods (verbal, visual, demonstration), repeat-back method (teach-back), involving community leaders, and two-way communication','Only mass media','Only one-to-one counselling by doctors'], ans:1, expl:'Effective health education (IEC - Information, Education, Communication; BCC - Behaviour Change Communication): Appropriate message (clear, specific, actionable). Right medium: interpersonal (most effective for behaviour change), group education, mass media (awareness). Local language. Two-way communication (not just one-way message delivery). Teach-back method (ask patient to explain back). Cultural sensitivity. SBCC (Social Behaviour Change Communication): comprehensive approach including social norms change.' },
  { topic:'community', q:'The BCG scar provides evidence of:', opts:['Immunity to all infections','Past exposure/vaccination with BCG (indicates likely immune response but does not guarantee protection against TB in all forms)','Current tuberculosis infection','Inadequate immunity'], ans:1, expl:'BCG scar: develops 4-8 weeks after BCG vaccination. Indicates immune response (Cell-mediated immunity) was mounted. BCG protection: greatest against miliary TB and TB meningitis in children (80% protection). Less consistent protection against adult pulmonary TB (varies: 0-80% in trials). Absence of BCG scar: does NOT mean BCG failed (up to 10% do not develop scar). Do NOT re-vaccinate based on absent scar alone. BCG also protects against leprosy (50-80%) and reduces all-cause neonatal mortality (non-specific effects).' },
  { topic:'community', q:'Global Fund to fight AIDS, Tuberculosis and Malaria provides funding for:', opts:['Emergency humanitarian response only','Prevention, treatment, and care programs for HIV/AIDS, TB, and malaria in low- and middle-income countries through grants to governments and NGOs','Vaccine development only','Research and development only'], ans:1, expl:'Global Fund (GFATM): international financing institution, established 2002, headquartered Geneva. Provides grants to countries for: HIV/AIDS (ART, prevention, PMTCT), Tuberculosis (DOTS, MDR-TB treatment), Malaria (insecticide-treated bed nets, ACT, IRS). India: one of largest recipients. Funded through: government contributions from wealthy nations (US, UK, France, Germany, Japan largest donors). Disbursed over $50 billion since 2002. Works through Principal Recipients (government ministries, NGOs).' },
  { topic:'nursing', q:'Decubitus ulcer (pressure sore) staging - Stage III is characterized by:', opts:['Non-blanchable erythema of intact skin','Partial thickness skin loss (epidermis/dermis)','Full thickness skin loss involving damage to subcutaneous tissue (but not fascia, muscle, bone)','Full thickness tissue loss with exposed bone, tendon, or muscle'], ans:2, expl:'NPUAP/EPUAP Pressure Injury Staging: Stage I: Non-blanchable erythema, intact skin. Stage II: Partial thickness skin loss (dermis) - blister, shallow ulcer. Stage III: Full thickness skin loss, subcutaneous fat visible, may have undermining/tunnelling, NO exposed bone/tendon/muscle. Stage IV: Full thickness tissue loss, exposed bone/tendon/muscle. Unstageable: full thickness, covered by slough/eschar (cannot stage until debridement). Suspected Deep Tissue Injury (DTI): purple/maroon intact or ruptured blood-filled blister.' },
  { topic:'nursing', q:'The correct technique for measuring blood pressure by sphygmomanometer:', opts:['Apply cuff over clothing, patient standing','Patient seated for 5 minutes, arm at heart level, cuff placed 2-3 cm above antecubital fossa, deflate at 2-3 mmHg/second, read to nearest 2 mmHg','Apply cuff very loosely, inflate rapidly','Check only the diastolic pressure'], ans:1, expl:'BP measurement technique: (1) Rest 5 minutes (remove anxious artefact). (2) Arm bare, supported at heart level. (3) Cuff: lower border 2-3 cm above antecubital fossa, 80% of arm circumference (correct cuff size - too small: falsely elevated). (4) Inflate 20-30 mmHg above disappearance of radial pulse. (5) Deflate at 2-3 mmHg/second. (6) Korotkoff sounds: Phase I (first sound = systolic), Phase V (last sound disappears = diastolic). (7) Average of 2 readings, 1 minute apart. (8) Both arms first visit (use higher value).' },
  { topic:'nursing', q:'Pain assessment - "PQRST" mnemonic stands for:', opts:['Pressure, Quality, Radiation, Severity, Time','Provocation/Palliation, Quality, Region/Radiation, Severity/Scale, Timing/Treatment','Prevention, Quantity, Relief, Severity, Temperature','Pulse, Quality, Respiration, Systolic, Timing'], ans:1, expl:'PQRST Pain Assessment: P = Provocation/Palliation (what makes it worse? better?); Q = Quality/Character (sharp, dull, burning, crushing, throbbing, squeezing?); R = Region/Radiation (where exactly? does it radiate anywhere?); S = Severity/Scale (0-10 numeric, Wong-Baker FACES, VAS); T = Timing (onset, duration, constant vs intermittent, pattern). Comprehensive pain assessment informs analgesic choice and evaluation of therapy effectiveness.' },
  { topic:'community', q:'NITI Aayog (National Institution for Transforming India) replaced:', opts:['Ministry of Health','Planning Commission of India (dissolved 2015)','Election Commission','Finance Commission'], ans:1, expl:'NITI Aayog: replaced Planning Commission (established 1950 by PM Nehru, 1st Five Year Plan). Dissolved January 2015 by PM Modi. NITI Aayog (2015): think tank with bottom-up approach (vs Planning Commission top-down). Key documents: 3-Year Action Agenda, 7-Year Strategy, 15-Year Vision. Health Mission: co-designing health policy with states, publishing Health Index (ranking states on health outcomes). No financial allocation power (unlike Planning Commission - that now rests with Ministry of Finance through NHM PIPs).' },
  { topic:'community', q:'The "Inverse Care Law" (Julian Tudor Hart 1971) states:', opts:['More healthcare leads to worse health outcomes','Availability of good medical care tends to vary inversely with the need for it - those who need it most get it least','Preventive care is always more effective than curative','Expensive care is always better than cheaper care'], ans:1, expl:'Inverse Care Law (Julian Tudor Hart, 1971, The Lancet): "The availability of good medical care tends to vary inversely with the need of the population served." Those in deprived areas (with more disease burden) have worse access to quality healthcare. Applies globally and in India: rural/tribal areas with high disease burden have fewer doctors, worse facilities. NHM, HWC, Mission Indradhanush: attempts to address the inverse care law. Universal Health Coverage: counteracts this.' },
  { topic:'community', q:'The "epidemiological iceberg" concept in infectious disease means:', opts:['Most disease occurs in winter','Only a small visible proportion of all infection/disease is detected (clinical cases) while a much larger invisible portion (subclinical, mild cases) exists below the surface','Disease spreads in waves like ocean','Epidemics peak and then decline like icebergs melting'], ans:1, expl:'Epidemiological Iceberg: most infections are SUBCLINICAL (no symptoms) or mild (not reaching medical care) - invisible below waterline. Clinical cases (hospitalised, diagnosed): only the visible tip. Example: For every 1 polio paralytic case: 100 subclinical infections. For every 1 HIV-diagnosed case: multiple undiagnosed. For every 1 Salmonella foodborne illness hospitalised: 30+ unreported. Implications: surveys underestimate true disease burden; community transmission continues despite low reported cases.' },
  { topic:'nursing', q:'Anaphylaxis - how long after exposure can anaphylaxis occur (late phase reaction)?', opts:['Only within 30 minutes','Usually within 15-30 minutes for immediate phase; up to 72 hours for biphasic reaction (secondary surge)','Only within 5 minutes','Only within 24 hours for first reaction'], ans:1, expl:'Anaphylaxis timing: Immediate phase: typically within 15-30 minutes (up to 1 hour) of exposure. Biphasic reaction: secondary anaphylactic response 1-72 hours after initial episode (8-11% incidence) even without re-exposure. Protracted anaphylaxis: prolonged symptoms. Therefore: observe patients in facility for minimum 4-6 hours (some guidelines say 24 hours if severe) after treating anaphylaxis. Most common triggers: foods (peanuts, shellfish), insect stings, medications (penicillin, NSAIDs), latex, exercise.' },
  { topic:'community', q:'India\'s National Health Policy 2017 sets which SDH (Social Determinants of Health) goals?', opts:['Medical targets only','Life expectancy to 70 years by 2025, TFR 2.1, IMR 28, U5MR 23, MMR 100, end TB 2025, and address SDH through inter-sectoral action','GDP growth only','GDP targets only'], ans:1, expl:'NHP 2017 health targets: LE at birth 70 years by 2025 (India currently ~70 years). TFR 2.1 by 2025 (achieved: 2.0 in NFHS-5). IMR 28/1000 by 2019 (achieved). U5MR 23/1000 by 2025. MMR 100/1,00,000 by 2020 (currently 97). End TB by 2025 (5 years before SDG). Reduce malaria by 75% by 2020. NHP also addresses inter-sectoral action for SDH (WASH, nutrition, education, gender equity). India\'s commitment to UHC (Universal Health Coverage) as a right.' },
  { topic:'community', q:'The NFHS-5 (2019-21) found that India\'s Total Fertility Rate (TFR) has:', opts:['Increased to 3.0','Remained stable at 2.5','Declined to 2.0 (below replacement level of 2.1 for the first time)','Remained at 2.1'], ans:2, expl:'NFHS-5 (2019-21): India TFR = 2.0 (national average). First time below replacement level (2.1). Significant decline from NFHS-4 (2015-16): 2.2. Rural TFR: 2.1. Urban TFR: 1.6. State variation: Bihar 3.0 (highest), Goa 1.3 (lowest). 31 states/UTs at or below replacement level (including J&K: ~1.4). J&K TFR: significantly below national average. Implication: India approaching demographic transition Stage 3-4; population will stabilise. However: population momentum means India will continue to grow until ~2060.' },
  { topic:'community', q:'Vector control for dengue fever focuses on:', opts:['Indoor residual spraying only','Eliminating Aedes breeding sites (stagnant water in containers, tyres, flower pots, coolers) and biological control - not IRS because Aedes bites outdoors during day','Only chemical fogging','Only bed nets'], ans:1, expl:'Dengue vector control (Aedes aegypti - day-biting, domestic breeder in clean water): Source reduction (SR): remove/empty containers holding water (coolers, flower pots, tyres, water storage, roof debris). Key principle: Dengue Aedes breeds in SMALL, CLEAN water containers near homes. IRS: NOT effective for dengue (Aedes rests outdoors). Larviciding: BTi (Bacillus thuringiensis israelensis) in unmovable containers. Biological: Gambusia fish, copepods. Fogging (ULV spraying): only during outbreaks. Personal protection: repellents, long sleeves, window screens.' },
  { topic:'community', q:'Quarantine versus isolation in infectious disease control:', opts:['Same thing, used interchangeably','Isolation: separates SICK (infectious) people from healthy. Quarantine: separates and restricts movement of EXPOSED (possibly infected but not yet sick) people to prevent potential spread during incubation period','Quarantine is for animals only','Isolation is for animals only'], ans:1, expl:'Isolation vs Quarantine: ISOLATION: for people who ARE SICK (confirmed or suspected infectious disease) - separates from healthy population. Respiratory/droplet/contact precautions as applicable. Example: TB patient in negative pressure room. QUARANTINE: for people EXPOSED to infectious agent but NOT YET SICK - restricts movement for the duration of incubation period to monitor for illness. Example: COVID-19 exposure quarantine for 14 days. Both used in outbreak response. Cohorting: isolating multiple patients with same infection together.' },
  { topic:'nursing', q:'Which position is BEST for a patient with severe dyspnoea and hypoxia?', opts:['Supine (flat)','Prone position','High Fowler\'s (60-90 degrees) with legs dependent - maximises lung expansion and reduces venous return (preload)','Trendelenburg'], ans:2, expl:'Severe dyspnoea/hypoxia positioning: HIGH FOWLER\'S (60-90 degrees): (1) Gravity helps lung bases expand (diaphragm moves down). (2) Reduces venous return to overloaded pulmonary circulation. (3) Reduces work of breathing. (4) Sitting upright allows accessory muscle use. PRONE position: beneficial in ARDS on ventilator (opens posterior lung segments). NOT for conscious patients with dyspnoea (cannot maintain safely). Supplemental oxygen + position + treat underlying cause (bronchodilators for asthma/COPD; diuretics for pulmonary oedema).' },
  { topic:'programs', q:'Deen Dayal Upadhyaya Grameen Kaushalya Yojana (DDU-GKY) contributes to health by:', opts:['Providing health insurance to rural youth','Providing skill training and placement for rural youth reducing poverty - a key social determinant of health','Building rural hospitals','Providing free medicines'], ans:1, expl:'DDU-GKY (MGNREGA + skill development for rural youth): reduces poverty (primary SDH) by providing market-linked skill training and placement. Health linkage: poverty → malnutrition → disease → poverty cycle. Skilled employment → income → better food, housing, healthcare access. Healthcare sector component: nursing aide, home health aide, medical lab technician, physiotherapy assistant training. Empowerment of rural poor (especially women) → better health decision-making. Part of Skill India Mission.' },
  { topic:'community', q:'The major challenges in achieving Universal Health Coverage (UHC) in India include:', opts:['Only lack of hospitals','Shortage of skilled health workforce (especially in rural areas), inadequate public health financing, geographic access barriers, out-of-pocket spending, quality of care, health literacy, and social determinants','Only corruption','Only lack of vaccines'], ans:1, expl:'UHC challenges in India: (1) HR: India has 1 physician per 1000+ population (WHO recommends 4.45 healthcare workers per 1000). Rural-urban maldistribution. (2) Financing: public health expenditure 1.13% GDP (very low). (3) Access: remote/tribal/hilly areas. (4) OOP spending: 47% of total health expenditure (pushes 55-65 million into poverty annually). (5) Quality: variable, patient safety concerns. (6) Accountability and governance. NHM, PM-JAY, ABDM: steps toward UHC. Ayushman Bharat: most significant push.' },
  { topic:'community', q:'The "Ten essential public health operations" (WHO 2012 for European region) include:', opts:['Only vaccination and treatment','Surveillance, epidemiology, protection, preparedness, disease prevention, health promotion, governance, workforce, health information, research - comprehensive framework','Only clinical services','Only administrative functions'], ans:1, expl:'WHO 10 Essential Public Health Operations (EPHO): (1) Surveillance, monitoring, evaluation; (2) Epidemiology; (3) Health protection (environmental, occupational, food safety); (4) Health security and emergency preparedness; (5) Disease prevention; (6) Health promotion; (7) Assuring governance for health; (8) Health workforce; (9) Health communication, literacy; (10) Advancing public health research. Used by countries to assess public health system capacity and identify gaps.' },
  { topic:'nursing', q:'When administering eye drops, the nurse should instil the drops into:', opts:['Directly onto the cornea','The conjunctival sac (lower lid pocket) - pull down lower lid, patient looks up, drop in pocket','Into the upper fornix only','Into the lacrimal punctum'], ans:1, expl:'Eye drop instillation technique: (1) Wash hands. (2) Tilt patient\'s head back. (3) Pull down lower lid to form conjunctival sac (pocket). (4) Patient looks upward. (5) Hold dropper 1-2 cm above eye (do NOT touch eye). (6) Instil prescribed number of drops into conjunctival sac. (7) Patient closes eye gently (do NOT squeeze - expels medication). (8) Apply gentle pressure on lacrimal punctum (nasolacrimal duct) for 1-2 minutes - reduces systemic absorption. (9) If multiple drops: wait 3-5 minutes between different medications. (10) Ointment: lower lid pocket, instil strip.' },
  { topic:'nursing', q:'Which complication is most feared immediately post-thyroidectomy (within first hours)?', opts:['Wound infection','Thyroid storm (thyrotoxic crisis)','Haematoma compressing airway (can cause asphyxia - keep tracheostomy set at bedside)','Hypothyroidism'], ans:2, expl:'Post-thyroidectomy immediate complications: (1) HAEMATOMA: most feared immediate complication (2-4% incidence). Neck swelling, tracheal compression → stridor, dyspnoea, respiratory arrest. EMERGENCY: open wound immediately (bedside tracheostomy set mandatory post-op). (2) Hypoparathyroidism (24-72 hours): hypocalcaemia, tetany, Chvostek sign, Trousseau sign → IV calcium gluconate. (3) Recurrent laryngeal nerve damage: hoarseness (unilateral - temporary usually; bilateral - stridor, emergency). (4) Thyroid storm: rare, if not euthyroid pre-op.' },
  { topic:'nursing', q:'In which DIRECTION does blood flow in the portal circulation?', opts:['From liver to intestines','From intestines, spleen, pancreas → portal vein → liver → hepatic veins → inferior vena cava → heart','From liver to kidneys','From stomach directly to heart'], ans:1, expl:'Portal circulation: Mesenteric veins (drain intestines) + Splenic vein (spleen + pancreas) → Portal vein → Liver sinusoids (metabolise absorbed nutrients, drugs, remove gut bacteria) → Hepatic veins → Inferior Vena Cava (IVC) → Right Atrium. First-pass effect: absorbed drugs pass through liver before systemic circulation (metabolised - reduces bioavailability). Portal hypertension: cirrhosis/thrombosis → raised portal pressure → oesophageal varices, ascites, hypersplenism.' },
  { topic:'anatomy', q:'In a healthy adult in supine position, the most dependent part of the lung (most prone to hypostatic pneumonia) is:', opts:['Upper lobes (apices)','Anterior segments','Posterior basal segments (posterior lower lobes - lowest in supine position, secretions pool here)','Right upper lobe'], ans:2, expl:'Hypostatic pneumonia: complication of prolonged bed rest/immobility. Secretions pool in the most dependent (lowest) part of lungs. In SUPINE position: posterior basal segments of lower lobes = most dependent. Prevention: 2-hourly turning, deep breathing exercises, coughing, incentive spirometry, early ambulation. High-risk: unconscious/ventilated patients, post-operative, paralysed. Treatment: antibiotics, physiotherapy (chest percussion, postural drainage).' },
  { topic:'community', q:'The "last mile" problem in health service delivery refers to:', opts:['Long waiting times in hospitals','Difficulty reaching the final/most remote beneficiaries with services - the hardest-to-reach populations (remote villages, urban slums, tribal areas)','Emergency services response time','Supply chain management of medicines'], ans:1, expl:'"Last mile" problem: ensuring health services reach the remotest, most marginalised communities (last to be served). Examples: tribal villages without roads, urban slums without registered addresses, nomadic/migrant populations (Gujjar-Bakarwal in J&K), remote island communities. Solutions: mobile health units, boat ambulances, telemedicine, outreach camps, community health workers (ASHA in remote areas), helicopter medical services (Himachal Pradesh), Pradhan Mantri Gram Sadak Yojana (roads).' },
  { topic:'community', q:'The birth rate required to maintain population replacement (replacement fertility) is:', opts:['TFR 1.0','TFR 2.1 (accounting for mortality before reproductive age and slight male excess at birth)','TFR 3.0','TFR 4.0'], ans:1, expl:'Replacement-level fertility: TFR 2.1 (in countries with low mortality). Each woman needs to bear ~2.1 children on average to replace herself and partner, with 0.1 accounting for female child mortality before reproduction and sex ratio at birth. In high-mortality countries (high child mortality): replacement TFR may be 3.0+. India TFR (NFHS-5): 2.0 - below replacement. This does NOT mean India\'s population is declining now (population momentum - large reproductive-age cohort keeps births high for years).' },
  { topic:'nursing', q:'The nurse should assess a patient\'s apical pulse for patients on:', opts:['Antacids','Digoxin (cardiac glycoside - apex for full minute to accurately count and assess for bradycardia, irregular rate before administering)','Antacids and antibiotics','Vitamins'], ans:1, expl:'Apical pulse assessment before digoxin: digoxin causes bradycardia (increases vagal tone, slows AV node). Hold digoxin if apical pulse <60 bpm (adult) or <70 bpm (child) or <90 bpm (infant) - report to physician. Auscultate at 5th intercostal space, midclavicular line (apex of heart) for full 1 minute. Also assess for irregular rhythm (digoxin can cause AV block, atrial/ventricular arrhythmias if toxic). Check digoxin level: therapeutic 0.5-2 ng/mL.' },
  { topic:'nursing', q:'When collecting a urine specimen for culture and sensitivity (MSU - midstream urine), the patient should:', opts:['Collect the entire first void in the morning','Start urinating, discard first portion (clean), collect MIDSTREAM urine in sterile container, discard final portion','Collect any time with no special precautions','Use a non-sterile container'], ans:1, expl:'Midstream urine (MSU) collection for C&S: (1) Clean genitalia with antiseptic wipe (anterior to posterior for females - reduce contamination). (2) Begin urinating - discard first 20-30 mL (flushes urethral flora). (3) Collect MIDSTREAM urine in STERILE container WITHOUT stopping stream. (4) Discard final portion. (5) Transport to lab within 2 hours (or refrigerate at 4 degrees C). MSU reduces contamination from periurethral flora. Catheter specimen: most reliable (for catheterised patients - aspirate from catheter port).' },
  { topic:'community', q:'Occupational health service - Pre-employment medical examination is done to:', opts:['Screen for pre-existing conditions only','Establish baseline health status, identify any pre-existing conditions that may be aggravated by work, fitness for the proposed job, and legal protection for employer and employee','Reject unhealthy candidates from all jobs','Check only for communicable diseases'], ans:1, expl:'Pre-employment medical examination: (1) Establish BASELINE: health status before work exposures (medicolegal protection - if disease develops later, can determine work-relatedness). (2) Fitness for job (e.g., no colour blindness for electrical work; no hearing loss for sound-dependent jobs). (3) Identify pre-existing conditions: ensure not placed in roles that aggravate them (e.g., silicosis-prone work if pre-existing lung disease). NOT for discrimination but for appropriate placement. Periodic examination: monitors health changes during employment.' },
  { topic:'programs', q:'Janani Express (102 ambulance) and 108 Emergency Service - the key difference is:', opts:['102 is for maternal/child health (ANC, delivery, PNC, sick newborn); 108 is for ALL emergencies','102 is faster','108 is for maternal health only','102 covers cities only'], ans:0, expl:'102 Ambulance (Janani Express): specifically for maternal and newborn health - pregnant women for ANC check-ups, institutional delivery, return home after delivery, and sick newborns up to 30 days. Free under JSSK/NHM. 108 Emergency Ambulance (Emergency Response Service): covers ALL medical emergencies - accidents, cardiac events, stroke, burns, poisoning, obstetric emergencies when 102 unavailable. Available 24/7. Both NHM-funded. Together: help address 2nd delay in maternal mortality (reaching facility).' },
  { topic:'community', q:'Which organization publishes the World Health Statistics annually?', opts:['UNICEF','WHO (World Health Organization) - annual report with health data from all member states','World Bank','IMF'], ans:1, expl:'World Health Statistics: published annually by WHO. Contains health-related SDG indicators, mortality data, morbidity, health systems, risk factors for all 194 member states. Other key WHO publications: World Health Report (major report on global health), Global Health Observatory (GHO - online database), World Malaria Report (annual), Global TB Report (annual), State of the World\'s Nursing (2020). UNICEF: State of World\'s Children. World Bank: World Development Report. UNDP: Human Development Report.' },
  { topic:'community', q:'The Poshan Tracker (formerly ICDS-CAS - Common Application Software) is a digital tool for:', opts:['Hospital management','Real-time monitoring of ICDS services and nutritional status at Anganwadi Centre level - tracks weight, height, immunisation, supplementary nutrition, VHND activities','Prescription writing','Disease surveillance only'], ans:1, expl:'Poshan Tracker (formerly ICDS-CAS, renamed 2021): mobile app + web platform for AWW. Tracks: growth monitoring (weight, height, MUAC of children), immunisation status, beneficiary registration (pregnant, lactating, children), supplementary nutrition distribution, home visits, VHND activities. Real-time data visible to supervisors, district, state, national levels. Supports POSHAN Abhiyaan evidence-based targeting. Over 1.4 lakh AWCs using Poshan Tracker. Reduces paper registers, enables timely intervention.' },
  { topic:'programs', q:'Pradhan Mantri Awas Yojana (PMAY) has health significance because:', opts:['Provides medical care','Housing is a key social determinant of health - poor housing linked to TB, respiratory infections, malnutrition, mental health issues. PMAY provides affordable housing to urban and rural poor.','Provides nutritional supplements','Provides health insurance'], ans:1, expl:'Housing as SDH: Inadequate housing → TB spread (overcrowding, poor ventilation), respiratory diseases, injuries (unsafe structures), mental stress, lead paint poisoning (old buildings), malnutrition (no cooking space/safe water), rodent/insect exposure. PMAY-Gramin (2016): rural housing (pucca house with toilet + cooking space - LPG connection under PMUY). PMAY-Urban (2015): urban affordable housing. Together: directly improve living conditions, reduce disease burden. PMAY + SBM (toilet) + PMUY (LPG) = synergistic health improvement.' },
  { topic:'community', q:'The WASH (Water, Sanitation, Hygiene) and nutrition linkage: how does WASH affect nutritional status?', opts:['No relationship','Poor WASH leads to diarrhoea and intestinal parasites → impairs nutrient absorption → malnutrition (environmental enteric dysfunction) - WASH is essential for nutrition programs to succeed','WASH only affects hydration, not nutrition','Only affects Vitamin D status'], ans:1, expl:'WASH-Nutrition nexus: (1) Diarrhoea (poor WASH) → impairs nutrient absorption → malnutrition. (2) Intestinal parasites (hookworm - blood loss → iron deficiency anaemia; Ascaris - nutrient competition). (3) Environmental Enteric Dysfunction (EED): chronic exposure to faecal pathogens → sub-clinical gut inflammation → malabsorption → stunting despite adequate dietary intake. (4) Safe food preparation (hygiene): prevents foodborne illness. POSHAN Abhiyaan: includes WASH component. "Wash your hands" before feeding child.' },
  { topic:'anatomy', q:'The cranial nerve responsible for hearing is:', opts:['CN V (Trigeminal)','CN VII (Facial)','CN VIII (Vestibulocochlear/Auditory nerve)','CN IX (Glossopharyngeal)'], ans:2, expl:'CN VIII (Vestibulocochlear / Auditory / Acoustic nerve): two divisions. Cochlear division: hearing (cochlea → CN VIII → cochlear nuclei → auditory cortex, superior temporal gyrus). Vestibular division: balance (semicircular canals, utricle, saccule → CN VIII → vestibular nuclei → cerebellum). Lesion: sensorineural hearing loss, tinnitus, vertigo. Acoustic neuroma (vestibular schwannoma): tumour of CN VIII, presents with progressive unilateral sensorineural deafness, tinnitus, balance issues.' },
  { topic:'anatomy', q:'The largest gland in the body is:', opts:['Thyroid gland','Adrenal gland','Liver (largest gland, approximately 1.5 kg)','Pancreas'], ans:2, expl:'Liver: largest gland AND largest internal organ (approximately 1.5 kg, right upper quadrant). Functions: (1) Metabolism (glucose, lipids, proteins). (2) Detoxification (drugs, alcohol, bilirubin). (3) Synthesis (clotting factors, albumin, globulins). (4) Bile production (bile salts for fat digestion). (5) Storage (glycogen, Vitamin B12, fat-soluble vitamins A,D,K, iron). (6) Immune function (Kupffer cells). (7) Haematopoiesis (fetal life). Liver disease: hepatitis → cirrhosis → portal hypertension → liver failure.' },
  { topic:'anatomy', q:'The term "orthopnoea" describes:', opts:['Dyspnoea at rest','Dyspnoea that occurs only when lying flat and is relieved by sitting up (due to increased preload and reduced FRC in supine position - classic symptom of left heart failure)','Dyspnoea on exertion only','Dyspnoea at night'], ans:1, expl:'Orthopnoea: dyspnoea in recumbent position, relieved by sitting/standing. Mechanism: lying flat → increased venous return → increased preload → pulmonary congestion in already failing left ventricle. Also: supine position reduces FRC (functional residual capacity) due to diaphragm rising. Graded by number of pillows needed: 2-pillow orthopnoea = moderate LVF. Paroxysmal Nocturnal Dyspnoea (PND): wakes from sleep 1-3 hours after lying down - relieved sitting. Both: cardinal symptoms of left heart failure.' },
  { topic:'nursing', q:'Which route of medication administration has the fastest absorption and onset of action?', opts:['Oral (PO)','Sublingual (SL)','Intravenous (IV) - drug directly enters bloodstream, no absorption barrier','Intramuscular (IM)'], ans:2, expl:'Speed of onset by route: IV (intravenous) = fastest (0-1 min, directly into bloodstream, no absorption step). Inhalation: 2-3 min (lungs). Sublingual: 3-5 min (under tongue, directly into sublingual veins, bypasses first-pass). Intramuscular: 10-30 min (absorbed from muscle capillaries). Subcutaneous: 15-45 min. Oral: 30-90 min (absorbed from GI tract, first-pass hepatic metabolism). Rectal/topical: variable. Transdermal: hours (patch systems - fentanyl, nicotine, GTN).' },
  { topic:'community', q:'Which year was the National Rural Health Mission (NRHM) launched in India?', opts:['2000','2002','2005','2008'], ans:2, expl:'NRHM (National Rural Health Mission): launched 5 April 2005 by PM Manmohan Singh. Duration: 2005-2012 (extended to 2017, then merged into NHM). Focus states: 18 states with weak health indicators (including J&K, NE states, Bihar, UP, MP, Rajasthan, Odisha). Key innovations: ASHA programme, untied funds (VHSNCs, PHCs, CHCs), community monitoring, flexible pool funding through PIPs, mobile medical units, Janani Suraksha Yojana (JSY). Reduced MMR from 303 to 167 during NRHM period.' },
  { topic:'community', q:'Pulse polio immunisation day (National Immunisation Day - NID) was started in India in:', opts:['1985','1995','2000','2010'], ans:1, expl:'Pulse Polio Programme (National Immunisation Day - NID): launched in India in 1995. Children under 5 years given 2 drops of OPV regardless of previous vaccination status (zero-dose counts). Two rounds per year (usually January and February). Sub-National Immunisation Days (SNIDs): in high-risk states. Mop-up: house-to-house vaccination in areas with missed children. India declared POLIO-FREE by WHO on 27 March 2014 (last case: January 2011, Howrah, WB). WHO Wild Polio Type 2 eradicated 1999; Type 3 eradicated 2019.' },
  { topic:'community', q:'India was certified free from Guinea worm disease (Dracunculiasis) in:', opts:['1995','2000','2000 (India certified elimination of guinea worm - 1997 last case)','2010'], ans:2, expl:'Guinea worm disease (Dracunculiasis - Dracunculus medinensis): waterborne parasitic disease. India: last case in 1996 (Rajasthan). India certified guinea worm free: 2000 (WHO/Carter Center). Global eradication campaign: 3.5 million cases in 1986 → fewer than 15 cases/year now (2022-23). Remaining: Chad (most cases), Cameroon, Ethiopia, South Sudan, Mali. No vaccine, no drug - prevention only: drinking water filtration through fine cloth, treating water sources. Carter Center: leads global eradication effort.' },
  { topic:'community', q:'The primary data collection method in Village Health Nutrition Day (VHND) monitoring is:', opts:['Hospital records only','Register maintained at Anganwadi Centre + supervisory visits by LHV/ANM supervisor to verify VHND quality','National surveys only','Police records'], ans:1, expl:'VHND monitoring: Anganwadi Register (attendance, services provided, beneficiaries). ANM/LHV Supervisory visit: monthly to verify VHND quality (services checklist, beneficiary feedback). ASHA reports: HBNC visit records. District reporting through HMIS and Poshan Tracker. Mother and Child Tracking System (MCTS): tracks individual mothers and children. Community Score Card (CSC) or social audit: community participation in assessing health service quality. VHSNC: community oversight.' },
  { topic:'stats', q:'A screening test has sensitivity 95% and specificity 90% in a population where disease prevalence is 5%. Calculate approximate PPV:', opts:['95%','33%','50%','75%'], ans:1, expl:'Calculation: Population = 10,000. Disease prevalence 5% = 500 cases, 9500 non-cases. Sensitivity 95%: 500 x 0.95 = 475 TP, 25 FN. Specificity 90%: 9500 x 0.90 = 8550 TN, but 9500 x 0.10 = 950 FP. PPV = TP/(TP+FP) = 475/(475+950) = 475/1425 = 33.3% approximately. Despite 95% sensitivity and 90% specificity, PPV is only 33% because prevalence is low (5%). Most positive test results are false positives (950 FP vs 475 TP). NPV = 8550/(8550+25) = 99.7% (high because low prevalence).' },
  { topic:'stats', q:'The NNT (Number Needed to Treat) for a drug that reduces absolute risk of heart attack from 10% to 7% is:', opts:['3','33','100','0.03'], ans:1, expl:'NNT calculation: ARR (Absolute Risk Reduction) = Control rate - Treatment rate = 10% - 7% = 3% = 0.03. NNT = 1/ARR = 1/0.03 = 33.3 ~ 33. Interpretation: Need to treat 33 patients for 1 year to prevent 1 heart attack. RRR (Relative Risk Reduction) = ARR/Control rate = 3%/10% = 30% (seems impressive, but NNT of 33 tells clinical meaningfulness). Always calculate NNT alongside RRR for clinical decision-making. NNH (Number Needed to Harm) = 1/Absolute Risk Increase.' },
  { topic:'programs', q:'The Elimination of Mother-to-Child Transmission (EMTCT) of HIV and syphilis targets:', opts:['Zero HIV cases globally','Reduce MTCT of HIV to <50 cases/100,000 live births AND syphilis to <50 cases/100,000 live births (WHO dual elimination targets)','Zero syphilis cases globally','Only improve HIV testing coverage'], ans:1, expl:'WHO EMTCT criteria (dual elimination of HIV and congenital syphilis): (1) HIV MTCT rate <50 per 100,000 live births AND MTCT rate <2% (breastfeeding) or <5% (no breastfeeding). (2) Syphilis: incidence <50 cases per 100,000 live births. (3) Both: >95% ANC coverage, >95% HIV/syphilis testing in ANC, >95% treatment of positive women. India: working towards dual elimination. Cuba (2015): first country to achieve EMTCT dual elimination.' },
  { topic:'community', q:'HBNC (Home-Based Newborn Care) by ASHA is NOT a substitute for:', opts:['Village health nutrition day','Institutional delivery, essential newborn care at birth by skilled attendant, and timely referral of danger signs (ASHA refers but cannot treat serious conditions)','Home follow-up visits','Counselling of mother'], ans:1, expl:'HBNC limitations: ASHA can visit at home, assess, counsel, and refer - but CANNOT replace: (1) Skilled birth attendant at delivery (SBA: trained ANM/doctor for normal delivery; FRU for complications). (2) Essential Newborn Care (ENC): immediately after birth - warm, dry, skin-to-skin, delayed cord clamping, exclusive breastfeeding within 1 hour (best done at facility). (3) Medical treatment for PSBI (possible serious bacterial infection), LBW care, jaundice management. HBNC: follow-up, early detection, referral support.' },
  { topic:'anatomy', q:'The normal erythrocyte sedimentation rate (ESR) for adult males is:', opts:['0-5 mm/hour','0-20 mm/hour (males); 0-30 mm/hour (females)','40-60 mm/hour','80-100 mm/hour'], ans:1, expl:'ESR (Westergren method): Males: 0-20 mm/hour; Females: 0-30 mm/hour; Elderly: higher (males <age/2; females <(age+10)/2). ESR measures rate of RBC sedimentation in plasma. Elevated in: inflammation (acute + chronic), infection, malignancy, anaemia, pregnancy, autoimmune (RA, SLE). Very high ESR (>100 mm/hour): temporal arteritis, multiple myeloma, septic arthritis. Low ESR: polycythaemia, sickle cell, severe liver disease. Non-specific marker - must be interpreted with clinical context.' },
  { topic:'anatomy', q:'The process of respiration controlled by the respiratory centre located in:', opts:['Cerebral cortex','Brainstem (medulla oblongata for basic rhythm + pons for fine-tuning)','Hypothalamus','Cerebellum'], ans:1, expl:'Respiratory centre: Medulla oblongata (primary control): pre-Botzinger complex (inspiratory rhythm generator), dorsal respiratory group (inspiration), ventral respiratory group (forceful expiration). Pons: apneustic centre (prolonged inspiration if damaged) and pneumotaxic centre (limits inspiration). Peripheral chemoreceptors: carotid and aortic bodies (respond to O2, CO2, pH). Central chemoreceptors: medulla (respond to CO2/pH in CSF). Voluntary control of breathing: cerebral cortex (can override brainstem temporarily).' },
  { topic:'anatomy', q:'Which type of muscle tissue is striated and under voluntary control?', opts:['Smooth muscle (visceral)','Cardiac muscle (striated, involuntary)','Skeletal muscle (striated, voluntary - under somatic nervous system control)','All muscle types'], ans:2, expl:'Muscle types: Skeletal muscle: striated (cross-striations from sarcomere arrangement), voluntary (somatic nervous system), multinucleate, fast contraction. Cardiac muscle: striated, involuntary (autonomic + intrinsic), intercalated discs (gap junctions for electrical coupling), uninucleate, can work as syncytium. Smooth muscle: non-striated (no sarcomeres), involuntary (autonomic), spindle-shaped, uninucleate - in GI tract, blood vessels, uterus, bronchi, urinary bladder. Actin and myosin: present in all muscle types.' },
  { topic:'nursing', q:'A patient with diabetes mellitus - foot care education should include:', opts:['Walk barefoot whenever possible','Cut toenails in curves following toe shape','Daily inspection of feet (especially between toes), wash and dry thoroughly, wear well-fitting socks and shoes, never go barefoot, cut toenails straight across, report any wounds/cuts to provider immediately','Soak feet in hot water daily'], ans:2, expl:'Diabetic foot care (preventing diabetic foot ulcers): (1) DAILY inspection (mirror for sole); look for cuts, blisters, calluses, colour changes, between toes. (2) Wash with mild soap, lukewarm water (test temperature with elbow), dry thoroughly especially between toes. (3) Moisturise (not between toes - fungal risk). (4) Toenails: cut straight across, not too short. (5) ALWAYS wear properly fitting footwear (no going barefoot). (6) No heating pads (reduced sensation). (7) Report any wound immediately (reduced healing). Charcot foot: neuropathic joint destruction.' },
  { topic:'nursing', q:'A diabetic patient presents with confusion, sweating, and blood glucose of 45 mg/dL. What is the PRIORITY action?', opts:['Give insulin immediately','Give 15g fast-acting carbohydrates if conscious (15-15 rule) OR 25 mL of 50% dextrose IV if unconscious (priority is glucose correction)','Check HbA1c first','Give glucocorticoids'], ans:1, expl:'Hypoglycaemia management (blood glucose <70 mg/dL with symptoms): If CONSCIOUS: 15g fast-acting carbs: 4 glucose tablets OR 150 mL fruit juice OR 15 mL honey OR regular (not diet) cola. Wait 15 minutes, recheck glucose. If still <70: repeat. When >70: give complex carbs/meal. If UNCONSCIOUS/cannot swallow: (1) 25-50 mL of 50% dextrose IV (fast, reliable). (2) Glucagon 1 mg IM/SC (if IV access unavailable). NEVER give anything by mouth to unconscious patient. DO NOT give insulin (will worsen).' },
  { topic:'community', q:'Neonatal mortality rate (NMR) in India as per NFHS-5 (2019-21) is approximately:', opts:['5/1000 live births','20/1000 live births (NMR = 24.9 in NFHS-5)','50/1000 live births','100/1000 live births'], ans:1, expl:'India NMR (NFHS-5, 2019-21): 24.9 per 1000 live births (neonatal period = first 28 days). Early NMR (first 7 days): ~18/1000. IMR (first year): 35.2/1000. Under-5 MR: 41.9/1000. NMR comprises ~67% of IMR (most infant deaths in first month). Leading causes of neonatal death: prematurity/LBW (35%), infections/sepsis (25%), birth asphyxia (25%). India interventions: HBNC (ASHA home visits), SNCU (Special Newborn Care Unit), Kangaroo Mother Care, IMNCI/IMAI protocol. Target: NMR <12/1000 by 2030.' },
  { topic:'community', q:'The international coding system for causes of death used in India is:', opts:['DSM-5','ICD (International Classification of Diseases) - currently ICD-10 for death certificates, transitioning to ICD-11','Medical Subject Headings (MeSH)','Snomed CT'], ans:1, expl:'ICD (International Classification of Diseases): WHO classification system for diseases, disorders, injuries, symptoms, causes of death. ICD-10: currently used for official death certificates and morbidity coding in India. ICD-11: adopted WHO 2018, India transitioning. Death certificate in India: Medical certification of cause of death (MCCD) uses ICD coding. MoRGI (Medical Registration of India) and SRS: track mortality data. Verbal autopsy: used where MCCD not available (rural deaths) - assigns probable ICD code based on family interview.' },
  { topic:'programs', q:'The "1000 days" concept in nutrition refers to:', opts:['First 1000 days of a programme','First 1000 days of life from conception to 2nd birthday - critical window for brain development and nutritional programming','1000 days of exclusive breastfeeding','1000 days of supplementary nutrition'], ans:1, expl:'First 1000 Days: from conception (day 1 of pregnancy) to child\'s 2nd birthday (~1000 days). Critical window for: brain development (80% brain size by age 2), linear growth, immune system development, metabolic programming (Barker hypothesis - early nutrition affects adult NCD risk). Nutrition during this period: maternal nutrition + exclusive breastfeeding 6 months + complementary feeding 6-24 months + micronutrients (IFA, Vitamin A, zinc). POSHAN Abhiyaan: centres on this 1000-day framework.' },
  { topic:'anatomy', q:'The normal menstrual blood loss per cycle is:', opts:['5-10 mL','30-80 mL','100-150 mL','200+ mL'], ans:1, expl:'Normal menstrual blood loss: 30-80 mL per cycle (average 40 mL). Duration: 3-7 days. Cycle length: 21-35 days (average 28 days). Menorrhagia (heavy menstrual bleeding): >80 mL/cycle (need to change pad/tampon more than hourly, or passing large clots). Causes: fibroids, endometrial polyps, coagulation disorders (von Willebrand disease), thyroid dysfunction, IUCD. Management: hormonal (OCP, progesterone, Mirena-LNG-IUS), tranexamic acid, NSAIDs, surgical (hysteroscopy, hysterectomy).' },
  { topic:'anatomy', q:'The main function of Vitamin B1 (thiamine) is:', opts:['Blood clotting','Coenzyme in carbohydrate metabolism (pyruvate dehydrogenase, alpha-ketoglutarate dehydrogenase, transketolase)','Night vision','Collagen synthesis'], ans:1, expl:'Thiamine (Vitamin B1): coenzyme in carbohydrate metabolism. Deficiency (in alcoholics, malnutrition): Dry Beri-beri: peripheral neuropathy (tingling, burning, sensory loss lower limbs). Wet Beri-beri: high-output cardiac failure, oedema. Wernicke\'s Encephalopathy: ophthalmoplegia, ataxia, confusion (emergency - give thiamine IV/IM before IV glucose in alcohol withdrawal). Korsakoff\'s Psychosis: anterograde amnesia, confabulation (chronic thiamine deficiency). Treatment: Thiamine 100 mg IV/IM.' },
  { topic:'community', q:'Entomological surveillance for malaria monitors:', opts:['Patient blood slides','Mosquito density, species, breeding sites, insecticide resistance, parasite infection rates in mosquitoes - guides vector control decisions','Only hospital cases','Only water quality'], ans:1, expl:'Malaria entomological surveillance: (1) Species identification and density (man biting rates, catching mosquitoes). (2) Breeding site mapping (larval surveys). (3) Insecticide resistance testing (before spraying campaigns). (4) Sporozoite/entomological inoculation rate (EIR) - how infectious mosquitoes are. Data used for: selecting correct insecticide for IRS/LLIN, timing of spraying, identifying high-transmission areas. WHO WHOPES (Pesticide Evaluation Scheme): recommends insecticides for public health use.' },
  { topic:'community', q:'Aarogya Setu app was launched in India primarily for:', opts:['Booking hospital appointments','COVID-19 contact tracing and health status alerts (digital contact tracing using Bluetooth and GPS)','Telemedicine consultations','Storing health records'], ans:1, expl:'Aarogya Setu app (launched April 2020 during COVID-19 pandemic): India\'s official digital contact tracing app. Uses Bluetooth and GPS to trace contacts of COVID-19 positive persons. Features: Self-assessment test, COVID statistics, E-pass, CoWIN vaccine registration integration, ABDM health records linkage (later). Privacy concerns raised: location data collection. Over 20 crore downloads. Part of India\'s tech-based COVID response. ABDM (Ayushman Bharat Digital Mission): broader digital health ecosystem.' },
  { topic:'programs', q:'NSSO (National Sample Survey Organisation) data on health is used for:', opts:['Individual patient management','Population-level estimates of health expenditure, morbidity, disability, nutritional status, healthcare utilisation - used for policy planning','Tracking individual vaccination','Issuing death certificates'], ans:1, expl:'NSSO (National Sample Survey Office, now NSO - National Statistical Office): conducts sample surveys. Key health-related rounds: 75th round (2017-18): Social Consumption: Health - healthcare utilisation, OOP expenditure, hospitalisation, disease burden. 52nd round (1995-96): first comprehensive health data. NSS data: estimates prevalence of morbidity (self-reported), healthcare-seeking patterns, OOP expenditure, private vs public sector utilisation, tribal health. Used for: National Health Accounts, policy planning, identifying underserved populations.' },

  /* ═══ BATCH H — FINAL 63 ═══ */
  { topic:'anatomy', q:'The normal menstrual cycle - which phase follows ovulation?', opts:['Follicular phase','Proliferative phase','Luteal phase (corpus luteum secretes progesterone for 12-14 days)','Menstrual phase'], ans:2, expl:'Menstrual cycle phases: Menstrual (days 1-5): shedding endometrium. Proliferative/Follicular (days 6-14): oestrogen from growing follicle thickens endometrium. OVULATION: day 14 (LH surge). Luteal/Secretory (days 15-28): corpus luteum secretes progesterone - endometrium becomes secretory (prepares for implantation). If no fertilisation: corpus luteum regresses → progesterone falls → menstruation. If fertilisation: hCG from trophoblast maintains corpus luteum until placenta takes over.' },
  { topic:'anatomy', q:'The lymph from the right side of the head, neck, right arm, and right side of thorax drains into:', opts:['Thoracic duct','Right lymphatic duct → right subclavian vein','Left subclavian vein directly','Superior vena cava directly'], ans:1, expl:'Right lymphatic duct: drains lymph from: right side of head and neck, right upper limb, right side of thorax. Empties into right subclavian vein at right jugulosubclavian junction. Thoracic duct: drains ALL OTHER lymph (left side of body, both legs, abdominal organs) → left subclavian vein. Clinical: chylothorax (leak of thoracic duct) after thoracic surgery causes milky pleural effusion. Right-sided chyle: from right lymphatic duct injury.' },
  { topic:'nursing', q:'The correct technique for venipuncture (blood collection) includes:', opts:['Apply tourniquet above site for entire duration','Apply tourniquet 4-5 cm above intended site, release tourniquet BEFORE removing needle (or within 1 minute to avoid haemoconcentration), apply firm pressure after','Never use tourniquet','Collect blood with patient lying down always'], ans:1, expl:'Venipuncture technique: (1) Assemble equipment. (2) Identify patient (2 identifiers). (3) Apply tourniquet 4-5 cm above site. (4) Select vein, cleanse with 70% alcohol (let dry). (5) Insert needle (15-30 degrees, bevel up). (6) RELEASE TOURNIQUET before or soon after blood flows. (7) Collect required volume. (8) Release tourniquet if still on, remove needle. (9) Apply firm pressure with gauze 2-3 minutes. (10) Label specimen immediately at bedside. Haemoconcentration: tourniquet >1 minute falsely concentrates blood results.' },
  { topic:'nursing', q:'In caring for a patient with a chest tube (intercostal drain), the nurse should:', opts:['Clamp the tube routinely','Keep the drainage system below the level of the patient\'s chest, ensure water seal is intact, check for fluctuation (tidaling) in water seal chamber, avoid dependent loops','Raise the drainage system above chest level','Milk the tube every hour'], ans:1, expl:'Chest tube (ICD) nursing care: (1) Keep drainage system BELOW chest level (gravity drainage). (2) Water seal: 2 cm water in water-seal chamber - prevents air entering pleural space. (3) Tidaling: water level fluctuates with breathing (rises on inspiration, falls on expiration) - confirms tube patent and in pleural space. No tidaling + drainage = possible blockage/kinking. (4) No dependent loops (pools drainage). (5) Do NOT clamp routinely (only during transport, tube change as ordered). (6) Measure and record drainage hourly in acute phase.' },
  { topic:'nursing', q:'Principles of wound irrigation include:', opts:['Use maximum pressure to remove debris','Use sterile normal saline, gentle pressure (8 psi = 35 mL syringe with 19G angiocath), warm to body temperature, irrigate from clean to dirty','Use tap water with high pressure','Irrigate wound once only'],  ans:1, expl:'Wound irrigation: (1) Sterile NS (preferred) or clean water (community settings). (2) Pressure: 8-15 psi optimal (35 mL syringe with 19G needle/angiocath OR 30-35 mL syringe alone). Too little: inadequate cleaning. Too much: traumatise tissue, drive bacteria deeper. (3) Warm to body temperature (35-37 degrees C) - prevents vasoconstriction. (4) Irrigate from least contaminated to most contaminated. (5) Continue until effluent clear. (6) Antimicrobial solutions (Dakin\'s, chlorhexidine): for infected wounds, with caution (cytotoxic to granulation tissue if too strong).' },
  { topic:'community', q:'The Germ theory contribution of Joseph Lister was:', opts:['Discovery of penicillin','Introduction of antiseptic surgery (carbolic acid/phenol spray in operating theatres - dramatically reducing post-operative mortality)','Development of vaccines','Discovery of bacteria'], ans:1, expl:'Joseph Lister (1827-1912): Father of Antiseptic Surgery. Applied Pasteur\'s germ theory to surgery. Used carbolic acid (phenol) spray on wounds, instruments, and in operating theatre (1867). Reduced post-operative mortality from 40-50% to <15%. Established principles of antisepsis (killing germs) and later asepsis (preventing germs). Robert Koch: discovered M. tuberculosis, V. cholerae. Alexander Fleming: penicillin (1928). Louis Pasteur: germ theory, vaccines, pasteurisation.' },
  { topic:'community', q:'The WHO SEARO (South-East Asia Regional Office) headquarters is in:', opts:['Geneva, Switzerland','New Delhi, India','Manila, Philippines','Cairo, Egypt'], ans:1, expl:'WHO Regional Offices: AFRO (African Region): Brazzaville, Congo. AMRO/PAHO (Americas): Washington DC, USA. SEARO (South-East Asia): New Delhi, India. EURO (Europe): Copenhagen, Denmark. EMRO (Eastern Mediterranean): Cairo, Egypt. WPRO (Western Pacific): Manila, Philippines. India is part of SEARO. SEARO member states: Bangladesh, Bhutan, DPR Korea, India, Indonesia, Maldives, Myanmar, Nepal, Sri Lanka, Thailand, Timor-Leste (11 countries).' },
  { topic:'community', q:'The Epidemiological basis of vaccination is based on:', opts:['Treating individual disease','Creating population immunity (herd immunity) to block transmission chains, protect unvaccinated individuals, eventually eliminate/eradicate pathogens','Only protecting rich populations','Only protecting high-risk individuals'], ans:1, expl:'Vaccination population benefit: Individual protection + Herd immunity (indirect protection of unvaccinated when high proportion immune - interrupts transmission chains). Herd immunity threshold varies: measles ~95%, polio ~85%, COVID-19 original strain ~60-70%. Population-level vaccination: eradication possible (smallpox - done), elimination possible (polio - close). Vaccine hesitancy: threatens herd immunity. WHO: vaccine hesitancy in top 10 health threats (2019).' },
  { topic:'stats', q:'In a normal distribution, what is the relationship between mean, median, and mode?', opts:['Mean > Median > Mode','Mean < Median < Mode','Mean = Median = Mode (all equal - symmetric bell curve)','No fixed relationship'], ans:2, expl:'Normal distribution: Perfectly symmetrical bell curve. Mean = Median = Mode (all equal, all at centre). Measures of central tendency are identical. This is the defining property. Positive (right) skew: tail extends right, Mean > Median > Mode. Negative (left) skew: tail extends left, Mean < Median < Mode. Standard deviation: describes spread. Kurtosis: describes height/flatness of distribution. Most biological variables approximately normally distributed (height, BP, IQ).' },
  { topic:'community', q:'Post-exposure prophylaxis (PEP) for HIV must be started within:', opts:['7 days of exposure','24 hours (ideally, within 72 hours maximum for greatest effectiveness)','5 days only','1 hour only'], ans:1, expl:'HIV PEP (Post-Exposure Prophylaxis): started ASAP, ideally within 2 hours, MAXIMUM 72 hours (3 days) after exposure. Effectiveness declines sharply after 72 hours. Duration: 28 days. Regimen: TDF + 3TC/FTC + RAL (raltegravir) or dolutegravir. Indications: occupational exposure (needlestick in healthcare), sexual assault, condom failure with high-risk partner. First assess risk level. HIV testing: at baseline, 4 weeks, 12 weeks after exposure. PrEP (Pre-Exposure Prophylaxis): TDF+FTC daily for HIV-negative high-risk individuals.' },
  { topic:'community', q:'Brucellosis (undulant fever) is transmitted to humans primarily through:', opts:['Mosquito bites','Consumption of unpasteurised milk/dairy products from infected animals (cattle, goats, sheep) or direct contact with infected animals/abortion products','Airborne route only','Contaminated water'], ans:1, expl:'Brucellosis (Brucella abortus/melitensis/suis/canis): zoonotic disease. Transmission: ingestion of raw/unpasteurised milk, cheese from infected animals (goats: B. melitensis most common globally, most virulent). Direct contact: handling infected animals, abortion products, blood (farmers, veterinarians, abattoir workers). Features: undulant (fluctuating) fever, sweats, fatigue, joint pains, orchitis, endocarditis. Treatment: Doxycycline + Rifampicin x 6 weeks. Prevention: pasteurisation, PPE for animal workers.' },
  { topic:'nursing', q:'When preparing a patient for colonoscopy, the nurse should:', opts:['Give food until 1 hour before','Administer bowel preparation (polyethylene glycol solution) the day before, clear liquid diet, explain procedure, ensure IV access, monitor for electrolyte imbalance','Give antibiotics for 3 days before','No preparation needed'], ans:1, expl:'Pre-colonoscopy preparation: (1) Bowel preparation: polyethylene glycol (PEG) solution (4 litres the day before OR split-dose) OR sodium phosphate. (2) Diet: clear liquids only for 24 hours before. (3) Nil by mouth 4-6 hours before (with sedation). (4) Consent. (5) IV access. (6) Monitor electrolytes (risk of hyponatraemia, volume overload with PEG). (7) Anticoagulants: discuss with physician (hold warfarin 5 days, LMWH 24 hours). Post-colonoscopy: monitor for perforation (abdominal pain, fever, bleeding), pass gas, avoid driving (sedation).' },
  { topic:'community', q:'Herd immunity concept - which of the following diseases requires the HIGHEST vaccination coverage for herd immunity?', opts:['Influenza (~60%)','Polio (~85%)','COVID-19 original (~70%)','Measles (~92-95%) - most contagious with highest R0'], ans:3, expl:'Measles: R0 (basic reproduction number) = 12-18 (most contagious of common childhood diseases). Requires 92-95% vaccination coverage for herd immunity. Polio: R0 5-7, threshold 80-85%. Mumps: R0 4-7, threshold 75-86%. Rubella: R0 5-7, threshold 83-85%. Influenza: R0 2-3, threshold 33-44%. COVID-19 original strain: R0 2-4, threshold 50-70%. Delta variant: R0 5-6, much higher threshold. Herd immunity threshold = 1 - (1/R0).' },
  { topic:'community', q:'In school health programme, the mid-day meal (PM POSHAN) caloric content for upper primary (Classes 6-8) is:', opts:['300 kcal and 8g protein','450 kcal and 12g protein','700 kcal and 20g protein','1000 kcal and 30g protein'], ans:2, expl:'PM POSHAN (MDM) caloric norms: Primary (Classes 1-5): 450 kcal + 12g protein. Upper Primary (Classes 6-8): 700 kcal + 20g protein. Menu: cereals (rice/wheat), pulses, vegetables, sometimes egg/meat/fish. Micronutrient fortification (iron, folic acid, Vitamin A) in fortified salt, oil, flour. School feeding: increases enrolment, attendance, retention, reduces dropout (especially girls). India: world\'s largest school meal programme. Teachers not to cook or serve (kitchen staff).' },
  { topic:'community', q:'National Population Policy 2000 long-term objective is:', opts:['Achieve zero population growth','Achieve stable population at a level consistent with sustainable development by 2045','Reduce population to 500 million','Forced sterilisation for large families'], ans:1, expl:'NPP 2000 objectives: Immediate (7 years): address unmet contraceptive needs. Medium-term (by 2010): achieve TFR 2.1. Long-term (by 2045): stable population consistent with sustainable economic growth, social development, environmental protection. India\'s population: 1.4 billion (2023), projected to peak at 1.7 billion around 2060-2065 then stabilise. Population stabilisation: through voluntary family planning, female education, empowerment, not coercive measures.' },
  { topic:'nursing', q:'The SBAR tool for clinical handover stands for:', opts:['Symptoms, Background, Assessment, Recommendations','Situation (what is happening), Background (context/history), Assessment (what nurse thinks is the problem), Recommendation (what is needed)','Safe, Brief, Accurate, Responsive','Status, Breathing, Airway, Resuscitation'], ans:1, expl:'SBAR (Situation, Background, Assessment, Recommendation): standardised communication tool for clinical handover. S (Situation): "I am calling about Patient X in Room Y. The current situation is..." B (Background): "Patient was admitted for... Past history includes..." A (Assessment): "I think the problem is... I am concerned because..." R (Recommendation): "I would like you to... I need you to..." Reduces communication errors at handover. Used between nurses (shift change), nurse to doctor calls, between units/hospitals. Joint Commission: recommends SBAR for handover.' },
  { topic:'community', q:'The ratio of doctors to population recommended by WHO is:', opts:['1:5,000','1:10,000','At least 44.5 health workers (doctors + nurses + midwives) per 10,000 population','1:1,000'], ans:2, expl:'WHO health workforce threshold: 44.5 health workers per 10,000 population (doctors + nurses/midwives combined) for achieving UHC health coverage targets. India (2021): approximately 26 doctors + nurses per 10,000 (below threshold). Doctor-population ratio in India: approximately 1:1456 (all registered doctors), but rural ratio much worse. Rural health workforce shortage: specialist gap at CHCs (73-88% vacancy). Task-shifting: AYUSH practitioners, CHOs fill gaps in primary care. ANM: keystone of rural MCH services.' },
  { topic:'community', q:'IEC (Information, Education, Communication) materials used in health programs include:', opts:['Surgical instruments only','Pamphlets, posters, flip charts, audio-visual aids, street plays (nukkad natak), folk media, radio/TV programs, mobile SMS - multiple formats for different audiences','Only printed newspapers','Only television broadcasts'], ans:1, expl:'IEC materials in health: Printed: pamphlets (leaflets), brochures, posters, flip charts, booklets. Audio-visual: films, documentaries, videos. Electronic media: radio (community/national), TV, social media, mobile health (mHealth, SMS). Interpersonal: counselling cards, demonstration kits. Folk/Traditional: nukkad natak (street play), puppet shows, song and drama, folk songs (Nirogi Haryana, Bihar health songs). Development of IEC: message development (SBCC), pre-testing with target audience, appropriate language, cultural sensitivity.' },
  { topic:'nursing', q:'Glasgow Coma Scale motor response - "withdraws" from pain scores:', opts:['M1 (no response)','M2 (extension posturing)','M3 (abnormal flexion)','M4 (withdrawal - pulls away from painful stimulus)'], ans:3, expl:'GCS Motor responses: M1 = No response to pain. M2 = Abnormal extension (decerebrate - elbows extend, wrists pronate - damage below midbrain). M3 = Abnormal flexion (decorticate - elbows flex, wrists flex - damage above midbrain). M4 = Withdrawal (pulls limb away from pain, normal response). M5 = Localises to pain (moves hand toward stimulus). M6 = Obeys commands ("squeeze my hand, wiggle your toes"). M4-M6: improving prognosis. M1-M3: poor prognosis.' },
  { topic:'community', q:'Rapid Diagnostic Test (RDT) for malaria detects:', opts:['Parasite DNA only','Malaria parasite antigens (HRP-2 for P. falciparum, pLDH or aldolase for other species) in a finger-prick blood sample','Malaria antibodies in serum','Complete blood count only'], ans:1, expl:'Malaria RDT: point-of-care immunochromatographic test. Detects malaria parasite antigens: HRP-2 (Histidine-rich protein 2): specific for P. falciparum. pLDH (plasmodium lactate dehydrogenase): detects all species. Aldolase: all species. Bivalent RDT: detects falciparum (HRP-2) + non-falciparum (pLDH) simultaneously. Advantages: no microscope needed, quick result (15-20 min), field-friendly. Limitations: cannot determine parasite density, HRP-2 deletions cause false-negative (pfhrp2 deletions). Gold standard: microscopy.' },
  { topic:'nursing', q:'Which nursing intervention reduces the risk of aspiration in an unconscious patient?', opts:['Keep patient supine (flat on back) for comfort','Lateral (recovery) position and elevating head of bed 30-45 degrees, regular oral suctioning, avoid oral feeds until gag reflex confirmed','Give oral fluids every 2 hours','Lie face down (prone position)'], ans:1, expl:'Aspiration prevention in unconscious/dysphagic patient: (1) Lateral/semi-prone position (prevents aspiration of oral secretions and vomit). (2) Head of bed elevation 30-45 degrees (especially during NG feeds). (3) Regular oral suctioning (remove secretions before they accumulate). (4) Oral care (reduce bacterial load in mouth). (5) Assess gag reflex before oral intake. (6) If NG feeding: check gastric residual volumes, check tube position. (7) NPO if gag/swallow absent, arrange SLT (speech and language therapy) assessment. Aspiration pneumonia: most preventable HAI.' },
  { topic:'community', q:'Maternal near-miss (MNM) event is defined as:', opts:['Maternal death','A woman who nearly died but survived a severe acute maternal complication (organ dysfunction/failure) during pregnancy, childbirth or within 42 days of termination','Normal delivery with complications','Anaemia in pregnancy'], ans:1, expl:'Maternal Near-Miss (MNM): WHO 2009 definition - woman who survived life-threatening condition during pregnancy/childbirth/42 days. Criteria: one of 12 life-threatening conditions (organ dysfunction/failure markers). Examples: severe pre-eclampsia/eclampsia, severe haemorrhage, septic shock, severe anaemia (Hb <6 g/dL), cardiac failure, renal failure. MNM surveillance: identifies near-deaths + deaths to analyse quality of care. Near-miss to death ratio: indicator of quality (higher ratio = more near-misses surviving = better quality care). L2MNS: Level-2 Maternal Near-miss Surveillance in India.' },
  { topic:'community', q:'Safe abortion services in India are governed by:', opts:['Consumer Protection Act','Medical Termination of Pregnancy (MTP) Act 1971 (amended 2021) - legal abortions up to 24 weeks with conditions','Prevention of Immoral Trafficking Act','Indian Penal Code Section 302'], ans:1, expl:'MTP Act 1971 (amended 2021): Permits legal abortion by qualified doctors. Duration: up to 20 weeks (single doctor opinion), 20-24 weeks (2 doctors opinion) for special categories: survivors of rape/sexual assault, minors, differently-abled, mentally ill, fetal anomalies incompatible with life. Court permission: beyond 24 weeks. Special category expanded by 2021 amendment to include unmarried women (all women, not just married). Pre-abortion: no mandatory waiting period, informed consent. Not permissible for sex selection.' },
  { topic:'nursing', q:'In hospital infection control, the MOST effective single measure to prevent healthcare-associated infections (HAIs) is:', opts:['Wearing gloves always','Using sterile equipment only','HAND HYGIENE (hand washing/alcohol rub) - recommended by WHO as most effective single intervention','Wearing N95 masks at all times'], ans:2, expl:'Hand hygiene: single MOST effective measure to prevent HAIs. WHO 5 Moments. Alcohol-based hand rub (ABHR): preferred when hands not visibly soiled (kills 99.9% organisms in 20-30 seconds). Soap and water: mandatory for visibly soiled hands, C. difficile (spores not killed by alcohol). Healthcare workers\' compliance: 40-60% in studies (poor). Monitoring: direct observation, product consumption. HAI impact: 10% hospitalised patients in developing countries get HAI. WHO Global Patient Safety Challenge "Clean Care is Safer Care" (2005).' },
  { topic:'programs', q:'The Maternal Death Review (MDR) process in India aims to:', opts:['Punish healthcare providers for maternal deaths','Identify causes of maternal death and contributing factors to improve quality of care and prevent future deaths','Count maternal deaths only for statistics','Provide compensation to families'], ans:1, expl:'Maternal Death Review (MDR): systematic review of every maternal death (within facility and community). Three types: Verbal autopsy (community-based - interview family), Facility-based review (facility review committee), Confidential enquiry (state/national level). Process: identify the death, collect information, review by multi-disciplinary team, identify avoidable factors and substandard care, recommend corrective actions, implement, monitor. Maternal Death Surveillance and Response (MDSR): broader system including community deaths. Blameless, no punitive intent - learning exercise.' },
  { topic:'community', q:'The Declaration of Astana 2018 (Global Conference on PHC) reaffirmed which principle?', opts:['Focus on hospital-based care','Primary Health Care as the cornerstone of Universal Health Coverage and the Sustainable Development Goals - reaffirmed Alma Ata principles for the 40th anniversary','Elimination of community health workers','Privatisation of health services'], ans:1, expl:'Declaration of Astana 2018 (Astana, Kazakhstan - exactly 40 years after Alma Ata): reaffirmed PHC as cornerstone of UHC and achievement of SDGs. Key commitments: PHC as the most inclusive, equitable, cost-effective approach. Bold commitments on: multi-sectoral action (SDH), empowered people/communities, strengthened PHC function, UHC. Addressed criticism that Alma Ata\'s "Health for All by 2000" failed - renewed commitment. India: reaffirmed through Ayushman Bharat (HWC + PM-JAY).' },
  { topic:'anatomy', q:'The peritoneum is:', opts:['The membrane covering the heart','The serous membrane lining the abdominal cavity (parietal peritoneum - lines wall) and covering abdominal organs (visceral peritoneum)','The membrane covering the lung','The membrane covering the brain'], ans:1, expl:'Peritoneum: serous membrane (mesothelial cells on connective tissue) of abdominal and pelvic cavity. Parietal: lines inner surface of abdominal wall and pelvis. Visceral: covers abdominal organs (mesenteric attachments). Peritoneal cavity: potential space between parietal and visceral (normally small amount of fluid). Peritonitis: inflammation (bacteria, chemical). Ascites: fluid accumulation (portal hypertension, cancer, hypoalbuminaemia). Mesentery: double fold of peritoneum attaching intestine to posterior abdominal wall, carries blood vessels/nerves.' },
  { topic:'anatomy', q:'The appendicular skeleton consists of:', opts:['Skull, vertebrae, ribs, sternum','Bones of upper and lower limbs + pectoral and pelvic girdles (126 bones)','Only the legs and arms','Only the pelvic girdle'], ans:1, expl:'Appendicular skeleton (126 bones): Pectoral girdle (4 bones: 2 clavicles + 2 scapulae), Upper limbs (60 bones: 30 each - humerus, radius, ulna, 8 carpals, 5 metacarpals, 14 phalanges), Pelvic girdle (2 hip bones - each = ilium + ischium + pubis), Lower limbs (60 bones: 30 each - femur, patella, tibia, fibula, 7 tarsals, 5 metatarsals, 14 phalanges). Axial skeleton: 80 bones (skull 22, vertebrae 26, sternum 1, ribs 24, hyoid 1, ossicles 6).' },
  { topic:'community', q:'Village Health and Nutrition Day (VHND) services provided to adolescent girls include:', opts:['Nothing specific for adolescents','IFA tablets (Weekly Iron Folic Acid Supplementation - WIFS), deworming, nutrition counselling, health education on menstrual hygiene, anaemia screening','Vaccination only','Delivery services'], ans:1, expl:'VHND services for adolescent girls: WIFS (Weekly Iron Folic Acid Supplementation): IFA large tablet (60 mg iron + 500 mcg FA) weekly for all girls 10-19 years, adolescent boys in select states. Biannual Albendazole (deworming). Nutrition counselling (RKSK). Menstrual hygiene promotion (sanitary napkins under NHM). Anaemia screening (Hb by copper sulphate method or Sahli). Skin and hair care (scabies, ringworm). Growth monitoring for this age group at AFHC (Adolescent Friendly Health Clinics).' },
  { topic:'nursing', q:'Enteral nutrition (tube feeding) is PREFERRED over total parenteral nutrition (TPN) because:', opts:['Enteral is faster to administer','Enteral maintains gut integrity, reduces translocation of bacteria, maintains gut microbiome, fewer complications, cheaper, more physiological','TPN is more complete nutrition','Enteral requires no skills'], ans:1, expl:'"If the gut works, use it" principle. Enteral nutrition advantages over TPN: (1) Maintains gut mucosal integrity (prevents villous atrophy, reduces bacterial translocation from gut). (2) Maintains gut microbiome. (3) Stimulates bile/pancreatic secretions (prevents cholestasis). (4) Fewer metabolic complications (hyperglycaemia, electrolyte imbalance less severe). (5) Cheaper (TPN expensive). (6) Lower risk of central line infections (TPN requires central venous access). TPN: only when gut cannot be used (obstruction, ileus, post-GI surgery, short bowel syndrome).' },
  { topic:'programs', q:'Pradhan Mantri Jan Aushadhi Pariyojana (PMJAP) generic medicine stores are opened by:', opts:['Government directly','Individuals, NGOs, hospitals, government institutions can apply to open Jan Aushadhi Kendra (JAK) - supported by BPPI with setup assistance and stock','Only private pharmacies','Only AIIMS hospitals'], ans:1, expl:'PMBJP (Pradhan Mantri Bhartiya Janaushadhi Pariyojana): Bureau of Pharma PSUs of India (BPPI) under MoC&FPI implements. Jan Aushadhi Kendras (JAK) can be opened by: individuals, entrepreneurs, NGOs, hospitals, government/co-operative bodies, retired defence personnel. BPPI provides: Rs 2 lakh furniture/computer support, Rs 2.5 lakh medicine samples, marketing material. Medicines 50-90% cheaper than branded. Currently 10,000+ stores. 1750+ generic medicines, 285 surgical items. Targets: 25,000 stores by 2024-25.' },
  { topic:'community', q:'The term "syndromic surveillance" in IDSP refers to:', opts:['Lab-confirmed case reporting','Tracking symptoms (syndromes like acute diarrhoeal disease, fever with rash, fever with bleeding, acute respiratory illness) to detect outbreaks BEFORE lab diagnosis - faster early warning','Death reporting only','Insurance billing surveillance'], ans:1, expl:'Syndromic surveillance (S-form in IDSP): tracks clinical syndromes (not waiting for lab confirmation). 5 syndromes: Acute diarrhoeal disease/Diarrhoea with blood, Fever with rash, Acute respiratory illness, Fever with bleeding/haemorrhage, Acute flaccid paralysis (AFP). Reported weekly by community health workers, schools, drug shops to district. Triggers outbreak investigation. Faster than lab-confirmed surveillance. Limitations: non-specific (fever with rash = measles OR dengue OR many others - needs lab for confirmation). IDSP S-form + P-form (presumptive) + L-form (lab-confirmed).' },
  { topic:'community', q:'Cholera prevention and control at community level requires:', opts:['Only antibiotics for all contacts','Safe water supply, adequate sanitation (ODF), proper food hygiene, proper handwashing, prompt case management with ORS, and oral cholera vaccine in high-risk areas','Only vaccination','Only quarantine of cases'], ans:1, expl:'Cholera prevention: WASH is primary. Safe water: chlorination (free residual 0.2-0.5 mg/L), point-of-use water treatment (boiling, chlorine tablets, filtration). Sanitation: latrines, ODF (stop faecal-oral transmission). Food hygiene: cook food thoroughly, eat hot, wash fruits/vegetables, avoid raw seafood. Handwashing: after defecation, before eating/cooking. ORS: primary treatment (replaces fluid/electrolytes). Antibiotics (doxycycline/azithromycin): reduce severity/duration. Oral Cholera Vaccine (OCV): reactive vaccination in outbreak areas. Ring of immunity.' },
  { topic:'programs', q:'Which one of the following is NOT a function of an Anganwadi Worker (AWW)?', opts:['Supplementary nutrition distribution','Conducting deliveries (AWW is NOT trained for delivery - this is NOT her role)','Pre-school non-formal education','Immunisation mobilisation'], ans:1, expl:'AWW (Anganwadi Worker) roles (ICDS): Supplementary nutrition distribution, Pre-school education (3-6 years), Immunisation mobilisation and coordination with ANM, Nutrition and health education, Growth monitoring, Referral for sick children and pregnant women. What AWW does NOT do: Conduct deliveries (this is ANM\'s role at facility or skilled birth attendant - AWW is NOT trained for clinical procedures). AWW: paraprofessional selected from same village, Class 10 preferred, 3-month training. Not a healthcare provider for clinical services.' },
  { topic:'community', q:'Social vaccine concept refers to:', opts:['Immunisation against social diseases','Social determinants of health (education, income, empowerment) as "vaccines" against disease - addressing root causes just as vaccines address biological causes','Vaccination campaigns in schools','Community-based immunisation'], ans:1, expl:'Social vaccine (term coined by David Werner): educational empowerment, income, housing, food security, gender equity as "vaccines" against disease. Addresses WHY people get sick (social determinants) not just HOW they get sick (biological agents). Example: Female education → delayed marriage + improved child nutrition + healthcare seeking = reduces child mortality more than individual vaccines. Rudolf Virchow: "Medicine is a social science and politics is nothing else but medicine on a large scale" (1848). Primary health care: addresses social vaccine alongside biological vaccines.' },
  { topic:'drug', q:'Which drug class is used as first-line for management of type 2 diabetes mellitus in India?', opts:['Insulin (first-line)','Sulfonylureas (first-line)','Metformin (Biguanide) - first-line if no contraindications (reduces hepatic glucose production, improves insulin sensitivity)','DPP-4 inhibitors (first-line)'], ans:2, expl:'Type 2 DM management (India RSSDI/ADA guidelines): Metformin: first-line drug (reduces hepatic glucose output, improves insulin sensitivity, does not cause hypoglycaemia, weight-neutral, cardioprotective, cheap). Contraindications: eGFR <30, acute illness, IV contrast, alcohol excess. Added if HbA1c not controlled: SGLT-2 inhibitor (empagliflozin - CV/renal benefit), GLP-1 agonist, DPP-4 inhibitor, sulfonylurea. Insulin: usually added later (or first if symptomatic hyperglycaemia, HbA1c >10%). Lifestyle modification: always alongside medications.' },
  { topic:'drug', q:'Which drug is the antidote for benzodiazepine overdose?', opts:['Naloxone','Flumazenil (competitive antagonist at GABA-benzodiazepine receptor)','Atropine','Physostigmine'], ans:1, expl:'Flumazenil (Anexate): competitive antagonist at GABA-A benzodiazepine receptor binding site. Reverses: CNS depression, sedation, respiratory depression from benzodiazepines. Dose: 0.2 mg IV, repeat every minute up to 1 mg. Duration: 30-90 minutes (shorter than most benzodiazepines - may need repeated doses/infusion). Cautions: may precipitate seizures in benzodiazepine-dependent patients (acute withdrawal). Not routinely used for all BZD overdose (supportive care usually sufficient). Naloxone: opioids. Atropine: organophosphates.' },
  { topic:'anatomy', q:'The carotid body (chemoreceptor) located at the bifurcation of common carotid artery responds to:', opts:['Blood pressure changes','Decreased PaO2, increased PaCO2, and decreased pH (acidosis) - triggers increased respiratory rate','Temperature changes','Blood glucose changes'], ans:1, expl:'Carotid body (peripheral chemoreceptor): at carotid bifurcation (C4 level). Responds primarily to: PaO2 <60 mmHg (hypoxia), increased PaCO2, decreased pH (acidosis). Sends signals via CN IX (Glossopharyngeal) to respiratory centre in medulla. Aortic bodies (at aortic arch, CN X): similar function. Central chemoreceptors (medulla): respond mainly to CO2/pH in CSF. Carotid sinus: baroreceptor (blood pressure sensing), different structure adjacent to carotid body.' },
  { topic:'anatomy', q:'The nerve plexus that supplies the upper limb is:', opts:['Lumbar plexus','Sacral plexus','Brachial plexus (C5-T1 nerve roots)','Cervical plexus (C1-C4)'], ans:2, expl:'Brachial plexus: C5, C6, C7, C8, T1 nerve roots. Supplies all muscles and skin of upper limb. Major branches: Musculocutaneous (C5-7: biceps, coracobrachialis, brachialis), Radial (C5-T1: extensors of arm - wrist drop if damaged), Median (C6-T1: flexors, thenar muscles - "carpal tunnel syndrome" - ape hand), Ulnar (C8-T1: intrinsics - claw hand if damaged), Axillary (C5-6: deltoid - shoulder abduction). Erb\'s palsy: C5-6 injury (waiter\'s tip). Klumpke\'s palsy: C8-T1 injury (claw hand).' },
  { topic:'community', q:'The MIDLINE model for health communication stands for:', opts:['Middle, Interaction, Delivery, Learning, Implementation, Needs, Education','Message, Interests, Desire, Learning, Implementation, Needs, Evaluation - a framework for developing effective health communication campaigns','No standard expansion - not a widely used term','Ministry of Health Communication Framework'], ans:1, expl:'Health communication models for behaviour change: SBCC (Social and Behaviour Change Communication) frameworks used in India include: Information, Education, Communication (IEC). Behaviour Change Communication (BCC). Communication for Development (C4D). The MIDLINE is sometimes used for: Message development, Intended audience, Delivery channel, Learning (testing), Implementation, Needs assessment, Evaluation - though exact expansions vary. Social marketing 4Ps: Product, Price, Place, Promotion. Diffusion of Innovation (Rogers): innovators → early adopters → early majority → late majority → laggards.' },
  { topic:'community', q:'FMPHW (Female Multi-Purpose Health Worker) is the same as:', opts:['ASHA','AWW (Anganwadi Worker)','ANM (Auxiliary Nurse Midwife) - renamed in some states as FMPHW, core sub-centre health worker','Medical Officer'], ans:2, expl:'FMPHW (Female Multi-Purpose Health Worker) = ANM (Auxiliary Nurse Midwife): same cadre, different name used in different states/documentation. Core sub-centre health worker. Qualification: 18-month ANM diploma. Roles: Antenatal care, Immunisation (UIP), Family planning (IUD insertion, distribution of contraceptives), MCH services, RMNCH+A, disease surveillance, referral. Staff nurse with midwifery: different from ANM. MMPHW: Male Multi-Purpose Health Worker (MPW-M) - male counterpart at sub-centre, assists ANM with environmental health, vector control.' },
  { topic:'nursing', q:'In antenatal care, fundal height measurement in centimetres corresponds approximately to:', opts:['Weeks of gestation x 2','Weeks of gestation (in weeks) after 20 weeks - symphysis-fundal height in cm approximates gestational age in weeks','Months of gestation x 4','No relationship to gestational age'], ans:1, expl:'Symphysis-Fundal Height (SFH) measurement: from symphysis pubis to top of fundus. After 20 weeks: SFH in cm approximately equals gestational age in weeks (normal range: gestational age ± 3 cm). Example: at 28 weeks: SFH should be 25-31 cm. Below 10th percentile: IUGR suspected. Above 90th percentile: macrosomia, polyhydramnios, multiple pregnancy. McRobert\'s manoeuvre: shoulder dystocia. Measured at each ANC visit from 20 weeks. Calibrated tape, standing position.' },
  { topic:'community', q:'The concept of "PHC is Primary Not Primitive" emphasises that:', opts:['PHC provides simple, low-quality care','PHC is the FIRST CONTACT with the healthcare system, not inferior or basic - it should be comprehensive, integrated, and of high quality at community level','PHC is only for rural areas','PHC is temporary until proper hospitals are built'], ans:1, expl:'"PHC is primary, not primitive" (attributed to Halfdan Mahler, former WHO DG): Primary means FIRST POINT OF CONTACT, not rudimentary/inadequate care. PHC should be: comprehensive (preventive + promotive + curative + rehabilitative), continuous, coordinated, community-oriented, person-centred. Not just treating minor ailments. Strong PHC: backbone of health systems globally (UK NHS, Cuba, Thailand). India: Ayushman Bharat HWC - upgraded PHC to provide comprehensive primary care (12 service packages).' },
  { topic:'community', q:'Family Health Index (FHI) used in rural health survey assesses:', opts:['Only number of family members','Combined score of selected health indicators of a family (vaccination status, ORS use, antenatal care, family planning, nutrition) - used to assess health status of a community through family visits','Only economic status','Only housing conditions'], ans:1, expl:'Family Health Index (FHI): scoring tool used in community surveys (often by nursing/MPW students and health workers). Assesses 10 parameters of a family: Immunisation of children, ANC care, Institutional delivery, FP use, ORS for diarrhoea, Sanitary latrine, Safe drinking water, Nutrition (breastfeeding, complementary feeding), Vitamin A, Iron tablets. Each parameter scored 0-1. Total FHI = sum of scores. Used for: baseline survey of PHC area, prioritising interventions, comparing villages, monitoring progress of health activities.' },
  { topic:'community', q:'Non-Communicable Disease (NCD) surveillance in India tracks:', opts:['Only hospitalised NCD cases','Prevalence, risk factors (tobacco, alcohol, diet, physical inactivity, obesity, hypertension, blood glucose) at population level through NFHS, STEPS, ICMR-INDIAB surveys','Acute infectious disease outbreaks only','Vaccine-preventable diseases only'], ans:1, expl:'NCD surveillance India: NFHS: hypertension, diabetes, obesity, anaemia (population-level prevalence). WHO STEPwise approach (STEPS) surveys: standardised NCD risk factor surveys (Step 1: questionnaire; Step 2: physical measurements; Step 3: biochemical measurements). ICMR-INDIAB (India Diabetes): national diabetes prevalence. NPCDCS: screening at 30+ years at HWC. Cancer registry: NCRP (National Cancer Registry Programme) - population-based and hospital-based. Tobacco: Global Adult Tobacco Survey (GATS). CVD: Delhi registries. Mental health: NMHS (National Mental Health Survey) 2016.' },
  { topic:'nursing', q:'When changing a colostomy bag, the nurse should:', opts:['Change it once weekly only','Empty bag when 1/3-1/2 full, change the entire pouching system every 3-5 days, clean stoma gently, protect peristomal skin, measure stoma and cut flange to correct size (2-3 mm larger than stoma)','Apply antiseptic cream to stoma','Never empty the bag - always change the entire system'], ans:1, expl:'Colostomy care: (1) Empty bag when 1/3-1/2 full (prevents weight pulling flange off skin). (2) Change entire pouching system every 3-5 days (or when leaking/edges lifting). (3) Best time: 30 min after meals (peristalsis active - more effluent). (4) Clean stoma: warm water, soft cloth (no soap with irritants, no alcohol). (5) Dry skin thoroughly. (6) Measure stoma (oedema - stoma shrinks first 6-8 weeks post-op). (7) Cut flange 2-3 mm larger than stoma (prevent trauma). (8) Peristomal skin: protect with barrier cream/wipes (no faecal contact). (9) Observe stoma colour (should be red/pink and moist).' },
  { topic:'programs', q:'State-specific health scheme in J&K - which scheme provides health benefits to all government employees?', opts:['PM-JAY only','Government Medical Attendance (GMA) Rules for government employees - treated at government hospitals or reimbursed for private treatment; SEHAT Card extended to all J&K residents including govt employees','ESI only','CGHS only'], ans:1, expl:'J&K Government Employees: Government Medical Attendance (GMA) Rules: entitled to medical reimbursement for treatment at government hospitals (free) or reimbursement for authorised private treatment for certain specialist procedures. SEHAT (Social, Economic and Health Activities for Transformation) Card: launched Jan 2021, extended PM-JAY coverage to ALL J&K residents including government employees (Rs 5 lakh/family/year cashless treatment). Central government employees: CGHS (Central Government Health Scheme) also applies. Unique J&K: only state/UT with 100% population PM-JAY coverage.' },
  { topic:'nursing', q:'In a patient on mechanical ventilation, which assessment is most critical every 1-2 hours?', opts:['Blood glucose only','Airway patency + Ventilator settings confirmation + Bilateral breath sounds + SpO2 + ETCO2 + Sedation level + VAP prevention bundle compliance','Temperature only','Daily weight only'], ans:1, expl:'Ventilated patient monitoring: (1) Airway: confirm ETT position (cm marking at lip, bilateral breath sounds, CXR). (2) Ventilator: mode, rate, VT (tidal volume 6-8 mL/kg ideal body weight - lung protective), PEEP, FiO2, peak airway pressure. (3) SpO2 + ETCO2. (4) Sedation/analgesia (RASS scale - target RASS -2 to 0). (5) VAP prevention bundle: HOB 30-45 degrees, oral care with chlorhexidine, daily sedation holidays, spontaneous breathing trials, cuff pressure monitoring (25-30 cmH2O), sub-glottic suction. (6) Haemodynamic: BP, HR, CVP. Ventilator alarms: respond within 60 seconds.' },
  { topic:'community', q:'The National Programme for Family Planning and Reproductive Health in India currently emphasises:', opts:['Forced sterilisation targets','Rights-based, voluntary, informed choice of family planning methods - basket of choices, spacing methods prioritised, no coercion, no incentive/disincentive targets','Target-driven sterilisation camps','Only male sterilisation'], ans:1, expl:'India FP programme evolution: Post-1994 ICPD Cairo (International Conference on Population and Development): shift from demographic targets to rights-based approach. India removed explicit sterilisation targets (2005) - though in practice target pressure continues at field level. Current emphasis: basket of contraceptive choices (spacing methods: PPIUCD, IUCD, DMPA/MPA, OCPs, condoms, LAM, emergency contraception), informed choice, quality of care, no coercion. Male involvement. Assured contraceptive commodities. Saheli (centchroman/ormeloxifene): India-developed weekly non-steroidal OCP.' },
  { topic:'community', q:'The Gujjar and Bakarwal communities in J&K represent a unique health challenge because:', opts:['They are wealthy communities who don\'t need public health services','They are nomadic/semi-nomadic tribal communities with seasonal migration to high-altitude areas - requiring special outreach, mobile health services, and health scheme coverage during migration','They live only in cities','They have all health facilities readily accessible'], ans:1, expl:'Gujjar-Bakarwal health challenges (J&K tribal communities): Nomadic pastoral: migrate to high-altitude pastures (bugyals) in summer (May-Oct), return to lower areas in winter. Health access: seasonal inaccessibility, no fixed address (difficulty accessing JSY, JSSK), no formal education/literacy, language barrier (Gojri language). Pregnant women at high altitude: higher risk. Mobile health units (MHUs) under NHM reach them in transit. SEHAT card: attempt to provide universal coverage. PMJDY: financial inclusion. Tribal health action plan: J&K.' },
  { topic:'community', q:'Primary prevention of cardiovascular disease (CVD) at population level includes:', opts:['Only treating existing CVD patients','Tobacco cessation, healthy diet promotion, regular physical activity, sodium reduction, alcohol reduction, hypertension screening and control - addressing risk factors BEFORE disease occurs','Only prescribing statins to all adults','Only surgical interventions'], ans:1, expl:'CVD primary prevention (population + individual): Tobacco control (COTPA, cessation services). Healthy eating: reduce salt (<5 g/day WHO), trans fats, saturated fats; increase fruits/vegetables. Physical activity: 150 min/week moderate. Alcohol: reduce/avoid. Obesity prevention. Hypertension: screen + treat (<130/80 target). Diabetes: prevent/manage. WHO HEARTS: primary care CVD management. WHO SHAKE package (salt reduction), MPOWER (tobacco), SAFER (alcohol), ACTIVE (physical activity). India\'s National Programme: NPCDCS for NCD prevention at community level.' },
  { topic:'community', q:'The correct sequence of PHC tiers in India from community to facility level is:', opts:['Hospital > CHC > PHC > Sub-Centre > Community','Community/Village → ASHA/Sub-centre (ANM) → PHC (MO) → CHC (Specialists) → District Hospital → Medical College → National Institutes','PHC > Sub-Centre > CHC > Hospital','CHC > PHC > Hospital > Sub-Centre'], ans:1, expl:'Health system tiers in India: (1) Community: ASHA, AWW, village-level IEC. (2) Sub-centre (HWC): ANM + CHO, population 5000 (plains). (3) PHC (Health and Wellness Centre-PHC): MO + supporting staff, population 30,000. (4) CHC/Community Health Centre: 4 specialists + 30 beds, population 1,00,000. First Referral Unit (FRU): at CHC or District Hospital. (5) District Hospital: 100-500+ beds. (6) Medical College: tertiary care, teaching. (7) National Institutes: AIIMS, PGIMER, NIMHANS. Referral system: each level refers to next when beyond capacity. Free transport: 102/108.' },
  { topic:'anatomy', q:'The normal fasting blood glucose level in an adult is:', opts:['50–60 mg/dL','70–100 mg/dL','120–140 mg/dL','150–180 mg/dL'], ans:1, expl:'Normal fasting blood glucose: 70–100 mg/dL (3.9–5.6 mmol/L). Prediabetes (IFG): 100–125 mg/dL. Diabetes: ≥126 mg/dL on two occasions. Postprandial (2 h): normal <140, prediabetes 140–199, diabetes ≥200. HbA1c: normal <5.7%, prediabetes 5.7–6.4%, diabetes ≥6.5%. Hypoglycaemia: <70 mg/dL (Whipple triad: low glucose + symptoms + relief on glucose). Glucose regulated by insulin (lowers), glucagon (raises), cortisol, adrenaline.' },
  { topic:'nutrition', q:'Xerophthalmia is caused by deficiency of:', opts:['Vitamin C','Vitamin D','Vitamin A','Vitamin B12'], ans:2, expl:'Xerophthalmia (dry eye disease): Vitamin A deficiency. Stages: XN (night blindness), X1A (conjunctival xerosis), X1B (Bitot spots - foamy grey patches on conjunctiva), X2 (corneal xerosis), X3A (corneal ulceration <1/3), X3B (keratomalacia - >1/3, blinding). Prevention: Vitamin A supplementation (VASI): 9 months - 5 years, 1 lakh IU at 6 months, 2 lakh IU every 6 months. Postpartum: 2 lakh IU within 6 weeks. Rich dietary sources: liver, egg yolk, milk, orange/yellow vegetables (beta-carotene). Causes ~250,000-500,000 childhood blindness/year globally (WHO).' },
  { topic:'immunization', q:'The pentavalent vaccine given in UIP protects against how many diseases?', opts:['3','4','5','7'], ans:2, expl:'Pentavalent vaccine: 5 diseases in one injection. Covers: (1) Diphtheria, (2) Pertussis (whooping cough), (3) Tetanus — DPT component; (4) Hepatitis B; (5) Haemophilus influenzae type b (Hib) — meningitis, pneumonia. Schedule: 6, 10, 14 weeks. Introduced in India under UIP from 2011-12 (Kerala and Tamil Nadu first, rolled out nationally by 2015). Replaces separate DPT + Hep B + Hib injections. Given IM in anterolateral thigh. Cold chain: 2–8°C. Note: freeze-sensitive (do not freeze). India also gives fIPV (fractional inactivated polio vaccine) at same visit (intradermal 0.1 mL).' },
  { topic:'mch', q:'Exclusive breastfeeding (EBF) is recommended for how long?', opts:['First 2 months only','First 4 months','First 6 months','First 12 months'], ans:2, expl:'WHO/UNICEF/India recommendation: Exclusive breastfeeding for first 6 months (180 days) of life - no water, no other food, no other liquids (except medicines/vaccines if needed). Benefits: reduces diarrhoea, ARI, otitis media, SIDS, necrotising enterocolitis (in preterm), childhood obesity, maternal ovarian/breast cancer, type 2 diabetes. EBF rates India (NFHS-5): 63.7% - improved from 54.9% (NFHS-4). Complementary feeding begins at 6 months while breastfeeding continues to 2 years. LAM (Lactational Amenorrhoea Method): EBF + amenorrhoea + <6 months = 98% contraceptive efficacy.' },
  { topic:'mental', q:'The CAGE questionnaire is used for screening:', opts:['Depression','Anxiety disorder','Alcohol use disorder','Schizophrenia'], ans:2, expl:'CAGE questionnaire: 4 questions for alcohol use disorder screening. C - Cut down (ever felt need to cut down drinking?), A - Annoyed (been annoyed by people criticising drinking?), G - Guilty (ever felt guilty about drinking?), E - Eye-opener (ever needed drink first thing in morning?). Score ≥2: suggests alcohol use disorder (sensitivity ~71-74%, specificity ~79-90%). Other alcohol tools: AUDIT (Alcohol Use Disorders Identification Test - WHO, 10 questions), AUDIT-C (3 questions). For depression: PHQ-9 (Patient Health Questionnaire). Anxiety: GAD-7. India: National Mental Health Policy 2014, DMHP (District Mental Health Programme) under NMHP.' },
  { topic:'stats', q:'The p-value of 0.03 in a study with alpha set at 0.05 means:', opts:['The null hypothesis is proven true','The result is statistically significant - the probability of observing these results by chance alone is 3%, which is less than the 5% threshold','The study is clinically meaningless','The effect size is 3%'], ans:1, expl:'p-value interpretation: p = probability of getting the observed result (or more extreme) IF the null hypothesis (H0) were true. p = 0.03: only 3% probability this result occurred by chance (if H0 true). Since 0.03 < alpha (0.05), we REJECT H0 - result is statistically significant. Important: statistical significance ≠ clinical significance. A very large study can make trivially small differences statistically significant. Always report effect size (RR, OR, mean difference) + 95% CI alongside p-value. p-value does NOT tell us the probability that H0 is true or false. p > 0.05: fail to reject H0 (not the same as proving H0 true).' },
  { topic:'environment', q:'The permissible limit of fluoride in drinking water as per BIS/WHO is:', opts:['0.5 mg/L','1.0 mg/L','2.0 mg/L','5.0 mg/L'], ans:1, expl:'Fluoride in drinking water: WHO guideline: 1.5 mg/L. BIS (IS 10500:2012) permissible limit: 1.0 mg/L (desirable: 0.6-1.0 mg/L). Dental fluorosis: >1.5 mg/L long-term. Skeletal fluorosis (crippling): >4 mg/L. Dental caries prevention: 0.5-1.0 mg/L optimal. Fluorosis-endemic states India: Rajasthan, Andhra Pradesh, Telangana, Gujarat, Uttar Pradesh, Punjab. J&K: some areas with high natural fluoride. National Programme: Rajiv Gandhi National Drinking Water Mission. Defluoridation methods: Nalgonda technique (alum + lime), activated alumina, bone char. Fluoride monitoring: FTK (Field Test Kit).' },
  { topic:'firstaid', q:'The correct ratio of chest compressions to rescue breaths in adult CPR (single rescuer) is:', opts:['15:1','30:1','30:2','15:2'], ans:2, expl:'Adult CPR (AHA/ERC 2020 guidelines): 30 compressions : 2 rescue breaths (30:2). Compression depth: at least 5 cm (2 inches), not >6 cm. Rate: 100–120/min. Recoil: allow full chest recoil between compressions. Minimize interruptions. Hand position: heel of hand on lower half of sternum. 2 thumbs-encircling technique for infant CPR (professional rescuer). Infant/child CPR: 30:2 single rescuer, 15:2 two healthcare providers. CAB sequence: Compressions → Airway → Breathing (adults). For witnessed VF/VT: defibrillate ASAP (AED). Chain of survival: recognition → activation (112) → CPR → defibrillation → ACLS → recovery.' },
  { topic:'drug', q:'The antidote for organophosphorus (OP) poisoning is:', opts:['Naloxone','N-acetylcysteine','Atropine + Pralidoxime (PAM)','Flumazenil'], ans:2, expl:'OP poisoning antidote: Atropine + Pralidoxime (2-PAM). OP compounds (pesticides: malathion, chlorpyrifos; nerve agents: sarin) inhibit acetylcholinesterase → ACh accumulation. Muscarinic effects (SLUDGE/DUMBBELS): Salivation, Lacrimation, Urination, Defecation, GI cramps, Emesis. Nicotinic: muscle weakness, fasciculations, paralysis. CNS: seizures, coma. Treatment: (1) Atropine: blocks muscarinic receptors - large doses until secretions dry (endpoint: dry secretions, not heart rate). (2) Pralidoxime (2-PAM): reactivates cholinesterase if given early (before aging). (3) Diazepam: for seizures. (4) Supportive: airway, ventilation. Other antidotes: Naloxone (opioids), N-acetylcysteine (paracetamol), Flumazenil (benzodiazepines), Digoxin antibodies (digoxin toxicity).' },
  { topic:'programs', q:'The Mission Indradhanush programme aims to achieve what vaccination coverage target?', opts:['70% by 2020','90% full immunisation coverage by 2020 (subsequently extended)','50% by 2025','100% by 2030'], ans:1, expl:'Mission Indradhanush (MI): Launched September 2014. Target: ≥90% full immunisation coverage. Focus: children under 2 years + pregnant women missed by routine immunization. Named after rainbow (7 vaccines initially). Strategy: special immunization drives in low-coverage districts. Vaccines: BCG, OPV, DPT, Hep B, Measles (+ Rubella, JE, rotavirus, pneumococcal in select areas). Intensified Mission Indradhanush (IMI) 1.0, 2.0, 3.0, 4.0 — successive phases. IMI 5.0 (2023): targets <2 years + pregnant women. U-WIN (digital platform for immunisation tracking). India FIC (full immunisation coverage): NFHS-5: 76.4% (improved from 62% in NFHS-4).' },
  { topic:'nursing', q:'When administering an IM injection to an adult, the preferred site with lowest complication risk is:', opts:['Deltoid (always preferred)','Dorsogluteal (upper outer quadrant of buttock)','Ventrogluteal (von Hochstetter site)','Vastus lateralis only in infants'], ans:2, expl:'IM injection site safety (WHO/clinical evidence): Ventrogluteal site (von Hochstetter): SAFEST for adults. Located by placing palm on greater trochanter, index finger on ASIS, middle finger back toward iliac crest — injection in triangle formed. No major nerves or vessels. Dorsogluteal: avoid — risk of sciatic nerve injury, subcutaneous deposit in obese patients. Deltoid: small muscle, max 1 mL, risk of radial nerve injury if too low. Vastus lateralis: preferred in infants/toddlers (<3 years) and adults when other sites unavailable. Needle length: 38 mm (1.5 inch) for most adults IM; 25 mm for deltoid in lean adults. Z-track technique: reduces leakage, recommended for all IM injections.' },
  { topic:'community', q:'In India, the Integrated Child Development Services (ICDS) provides services through:', opts:['PHC doctors only','Anganwadi Centres (AWCs) staffed by Anganwadi Workers (AWW) + Anganwadi Helpers','Hospitals only','ASHA workers alone'], ans:1, expl:'ICDS (launched 1975, world\'s largest child development programme): Delivered through Anganwadi Centres. Beneficiaries: children 0-6 years + pregnant/lactating women. 6 services: (1) Supplementary nutrition (SNP) - THR/hot cooked meals. (2) Immunisation (linked with health dept). (3) Health check-up. (4) Referral services. (5) Pre-school non-formal education (3-6 yr). (6) Nutrition + health education (mothers). AWW: key functionary. AWH (Anganwadi Helper): assists AWW. Poshan Abhiyaan (PM Poshan Mission 2018): targets stunting, wasting, underweight, anaemia reduction. Poshan Tracker: digital monitoring. India NFHS-5 stunting: 35.5% (from 38.4% NFHS-4).' },
];

