function buildMockPaper(paper) {
  if (paper.qs) return paper.qs;
  const pool = [...QUESTIONS].sort(() => Math.random() - 0.5);
  paper.qs = pool.slice(0, Math.min(100, pool.length));
  return paper.qs;
}

