/* ──────────────────── PROGRESS ──────────────────── */
function renderProgress() {
  const { total, correct } = getTotals();
  const wrong = total - correct;
  const acc   = total ? Math.round(correct / total * 100) : 0;
  if (el('ps-total'))   el('ps-total').textContent   = total;
  if (el('ps-correct')) el('ps-correct').textContent = correct;
  if (el('ps-acc'))     el('ps-acc').textContent     = acc + '%';
  if (el('ps-streak'))  el('ps-streak').textContent  = bestStreak;
  if (el('ps-mocks'))   el('ps-mocks').textContent   = mockHistory.length;
  const weak   = TOPICS.filter(t => { const p = progress[t.id]; return p && p.attempted >= 3 && (p.correct / p.attempted) < 0.6; });
  const strong = TOPICS.filter(t => { const p = progress[t.id]; return p && p.attempted >= 3 && (p.correct / p.attempted) >= 0.8; });
  if (el('weak-list'))   el('weak-list').innerHTML   = weak.length
    ? weak.map(t => `<span class="area-tag weak">${t.icon} ${t.name}</span>`).join('')
    : '<span style="color:#64748b;font-size:.85rem">Attempt ≥3 questions per topic to see weak areas</span>';
  if (el('strong-list')) el('strong-list').innerHTML = strong.length
    ? strong.map(t => `<span class="area-tag strong">${t.icon} ${t.name}</span>`).join('')
    : '<span style="color:#64748b;font-size:.85rem">Keep practising to build strong topics!</span>';
  if (el('topic-bars')) {
    el('topic-bars').innerHTML = TOPICS.map(t => {
      const p   = progress[t.id] || { attempted: 0, correct: 0 };
      const pct = p.attempted ? Math.round(p.correct / p.attempted * 100) : 0;
      const col = pct >= 70 ? '#4ade80' : pct >= 40 ? '#f59e0b' : '#f87171';
      return `<div class="topic-bar-row">
        <span class="tbr-name">${t.icon} ${t.name}</span>
        <div class="tbr-bar-wrap"><div class="tbr-bar" style="width:${pct}%;background:${col}"></div></div>
        <span class="tbr-meta">${p.correct}/${p.attempted} (${pct}%)</span>
      </div>`;
    }).join('');
  }
  if (el('mock-history')) {
    el('mock-history').innerHTML = mockHistory.length
      ? mockHistory.map(h => `<div class="mh-row">
          <span>${h.title} — ${h.date}</span>
          <span class="mh-score" style="color:${h.pct>=60?'#4ade80':'#f87171'}">${h.score}/${h.total} (${h.pct}%)</span>
        </div>`).join('')
      : '<p style="color:#64748b;font-size:.85rem">No mock papers attempted yet.</p>';
  }
}

function resetProgress() {
  if (!confirm('Reset ALL progress? This cannot be undone.')) return;
  progress = {}; streak = 0; bestStreak = 0; mockHistory = [];
  MOCK_PAPERS.forEach(p => p.qs = null);
  saveProgress(); renderProgress(); renderHome();
}

/* ──────────────────── AI TUTOR ──────────────────── */
function initAI() {
  if (nvApiKey) { hide('ai-key-gate'); show('ai-chat'); }
  else          { show('ai-key-gate'); hide('ai-chat'); }
}

el('ai-key-btn').addEventListener('click', () => {
  const key = el('ai-key-input').value.trim();
  if (!key || !key.startsWith('nvapi-')) { alert('Enter a valid NVIDIA API key starting with nvapi-'); return; }
  nvApiKey = key;
  localStorage.setItem('jkssb_nvkey', key);
  initAI();
  addBotMsg('🏥 AI Tutor activated! I\'m ready to help you crack JKSSB FMPHW/MMPHW 2025. Ask me anything about the syllabus!');
});

el('ai-reset-key').addEventListener('click', () => {
  nvApiKey = ''; localStorage.removeItem('jkssb_nvkey');
  if (el('ai-key-input')) el('ai-key-input').value = '';
  initAI();
});

document.querySelectorAll('.qchip').forEach(btn => {
  btn.addEventListener('click', () => {
    if (el('chat-input')) el('chat-input').value = btn.dataset.q;
    sendAI();
  });
});

el('send-btn').addEventListener('click', sendAI);
el('chat-input').addEventListener('keydown', e => {
  if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); sendAI(); }
});

async function sendAI() {
  const inp  = el('chat-input');
  const text = inp.value.trim();
  if (!text) return;
  if (!nvApiKey) { alert('Please enter your NVIDIA API key first.'); return; }
  inp.value = '';
  addUserMsg(text);
  const tid = addTypingIndicator();
  try {
    const model = el('ai-model') ? el('ai-model').value : 'meta/llama-3.3-70b-instruct';
    const res = await fetch('https://integrate.api.nvidia.com/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + nvApiKey },
      body: JSON.stringify({
        model,
        messages: [
          { role: 'system', content: 'You are an expert tutor for the JKSSB FMPHW/MMPHW 2025 health worker exam in Jammu & Kashmir. Answer clearly with bullet points, tables, and ⭐ for exam-important points. Topics: MCH, ANC, immunization UIP schedule, cold chain, family planning, nutrition deficiencies, national health programs (NHM, NTEP, NACP, NPCDCS, RMNCH+A), first aid, CPR, anatomy, vital signs, environmental health, biomedical waste, health statistics, essential medicines. Be concise and practical.' },
          { role: 'user', content: text }
        ],
        max_tokens: 1024, temperature: 0.4, stream: false
      })
    });
    removeTypingIndicator(tid);
    if (!res.ok) {
      const err = await res.json().catch(() => ({}));
      addBotMsg('❌ API Error: ' + (err.message || res.status) + '. Check your API key.');
      return;
    }
    const data  = await res.json();
    const reply = data.choices?.[0]?.message?.content || 'No response received.';
    addBotMsg(reply);
  } catch (e) {
    removeTypingIndicator(tid);
    addBotMsg('❌ Network error: ' + e.message);
  }
}

function addUserMsg(text) {
  const w = el('chat-window');
  if (!w) return;
  w.innerHTML += `<div class="chat-msg user"><div class="chat-avatar">👤</div><div class="chat-bubble">${esc(text)}</div></div>`;
  w.scrollTop = w.scrollHeight;
}

let _tc = 0;
function addTypingIndicator() {
  const id = 'typ-' + (++_tc);
  const w  = el('chat-window');
  if (!w) return id;
  w.innerHTML += `<div class="chat-msg bot" id="${id}"><div class="chat-avatar">🤖</div><div class="chat-bubble"><span class="typing-dots"><span></span><span></span><span></span></span></div></div>`;
  w.scrollTop = w.scrollHeight;
  return id;
}
function removeTypingIndicator(id) { document.getElementById(id)?.remove(); }

function addBotMsg(text) {
  const w = el('chat-window');
  if (!w) return;
  w.innerHTML += `<div class="chat-msg bot"><div class="chat-avatar">🤖</div><div class="chat-bubble">${fmtAI(text)}</div></div>`;
  w.scrollTop = w.scrollHeight;
}

function esc(s) { return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function fmtAI(t) {
  return t.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
    .replace(/\*\*(.+?)\*\*/g,'<strong>$1</strong>')
    .replace(/\*(.+?)\*/g,'<em>$1</em>')
    .replace(/`(.+?)`/g,'<code>$1</code>')
    .replace(/⭐/g,'<strong style="color:#f59e0b">⭐</strong>')
    .replace(/^#{1,3} (.+)$/gm,'<strong style="color:#38bdf8;font-size:1rem">$1</strong>')
    .replace(/^[-•] (.+)$/gm,'<br/>• $1')
    .replace(/\n\n/g,'<br/><br/>')
    .replace(/\n/g,'<br/>');
}

/* ──────────────────── PARTICLE CANVAS ──────────────────── */
(function initParticles() {
  const canvas = document.getElementById('bg-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  let W, H, particles = [];
  function resize() {
    W = canvas.width  = window.innerWidth;
    H = canvas.height = window.innerHeight;
  }
  resize();
  window.addEventListener('resize', resize);
  for (let i = 0; i < 80; i++) {
    particles.push({
      x: Math.random() * W, y: Math.random() * H,
      r: Math.random() * 2 + 0.5,
      vx: (Math.random() - 0.5) * 0.4, vy: (Math.random() - 0.5) * 0.4,
      a: Math.random() * 0.5 + 0.1
    });
  }
  function draw() {
    ctx.clearRect(0, 0, W, H);
    particles.forEach(p => {
      p.x += p.vx; p.y += p.vy;
      if (p.x < 0) p.x = W; if (p.x > W) p.x = 0;
      if (p.y < 0) p.y = H; if (p.y > H) p.y = 0;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
      ctx.fillStyle = `rgba(0,212,255,${p.a})`;
      ctx.fill();
    });
    requestAnimationFrame(draw);
  }
  draw();
})();

/* ──────────────────── CONFETTI ──────────────────── */
const _confCanvas = document.getElementById('confetti-canvas');
const _confCtx    = _confCanvas ? _confCanvas.getContext('2d') : null;
let   _confetti   = [];
if (_confCanvas) {
  _confCanvas.width  = window.innerWidth;
  _confCanvas.height = window.innerHeight;
  window.addEventListener('resize', () => { _confCanvas.width = window.innerWidth; _confCanvas.height = window.innerHeight; });
}
function launchConfetti() {
  if (!_confCtx) return;
  const colors = ['#00d4ff','#7c3aed','#00ff88','#ffd700','#ff6b35','#ff2d78'];
  for (let i = 0; i < 40; i++) {
    _confetti.push({
      x: window.innerWidth / 2, y: window.innerHeight / 3,
      vx: (Math.random() - 0.5) * 12, vy: (Math.random() - 1.2) * 10,
      r: Math.random() * 5 + 3, c: colors[Math.floor(Math.random() * colors.length)],
      life: 1, spin: Math.random() * 0.3
    });
  }
  if (_confetti.length === 40) animateConfetti();
}
function animateConfetti() {
  if (!_confCtx) return;
  _confCtx.clearRect(0, 0, _confCanvas.width, _confCanvas.height);
  _confetti = _confetti.filter(p => p.life > 0);
  _confetti.forEach(p => {
    p.x += p.vx; p.y += p.vy; p.vy += 0.3; p.life -= 0.015;
    _confCtx.globalAlpha = p.life;
    _confCtx.fillStyle = p.c;
    _confCtx.fillRect(p.x, p.y, p.r, p.r * 0.5);
  });
  _confCtx.globalAlpha = 1;
  if (_confetti.length > 0) requestAnimationFrame(animateConfetti);
  else _confCtx.clearRect(0, 0, _confCanvas.width, _confCanvas.height);
}

/* ──────────────────── BOOKMARKS ──────────────────── */
let bookmarks = JSON.parse(localStorage.getItem('jkssb_bookmarks') || '[]');

function saveBookmarks() {
  localStorage.setItem('jkssb_bookmarks', JSON.stringify(bookmarks));
}

function toggleBookmark() {
  const q = currentQuiz.questions[currentQuiz.idx];
  if (!q) return;
  const key = q.q;
  const idx = bookmarks.findIndex(b => b.q === key);
  const btn = el('bookmark-btn');
  if (idx === -1) {
    bookmarks.push(q);
    saveBookmarks();
    if (btn) { btn.textContent = '⭐'; btn.classList.add('bookmarked'); }
  } else {
    bookmarks.splice(idx, 1);
    saveBookmarks();
    if (btn) { btn.textContent = '🔖'; btn.classList.remove('bookmarked'); }
  }
}

function updateBookmarkBtn() {
  const q = currentQuiz.questions[currentQuiz.idx];
  const btn = el('bookmark-btn');
  if (!btn || !q) return;
  const saved = bookmarks.some(b => b.q === q.q);
  btn.textContent = saved ? '⭐' : '🔖';
  btn.classList.toggle('bookmarked', saved);
}

function renderBookmarks() {
  const list = el('bookmarks-list');
  const empty = el('bookmarks-empty');
  const clearBtn = el('clear-bookmarks-btn');
  if (!list) return;
  if (!bookmarks.length) {
    list.innerHTML = '';
    if (empty) empty.classList.remove('hidden');
    if (clearBtn) clearBtn.style.display = 'none';
    return;
  }
  if (empty) empty.classList.add('hidden');
  if (clearBtn) clearBtn.style.display = 'inline-block';
  list.innerHTML = bookmarks.map((q, i) => {
    const topicName = TOPICS.find(t => t.id === q.topic)?.name || q.topic;
    return `<div class="bookmark-card">
      <div class="bk-meta"><span class="topic-chip">${topicName}</span><button class="bk-remove" data-idx="${i}" title="Remove bookmark">✕</button></div>
      <p class="bk-q">${q.q}</p>
      <div class="bk-opts">${q.opts.map((o, oi) => `<div class="bk-opt ${oi === q.ans ? 'bk-correct' : ''}">${String.fromCharCode(65+oi)}. ${o}</div>`).join('')}</div>
      <div class="bk-expl">💡 ${q.expl}</div>
    </div>`;
  }).join('');
  list.querySelectorAll('.bk-remove').forEach(btn => {
    btn.addEventListener('click', () => {
      bookmarks.splice(parseInt(btn.dataset.idx), 1);
      saveBookmarks();
      renderBookmarks();
    });
  });
}

el('clear-bookmarks-btn') && el('clear-bookmarks-btn').addEventListener('click', () => {
  if (confirm('Clear all bookmarks?')) { bookmarks = []; saveBookmarks(); renderBookmarks(); }
});

/* ──────────────────── DAILY CHALLENGE ──────────────────── */
let dailyState = JSON.parse(localStorage.getItem('jkssb_daily') || '{}');
/* dailyState = { streak, bestStreak, lastDate, completedToday } */

function getTodayStr() {
  return new Date().toISOString().slice(0, 10);
}

function getDailyQuestions() {
  const today = getTodayStr();
  /* seed shuffle by date so same 10 questions appear all day */
  const seed = today.split('-').reduce((a, v) => a + parseInt(v), 0);
  const shuffled = [...QUESTIONS].sort((a, b) => {
    const ha = Math.sin(seed + QUESTIONS.indexOf(a)) * 10000;
    const hb = Math.sin(seed + QUESTIONS.indexOf(b)) * 10000;
    return (ha - Math.floor(ha)) - (hb - Math.floor(hb));
  });
  return shuffled.slice(0, 10);
}

let dailyQuiz = { questions: [], idx: 0, score: 0, answers: [] };

function renderDailyHome() {
  const today = getTodayStr();
  if (dailyState.lastDate !== today) {
    dailyState.completedToday = false;
  }
  if (el('daily-streak-num')) el('daily-streak-num').textContent = dailyState.streak || 0;
  if (el('daily-best-streak')) el('daily-best-streak').textContent = dailyState.bestStreak || 0;
  const statusEl = el('daily-done-today');
  if (statusEl) statusEl.textContent = dailyState.completedToday ? '✅ Done!' : '⏳ Pending';
  const startBtn = el('start-daily-btn');
  if (startBtn) startBtn.textContent = dailyState.completedToday ? '🔁 Redo Today\'s Challenge' : '📅 Start Today\'s Challenge';
  show('daily-home'); hide('daily-arena'); hide('daily-result');
}

function startDailyChallenge() {
  dailyQuiz = { questions: getDailyQuestions(), idx: 0, score: 0, answers: [] };
  hide('daily-home'); show('daily-arena'); hide('daily-result');
  el('dc-flip-card').classList.remove('flipped');
  renderDailyQuestion();
}

function renderDailyQuestion() {
  const q = dailyQuiz.questions[dailyQuiz.idx];
  const total = 10;
  if (el('dc-counter')) el('dc-counter').textContent = `Q ${dailyQuiz.idx + 1} / ${total}`;
  if (el('dc-num-badge')) el('dc-num-badge').textContent = `Q${dailyQuiz.idx + 1}`;
  if (el('dc-score')) el('dc-score').textContent = dailyQuiz.score;
  if (el('dc-streak')) el('dc-streak').textContent = '🔥' + streak;
  if (el('dc-bar')) el('dc-bar').style.width = (dailyQuiz.idx / total * 100) + '%';
  if (el('dc-q-text')) el('dc-q-text').textContent = q.q;
  if (el('dc-options')) {
    el('dc-options').innerHTML = q.opts.map((opt, i) =>
      `<button class="opt-btn" data-idx="${i}"><span class="opt-label">${String.fromCharCode(65+i)}</span>${opt}</button>`
    ).join('');
    el('dc-options').querySelectorAll('.opt-btn').forEach(btn =>
      btn.addEventListener('click', () => selectDailyOption(parseInt(btn.dataset.idx)))
    );
  }
  el('dc-flip-card').classList.remove('flipped');
}

function selectDailyOption(chosen) {
  const q = dailyQuiz.questions[dailyQuiz.idx];
  const isCorrect = chosen === q.ans;
  const isLast = dailyQuiz.idx === 9;
  dailyQuiz.answers.push({ chosen, correct: q.ans, isCorrect, q });
  if (isCorrect) { dailyQuiz.score++; launchConfetti(); }
  recordAnswer(q.topic, isCorrect);
  el('dc-options').querySelectorAll('.opt-btn').forEach((btn, i) => {
    btn.disabled = true;
    if (i === q.ans) btn.classList.add('correct');
    if (i === chosen && !isCorrect) btn.classList.add('wrong');
  });
  if (el('dc-score')) el('dc-score').textContent = dailyQuiz.score;
  if (el('dc-expl')) el('dc-expl').textContent = q.expl;
  if (el('dc-next-btn')) el('dc-next-btn').textContent = isLast ? 'Show Results 🏆' : 'Next Question →';
  setTimeout(() => el('dc-flip-card').classList.add('flipped'), 500);
}

el('dc-next-btn') && el('dc-next-btn').addEventListener('click', () => {
  el('dc-flip-card').classList.remove('flipped');
  setTimeout(() => {
    if (dailyQuiz.idx >= 9) { showDailyResult(); return; }
    dailyQuiz.idx++;
    renderDailyQuestion();
  }, 400);
});

function showDailyResult() {
  hide('daily-arena');
  show('daily-result');
  const pct = Math.round(dailyQuiz.score / 10 * 100);
  const today = getTodayStr();
  if (!dailyState.completedToday || dailyState.lastDate !== today) {
    if (dailyState.lastDate === getPreviousDayStr()) {
      dailyState.streak = (dailyState.streak || 0) + 1;
    } else if (dailyState.lastDate !== today) {
      dailyState.streak = 1;
    }
    dailyState.bestStreak = Math.max(dailyState.streak || 0, dailyState.bestStreak || 0);
    dailyState.lastDate = today;
    dailyState.completedToday = true;
    localStorage.setItem('jkssb_daily', JSON.stringify(dailyState));
  }
  let emoji = '😞', title = 'Keep Going!';
  if (pct >= 90) { emoji = '🏆'; title = 'Perfect Score! Brilliant!'; launchConfetti(); setTimeout(launchConfetti, 300); }
  else if (pct >= 70) { emoji = '🎉'; title = 'Great Job!'; launchConfetti(); }
  else if (pct >= 50) { emoji = '👍'; title = 'Good Effort!'; }
  if (el('dc-r-orb')) el('dc-r-orb').textContent = emoji;
  if (el('dc-r-title')) el('dc-r-title').textContent = title;
  if (el('dc-r-pct')) el('dc-r-pct').textContent = pct + '%';
  if (el('dc-r-detail')) el('dc-r-detail').textContent = `${dailyQuiz.score} / 10 correct`;
  const badgeEl = el('dc-streak-badge');
  if (badgeEl) badgeEl.textContent = `🔥 Day Streak: ${dailyState.streak} days`;
  animateArc('dc-score-arc', pct);
}

function getPreviousDayStr() {
  const d = new Date(); d.setDate(d.getDate() - 1);
  return d.toISOString().slice(0, 10);
}

